var COURSES_DB = {};
COURSES_DB['computer-literacy'] = {"id":"computer-literacy","title":"Computer Literacy: From Zero to Confident Digital User","shortDesc":"For complete beginners, learn to use a computer confidently, navigate the internet safely, master Word, Excel, and PowerPoint, and gain the digital skills every Liberian employer expects.","category":"Computer Fundamentals","icon":"💻","gradient":"linear-gradient(135deg,#1e3a5f,#002868)","instructor":"Samuel Tolbert","instructorTitle":"Founder & CEO, Tolbert Innovation Hub","instructorBio":"Samuel Tolbert founded TIH to bring world-class digital education to Liberia and West Africa. He has trained over 10,000 students across the region in foundational technology skills.","rating":4.9,"reviewCount":1247,"students":"8,400+","duration":"34h","level":"Beginner","price":"FREE","origPrice":"$120","isFree":true,"badge":"free","certId":"TIH-2026-CCL-0042","learn":["Navigate Windows and macOS with full confidence","Create, save, and organize files and folders efficiently","Use the internet safely for research, email, and communication","Create professional documents using Microsoft Word","Build spreadsheets and track data with Microsoft Excel","Design compelling presentations with Microsoft PowerPoint","Protect yourself from viruses, phishing, and online scams","Use Gmail, Google Drive, and collaboration tools productively"],"requirements":["No prior computer experience needed, this course starts from zero","Access to a computer or smartphone (Windows, Mac, or Android)","Willingness to practice daily exercises provided in each module"],"about":["Computer literacy is the foundation of every digital opportunity available today. In Liberia and across West Africa, the ability to confidently use a computer separates those who can access global opportunities from those who cannot. This course was designed specifically for our community, starting from the very basics and building up to professional-level digital skills.","You will learn to use a computer from scratch, master the Microsoft Office suite used in every professional environment, and navigate the internet safely. Each lesson is practical, hands-on, and immediately applicable to real jobs, business, and daily life.","Thousands of Liberians have already completed this course and gone on to secure office jobs, start online businesses, and help their families. Whether you are a student, a job seeker, or a professional wanting to upgrade your skills, this free course is your starting point."],"modules":[{"title":"Module 1: Getting Started with Computers","icon":"💻","meta":"5 lessons · 45 min","lessons":[{"t":"1.1 What is a Computer? Hardware vs Software","d":"8:30","v":"NARrnGza4kA"},{"t":"1.2 Navigating Windows: Desktop, Files & Folders","d":"12:00","v":"qIRRiM6Ibno"},{"t":"1.3 Typing Skills & Keyboard Shortcuts","d":"10:00","v":"QTeX0Za2Ur8"},{"t":"1.4 Managing Files: Save, Copy, Move & Delete","d":"9:00","v":"k-EID5_2D9U"},{"t":"📝 Quiz: Computer Basics","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Internet & Digital Communication","icon":"🌐","meta":"5 lessons · 42 min","lessons":[{"t":"2.1 How the Internet Works & Staying Safe Online","d":"10:00","v":"bSBLF66cCN0"},{"t":"2.2 Effective Google Search & Evaluating Sources","d":"8:00","v":"iLMUrr0C_0c"},{"t":"2.3 Setting Up & Using Gmail Professionally","d":"9:30","v":"PEB9jEXh0X4"},{"t":"2.4 Google Drive, Docs & Cloud Storage","d":"9:30","v":"NZlemQPeo0Q"},{"t":"📝 Quiz: Internet & Digital Safety","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Microsoft Office Productivity","icon":"📄","meta":"5 lessons · 55 min","lessons":[{"t":"3.1 Microsoft Word: Documents, CVs & Letters","d":"12:00","v":"EuWTrvT_YyY"},{"t":"3.2 Microsoft Excel: Spreadsheets & Basic Formulas","d":"14:00","v":"Vl0H-qTclOg"},{"t":"3.3 Microsoft PowerPoint: Creating Presentations","d":"10:00","v":"DzPhjLPLLeg"},{"t":"3.4 Printing, Formatting & Professional Documents","d":"9:00","v":"CBPe_IFxJWc"},{"t":"🛠️ Project: Create a Professional CV & Cover Letter","d":"Project","isProject":true}]},{"title":"Module 4: Digital Safety & Career Readiness","icon":"🏆","meta":"4 lessons · 38 min","lessons":[{"t":"4.1 Cybersecurity Basics: Passwords, Viruses & Scams","d":"10:00","v":"ey4dXseAODE"},{"t":"4.2 Online Job Searching & LinkedIn Basics","d":"9:00","v":"dOZDQpulyCQ"},{"t":"4.3 Digital Payments & Mobile Money Safety","d":"9:30","v":"CQFXF6bbeI8"},{"t":"📝 Quiz: Digital Safety & Career Readiness","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Online Collaboration & Remote Work Tools","icon":"🤝","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Video Meetings with Zoom & Google Meet","d":"Video + notes","v":"5kedqr2Ds-E"},{"t":"5.2 Professional Communication: Email Etiquette, WhatsApp Business & Slack","d":"Video + notes","v":"ZeY62YV_6rs"},{"t":"5.3 Digital Organization: Calendars, Scheduling & Task Management","d":"Video + notes","v":"aEJ7QGrJshA"},{"t":"📝 Quiz: Online Collaboration & Remote Work","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Launching Your Digital Career","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Building Your Professional Online Presence","d":"Video + notes","v":"YCb2icQuv8Y"},{"t":"6.2 Freelancing & Earning Online from Liberia","d":"Video + notes","v":"KR1WYQEehwc"},{"t":"6.3 Capstone Project: Your Digital Job Application Kit","d":"Video + notes","v":"KfScugUnSSM"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Computer Basics","moduleNum":1,"unlocks":3,"questions":[{"q":"What does CPU stand for?","opts":["Central Processing Unit","Computer Personal Unit","Central Peripheral Unit","Control Processing Unit"],"correct":0,"exp":"CPU is the brain of the computer that processes all instructions."},{"q":"Which is an INPUT device?","opts":["Monitor","Speaker","Keyboard","Printer"],"correct":2,"exp":"The keyboard sends data INTO the computer, making it an input device."},{"q":"What is an Operating System?","opts":["A website browser","Software managing hardware and software","A storage device","A type of keyboard"],"correct":1,"exp":"The OS like Windows manages all hardware and software resources."},{"q":"RAM stands for:","opts":["Remote Access Memory","Random Access Memory","Read-After Memory","Rapid Access Module"],"correct":1,"exp":"RAM is your computer's temporary working memory used while programs run."},{"q":"Which is a permanent storage device?","opts":["RAM","CPU","Hard Drive","Monitor"],"correct":2,"exp":"Hard drives store data permanently, even when the computer is powered off."},{"q":"Which keyboard shortcut copies selected text or files?","opts":["Ctrl+V","Ctrl+C","Ctrl+Z","Ctrl+P"],"correct":1,"exp":"Ctrl+C copies the selection to the clipboard, while Ctrl+V pastes it in a new location."},{"q":"Which of these is an example of software?","opts":["The monitor","Microsoft Word","The mouse","The hard drive"],"correct":1,"exp":"Software is a program you run, like Microsoft Word, while monitors, mice, and drives are physical hardware."},{"q":"When you delete a file in Windows, where does it usually go first?","opts":["The Recycle Bin","The Documents folder","The cloud","It is erased permanently and instantly"],"correct":0,"exp":"Deleted files move to the Recycle Bin first, giving you a chance to restore them before permanent removal."},{"q":"A file named report.docx was most likely created in which program?","opts":["Microsoft Excel","Microsoft PowerPoint","Microsoft Word","Paint"],"correct":2,"exp":"The .docx extension identifies a Microsoft Word document, just as .xlsx identifies Excel and .pptx identifies PowerPoint."},{"q":"In touch typing, which keys form the home row where your fingers rest?","opts":["Q W E R and U I O P","A S D F and J K L ;","Z X C V and B N M ,","1 2 3 4 and 7 8 9 0"],"correct":1,"exp":"Touch typists rest their fingers on A S D F and J K L ; and reach other keys from that position without looking down."}]},"mod2":{"title":"Quiz: Internet & Digital Safety","moduleNum":2,"unlocks":3,"questions":[{"q":"HTTPS means a website is:","opts":["Popular","Fast loading","Secure and encrypted","Free to use"],"correct":2,"exp":"HTTPS encrypts the connection between your browser and the server."},{"q":"A phishing email typically:","opts":["Is from a colleague","Has a professional design","Creates urgency asking for passwords via suspicious links","Has a phone number"],"correct":2,"exp":"Phishing uses urgency and fake links to steal your personal information."},{"q":"A strong password should:","opts":["Be your name","Be short and simple","Mix letters, numbers, and symbols","Be shared with family"],"correct":2,"exp":"Complex passwords mixing characters are much harder to crack."},{"q":"2FA means:","opts":["Two passwords","Two devices","Two verification methods","Two accounts"],"correct":2,"exp":"2FA requires a second proof of identity beyond just your password."},{"q":"Safest for online banking?","opts":["Public café Wi-Fi","Neighbour's Wi-Fi","Private home network with HTTPS","Incognito mode anywhere"],"correct":2,"exp":"A private network combined with HTTPS is the safest combination for banking."},{"q":"Which of these is a web browser?","opts":["Windows 11","Google Chrome","Gmail","Microsoft Excel"],"correct":1,"exp":"Google Chrome is a browser used to visit websites, while Windows is an operating system and Gmail is an email service."},{"q":"You email 30 customers and want to hide their addresses from each other. Which field should you use?","opts":["To","CC","BCC","Subject"],"correct":2,"exp":"BCC (blind carbon copy) hides each recipient's address from the others, protecting their privacy."},{"q":"What is the main advantage of saving files in Google Drive?","opts":["Files open faster than from the hard drive","Files are stored online and accessible from any device","Files can never be deleted","Files do not need an internet connection to upload"],"correct":1,"exp":"Cloud storage keeps your files online so you can reach them from any computer or phone with internet access."},{"q":"To search Google for an exact phrase like a song title, you should:","opts":["Type the phrase in quotation marks","Type the phrase in capital letters","Add the word 'exact' before the phrase","Search each word separately"],"correct":0,"exp":"Putting quotation marks around a phrase tells Google to return only pages containing those exact words in that order."},{"q":"Which signal suggests a website is a trustworthy source for research?","opts":["It has many pop-up advertisements","It names its author, cites sources, and shows a recent date","It promises secret information no one else has","It asks you to register before showing any content"],"correct":1,"exp":"Reliable sources identify their authors, cite where facts come from, and show when content was published or updated."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Microsoft Word is best for:","opts":["Spreadsheets","Slide presentations","Text documents and CVs","Video editing"],"correct":2,"exp":"Word is the standard application for creating text documents and professional CVs."},{"q":"Best way to back up files?","opts":["Desktop only","Email to self","Cloud storage + local copy","Print them"],"correct":2,"exp":"Multiple backup locations protect against data loss from any single failure."},{"q":"NEVER do with cybersecurity:","opts":["Use unique passwords","Enable 2FA","Click unknown links to test them","Update software regularly"],"correct":2,"exp":"Never click suspicious links to verify them, use official websites instead."},{"q":"A verifiable digital certificate means:","opts":["Printed on special paper","Can be confirmed genuine using a verification code","Issued by government","Cost money"],"correct":1,"exp":"Verification codes let employers instantly confirm your certificate's authenticity."},{"q":"This course teaches you to:","opts":["Program software","Use computers professionally and stay safe online","Repair hardware","Build websites"],"correct":1,"exp":"Computer literacy enables professional digital use across all areas of life and work."},{"q":"Which component is considered the 'brain' of the computer?","opts":["The CPU","The monitor","The keyboard","The power supply"],"correct":0,"exp":"The CPU (Central Processing Unit) executes instructions and processes all data in the computer."},{"q":"What is the difference between RAM and a hard drive?","opts":["RAM stores files permanently; the hard drive is temporary","RAM is temporary working memory; the hard drive stores data permanently","They are two names for the same part","RAM is only used for the internet"],"correct":1,"exp":"RAM holds data only while the computer is on, while the hard drive keeps files even when power is off."},{"q":"Ctrl+Z is the shortcut to:","opts":["Print a document","Undo your last action","Save a file","Close the program"],"correct":1,"exp":"Ctrl+Z reverses your most recent action, a lifesaver when you make a mistake."},{"q":"Which address shows a secure website connection?","opts":["http://mybank.com","https://mybank.com","ftp://mybank.com","www-mybank-com"],"correct":1,"exp":"The 's' in https means the connection is encrypted, protecting information you send to the site."},{"q":"An email from 'support@gmaii-security.com' asking you to confirm your password is most likely:","opts":["An official Google message","A phishing attempt using a lookalike address","A message from your employer","A harmless newsletter"],"correct":1,"exp":"Scammers use misspelled lookalike addresses like 'gmaii' to impersonate real companies and steal credentials."},{"q":"Which program would you use to calculate monthly sales totals with formulas?","opts":["Microsoft PowerPoint","Microsoft Word","Microsoft Excel","Notepad"],"correct":2,"exp":"Excel is built for numbers, formulas, and calculations across rows and columns of data."},{"q":"In PowerPoint, a good slide should:","opts":["Contain your full speech word-for-word","Use short points and visuals to support what you say","Use as many colors and animations as possible","Be read directly from the screen to the audience"],"correct":1,"exp":"Slides work best as visual support with brief points, while the detail comes from the speaker."},{"q":"Two-factor authentication protects your account by:","opts":["Making your password longer","Requiring a second proof of identity, like a code sent to your phone","Hiding your email address from senders","Blocking all emails from strangers"],"correct":1,"exp":"Even if a thief steals your password, 2FA stops them because they lack the second verification step."},{"q":"The safest response to an unexpected mobile money 'reversal' request from a stranger is to:","opts":["Send the money back immediately","Verify with your provider's official line before taking any action","Share your PIN so they can fix it","Forward the request to friends"],"correct":1,"exp":"Fake reversal requests are a common scam, always confirm through the provider's official customer service first."},{"q":"In a video meeting, the 'Share Screen' feature lets you:","opts":["Give others control of your mouse permanently","Show a window or presentation from your computer to all participants","Record other participants' screens","Increase your internet speed"],"correct":1,"exp":"Screen sharing displays your chosen window, such as a PowerPoint, to everyone in the meeting."},{"q":"BCC is the right email field when you want to:","opts":["Highlight the most important recipient","Send copies while keeping recipients' addresses hidden from each other","Mark the email as urgent","Attach large files"],"correct":1,"exp":"BCC protects privacy by hiding each recipient's address from all other recipients."},{"q":"Which habit best builds a reputation for reliability at work?","opts":["Keeping deadlines in your memory only","Recording every commitment in a calendar with reminders","Replying to messages once a month","Storing all files on the desktop"],"correct":1,"exp":"A maintained calendar with reminders ensures you never miss meetings or deadlines, which builds trust."},{"q":"On LinkedIn, your headline should ideally contain:","opts":["Only the words 'Job Seeker'","Your key skills and professional identity","Your password hint","Your favorite quotes only"],"correct":1,"exp":"A skills-rich headline like 'Administrative Assistant | Microsoft Office | TIH Certified' helps recruiters find and evaluate you."},{"q":"A client on a freelance platform asks you to pay a 'registration fee' before receiving your first task. You should:","opts":["Pay quickly before the offer expires","Refuse, asking workers to pay is a classic scam","Negotiate a smaller fee","Pay half now and half later"],"correct":1,"exp":"Legitimate clients and employers pay you for work; any request for upfront payment from a worker signals fraud."},{"q":"Why should you save your final CV as a PDF before emailing it to an employer?","opts":["PDF files cannot be opened on other computers","PDF preserves your formatting exactly on any device","PDF files are always smaller than one kilobyte","Employers cannot read Word documents at all"],"correct":1,"exp":"A PDF looks identical on every device, so your careful formatting is never broken on the employer's screen."}]},"mod4":{"title":"Quiz: Digital Safety & Career Readiness","moduleNum":4,"questions":[{"q":"Someone calls claiming to be from Orange Money and asks for your PIN to 'fix' your account. What should you do?","opts":["Give the PIN since they sound official","Refuse, no genuine provider ever asks for your PIN","Give an old PIN instead","Ask them to call back later"],"correct":1,"exp":"Mobile money providers never ask for your PIN; anyone who does is attempting fraud."},{"q":"What is the main job of antivirus software?","opts":["To speed up your internet connection","To detect, block, and remove malicious programs","To back up your files to the cloud","To create strong passwords for you"],"correct":1,"exp":"Antivirus software scans your computer to detect, quarantine, and remove viruses and other malware."},{"q":"Which is a warning sign that a job posting is a scam?","opts":["It lists required qualifications","It asks you to pay a fee before you can be hired","It includes the company's office address","It requests a CV and cover letter"],"correct":1,"exp":"Legitimate employers never charge candidates to apply or be hired, upfront fees are a classic scam."},{"q":"LinkedIn is best described as:","opts":["A photo-sharing app for friends","A professional networking and job-search platform","A mobile money service","A video streaming website"],"correct":1,"exp":"LinkedIn connects professionals with employers, recruiters, and industry contacts worldwide."},{"q":"What does a password manager do?","opts":["Deletes your old passwords every month","Securely stores unique passwords so you only remember one master password","Shares your passwords with trusted contacts","Makes all your accounts use the same password"],"correct":1,"exp":"A password manager stores strong, unique passwords in an encrypted vault protected by one master password."},{"q":"Malware is:","opts":["Hardware that has stopped working","Any software designed to harm or exploit a computer","An email that bounces back","A slow internet connection"],"correct":1,"exp":"Malware, malicious software, includes viruses, spyware, and ransomware designed to damage or steal from your system."},{"q":"After using email on a cybercafe computer in Monrovia, you should always:","opts":["Leave the account open for the next customer","Sign out of every account and close the browser","Save your password on the computer for next time","Turn off the monitor only"],"correct":1,"exp":"Signing out and closing the browser on shared computers prevents strangers from accessing your accounts."},{"q":"Why should you install software updates promptly?","opts":["Updates make the screen brighter","Updates often patch security holes that attackers exploit","Updates delete viruses from email","Updates are required to charge the battery"],"correct":1,"exp":"Updates fix known security vulnerabilities, closing the doors that hackers use to break in."},{"q":"A text message says you won a lottery you never entered and must click a link to claim it. This is most likely:","opts":["A smishing (SMS phishing) scam","A message from your bank","A government announcement","A harmless advertisement you should click"],"correct":0,"exp":"Unexpected prize messages with links are SMS phishing attempts designed to steal money or personal data."},{"q":"Which mobile money habit is safest?","opts":["Writing your PIN on the back of your phone","Confirming the recipient's name and number before sending money","Letting the agent enter your PIN for you","Sending money to any number that requests it"],"correct":1,"exp":"Verifying the recipient's details before confirming prevents irreversible transfers to wrong or fraudulent numbers."}]},"mod5":{"title":"Quiz: Online Collaboration & Remote Work","moduleNum":5,"questions":[{"q":"Before an important video meeting, when should you join?","opts":["Exactly on time","A few minutes early to test your audio and connection","Ten minutes late to be safe","Only after the host calls you"],"correct":1,"exp":"Joining early lets you fix microphone, camera, or connection problems before others are waiting."},{"q":"During a video meeting, you should mute your microphone when:","opts":["You are the host","You are speaking","You are not speaking","The meeting is being recorded"],"correct":2,"exp":"Muting when not speaking blocks background noise like traffic and generators from disturbing the meeting."},{"q":"Before sharing your screen in a meeting, it is wise to:","opts":["Close private windows like your email","Turn off your camera","Increase your screen brightness","Leave and rejoin the meeting"],"correct":0,"exp":"Everything on a shared screen is visible to all participants, so close anything private first."},{"q":"The easiest way to schedule a Google Meet call with colleagues is to:","opts":["Send them your phone number","Create a Google Calendar event and add Meet video conferencing","Post the meeting time on social media","Email them a Word document"],"correct":1,"exp":"Google Calendar generates the Meet link automatically and sends invitations to every guest you add."},{"q":"Which subject line is most professional for a job application email?","opts":["Hello!!","Please read this","Application for Finance Officer – Mary Kollie","(no subject)"],"correct":2,"exp":"A specific subject line tells the recipient exactly what the email is about and who it is from."},{"q":"What extra feature does WhatsApp Business offer over regular WhatsApp?","opts":["Free unlimited internet data","A business profile with catalog, quick replies, and automatic messages","The ability to send money abroad","Longer voice notes"],"correct":1,"exp":"WhatsApp Business adds professional tools like a business profile, product catalog, greeting messages, and quick replies."},{"q":"In Slack, work conversations are organized into:","opts":["Channels grouped by topic or team","One single chat for the whole company","Printed memos","Video playlists"],"correct":0,"exp":"Channels like #finance or #field-reports keep each topic's discussion in its own organized space."},{"q":"Which communication channel is best for a formal message you may need as a record later?","opts":["A voice note","A phone call","Email","A comment on social media"],"correct":2,"exp":"Email creates a written, timestamped record that both sides can search and reference later."},{"q":"In Google Calendar, setting an event to 'repeat weekly' is useful for:","opts":["One-time job interviews","A regular Monday staff meeting","Deleting old events","Sending emails automatically"],"correct":1,"exp":"Recurring events let you enter regular commitments once and have them appear automatically every week."},{"q":"Which file name follows good digital organization practice?","opts":["final2.xlsx","newdoc.xlsx","Sales_Report_2026-07.xlsx","untitled(3).xlsx"],"correct":2,"exp":"Clear names with content and date make files easy to find and identify months later."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Before this course I was afraid to touch a computer. Now I use Excel at work every day and my boss is impressed. Samuel explains everything so clearly, no step is skipped. This free course changed my career completely."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"I took this course after losing my job and needed to upgrade my skills. Within 3 weeks I could type fast, use Word and Excel, and send professional emails. I got a new job offer within a month. TIH is a blessing for Liberia."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"The module on internet safety alone was worth everything. I had already been scammed once online before. This course taught me exactly how to protect myself. Every Liberian should take this, especially our young people."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Living in Maryland County, I never thought I could access quality tech training. TIH made it possible online. The certificate is verified and I used it on my job application. Very grateful for this free resource."}],"faqs":[{"q":"Is this course really free?","a":"Yes, completely free. TIH believes foundational computer literacy should be accessible to every Liberian regardless of income. No credit card required."},{"q":"Do I need any equipment?","a":"You need access to a computer or smartphone. A computer is recommended for the Microsoft Office modules, but most lessons can be followed on any device."},{"q":"How long does the certificate take?","a":"Most students complete the course in 3-4 weeks studying 1-2 hours per day. Your certificate is issued immediately upon passing the final assessment."},{"q":"Is the certificate recognized by employers?","a":"Yes. TIH certificates include a unique verification code. Over 200 Liberian employers and NGOs recognize TIH certifications for hiring decisions."}]};
COURSES_DB['ai'] = {"id":"ai","title":"AI Fundamentals: ChatGPT, Gemini & Practical AI Tools","shortDesc":"For professionals, students, and entrepreneurs, learn to use ChatGPT, Gemini, and other AI tools to write faster, research smarter, automate tasks, and gain a real competitive edge in your career.","category":"Artificial Intelligence","icon":"🤖","gradient":"linear-gradient(135deg,#7c3aed,#5b21b6)","instructor":"Dr. Mariama Koroma","instructorTitle":"AI Researcher & Digital Education Lead","instructorBio":"Dr. Mariama Koroma holds a PhD in Computer Science with specialization in machine learning and has led AI literacy programs across West Africa. She is passionate about democratizing AI knowledge for African professionals.","rating":4.8,"reviewCount":832,"students":"5,200+","duration":"28h","level":"Beginner","price":"FREE","origPrice":"$150","isFree":true,"badge":"free","certId":"TIH-2026-AI-0088","learn":["Understand how AI and machine learning actually work behind the scenes","Write powerful prompts to get professional results from ChatGPT and Gemini","Use AI to write emails, reports, proposals, and marketing content","Generate images and creative content using AI tools like DALL-E and Canva AI","Automate repetitive business tasks using AI workflows","Critically evaluate AI output and identify hallucinations and errors","Apply AI ethically and responsibly in business and personal use","Build an AI-powered productivity system for your work or business"],"requirements":["Basic computer and internet skills (equivalent to our free Computer Literacy course)","A free ChatGPT or Gemini account (we walk you through setup in lesson 1)","Curiosity and openness to experiment, no coding or technical background needed"],"about":["Artificial Intelligence is transforming every industry in the world, and Africa is no exception. Businesses across Liberia and the continent are beginning to use AI to write content, analyze data, automate customer service, and compete globally. This course puts you ahead of that curve.","You will learn to use the most powerful and accessible AI tools available today: ChatGPT, Gemini, DALL-E, and more. More importantly, you will learn HOW to think about AI, understanding its capabilities, limitations, and how to integrate it responsibly into your work and business.","No technical background is required. Whether you are a business owner, student, marketer, teacher, or professional, this course gives you the practical AI skills that are rapidly becoming essential in every field. Join over 5,000 students who have already taken this step into the future."],"modules":[{"title":"Module 1: Understanding AI & Machine Learning","icon":"🤖","meta":"4 lessons · 38 min","lessons":[{"t":"1.1 What is AI? How Machines Learn from Data","d":"10:00","v":"Yq0QkCxoTHM"},{"t":"1.2 Types of AI: Narrow, Generative & Agentic AI","d":"9:00","v":"xvpeMdAs9pE"},{"t":"1.3 AI Tools Landscape: ChatGPT, Gemini, Claude & More","d":"10:00","v":"1PaJ28oVOAI"},{"t":"📝 Quiz: AI Fundamentals","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Working with ChatGPT & Gemini","icon":"💬","meta":"5 lessons · 48 min","lessons":[{"t":"2.1 Prompt Engineering: The Art of Asking AI the Right Way","d":"12:00","v":"mTzZod7cBj4"},{"t":"2.2 ChatGPT for Writing: Emails, Reports & Proposals","d":"11:00","v":"89EPPtzZHxE"},{"t":"2.3 Gemini for Research, Analysis & Summaries","d":"10:00","v":"YPOsbQzAPiI"},{"t":"2.4 Advanced Prompting: Role, Context, Format & Examples","d":"10:00","v":"V2Gmt1fEue4"},{"t":"📝 Quiz: Prompting & AI Tools","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: AI Creative & Productivity Tools","icon":"🎨","meta":"4 lessons · 42 min","lessons":[{"t":"3.1 AI Image Generation: DALL-E, Midjourney & Canva AI","d":"11:00","v":"qDtif1zxbkY"},{"t":"3.2 AI for Video, Audio & Content Creation","d":"10:00","v":"REqOxDfw914"},{"t":"3.3 Building AI Workflows to Automate Your Work","d":"11:00","v":"OA4UP4O1hz0"},{"t":"🛠️ Project: Build an AI-Powered Content Calendar","d":"Project","isProject":true}]},{"title":"Module 4: AI for Business & Ethics","icon":"🏆","meta":"4 lessons · 36 min","lessons":[{"t":"4.1 AI for Small Business: Customer Service & Marketing","d":"10:00","v":"sAhIne0U1Os"},{"t":"4.2 AI Ethics: Bias, Privacy & Responsible Use","d":"9:00","v":"qpp1G0iEL_c"},{"t":"4.3 The Future of AI: Careers, Opportunities & Risks","d":"8:00","v":"fWuzA77Mvzw"},{"t":"📝 Quiz: AI for Business & Ethics","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Advanced AI Skills, Custom Assistants, Data & Automation","icon":"⚙️","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Custom AI Assistants: Custom Instructions, GPTs & Gems","d":"Video + notes","v":"p6Z2d3T-fLM"},{"t":"5.2 AI for Data Analysis & Spreadsheets","d":"Video + notes","v":"MoPIkfscD3A"},{"t":"5.3 Connecting AI Tools: Automation Workflows & AI Agents","d":"Video + notes","v":"cXnPxN06boY"},{"t":"📝 Quiz: Advanced AI Skills & Automation","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Building Your AI-Powered Career","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 AI Freelancing & Consulting Opportunities in West Africa","d":"Video + notes","v":"-LCkwnpUilI"},{"t":"6.2 Designing an AI Solution for a Real Organization","d":"Video + notes","v":"x9Pl1XM4K7A"},{"t":"6.3 Capstone Project: Your AI Portfolio & Pitch","d":"Video + notes","v":"rGSmG7qp2Eg"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: AI Fundamentals","moduleNum":1,"unlocks":3,"questions":[{"q":"What does AI stand for?","opts":["Automated Input","Artificial Intelligence","Advanced Interface","Automated Integration"],"correct":1,"exp":"AI refers to computer systems that simulate human intelligence and decision-making."},{"q":"Machine Learning is:","opts":["A type of hardware","A programming language","AI that learns patterns from data","A computer operating system"],"correct":2,"exp":"ML algorithms improve automatically through experience without being explicitly reprogrammed."},{"q":"ChatGPT is primarily a:","opts":["Search engine","Image generator","Text-based AI language model","Video editor"],"correct":2,"exp":"ChatGPT is a large language model that generates and understands human text."},{"q":"A \"prompt\" in AI context is:","opts":["A hardware button","The instruction or question you give the AI","A type of database","An AI error message"],"correct":1,"exp":"Your prompt shapes the quality and direction of the AI's output entirely."},{"q":"Which is NOT an AI application?","opts":["Voice assistants","Recommendation algorithms","A manual calculator","Facial recognition"],"correct":2,"exp":"Manual calculators follow fixed arithmetic rules with no learning or adaptation."},{"q":"What is 'training data' in machine learning?","opts":["The electricity used to run AI servers","The examples an AI system learns patterns from","The instructions a user types into ChatGPT","The hardware inside an AI computer"],"correct":1,"exp":"AI models learn by finding patterns in large collections of examples called training data."},{"q":"Narrow AI refers to systems that:","opts":["Are smarter than humans at everything","Perform one specific task well, like translation or face recognition","Only run on small phones","Cannot learn from data"],"correct":1,"exp":"Narrow AI excels at a single defined task, unlike the general human-level intelligence seen in movies."},{"q":"An LLM (Large Language Model) like ChatGPT was primarily trained on:","opts":["Photographs and videos only","Massive amounts of text to predict likely words","Weather station measurements","Telephone call recordings only"],"correct":1,"exp":"LLMs learn language by processing enormous text collections and predicting the most likely next words."},{"q":"Which output is an example of generative AI at work?","opts":["A calculator adding two numbers","A thermostat turning on a fan","ChatGPT drafting a new business proposal from your description","A clock showing the time"],"correct":2,"exp":"Generative AI creates new content, text, images, or code, rather than following fixed rules."},{"q":"Which everyday service in West Africa already relies on AI?","opts":["A paper receipt book","Fraud detection on mobile money transactions","A handwritten market ledger","A battery-powered radio"],"correct":1,"exp":"Mobile money providers use AI models to spot unusual transaction patterns and flag possible fraud."}]},"mod2":{"title":"Quiz: Prompting & AI Tools","moduleNum":2,"unlocks":3,"questions":[{"q":"Prompt engineering means:","opts":["Hardware configuration","Writing effective AI instructions to get better results","Designing AI chips","Coding AI from scratch"],"correct":1,"exp":"Better prompts consistently produce significantly better AI outputs."},{"q":"AI \"hallucination\" means:","opts":["AI seeing images","AI generating false information confidently","AI processing speed","AI memory limitation"],"correct":1,"exp":"Always verify AI-generated facts before publishing or acting on them."},{"q":"Best practice for AI content:","opts":["Publish immediately","Always verify accuracy before using","Trust AI completely","Never use AI"],"correct":1,"exp":"AI can make convincing mistakes that require human review and verification."},{"q":"DALL-E and Midjourney specialize in:","opts":["Text generation","Code writing","AI image generation","Video production"],"correct":2,"exp":"These tools create realistic images from text descriptions using generative AI."},{"q":"\"Token\" in AI models refers to:","opts":["Digital currency","A unit of text (word/part word) the AI processes","A login credential","A type of AI chip"],"correct":1,"exp":"AI models process text as tokens to understand and generate language efficiently."},{"q":"Asking the AI to 'Act as an experienced Liberian HR manager' at the start of a prompt is called:","opts":["Role prompting","Data mining","Token counting","Model training"],"correct":0,"exp":"Assigning a role focuses the AI's tone, expertise, and perspective, producing more relevant answers."},{"q":"Your first AI answer is too generic. The best next step is to:","opts":["Give up and write it yourself","Refine your prompt with more context and specific requirements","Send the same prompt again unchanged","Switch off your computer and restart"],"correct":1,"exp":"Prompting is iterative, adding context, constraints, and examples steadily improves the output."},{"q":"Which prompt will most likely produce the best email?","opts":["'Write an email'","'Write email now fast'","'Write a polite 150-word email to a donor thanking them and inviting them to our Monrovia site visit on July 20'","'Email, formal, good'"],"correct":2,"exp":"Specific prompts with audience, purpose, length, and details give the AI everything it needs to deliver."},{"q":"Telling the AI 'Answer as a table with three columns' is an example of specifying:","opts":["The training data","The output format","The subscription plan","The internet speed"],"correct":1,"exp":"Format instructions, table, bullet list, or steps, control how the AI structures its response."},{"q":"In this course, Gemini was highlighted as especially useful for:","opts":["Editing videos offline","Research, analysis, and summarizing information","Repairing computer hardware","Sending mobile money"],"correct":1,"exp":"Gemini integrates with Google's ecosystem and excels at research, analysis, and summarization tasks."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Which is the safest approach to AI in business?","opts":["Replace all human decisions with AI","Use AI as a tool with human oversight","Share all company data with AI freely","Ignore AI entirely"],"correct":1,"exp":"AI is most valuable as a tool that augments and supports human judgment."},{"q":"What is \"generative AI\"?","opts":["AI that generates new content (text, images, code)","AI that only categorizes existing data","AI hardware","AI that controls robots"],"correct":0,"exp":"Generative AI creates new content based on patterns learned from training data."},{"q":"AI ethics primarily concerns:","opts":["AI processing speed","Fairness, transparency, privacy, and accountability of AI systems","The cost of AI tools","AI design aesthetics"],"correct":1,"exp":"Ethical AI ensures systems are fair, transparent, and accountable to all people."},{"q":"Which is a real limitation of current AI?","opts":["AI cannot do calculations","AI cannot process images","AI can confidently state incorrect facts (hallucination)","AI cannot speak"],"correct":2,"exp":"Hallucination is a major current limitation requiring human verification of all AI claims."},{"q":"To improve your AI prompts, you should:","opts":["Make them shorter always","Be vague to give AI freedom","Be specific, provide context, and specify the format you want","Never use examples"],"correct":2,"exp":"Specificity, context, and format guidance dramatically improve AI output quality."},{"q":"Machine learning systems improve primarily by:","opts":["Being manually reprogrammed for every new case","Learning patterns from data and experience","Adding more RAM to the computer","Copying answers from printed books"],"correct":1,"exp":"ML models refine their behavior by finding patterns in data rather than following hand-written rules for every case."},{"q":"Which set lists three generative AI tools covered in this course?","opts":["Windows, Linux, macOS","ChatGPT, Gemini, DALL-E","Excel, Word, PowerPoint","Chrome, Firefox, Safari"],"correct":1,"exp":"ChatGPT and Gemini generate text while DALL-E generates images, all are generative AI tools."},{"q":"The four pillars of an advanced prompt taught in this course are:","opts":["Speed, volume, repetition, luck","Role, context, format, and examples","Font, color, size, spacing","Copy, paste, send, delete"],"correct":1,"exp":"Assigning a role, giving context, specifying format, and providing examples consistently produces professional output."},{"q":"An AI confidently tells you a Liberian law exists that does not. This is an example of:","opts":["Hallucination","Encryption","Automation","Tokenization"],"correct":0,"exp":"Hallucination is AI generating false information with confidence, the reason verification is always required."},{"q":"The most reliable way to fact-check an AI claim before publishing is to:","opts":["Ask the same AI if it is sure","Confirm it against trusted primary sources yourself","Check if the answer is long","Publish it and wait for complaints"],"correct":1,"exp":"Independent verification against authoritative sources is the professional standard for AI-assisted work."},{"q":"Which task is the BEST first candidate for AI automation in a small business?","opts":["Final approval of staff salaries","Drafting replies to frequently asked customer questions","Signing legal contracts","Diagnosing customers' medical conditions"],"correct":1,"exp":"Frequent, low-risk, time-consuming tasks like FAQ replies are ideal first automations with human review."},{"q":"In an automation platform like Zapier, a new Google Form submission that starts the workflow is called:","opts":["The output","The trigger","The invoice","The token"],"correct":1,"exp":"Triggers are the events that start a workflow, followed by actions and outputs."},{"q":"A custom assistant keeps inventing product prices. The best fix is to:","opts":["Ask customers to ignore the prices","Upload your real price list as a knowledge file and instruct it to use only that","Delete the assistant's name","Use a brighter screen"],"correct":1,"exp":"Grounding the assistant in your actual documents replaces guessed details with your real data."},{"q":"Before uploading member records to an AI tool for analysis, a cooperative should:","opts":["Add photos of each member","Replace names and phone numbers with anonymous codes","Print and scan the file first","Email the file to all members"],"correct":1,"exp":"Anonymization protects personal data, which public AI tools may store after upload."},{"q":"AI-generated art and text raise copyright questions mainly because:","opts":["AI files are too large to store","Models learn from existing human works and ownership of outputs can be unclear","Computers cannot save images","Art is illegal to generate"],"correct":1,"exp":"Training on human-created works and unclear output ownership are central issues in AI copyright debates."},{"q":"When a client asks whether you used AI in delivered work, the professional response is to:","opts":["Deny it in all cases","Be honest about your AI-assisted process and the human review you applied","Change the subject","Charge them extra for asking"],"correct":1,"exp":"Transparency about AI use, combined with your verification and craft, builds lasting client trust."},{"q":"Charging clients 'per outcome' (e.g., a month of social content) rather than per hour is recommended because:","opts":["It hides how fast AI lets you work and communicates clear value","Hourly billing is illegal in Liberia","Outcomes cannot be measured","Clients prefer not knowing what they get"],"correct":0,"exp":"Outcome pricing sells clear value and rewards the speed your AI skills give you."},{"q":"In the five-step consulting method, what should happen BEFORE recommending any AI tool?","opts":["Buying software licenses","Diagnosing the organization's real problems through interviews","Firing the current staff","Announcing the project publicly"],"correct":1,"exp":"Diagnosis comes first, solutions chosen before understanding the problem usually fail."},{"q":"A strong AI solution pilot is judged primarily by:","opts":["How impressive the technology sounds","Measured results like minutes saved and faster response times","The number of tools used","How secret the project was kept"],"correct":1,"exp":"Hard measurements such as time saved prove value and make your case study credible."},{"q":"Which item most sets a professional AI portfolio apart for NGO and corporate clients?","opts":["A list of favorite movies","An ethics statement covering verification, privacy, bias, and disclosure","Screenshots of video games","A longer email address"],"correct":1,"exp":"An ethics statement signals responsibility and professionalism that few candidates demonstrate."}]},"mod4":{"title":"Quiz: AI for Business & Ethics","moduleNum":4,"questions":[{"q":"How can a small Monrovia shop use an AI chatbot most effectively?","opts":["To replace every employee immediately","To answer common customer questions instantly, with humans handling complex cases","To set prices randomly","To avoid keeping any business records"],"correct":1,"exp":"Chatbots handle repetitive questions around the clock while humans focus on complex or sensitive customers."},{"q":"Before pasting information into a public AI tool, you should ask:","opts":["Whether the text is long enough","Whether it contains confidential customer or company data","Whether the AI is in a good mood","Whether the font is correct"],"correct":1,"exp":"Public AI tools may store your inputs, so confidential data should never be pasted into them."},{"q":"AI bias most often comes from:","opts":["The color of the computer","Patterns and imbalances in the data the AI was trained on","The speed of the internet connection","The user's keyboard layout"],"correct":1,"exp":"If training data under-represents or stereotypes groups, the AI reproduces those unfair patterns."},{"q":"A business publishes an AI-written report containing a false statistic. Who is responsible?","opts":["Nobody, because the AI wrote it","The business that published it without verification","The internet provider","The readers who believed it"],"correct":1,"exp":"Humans remain accountable for AI output they use, verification before publishing is your responsibility."},{"q":"Which is a fair and transparent practice when using AI for marketing?","opts":["Generating fake customer reviews","Using AI to draft posts, then reviewing them for accuracy before publishing","Copying a competitor's private data into the AI","Claiming AI images are real photographs of your products"],"correct":1,"exp":"AI drafting plus human review is efficient and honest, while fake reviews and fake photos deceive customers."},{"q":"Research on AI and employment suggests that AI mostly:","opts":["Replaces specific tasks within jobs rather than entire jobs","Eliminates all office jobs instantly","Only affects farmers","Has no effect on any career"],"correct":0,"exp":"AI automates particular tasks, which is why workers who learn to use AI become more valuable, not obsolete."},{"q":"Which career habit best prepares you for an AI-shaped future?","opts":["Avoiding all new technology","Continuously learning to work alongside AI tools","Memorizing one software version forever","Keeping your skills secret from employers"],"correct":1,"exp":"The professionals who thrive are those who keep learning and combine human judgment with AI capability."},{"q":"An NGO uses AI to screen job applications. An important ethical safeguard is to:","opts":["Let the AI reject candidates with no human review","Regularly check the system's decisions for bias and keep human oversight","Hide the use of AI from everyone","Only interview candidates the AI scores at 100%"],"correct":1,"exp":"High-stakes decisions like hiring need human oversight and bias audits to keep the process fair."},{"q":"Deepfakes are a concern because they:","opts":["Use too much electricity","Can spread convincing fake videos or audio of real people","Make computers run slowly","Only work in cold climates"],"correct":1,"exp":"Deepfakes can impersonate real people convincingly, enabling scams and misinformation, so verify sources."},{"q":"Which describes responsible AI adoption for a Liberian business?","opts":["Start small, verify outputs, protect customer data, and be honest about AI use","Feed all customer records into free AI tools","Fire staff before testing whether AI works","Trust every AI answer without checking"],"correct":0,"exp":"Responsible adoption means starting small, keeping human review, protecting data, and being transparent."}]},"mod5":{"title":"Quiz: Advanced AI Skills & Automation","moduleNum":5,"questions":[{"q":"Custom instructions in ChatGPT are useful because they:","opts":["Make the AI respond faster on slow internet","Save your standing context so every new chat starts with it automatically","Remove the need to verify AI answers","Give you free premium access"],"correct":1,"exp":"Custom instructions store who you are and how you want answers, so you never retype that context."},{"q":"A custom GPT or Gemini Gem is best described as:","opts":["A new type of computer chip","A reusable AI assistant with its own instructions and reference files","A paid advertising service","A spreadsheet formula"],"correct":1,"exp":"Custom assistants package instructions and knowledge files into a named, reusable AI helper."},{"q":"Uploading your price list as a knowledge file to a custom assistant mainly helps by:","opts":["Making answers about your products grounded in real data","Increasing your internet speed","Hiding your business from competitors","Training the AI to speak Kpelle"],"correct":0,"exp":"Reference files ground the assistant in your actual information, reducing hallucinated details."},{"q":"Before uploading a clinic's patient spreadsheet to a public AI tool, you must:","opts":["Add more patient phone numbers","Remove or code out names, numbers, and identifying details","Convert it to a photo","Print it first"],"correct":1,"exp":"Anonymizing data protects patient privacy since public AI tools may store what you upload."},{"q":"You need a formula counting rows where status is 'Paid' after a certain date. The smartest AI use is to:","opts":["Guess the formula and hope","Describe the goal in plain English and ask the AI to write and explain the formula","Delete the columns involved","Retype the whole dataset"],"correct":1,"exp":"AI excels at translating plain-language goals into correct formulas and teaching you how they work."},{"q":"After AI calculates totals from your uploaded sales data, you should:","opts":["Present them immediately without checking","Spot-check key figures against manual calculations before presenting","Delete the original file","Round every number to zero"],"correct":1,"exp":"Verification is non-negotiable, AI can misread columns, so spot-check before you present numbers."},{"q":"Every automation workflow consists of:","opts":["A password, a username, and a login","A trigger, an action, and an output","A printer, a scanner, and a copier","A budget, a deadline, and a manager"],"correct":1,"exp":"Automations fire on a trigger, perform actions like AI drafting, and deliver an output such as a saved draft."},{"q":"Zapier and Make are examples of:","opts":["AI image generators","No-code platforms that connect apps into automated workflows","Antivirus programs","Mobile money providers"],"correct":1,"exp":"These platforms link tools like Google Forms, AI, and Gmail into workflows without programming."},{"q":"What distinguishes an AI agent from a normal chatbot reply?","opts":["Agents plan and execute multiple steps toward a goal","Agents only work offline","Agents cannot make mistakes","Agents are free while chatbots cost money"],"correct":0,"exp":"Agents autonomously chain steps, searching, comparing, drafting, while a chatbot answers one prompt at a time."},{"q":"When automating customer emails for the first time, best practice is to:","opts":["Auto-send everything immediately","Have AI create drafts that a human reviews before sending","Disable your email account","Send each customer ten copies"],"correct":1,"exp":"A human checkpoint before messages reach customers catches AI errors while you build trust in the system."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Dr. Koroma explains AI in a way that finally makes sense to me. I now use ChatGPT every day for my marketing work and it has tripled my output. The prompting module alone is worth ten times the course price."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"I was skeptical about AI but this course showed me how to use it practically for my business. I now automate my customer emails and social posts with AI. My competitors are still doing everything manually, I have a real advantage."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"The section on AI ethics and hallucinations was eye-opening. I used to trust everything AI said. Now I know how to verify and use AI responsibly. This should be required learning for every professional in Liberia."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Excellent course on a topic that is shaping the future. The practical projects made everything real, I built an actual AI content system for my organization. Great value for the price, highly recommended."}],"faqs":[{"q":"Do I need coding skills to use AI tools?","a":"Absolutely not. ChatGPT, Gemini, and all the tools in this course are designed for everyday users. If you can type, you can use AI effectively."},{"q":"Are the AI tools covered in this course free?","a":"ChatGPT and Gemini both offer free tiers that are sufficient for this entire course. We will also cover some premium features available at low cost."},{"q":"Will AI take my job?","a":"This course addresses this question directly. The evidence shows AI replaces tasks, not entire jobs, and people who know how to use AI will be far more valuable than those who do not."},{"q":"Is this course updated for the latest AI tools?","a":"Yes. TIH updates this course quarterly to reflect the rapidly evolving AI landscape. Enrolled students receive all updates at no extra charge."}]};
COURSES_DB['data'] = {"id":"data","title":"Data Analysis with Excel, Power BI & Google Sheets","shortDesc":"For analysts and NGO workers, clean, analyze, and visualize data using Excel, Power BI, and Google Sheets, and build a portfolio that proves your skills to employers.","category":"Data Analytics","icon":"📊","gradient":"linear-gradient(135deg,#0d9488,#065f46)","instructor":"Emmanuel Kamara","instructorTitle":"Senior Data Analyst & Business Intelligence Trainer","instructorBio":"Emmanuel Kamara has over 8 years of experience in business intelligence and data analytics, having worked with NGOs, government agencies, and private firms across West Africa. He specializes in making data analysis accessible to non-technical professionals.","rating":4.7,"reviewCount":645,"students":"3,800+","duration":"40h","level":"Intermediate","price":"FREE","origPrice":"$180","isFree":true,"badge":"free","certId":"TIH-2026-DA-0109","learn":["Master essential Excel functions: SUM, VLOOKUP, COUNTIF, SUMIF, and more","Build professional pivot tables to summarize and analyze large datasets","Create stunning interactive dashboards in Power BI from scratch","Use Google Sheets collaboratively for real-time team data analysis","Clean and prepare messy data for accurate analysis","Design charts and visualizations that communicate insights clearly","Apply data storytelling techniques to present findings to stakeholders","Complete real-world business intelligence projects for your portfolio"],"requirements":["Basic computer literacy and comfort using a computer (keyboard and mouse)","Microsoft Excel installed (2016 or later) or access to Google Sheets (free)","Power BI Desktop installed (free download from Microsoft) for BI modules"],"about":["Data is the new oil, and Liberia's businesses, NGOs, and government agencies are sitting on untapped reserves. The ability to collect, analyze, and present data is one of the most in-demand and highest-paid skills in today's job market. This course teaches you that skill from the ground up.","Starting with Excel fundamentals and advancing through pivot tables, dashboards, and Power BI, you will build a complete data analysis toolkit. Every lesson uses real-world African business datasets, sales data, donor reports, health statistics, and more, so you immediately see the practical value.","By the end of this course, you will be able to walk into any organization in Liberia, take their raw spreadsheet data, and transform it into clear, actionable business intelligence. This is a skill that commands respect and higher salaries in every sector."],"modules":[{"title":"Module 1: Excel Fundamentals","icon":"📊","meta":"5 lessons · 52 min","lessons":[{"t":"1.1 Excel Interface, Navigation & Essential Shortcuts","d":"10:00","v":"Nf6S6tUHOXw"},{"t":"1.2 Core Functions: SUM, AVERAGE, COUNT, IF, ROUND","d":"12:00","v":"Yov488pacDc"},{"t":"1.3 Sorting, Filtering & Conditional Formatting","d":"11:00","v":"kIZkNDKllws"},{"t":"1.4 Charts & Basic Visualizations","d":"9:00","v":"sVZiU9QHdB4"},{"t":"📝 Quiz: Excel Fundamentals","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Advanced Excel & Pivot Tables","icon":"🔢","meta":"5 lessons · 55 min","lessons":[{"t":"2.1 VLOOKUP, HLOOKUP & the New XLOOKUP","d":"13:00","v":"2s-zPZKERP4"},{"t":"2.2 Pivot Tables: Summarize Thousands of Rows Instantly","d":"14:00","v":"dvbLrwD2SpA"},{"t":"2.3 Advanced Formulas: SUMIF, COUNTIF, INDEX-MATCH","d":"12:00","v":"nGQfc0V3NXk"},{"t":"2.4 Data Validation & Protecting Spreadsheets","d":"9:00","v":"gPHzXAncp5I"},{"t":"📝 Quiz: Advanced Excel & Data Analysis","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Power BI & Data Visualization","icon":"📈","meta":"4 lessons · 48 min","lessons":[{"t":"3.1 Introduction to Power BI: Interface & Data Import","d":"12:00","v":"VaOhNqNtGGE"},{"t":"3.2 Building Interactive Dashboards in Power BI","d":"14:00","v":"kp_Mb4E-nig"},{"t":"3.3 DAX Basics: Writing Measures & Calculated Columns","d":"12:00","v":"lGhxfC0_g9c"},{"t":"🛠️ Project: NGO Donor Report Dashboard","d":"Project","isProject":true}]},{"title":"Module 4: Google Sheets Collaboration, Data Storytelling & Portfolio","icon":"🏆","meta":"4 lessons · 44 min","lessons":[{"t":"4.1 Google Sheets for Team Collaboration & Analysis","d":"10:00","v":"cjjAJM1o5E8"},{"t":"4.2 Data Storytelling: Presenting Insights to Decision Makers","d":"11:00","v":"H79S8YDuYUU"},{"t":"4.3 Building Your Data Analysis Portfolio","d":"12:00","v":"n9LNj8IEyQs"},{"t":"📝 Quiz: Google Sheets, Data Storytelling & Portfolio","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Data Cleaning & Automation with Power Query","icon":"🧹","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Power Query Basics: Import & Transform Data","d":"Video + notes","v":"QXzopqpHlSs"},{"t":"5.2 Cleaning Messy Real-World Datasets","d":"Video + notes","v":"1gOQYLgGpKA"},{"t":"5.3 Refreshable Reports: Automating Your Monthly Workflow","d":"Video + notes","v":"x7mzOYEn0XA"},{"t":"📝 Quiz: Data Cleaning & Power Query Automation","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, End-to-End Analytics Projects & Your Data Career","icon":"💼","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Scoping an Analytics Project with a Real Client","d":"Video + notes","v":"EYd36SJrCrg"},{"t":"6.2 Building the Dashboard: From Raw Data to Decision","d":"Video + notes","v":"9n-_vIAT-GY"},{"t":"6.3 Presenting Your Portfolio & Landing Data Jobs in West Africa","d":"Video + notes","v":"iNaDxZXc_Ao"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Excel Fundamentals","moduleNum":1,"unlocks":3,"questions":[{"q":"What does the SUM function do?","opts":["Counts cells","Adds all numbers in a range","Finds the average","Sorts data"],"correct":1,"exp":"=SUM(A1:A10) adds all numerical values in that range together."},{"q":"Best chart for trends over time?","opts":["Pie chart","Bar chart","Line chart","Scatter plot"],"correct":2,"exp":"Line charts clearly show how values change over time periods."},{"q":"VLOOKUP does what?","opts":["Deletes duplicate rows","Looks up a value in a table column","Creates charts automatically","Sends email reports"],"correct":1,"exp":"VLOOKUP finds matching data across different tables in your spreadsheet."},{"q":"A pivot table:","opts":["Creates presentations","Summarizes and analyzes large datasets","Sends automated reports","Protects cells from editing"],"correct":1,"exp":"Pivot tables transform thousands of rows of raw data into meaningful summaries."},{"q":"=AVERAGE(B2:B20) calculates:","opts":["The sum of B2 to B20","The largest value","The mean (average) of B2 to B20","The count of cells"],"correct":2,"exp":"AVERAGE divides the total sum by the number of values in the range."},{"q":"In Excel, the cell reference B3 points to:","opts":["Row B, column 3","Column B, row 3","The third worksheet","A named range called B3"],"correct":1,"exp":"Cell references combine the column letter and row number, so B3 is column B, row 3."},{"q":"What does the formula =IF(A2>50,\"Pass\",\"Fail\") return when A2 is 40?","opts":["Pass","Fail","50","An error"],"correct":1,"exp":"IF checks the condition first, since 40 is not greater than 50, it returns the second result, Fail."},{"q":"Conditional formatting is used to:","opts":["Automatically color cells based on their values","Delete rows that contain errors","Send spreadsheets by email","Convert Excel files to PDF"],"correct":0,"exp":"Conditional formatting applies colors or icons automatically when cells meet rules you define, making patterns visible."},{"q":"What is the difference between sorting and filtering data?","opts":["They are exactly the same feature","Sorting reorders all rows; filtering temporarily hides rows that do not match criteria","Sorting deletes data; filtering copies data","Filtering only works on numbers"],"correct":1,"exp":"Sorting rearranges every row by a chosen order, while filtering displays only the rows matching your criteria."},{"q":"Which chart is most appropriate for showing each county's share of total sales as parts of a whole?","opts":["Line chart","Scatter plot","Pie chart","Histogram"],"correct":2,"exp":"Pie charts show how a whole divides into proportional parts, ideal for a small number of share categories."}]},"mod2":{"title":"Quiz: Advanced Excel & Data Analysis","moduleNum":2,"unlocks":3,"questions":[{"q":"Power BI is used for:","opts":["Writing documents","Creating interactive business intelligence dashboards","Designing logos","Building websites"],"correct":1,"exp":"Power BI visualizes complex data with interactive reports and dashboards."},{"q":"Data cleaning means:","opts":["Deleting all old data","Removing errors, duplicates, and inconsistencies","Encrypting sensitive data","Formatting cells"],"correct":1,"exp":"Clean data is the foundation, garbage in, garbage out."},{"q":"KPI stands for:","opts":["Key Processing Index","Knowledge Performance Interface","Key Performance Indicator","Keyboard Productivity Input"],"correct":2,"exp":"KPIs measure progress toward specific business goals and objectives."},{"q":"CSV stands for:","opts":["Comma-Separated Values","Computer Standard Version","Chart Summary View","Cell Spreadsheet Variable"],"correct":0,"exp":"CSV files store tabular data as plain text with commas separating values."},{"q":"Best way to share data insights?","opts":["Raw spreadsheet dump","Email with all data","Interactive dashboard with visualizations","Verbal description only"],"correct":2,"exp":"Visualizations make complex data immediately understandable to any audience."},{"q":"A key advantage of XLOOKUP over classic VLOOKUP is that XLOOKUP:","opts":["Only works on sorted data","Can look to the left or right of the lookup column","Requires the internet to run","Can only return numbers"],"correct":1,"exp":"XLOOKUP searches in any direction and defaults to exact match, fixing VLOOKUP's biggest limitations."},{"q":"In the reference $A$2, the dollar signs mean:","opts":["The cell contains currency","The reference stays fixed on A2 when the formula is copied","The cell is protected from editing","The value is multiplied by 100"],"correct":1,"exp":"Dollar signs create an absolute reference so copying the formula does not shift it away from A2."},{"q":"=SUMIF(B2:B100,\"Montserrado\",C2:C100) does what?","opts":["Counts how many rows say Montserrado","Adds the values in column C only for rows where column B says Montserrado","Averages all of column C","Deletes rows that say Montserrado"],"correct":1,"exp":"SUMIF adds values from the sum range only where the criteria range matches your condition."},{"q":"In a pivot table, dragging 'County' to Rows and 'Sales' to Values produces:","opts":["A blank sheet","Total sales summarized for each county","A list of every individual transaction","A password-protected report"],"correct":1,"exp":"Pivot tables aggregate the values field for each category in the rows area, here, sales totals per county."},{"q":"Data validation with a dropdown list is valuable because it:","opts":["Makes the file smaller","Prevents typing errors by limiting entries to approved options","Automatically emails your team","Sorts data every hour"],"correct":1,"exp":"Restricting entries to a list stops inconsistent spellings like 'Paid', 'paid', and 'PAID' before they happen."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Before analyzing data you should:","opts":["Start building charts immediately","Clean and validate the data first","Share raw data with stakeholders","Delete outliers automatically"],"correct":1,"exp":"Data quality directly determines the reliability and credibility of your analysis."},{"q":"What is data storytelling?","opts":["Writing fiction about data","Presenting data with narrative context to drive understanding and action","Encrypting data","Automating data collection"],"correct":1,"exp":"Good data stories combine visuals, context, and clear recommendations for action."},{"q":"An outlier in data is:","opts":["The most common value","A value significantly different from other observations","The average value","A missing data point"],"correct":1,"exp":"Outliers can indicate data entry errors or genuinely important business insights."},{"q":"Which Excel function counts cells meeting a condition?","opts":["SUM","AVERAGE","COUNTIF","VLOOKUP"],"correct":2,"exp":"COUNTIF(range, criteria) counts only cells that match your specified condition."},{"q":"What makes a good data dashboard?","opts":["As many charts as possible","Complex formulas visible","Clear metrics, clean design, and actionable insights","Detailed raw data tables"],"correct":2,"exp":"Dashboards should enable quick decisions, not overwhelm viewers with complexity."},{"q":"=COUNTIF(D2:D200,\">100\") returns:","opts":["The sum of all values over 100","How many cells in D2:D200 contain values greater than 100","The largest value in the range","The average of the range"],"correct":1,"exp":"COUNTIF counts the cells meeting the condition, here, values greater than 100."},{"q":"Copying =B2*C2 down a column works because relative references:","opts":["Stay locked to row 2 forever","Adjust automatically to each new row","Convert to text when copied","Only work in the first row"],"correct":1,"exp":"Relative references shift with the formula's position, so row 3 calculates B3*C3 automatically."},{"q":"Your VLOOKUP returns #N/A even though the value looks present. A common hidden cause is:","opts":["The workbook is too colorful","Extra spaces or text-vs-number mismatches in the lookup values","The file name is too short","Too many worksheets"],"correct":1,"exp":"Invisible spaces and mismatched data types are the classic causes of failed lookups, Trim and type fixes solve them."},{"q":"INDEX-MATCH is often preferred over VLOOKUP because it:","opts":["Requires no formula at all","Can return values from columns to the left of the lookup column","Automatically colors the results","Only works on small tables"],"correct":1,"exp":"INDEX-MATCH looks up in any direction and does not break when table columns are inserted or moved."},{"q":"In a pivot table, changing a Values field from Sum to Count would tell you:","opts":["The total amount of money","How many records fall in each category","The alphabetical order of items","The color of each cell"],"correct":1,"exp":"The aggregation type controls the summary, Count tallies records while Sum adds their values."},{"q":"In Power BI, a DAX measure is:","opts":["A printed ruler for screens","A calculation like total revenue that updates dynamically with filters and slicers","A type of chart","A password setting"],"correct":1,"exp":"Measures are dynamic DAX calculations that recompute as users filter and slice the report."},{"q":"Slicers on a dashboard allow users to:","opts":["Edit the raw source data","Filter the visuals interactively, for example by county or month","Change the dashboard's password","Email the report automatically"],"correct":1,"exp":"Slicers give viewers self-service filtering so one dashboard answers many specific questions."},{"q":"Power Query's biggest benefit for a monthly report is that it:","opts":["Makes cells more colorful","Replays recorded cleaning steps on new data with one refresh","Removes the need for any data at all","Prints reports automatically"],"correct":1,"exp":"Recorded, refreshable transformations turn repetitive manual cleaning into a one-click operation."},{"q":"Before merging monthly branch files, an analyst discovers one branch renamed its 'Amount' column to 'Value'. This matters because:","opts":["Renamed columns break automated queries and must be standardized","Column names are decoration only","It makes the file prettier","Power Query cannot open files"],"correct":0,"exp":"Automation depends on consistent structure, an agreed template keeps refreshable pipelines working."},{"q":"A dataset lists a clinic visit dated 30 February. The professional response is to:","opts":["Assume it is correct","Flag it as an impossible value and trace the entry error","Delete the whole dataset","Change all dates to January"],"correct":1,"exp":"Impossible dates are validation failures to investigate and correct at the source, not accept or mass-delete."},{"q":"In Google Sheets, 'Editor' access differs from 'Viewer' access because Editors can:","opts":["Only print the sheet","Change the data and formulas","See the sheet without opening it","Delete the owner's Google account"],"correct":1,"exp":"Editors can modify content, so grant editing rights only to people who should change the data."},{"q":"The strongest opening for a findings presentation to an NGO board is:","opts":["A walkthrough of every formula used","The single most important insight and its recommended action","The complete raw dataset on screen","An apology for the data quality"],"correct":1,"exp":"Leading with the key insight and recommendation respects decision makers' time and frames the evidence that follows."},{"q":"When scoping a new analytics project, your first question should uncover:","opts":["The client's favorite chart colors","The decision the analysis must support","The brand of the office computers","The age of the organization's logo"],"correct":1,"exp":"Analytics exists to inform decisions, identifying the decision defines the questions, KPIs, and deliverables."},{"q":"A one-page scope document should include deliverables, timeline, KPIs, and:","opts":["What is explicitly out of scope","The analyst's home address","Every formula to be used","A list of unrelated projects"],"correct":0,"exp":"Stating what is out of scope prevents endless expansion and keeps the project deliverable."},{"q":"Which portfolio project description would most impress an M&E hiring manager?","opts":["'I know Excel very well'","'Built a refreshable donor dashboard that cut monthly reporting from two days to twenty minutes'","'I once watched a Power BI video'","'I can type quickly'"],"correct":1,"exp":"A concrete project with a measured result proves job-ready capability far better than any claim of knowledge."}]},"mod4":{"title":"Quiz: Google Sheets, Data Storytelling & Portfolio","moduleNum":4,"questions":[{"q":"The biggest advantage of Google Sheets over a desktop Excel file for team projects is:","opts":["It has more chart types","Multiple people can edit the same sheet simultaneously in real time","It works without any account","It prints faster"],"correct":1,"exp":"Google Sheets lets a whole team work in one live document, eliminating emailed copies and version confusion."},{"q":"When sharing a Google Sheet with a colleague who should only read it, choose:","opts":["Editor access","Viewer access","Owner transfer","Public editing"],"correct":1,"exp":"Viewer access lets people see the data without any risk of accidental changes."},{"q":"A teammate accidentally deleted a column yesterday. In Google Sheets you can:","opts":["Only retype everything manually","Use version history to restore an earlier version","Call Google support to rebuild it","Nothing, the data is gone"],"correct":1,"exp":"Version history keeps every past state of the sheet, letting you restore or copy from earlier versions."},{"q":"In Google Sheets, adding a comment with @colleague's email does what?","opts":["Deletes their access","Notifies them by email and links the discussion to that exact cell","Creates a new spreadsheet","Hides the cell from others"],"correct":1,"exp":"Cell comments with @mentions turn the sheet into a collaborative workspace with targeted notifications."},{"q":"Data storytelling combines which three elements?","opts":["Fonts, borders, and colors","Data, visuals, and narrative context","Passwords, backups, and printing","Rows, columns, and sheets"],"correct":1,"exp":"Effective data stories weave accurate data, clear visuals, and a narrative that drives understanding and action."},{"q":"When presenting findings to a busy executive director, you should start with:","opts":["Every formula you used","The key insight and recommendation, then supporting evidence","The full raw dataset","A history of spreadsheet software"],"correct":1,"exp":"Decision makers need the conclusion first, lead with the insight, then support it with evidence."},{"q":"Your chart shows clinic visits rising after a health campaign. The strongest storytelling title is:","opts":["Chart 4","Clinic Visits Data 2026","Clinic visits rose 40% after the March outreach campaign","Made by the data team"],"correct":2,"exp":"A takeaway title states the insight itself, so the audience understands the message before studying the chart."},{"q":"Which item belongs in a data analysis portfolio?","opts":["A completed dashboard project with a short write-up of the problem and insights","Screenshots of your desktop wallpaper","A list of software you have heard of","Someone else's dashboard presented as yours"],"correct":0,"exp":"Portfolios prove skill through real projects, the problem, your process, and the insights you produced."},{"q":"Why should portfolio projects use realistic datasets, like NGO donor or retail sales data?","opts":["They make files larger","They show employers you can handle the kind of data their organization actually uses","Realistic data never contains errors","Employers only accept government data"],"correct":1,"exp":"Realistic projects demonstrate job-ready skills on the messy, practical data employers deal with daily."},{"q":"The best way to share your portfolio dashboards with a potential employer is:","opts":["Describing them verbally in the interview only","A view-only online folder or published links they can open in one click","Printing every worksheet on paper","Sending your login password"],"correct":1,"exp":"One-click, view-only access lets employers see your work instantly without security risks."}]},"mod5":{"title":"Quiz: Data Cleaning & Power Query Automation","moduleNum":5,"questions":[{"q":"Power Query's main purpose is to:","opts":["Design PowerPoint slides","Import, clean, and transform data with repeatable recorded steps","Send automated emails","Protect workbooks with passwords"],"correct":1,"exp":"Power Query records transformation steps so data preparation becomes repeatable and refreshable."},{"q":"In the Power Query Editor, your transformations are recorded in:","opts":["The Applied Steps list","The Recycle Bin","A hidden chart","The printer queue"],"correct":0,"exp":"Applied Steps lists every transformation in order, and each step can be edited, reordered, or removed."},{"q":"When next month's data arrives in the same format, a Power Query user should:","opts":["Redo all cleaning manually","Replace the source file and click Refresh All","Buy a new computer","Retype the data into a new sheet"],"correct":1,"exp":"Refresh replays every recorded step on the new data, updating clean tables and reports in seconds."},{"q":"Invisible spaces before or after text entries are best removed with:","opts":["The Trim transformation","A pie chart","Bold formatting","Deleting the column"],"correct":0,"exp":"Trim strips leading and trailing spaces, which silently break lookups and grouping if left in place."},{"q":"A column of numbers stored as text is a problem because:","opts":["Text is invisible on screen","The numbers will not sum or calculate correctly until converted to a numeric type","Text uses more electricity","Excel deletes text automatically"],"correct":1,"exp":"Numeric operations require proper data types, text-stored numbers return wrong or blank results."},{"q":"'Monrovia', 'monrovia', and 'MONROVIA' in one column should be fixed by:","opts":["Deleting all three variants","Standardizing capitalization so they group as one value","Creating three separate reports","Hiding the column"],"correct":1,"exp":"Standardizing text case makes identical places group together correctly in pivots and charts."},{"q":"The Power Query folder connector is especially useful for:","opts":["Combining many same-format monthly files into one table automatically","Designing logos","Compressing photos","Backing up your operating system"],"correct":0,"exp":"The folder connector merges every matching file in a folder, so new monthly reports join the data on refresh."},{"q":"An age column containing the value 250 most likely indicates:","opts":["A healthy long life","A data entry error that should be investigated","A currency amount","A perfect record"],"correct":1,"exp":"Range validation flags impossible values like age 250 as errors to investigate, not analyze."},{"q":"Why keep a cleaning log of duplicates removed and blanks handled?","opts":["To make the file larger","To explain and defend your final figures when stakeholders question them","Logs are required to open Excel","To slow down the analysis"],"correct":1,"exp":"A documented trail of cleaning decisions protects your credibility when numbers are challenged."},{"q":"In a refreshable report design, pivot tables and charts should be built on:","opts":["The raw untouched source files directly","The clean table output by Power Query","A printed copy of the data","An empty worksheet"],"correct":1,"exp":"Analysis sits on the cleaned transformation layer, so refreshing the query updates everything above it."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Emmanuel is a fantastic teacher. I went from knowing only basic Excel to building full Power BI dashboards for my NGO. Our donors are impressed with our reporting. This course paid for itself in the first week of applying the skills."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"The pivot table module alone transformed how I manage our company's sales data. What used to take me two days now takes 20 minutes. The Power BI dashboard I built is now used in our weekly management meetings."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"I work in the health sector and the data skills I learned here have directly improved how we track and report patient outcomes. The course uses real African data examples which makes it immediately relevant to our work."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Solid, comprehensive course covering everything from basic formulas to Power BI. The difficulty level is well-paced, challenging enough to be valuable but clear enough to follow. I now list Data Analysis on my CV with confidence."}],"faqs":[{"q":"Do I need to buy Microsoft Excel?","a":"You can use the free Google Sheets for most modules. Microsoft Excel 2016+ is recommended but the free 30-day Microsoft trial is sufficient to complete the course."},{"q":"How is this different from the Office course?","a":"The Office course covers Excel basics for general use. This Data course goes much deeper into analytics, advanced functions, pivot tables, and Power BI for professional data work."},{"q":"Will I be able to get a data analyst job after this?","a":"This course builds strong foundational data skills. Combined with practice projects, many graduates have secured data analyst, reporting, and business intelligence roles."},{"q":"Are the datasets used in lessons realistic?","a":"Yes. All practice datasets are modeled on real Liberian and West African business scenarios, NGO reports, retail sales, health data, and government statistics."}]};
COURSES_DB['webdev'] = {"id":"webdev","title":"Web Development: HTML, CSS & JavaScript","shortDesc":"For aspiring developers and entrepreneurs, learn to build real, responsive websites from scratch using HTML5, CSS3, and JavaScript, and graduate with three portfolio projects deployed live online.","category":"Web Development","icon":"🌐","gradient":"linear-gradient(135deg,#0284c7,#0ea5e9)","instructor":"David Weah","instructorTitle":"Full-Stack Web Developer & Tech Lead","instructorBio":"David Weah is a full-stack developer with 9 years building web applications for businesses across Africa and Europe. He has taught web development to over 2,000 students and runs a thriving tech agency in Monrovia.","rating":4.8,"reviewCount":583,"students":"4,300+","duration":"42h","level":"Beginner","price":"FREE","origPrice":"$200","isFree":true,"badge":"free","certId":"TIH-2026-WD-0074","learn":["Write clean, semantic HTML5 to structure any web page","Style beautiful websites using CSS3, Flexbox, and Grid","Build fully responsive layouts that work on mobile, tablet, and desktop","Add interactivity with JavaScript and DOM manipulation","Work with HTML forms, inputs, and data validation","Debug code using browser developer tools","Deploy your website live using GitHub Pages for free","Build a professional portfolio of 3 complete web projects"],"requirements":["No coding or programming experience needed, completely beginner-friendly","A computer with a modern browser (Chrome recommended) and internet connection","VS Code code editor (free, setup instructions provided in lesson 1)"],"about":["Web development is one of the most powerful and portable skills you can learn. Every business, church, school, NGO, and government office needs a website, and people who can build them are always in demand. This course teaches you everything needed to build professional websites from scratch.","You will start from the very basics, how the web works, and progress through HTML structure, CSS styling, responsive design, and JavaScript interactivity. Every lesson builds on the last, and you will be building real projects from lesson one. No reading theory without application.","By the time you earn your certificate, you will have three complete websites in your portfolio: a personal portfolio site, a business landing page, and an interactive web application. Our graduates freelance, join tech companies, and launch their own digital agencies."],"modules":[{"title":"Module 1: HTML5, Structure of the Web","icon":"🌐","meta":"4 lessons · 40 min","lessons":[{"t":"1.1 How the Web Works: Browsers, Servers & HTML","d":"9:00","v":"pfYQz5pnFmo"},{"t":"1.2 HTML Tags, Semantic Structure & Page Layout","d":"11:00","v":"kX3TfdUqpuU"},{"t":"1.3 Forms, Tables, Links, Images & Multimedia","d":"11:30","v":"AJrkz0pzRV4"},{"t":"📝 Quiz: HTML5 Fundamentals","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: CSS3 & Responsive Design","icon":"🎨","meta":"4 lessons · 46 min","lessons":[{"t":"2.1 CSS Selectors, the Box Model & Typography","d":"11:00","v":"YhoK5y0HgPk"},{"t":"2.2 Flexbox Layouts: Build Any UI Component","d":"12:00","v":"fYq5PXgSsbE"},{"t":"2.3 CSS Grid & Media Queries for Responsive Design","d":"13:00","v":"dT3aujtzBe4"},{"t":"📝 Quiz: CSS3 & Layouts","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: JavaScript Interactivity","icon":"⚡","meta":"4 lessons · 44 min","lessons":[{"t":"3.1 JavaScript Variables, Functions & Logic","d":"11:00","v":"dJvPTRXyc6s"},{"t":"3.2 DOM Manipulation: Change Pages Dynamically","d":"11:30","v":"5fb2aPlgoys"},{"t":"3.3 Events, Forms & Input Validation","d":"11:30","v":"RjtarcWFc6A"},{"t":"🛠️ Project: Build an Interactive Business Landing Page","d":"Project","isProject":true}]},{"title":"Module 4: Professional Workflows & Deployment","icon":"🏆","meta":"4 lessons · 38 min","lessons":[{"t":"4.1 Git & GitHub: Version Control for Developers","d":"10:00","v":"PWqS4NBhEY8"},{"t":"4.2 Browser DevTools: Debugging & Inspecting Code","d":"9:30","v":"H0XScE08hy8"},{"t":"4.3 Deploy Live with GitHub Pages & Custom Domains","d":"9:00","v":"e5AwNU3Y2es"},{"t":"📝 Quiz: Professional Workflows & Deployment","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: JavaScript Deep Dive, Data, APIs & Dynamic Apps","icon":"🚀","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Arrays, Objects & Loops: Managing Real Data","d":"Video + notes","v":"orAS-MBh5f4"},{"t":"5.2 Fetch, JSON & Working with Live APIs","d":"Video + notes","v":"ubw2hdQIl4E"},{"t":"5.3 localStorage & Building a Complete Dynamic App","d":"Video + notes","v":"y71CdVq5SvI"},{"t":"📝 Quiz: JavaScript Data, APIs & Dynamic Apps","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Client Projects, Performance & Your Web Career","icon":"💼","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 The Client Website Workflow: From Brief to Launch","d":"Video + notes","v":"Jz_wyVdWKm8"},{"t":"6.2 Performance, Accessibility & SEO: Websites That Work for Everyone","d":"Video + notes","v":"AhxvJbG-kSA"},{"t":"6.3 Launching Your Career: Freelancing, Jobs & Growing Beyond This Course","d":"Video + notes","v":"TCgKGPr0trA"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: HTML5 Fundamentals","moduleNum":1,"unlocks":3,"questions":[{"q":"What does HTML stand for?","opts":["HyperText Markup Language","HyperTransfer Machine Language","HighText Making Language","Hyperlink & Text Markup Language"],"correct":0,"exp":"HTML is the standard language for creating and structuring web pages."},{"q":"Which tag creates the largest heading?","opts":["<heading>","<h6>","<h1>","<big>"],"correct":2,"exp":"<h1> is the most important heading. Headings range from <h1> (largest) to <h6> (smallest)."},{"q":"What attribute makes a link open in a new tab?","opts":["href=\"_new\"","target=\"_blank\"","rel=\"new\"","open=\"tab\""],"correct":1,"exp":"target=\"_blank\" opens the linked page in a new browser tab."},{"q":"Which element defines the main content area?","opts":["<div>","<body>","<main>","<content>"],"correct":2,"exp":"<main> is a semantic HTML element representing the primary content of the page."},{"q":"What does the <form> element do?","opts":["Creates a table","Defines a block of text","Creates an interface for user input submission","Adds images"],"correct":2,"exp":"HTML forms collect user input and can submit data to a server for processing."},{"q":"What is the purpose of the alt attribute on an <img> tag?","opts":["It sets the image width","It provides descriptive text if the image cannot load and for screen readers","It makes the image clickable","It compresses the image file"],"correct":1,"exp":"alt text describes the image for accessibility tools and displays when the image fails to load."},{"q":"Which tag creates a bulleted (unordered) list?","opts":["<ol>","<list>","<ul>","<bl>"],"correct":2,"exp":"<ul> creates an unordered (bulleted) list, while <ol> creates a numbered (ordered) list."},{"q":"What does <!DOCTYPE html> at the top of a page do?","opts":["It links the CSS file","It tells the browser the document is written in modern HTML5","It creates the page title","It starts the JavaScript engine"],"correct":1,"exp":"The doctype declaration tells browsers to render the page using the HTML5 standard."},{"q":"Which input type shows a mobile-friendly keyboard for typing an email address?","opts":["<input type=\"text\">","<input type=\"mail\">","<input type=\"address\">","<input type=\"email\">"],"correct":3,"exp":"type=\"email\" triggers email keyboards on phones and enables automatic email format validation."},{"q":"Which semantic element should wrap a site's navigation links?","opts":["<nav>","<menu-bar>","<links>","<header-links>"],"correct":0,"exp":"<nav> is the semantic HTML5 element for major navigation blocks, helping accessibility and SEO."}]},"mod2":{"title":"Quiz: CSS3 & Layouts","moduleNum":2,"unlocks":3,"questions":[{"q":"What does CSS stand for?","opts":["Computer Style Sheets","Cascading Style Sheets","Creative Styling System","Coded Structure Styles"],"correct":1,"exp":"CSS (Cascading Style Sheets) controls the visual presentation and layout of HTML pages."},{"q":"What is the CSS Box Model?","opts":["A design tool for creating boxes","Every HTML element as a box with content, padding, border, and margin","A CSS framework","A 3D CSS effect"],"correct":1,"exp":"The box model defines how space is calculated around every HTML element."},{"q":"What does display:flex do?","opts":["Hides an element","Enables flexbox layout on a container","Makes text flexible size","Adds animation"],"correct":1,"exp":"display:flex enables the powerful Flexbox layout model on a container element."},{"q":"Media queries are used for:","opts":["Playing audio","Querying databases","Applying different CSS at different screen sizes","Loading media files"],"correct":2,"exp":"Media queries make websites responsive by applying different styles at different viewports."},{"q":"CSS Grid is best for:","opts":["One-dimensional row/column layouts only","Two-dimensional page layouts (rows AND columns)","Adding animations","Setting font sizes"],"correct":1,"exp":"Grid handles complex 2D layouts with both rows and columns simultaneously."},{"q":"In CSS, how do you select an element with class=\"card\"?","opts":["#card","card()",".card","@card"],"correct":2,"exp":"A dot prefix (.card) selects elements by class; a hash prefix (#) selects by id."},{"q":"What is the difference between padding and margin?","opts":["They are identical","Padding is space inside the border; margin is space outside the border","Padding only works on text; margin only works on images","Margin is space inside the border; padding is space outside"],"correct":1,"exp":"Padding pushes content away from an element's border on the inside, while margin pushes other elements away outside."},{"q":"In Flexbox, what does justify-content: space-between do?","opts":["Stacks items vertically with no gaps","Centers all items in the middle","Adds a border between items","Spreads items along the main axis with equal space between them"],"correct":3,"exp":"space-between places the first and last items at the edges and distributes remaining space evenly between items."},{"q":"Which selector has the highest specificity in CSS?","opts":["An element selector like p","A class selector like .title","An id selector like #header","The universal selector *"],"correct":2,"exp":"id selectors outrank class selectors, which outrank element selectors, when styles conflict."},{"q":"How do you correctly link an external stylesheet to an HTML page?","opts":["<link rel=\"stylesheet\" href=\"style.css\"> inside <head>","<css src=\"style.css\"> inside <body>","<style href=\"style.css\"> at the end of the page","<script src=\"style.css\"> inside <head>"],"correct":0,"exp":"External CSS is attached with a <link> tag in the <head>, keeping styling separate from structure."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"JavaScript adds what to a website?","opts":["Page structure","Visual styling","Interactivity and dynamic behavior","Database storage"],"correct":2,"exp":"JS makes pages interactive, responding to clicks, updating content, validating forms."},{"q":"What is the DOM?","opts":["A CSS framework","A JavaScript library","The Document Object Model, a tree of HTML elements JavaScript can modify","A type of database"],"correct":2,"exp":"The DOM represents the HTML document as an object tree that JS can read and change."},{"q":"What does git commit do?","opts":["Uploads code online","Saves a snapshot of changes to the local repository","Deletes old code","Merges two projects"],"correct":1,"exp":"git commit creates a saved checkpoint of your staged code changes with a message."},{"q":"GitHub Pages hosts:","opts":["Only Node.js apps","Any static website (HTML/CSS/JS) directly from a GitHub repo for free","Paid WordPress sites","Databases"],"correct":1,"exp":"GitHub Pages is a free static site hosting service, perfect for portfolios and web projects."},{"q":"Semantic HTML means:","opts":["HTML with animations","Using HTML tags that describe their content's meaning","HTML with CSS included","Minimized HTML files"],"correct":1,"exp":"Semantic elements like <nav>, <article>, <footer> improve accessibility and SEO."},{"q":"Which HTML element is the correct semantic choice for a page's footer content?","opts":["<bottom>","<div id=\"end\">","<footer>","<section-last>"],"correct":2,"exp":"<footer> is the semantic HTML5 element for closing page content like contact info and copyright."},{"q":"A media query like @media (max-width: 600px) applies styles when:","opts":["The screen is 600px wide or narrower","The screen is wider than 600px","The page has more than 600 elements","The internet is slow"],"correct":0,"exp":"max-width: 600px targets viewports up to 600px, typically phones, the heart of responsive design."},{"q":"In JavaScript, document.querySelector(\".btn\") does what?","opts":["Creates a new button","Selects the first element matching the CSS selector .btn","Deletes all buttons","Styles every button red"],"correct":1,"exp":"querySelector finds the first DOM element matching a CSS selector so JavaScript can work with it."},{"q":"What does addEventListener(\"click\", handler) do?","opts":["Clicks the element automatically","Blocks the user from clicking","Runs the handler function whenever the element is clicked","Submits a form immediately"],"correct":2,"exp":"addEventListener attaches a function that runs each time the specified event occurs on that element."},{"q":"Why is validating form input with JavaScript useful?","opts":["It replaces the need for HTML","It makes the server unnecessary","It changes the page's colors","It catches errors like empty fields instantly before data is submitted"],"correct":3,"exp":"Client-side validation gives users immediate feedback, improving experience and data quality."},{"q":"What does git push origin main do?","opts":["Uploads your local main branch commits to the remote repository on GitHub","Deletes the main branch","Downloads teammates' changes","Renames the repository"],"correct":0,"exp":"git push sends your local commits to the remote (origin), publishing your work to GitHub."},{"q":"Which fetch() pattern correctly handles both success and failure?","opts":["fetch(url) alone with nothing chained","fetch(url).then(...).catch(...)","fetch(url).push(...).pop(...)","fetch(url).map(...).filter(...)"],"correct":1,"exp":"then() handles the successful response while catch() handles network or parsing failures."},{"q":"An API is best described as:","opts":["A styling framework for websites","A type of computer virus","A service that lets your code request and receive data, usually as JSON","A browser brand"],"correct":2,"exp":"APIs expose data and functionality over URLs, letting your site display live external information."},{"q":"Which array method transforms every item into a new value, returning a new array?","opts":["forEach()","pop()","length()","map()"],"correct":3,"exp":"map() applies a function to each item and returns the transformed results as a new array."},{"q":"What is the main advantage of localStorage for users in low-connectivity areas?","opts":["It uploads data faster to servers","Saved data remains available on the device even offline","It increases screen brightness","It compresses images automatically"],"correct":1,"exp":"localStorage persists data on the device, so apps can keep working without an internet connection."},{"q":"Why should images on a site for mobile-data users be optimized?","opts":["Large images cost users data and slow page loads dramatically","Browsers refuse to show images over 1MB","Optimized images improve JavaScript syntax","Google bans sites with photos"],"correct":0,"exp":"Compressed, resized images load faster and cost less data, critical for mobile-first African audiences."},{"q":"The loading=\"lazy\" attribute on an image:","opts":["Makes the image blurry","Prevents the image from ever loading","Delays loading until the image is about to scroll into view","Only works on desktop computers"],"correct":2,"exp":"Lazy loading defers offscreen images, cutting initial page weight and speeding up first load."},{"q":"Which tool built into Chrome audits your site's performance, accessibility, and SEO?","opts":["Photoshop","GitHub Actions","Notepad","Lighthouse"],"correct":3,"exp":"Lighthouse, inside Chrome DevTools, scores your site and lists concrete improvements."},{"q":"In a professional client project, why collect a written brief and deposit before coding?","opts":["It is required by Liberian law","It agrees scope and commitment upfront, preventing endless unpaid changes","It replaces the need for Git","Clients cannot see previews otherwise"],"correct":1,"exp":"A confirmed brief and deposit protect both sides by fixing expectations, scope, and commitment early."},{"q":"What most strengthens a junior developer's job application?","opts":["Listing many languages without examples","A long cover letter with no links","A live portfolio of deployed projects plus an active GitHub profile","Certificates alone with no code"],"correct":2,"exp":"Employers trust evidence: live projects and visible code history demonstrate real, working skill."}]},"mod4":{"title":"Quiz: Professional Workflows & Deployment","moduleNum":4,"questions":[{"q":"What does git init do?","opts":["Uploads your project to GitHub","Creates a new Git repository in the current folder","Installs Git on your computer","Deletes your commit history"],"correct":1,"exp":"git init turns a folder into a Git repository so Git can start tracking changes."},{"q":"What is the correct order of the basic Git workflow?","opts":["commit, add, push","push, commit, add","add, commit, push","commit, push, add"],"correct":2,"exp":"You stage changes with git add, save a snapshot with git commit, then upload with git push."},{"q":"What is a Git branch used for?","opts":["Working on new features separately without breaking the main code","Deleting old repositories","Compressing project files","Backing up your computer"],"correct":0,"exp":"Branches let you develop features in isolation, then merge them into main when ready."},{"q":"In git, what does the staging area (index) hold?","opts":["Deleted files only","Your GitHub password","Files already pushed to GitHub","Changes you have marked to include in the next commit"],"correct":3,"exp":"git add moves changes to the staging area, which becomes the content of your next commit."},{"q":"Which DevTools panel shows JavaScript errors and console.log output?","opts":["Elements","Console","Network","Sources"],"correct":1,"exp":"The Console panel displays errors, warnings, and anything you print with console.log, your first stop when debugging."},{"q":"What does the Elements panel in Chrome DevTools let you do?","opts":["Edit files saved on the server permanently","Scan for viruses","Inspect and temporarily modify the live HTML and CSS of a page","Measure internet speed only"],"correct":2,"exp":"The Elements panel shows the live DOM and applied styles, letting you experiment before editing your real files."},{"q":"For GitHub Pages to serve your site's homepage automatically, your main file should be named:","opts":["home.html","index.html","main.html","page1.html"],"correct":1,"exp":"Web servers, including GitHub Pages, serve index.html by default when someone visits your root URL."},{"q":"What is the default free URL format of a GitHub Pages project site?","opts":["username.github.io/repository-name","github.com/pages/username","pages.google.com/username","username.githubpages.dev/files"],"correct":0,"exp":"GitHub Pages publishes project sites at https://username.github.io/repository-name for free."},{"q":"To connect a custom domain like mybusiness.com.lr to GitHub Pages, you must configure:","opts":["A new Gmail account","DNS records (such as CNAME) at your domain registrar","A paid GitHub Enterprise plan","A local database"],"correct":1,"exp":"Pointing your domain's DNS records at GitHub's servers connects the custom domain to your Pages site."},{"q":"Why do developers write clear commit messages like \"Add contact form validation\"?","opts":["GitHub rejects commits without long messages","Commit messages change how the code runs","They make project history understandable for teammates and your future self","They increase website speed"],"correct":2,"exp":"Descriptive commit messages document why changes were made, which is vital when collaborating or reviewing history."}]},"mod5":{"title":"Quiz: JavaScript Data, APIs & Dynamic Apps","moduleNum":5,"questions":[{"q":"How do you access the first item of const products = [\"Rice\", \"Palm Oil\"]?","opts":["products[1]","products[0]","products.first()","products(0)"],"correct":1,"exp":"Array indexes start at zero, so products[0] returns the first item, \"Rice\"."},{"q":"Which array method adds an item to the end of an array?","opts":["push()","pop()","shift()","insert()"],"correct":0,"exp":"push() appends an item to the end of an array; pop() removes the last item."},{"q":"What does the filter() method return?","opts":["The first item only","The array sorted alphabetically","A single true or false value","A new array containing only items that pass a condition"],"correct":3,"exp":"filter() builds a new array with only the items whose test function returns true."},{"q":"In const vendor = { name: \"Musu\", stall: 14 }, how do you read the name?","opts":["vendor->name","vendor[name] without quotes","vendor.name","name.vendor"],"correct":2,"exp":"Dot notation (vendor.name) is the standard way to read an object property."},{"q":"What is JSON?","opts":["A JavaScript framework for animations","A text format for structured data used by APIs","A CSS preprocessor","A type of database server"],"correct":1,"exp":"JSON (JavaScript Object Notation) is the standard text format APIs use to exchange structured data."},{"q":"What does response.json() do in a fetch chain?","opts":["Sends JSON to the server","Checks the internet speed","Parses the response body from JSON text into JavaScript data","Converts JavaScript into HTML"],"correct":2,"exp":"response.json() reads the response body and parses the JSON text into usable JavaScript objects and arrays."},{"q":"Which part of a fetch chain should handle a failed network request?","opts":[".map()",".catch()",".length",".push()"],"correct":1,"exp":".catch() runs when the request fails, letting you show a friendly error message instead of a blank page."},{"q":"Why must you use JSON.stringify() before saving an array to localStorage?","opts":["localStorage only stores text strings","It encrypts the data for security","It makes the array load faster","localStorage requires XML format"],"correct":0,"exp":"localStorage stores strings only, so arrays and objects must be converted to JSON text first."},{"q":"What does localStorage.getItem(\"cart\") return if nothing was ever saved under that key?","opts":["An empty array","The number 0","null","An error that crashes the page"],"correct":2,"exp":"getItem() returns null for missing keys, so code should check for null before parsing."},{"q":"Which is a real limitation of localStorage?","opts":["It only works when online","It requires a paid subscription","It deletes data every time the tab closes","Data stays on one browser and device and does not sync elsewhere"],"correct":3,"exp":"localStorage is per-device and per-browser; syncing across devices requires a server database."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"I built my first website by lesson 3! By the end I had a full portfolio site and 2 paying clients. David makes coding feel natural and achievable. This course is the best investment I have made in my career by far."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"I was completely terrified of coding before this. Now I build websites for local businesses in Buchanan. The step-by-step approach is perfect for beginners. The JavaScript module was challenging but David explains everything so well."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"The project-based approach made learning stick. By Module 4 I had real work to show employers. I got hired as a junior web developer within 2 months of completing this course. TIH changed my life trajectory completely."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Excellent comprehensive course. The GitHub and deployment section was especially valuable, I can now deliver live websites to clients. The instructor is very responsive in the discussion forum. Highly recommended."}],"faqs":[{"q":"How hard is coding for a complete beginner?","a":"This course is specifically designed for people who have never coded. We start from zero and progress gradually. Most students are surprised by how quickly they pick it up with the right teaching approach."},{"q":"What tools do I need?","a":"VS Code (free), Chrome browser, and a free GitHub account. All are free and we provide step-by-step setup instructions in the first lesson."},{"q":"Can I get freelance clients after this course?","a":"Many graduates immediately start freelancing. We include a bonus lesson on how to find clients, price your services, and deliver professional websites to Liberian businesses."},{"q":"What should I learn after this course?","a":"We recommend our React & Modern JavaScript course for frontend advancement, or our Full-Stack Development course if you want to build databases and server-side applications."}]};
COURSES_DB['design'] = {"id":"design","title":"Graphic Design with Canva & Adobe Photoshop","shortDesc":"For entrepreneurs and aspiring designers, learn design principles, build brand identities, and create professional graphics in Canva and Photoshop, with an 8-piece portfolio.","category":"Graphic Design","icon":"🎨","gradient":"linear-gradient(135deg,#be185d,#ec4899)","instructor":"Patricia Sumo","instructorTitle":"Creative Director & Brand Design Specialist","instructorBio":"Patricia Sumo is a creative director with over 10 years of design experience working with brands across Liberia, Ghana, and Nigeria. She founded Sumo Creative Studio and has trained hundreds of designers at TIH Academy.","rating":4.6,"reviewCount":634,"students":"2,800+","duration":"30h","level":"Beginner","price":"FREE","origPrice":"$150","isFree":true,"badge":"free","certId":"TIH-2026-GD-0062","learn":["Apply fundamental design principles: layout, color theory, and typography","Create professional logos, flyers, posters, and brand identities in Canva","Master Canva Pro features for high-quality social media and marketing designs","Retouch photos and create composites in Adobe Photoshop","Design a complete brand identity package for a business","Create social media graphics optimized for every platform","Export designs correctly for print and digital use","Build a professional graphic design portfolio"],"requirements":["No design experience needed, all creative skill levels welcome","A computer with internet access for Canva (free browser-based)","Adobe Photoshop (30-day free trial sufficient; link provided in course)"],"about":["Good design is a superpower for business. In Liberia and across Africa, brands that invest in professional visual identity build more trust, attract more customers, and compete more effectively. This course makes professional design accessible to everyone.","Starting with core design principles that never change, you will progress through Canva mastery for everyday design needs, then into Adobe Photoshop for advanced photo editing and creative compositing. Real projects drive every module.","This course is ideal for entrepreneurs building a brand, marketers creating content, professionals wanting to design their own materials, or anyone wanting to start a freelance design career. By graduation you will have a portfolio of 8+ professional design pieces."],"modules":[{"title":"Module 1: Design Principles & Foundations","icon":"🎨","meta":"4 lessons · 36 min","lessons":[{"t":"1.1 Design Principles: Balance, Contrast & Hierarchy","d":"9:30","v":"FpwZTl3dCZE"},{"t":"1.2 Color Theory: Psychology & Palette Creation","d":"10:00","v":"BMDDGuUBO94"},{"t":"1.3 Typography: Fonts, Pairing & Text Design","d":"9:00","v":"HFVTZ7J0W1E"},{"t":"📝 Quiz: Design Principles","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Canva, Professional Design Made Easy","icon":"✏️","meta":"4 lessons · 44 min","lessons":[{"t":"2.1 Canva Interface, Templates & Brand Kit Setup","d":"10:00","v":"_ApwkN8BVsc"},{"t":"2.2 Logos, Flyers & Print Materials in Canva","d":"12:00","v":"ZB_LneYCkPU"},{"t":"2.3 Social Media Graphics & Animated Posts","d":"11:00","v":"DSbGwruIcfc"},{"t":"📝 Quiz: Canva Design","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Adobe Photoshop Essentials","icon":"🖼️","meta":"4 lessons · 46 min","lessons":[{"t":"3.1 Photoshop Interface & Essential Tools","d":"11:00","v":"OKkWRpoIFuw"},{"t":"3.2 Photo Retouching, Color Correction & Filters","d":"12:00","v":"0jzrqhsXwLo"},{"t":"3.3 Creating Composites & Advanced Selections","d":"12:00","v":"2R5fH8iKAXc"},{"t":"🛠️ Project: Full Brand Identity Package","d":"Project","isProject":true}]},{"title":"Module 4: Professional Design & Portfolio","icon":"🏆","meta":"4 lessons · 36 min","lessons":[{"t":"4.1 Designing for Print: Resolution, Bleed & CMYK","d":"9:30","v":"A4VePn0CAl4"},{"t":"4.2 Designing for Digital: Web, Email & Social Media","d":"9:00","v":"9CnrknQsg5E"},{"t":"4.3 Building & Presenting Your Design Portfolio","d":"9:00","v":"qelg3fYlxAE"},{"t":"📝 Quiz: Print, Digital & Portfolio Skills","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Brand Identity & Logo Design Mastery","icon":"🏷️","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 The Professional Logo Design Process","d":"Video + notes","v":"DxLR2CFFys0"},{"t":"5.2 Building a Complete Brand Identity System","d":"Video + notes","v":"vaqBJ2dX-Cs"},{"t":"5.3 Mockups & Presenting Brand Work Like a Professional","d":"Video + notes","v":"BSxg87CoOu4"},{"t":"📝 Quiz: Brand Identity & Logo Design","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, The Freelance Design Business","icon":"💼","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Winning Clients: Briefs, Pricing & Agreements","d":"Video + notes","v":"t1FdvLveV08"},{"t":"6.2 The Professional Workflow: Feedback, Files & Delivery","d":"Video + notes","v":"fbHP9pF8J2A"},{"t":"6.3 Your Design Career: Portfolio, Platforms & Growth","d":"Video + notes","v":"wHAVsrn4Adc"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Design Principles","moduleNum":1,"unlocks":3,"questions":[{"q":"What is \"visual hierarchy\" in design?","opts":["Using only one font","Arranging elements to guide the viewer's eye in order of importance","Using many colors","Making everything the same size"],"correct":1,"exp":"Visual hierarchy tells viewers what to look at first, second, and third through size, color, and placement."},{"q":"Complementary colors are:","opts":["Colors next to each other on the color wheel","Colors opposite each other on the color wheel","Only black and white","Random color combinations"],"correct":1,"exp":"Complementary colors (like red-green, blue-orange) create strong visual contrast when used together."},{"q":"Leading in typography refers to:","opts":["The first letter in a paragraph","The space between lines of text","Bold formatting","Letter spacing"],"correct":1,"exp":"Leading (line height) is the vertical space between lines of text, critical for readability."},{"q":"The rule of thirds in design means:","opts":["Use exactly three colors","Divide space into a 3x3 grid and place elements at intersections","Use three fonts","Create three versions of every design"],"correct":1,"exp":"The rule of thirds grid guides placement of key elements for natural, balanced compositions."},{"q":"What is white space in design?","opts":["Using white color only","Empty space around design elements that improves readability","A background color","An unused part of a canvas"],"correct":1,"exp":"White space (negative space) gives designs breathing room and improves visual clarity."},{"q":"What does contrast achieve in a design?","opts":["It makes all elements look identical","It makes key elements stand out by pairing differences in color, size, or weight","It reduces the file size of the design","It automatically aligns text"],"correct":1,"exp":"Contrast draws attention and creates emphasis, a dark headline on a light background is instantly readable."},{"q":"Analogous colors are:","opts":["Colors that sit next to each other on the color wheel","Colors directly opposite each other","Only shades of grey","Colors that clash on purpose"],"correct":0,"exp":"Analogous schemes (like blue, blue-green, green) sit side by side on the wheel and feel harmonious and calm."},{"q":"What is the main visual difference between serif and sans-serif fonts?","opts":["Serif fonts are always bold","Sans-serif fonts are only for print","Serif fonts have small strokes at letter ends; sans-serif fonts have clean ends without them","Serif fonts cannot be paired with other fonts"],"correct":2,"exp":"Serifs are the small finishing strokes on letters; sans-serif faces omit them for a cleaner, modern look."},{"q":"In color psychology, blue is most commonly used by banks and NGOs because it suggests:","opts":["Danger and urgency","Hunger and appetite","Playfulness and childhood","Trust, stability, and professionalism"],"correct":3,"exp":"Blue communicates trust and reliability, which is why financial and institutional brands favor it."},{"q":"The design principle of alignment means:","opts":["Placing every element in the exact center","Positioning elements along shared invisible lines so the layout feels ordered","Using only left-aligned text","Making all text the same size"],"correct":1,"exp":"Alignment connects elements visually along common edges or axes, creating order and professionalism."}]},"mod2":{"title":"Quiz: Canva Design","moduleNum":2,"unlocks":3,"questions":[{"q":"What is Canva primarily used for?","opts":["Video editing","Creating graphic designs with drag-and-drop tools","Coding websites","Photo storage"],"correct":1,"exp":"Canva is a browser-based design tool for creating professional graphics without technical skills."},{"q":"Canva's Brand Kit stores:","opts":["Product inventory","Your brand's colors, fonts, and logos for consistent use","Social media passwords","Customer contact information"],"correct":1,"exp":"The Brand Kit ensures every design uses your exact brand colors, fonts, and logo automatically."},{"q":"DPI (dots per inch) matters most for:","opts":["Social media posts","Email newsletters","Print materials like flyers and business cards","Video content"],"correct":2,"exp":"Print requires at least 300 DPI for sharp output. Screen graphics only need 72-96 DPI."},{"q":"RGB color mode is used for:","opts":["Print documents","Digital screens (web, social media, video)","Embroidery designs","Newspaper printing"],"correct":1,"exp":"RGB (Red, Green, Blue) is the color model for digital screens. Print uses CMYK."},{"q":"What file format is best for logos with transparent backgrounds?","opts":["JPG","BMP","PNG","PDF"],"correct":2,"exp":"PNG supports transparency, making it the standard format for logos placed on varied backgrounds."},{"q":"What is the fastest professional way to start a flyer in Canva?","opts":["Draw every element from a blank page with the pen tool","Write the design in code","Start from a quality template and customize it with your brand colors, fonts, and content","Screenshot another business's flyer and edit it"],"correct":2,"exp":"Templates give you professional layout foundations; customizing them with your Brand Kit makes them yours."},{"q":"In Canva, downloading a logo with a transparent background requires:","opts":["Choosing PNG format and ticking the transparent background option","Choosing JPG at maximum quality","Emailing Canva support","Printing and rescanning the design"],"correct":0,"exp":"PNG with the transparent background option (a Canva Pro feature) removes the canvas color behind your logo."},{"q":"The Position or layering tools in Canva let you:","opts":["Schedule social media posts","Move elements forward or backward so they overlap in the right order","Translate text into other languages","Compress your final download"],"correct":1,"exp":"Layering controls which element sits on top, essential when stacking text over images or shapes."},{"q":"To reuse one design across Instagram, Facebook, and a printed poster, Canva Pro offers:","opts":["A spell checker","The Charts tool","Background remover only","Magic Resize, which duplicates the design into other dimensions"],"correct":3,"exp":"Magic Resize instantly adapts one design to multiple platform sizes, saving hours of rework."},{"q":"Which export format should you choose for an animated Canva social media post?","opts":["PDF Print","SVG","MP4 video or GIF","DOCX"],"correct":2,"exp":"Animated designs must be exported as MP4 or GIF, static formats like PDF and JPG lose the motion."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"What is Photoshop primarily used for?","opts":["Building websites","Creating spreadsheets","Photo editing, retouching, and digital image composition","Writing documents"],"correct":2,"exp":"Photoshop is the industry standard for photo editing, compositing, and digital artwork creation."},{"q":"A \"bleed\" in print design is:","opts":["A design mistake","Extra artwork beyond the trim edge to prevent white borders","A color gradient","A type of font"],"correct":1,"exp":"Bleed extends art beyond the cut line so the final printed piece has no white edges after trimming."},{"q":"What is a mood board?","opts":["A social media post","A collection of visual references that capture the desired feel and direction of a design project","A type of calendar design","A font catalog"],"correct":1,"exp":"Mood boards help clients and designers align on visual direction before design work begins."},{"q":"Which format preserves layers in Photoshop?","opts":["JPG","PNG","PDF",".PSD (Photoshop native format)"],"correct":3,"exp":".PSD files save all Photoshop layers intact for future editing. JPG and PNG flatten the file."},{"q":"Kerning in typography is:","opts":["The space between lines","The space between individual letter pairs","Font weight (bold/thin)","Paragraph alignment"],"correct":1,"exp":"Kerning adjusts space between specific letter pairs for more natural, balanced text appearance."},{"q":"Visual hierarchy is mainly created through differences in:","opts":["File formats","Size, color, contrast, and placement of elements","Printer brands","Export settings"],"correct":1,"exp":"Designers guide the eye by making important elements bigger, bolder, higher-contrast, or better placed."},{"q":"Which color combination offers the strongest natural contrast?","opts":["Light grey on white","Yellow on white","Complementary colors like blue and orange","Two similar shades of green"],"correct":2,"exp":"Complementary pairs sit opposite each other on the color wheel and create maximum vibrancy and contrast."},{"q":"Pairing one serif headline font with one sans-serif body font is an example of:","opts":["Effective font pairing for contrast and readability","Breaking typography rules","Kerning","Color theory"],"correct":0,"exp":"Contrasting-but-complementary font pairs are a classic, safe typography strategy."},{"q":"Canva's Brand Kit combined with templates mainly helps a business achieve:","opts":["Cheaper printing costs","Faster internet","Automatic copyright registration","Visual consistency across all its designs"],"correct":3,"exp":"Storing exact brand colors, fonts, and logos ensures every design looks like the same brand."},{"q":"Which task is Photoshop clearly better at than Canva?","opts":["Quick social posts from templates","Advanced photo retouching and layered composites","Scheduling posts","Creating simple text flyers fastest"],"correct":1,"exp":"Photoshop's layers, masks, and selection tools make it the professional standard for photo manipulation."},{"q":"In Photoshop, working non-destructively means:","opts":["Editing with layers and adjustment layers so the original image stays intact","Deleting the original photo immediately","Flattening the file after every change","Only using the eraser tool"],"correct":0,"exp":"Non-destructive editing preserves the original pixels so any adjustment can be changed later."},{"q":"A design headed for professional printing should use which color mode and resolution?","opts":["RGB at 72 DPI","Greyscale at 100 DPI","CMYK at 300 DPI","RGB at 150 DPI"],"correct":2,"exp":"Print uses the CMYK ink model at 300 DPI; RGB at 72 DPI is for screens."},{"q":"Why does a logo need a suite of variations (horizontal, stacked, icon-only, one-color)?","opts":["To confuse competitors","Because clients pay per file","Because Canva requires four exports","Different spaces and printing methods each demand a different version"],"correct":3,"exp":"A profile photo, a signboard, and a stamped receipt each need a different form of the same logo."},{"q":"The purpose of a brand guidelines document is to:","opts":["Ensure anyone using the brand applies logos, colors, and fonts consistently","Replace the need for a designer","List the company's staff","Store passwords securely"],"correct":0,"exp":"Guidelines protect brand consistency even when different people create the designs."},{"q":"Presenting a logo on signboard, T-shirt, and phone-screen mockups helps because clients:","opts":["Prefer larger file sizes","Can see and feel the brand working in the real world","Cannot open PNG files","Need proof you own Photoshop"],"correct":1,"exp":"Mockups turn an abstract design into a believable future reality, which wins approval."},{"q":"What is the standard deposit practice for freelance design projects?","opts":["No deposit, always work fully on trust","100% before any conversation","Around 50% before work begins, remainder on completion","Payment only if the client likes it"],"correct":2,"exp":"A 50% deposit confirms client commitment and protects the designer's time."},{"q":"A client says \"make it pop\" with no details. The professional response is to:","opts":["Ignore the feedback entirely","Start the whole project again","Cancel the contract","Ask guided questions to translate it into specifics like contrast, color, or size"],"correct":3,"exp":"Translating vague feedback into concrete visual changes keeps revisions efficient and clients happy."},{"q":"Limiting a project to an agreed number of revision rounds protects the designer from:","opts":["Scope creep, endless unpaid changes beyond the original agreement","Learning new skills","Client compliments","Using templates"],"correct":0,"exp":"Defined revision rounds keep projects profitable and push clients to give consolidated, thoughtful feedback."},{"q":"A complete final logo delivery package should include:","opts":["Only one JPG file","A screenshot from your phone","Transparent PNGs, print-ready PDF, color codes, and font names","The Canva account password"],"correct":2,"exp":"Professional delivery gives the client every format they will need for print and digital use."},{"q":"For a Liberian designer seeking international clients online, the strongest strategy is:","opts":["Offering every possible service at the lowest price","Specializing in a clear niche with a strong portfolio and reliable delivery","Copying famous logos into the portfolio","Avoiding written communication"],"correct":1,"exp":"Specialization plus visible quality and reliability is how freelancers stand out on global platforms."}]},"mod4":{"title":"Quiz: Print, Digital & Portfolio Skills","moduleNum":4,"questions":[{"q":"What does CMYK stand for in print design?","opts":["Cyan, Magenta, Yellow, Key (black)","Color, Mixing, Yellow, Krypton","Cyan, Maroon, Yellow, Kelvin","Contrast, Margin, Yield, Kerning"],"correct":0,"exp":"CMYK is the four-ink color model printers use; designs for print should be set up in CMYK."},{"q":"The minimum resolution for sharp printed materials like flyers is:","opts":["72 DPI","150 DPI","300 DPI","30 DPI"],"correct":2,"exp":"300 DPI is the print industry standard, lower resolutions produce blurry, pixelated prints."},{"q":"The \"safe area\" in a print layout is:","opts":["The zone inside the trim line where important text and logos must stay","The area outside the bleed","The back side of the paper","A locked layer in Photoshop"],"correct":0,"exp":"Keeping key content within the safe area prevents it being cut off when the printer trims the sheet."},{"q":"Which format is generally best for a photograph shared on the web?","opts":["PSD","JPG","TIFF at full size","EPS"],"correct":1,"exp":"JPG compresses photos to small file sizes with good quality, ideal for fast-loading web images."},{"q":"Screen designs (social media, web) only need a resolution of about:","opts":["300 DPI","600 DPI","1200 DPI","72-96 DPI"],"correct":3,"exp":"Screens display at 72-96 DPI, so higher resolutions just create unnecessarily heavy files."},{"q":"A standard square Instagram post is:","opts":["1080 x 1080 pixels","500 x 200 pixels","3000 x 1000 pixels","210 x 297 millimeters"],"correct":0,"exp":"1080 x 1080 px is the standard square post size; designing at correct dimensions avoids awkward cropping."},{"q":"When sending final artwork to a print shop in Monrovia, the safest file format is usually:","opts":["A Canva share link only","An editable PowerPoint","A print-ready PDF with bleed included","A low-resolution screenshot"],"correct":2,"exp":"A print-ready PDF locks fonts, colors, and layout, and includes bleed so the shop can print accurately."},{"q":"Why should email graphics be kept small in file size?","opts":["Email providers convert them to text","Large images load slowly and may be clipped or ignored by email apps","Small images print better","Email only supports black and white"],"correct":1,"exp":"Lightweight images load quickly for recipients on mobile data and avoid email client clipping."},{"q":"A strong design portfolio should:","opts":["Include every design you have ever made, good or bad","Hide your process so competitors cannot copy it","Contain only text descriptions without visuals","Showcase your best, most relevant work with short context on the goal and result"],"correct":3,"exp":"Curated quality beats quantity, each piece should show the problem, your solution, and the outcome."},{"q":"When presenting a design case study, what impresses clients and employers most?","opts":["Explaining the business problem and how the design solved it","Listing every font you have installed","Showing the design at very small size","Using as many effects as possible"],"correct":0,"exp":"Clients hire problem-solvers; framing work around goals and results proves your design thinking."}]},"mod5":{"title":"Quiz: Brand Identity & Logo Design","moduleNum":5,"questions":[{"q":"What should happen before any logo sketching begins?","opts":["Choosing export formats","Research into the business, its customers, and its competitors","Printing test copies","Buying new fonts"],"correct":1,"exp":"Discovery research ensures the design solves the client's real problem instead of just looking nice."},{"q":"A combination mark logo is:","opts":["Two competing logos used together","A logo made only of initials","A symbol paired with the business name","A logo that changes color randomly"],"correct":2,"exp":"Combination marks pair an icon with a wordmark, giving businesses flexible, versatile branding."},{"q":"Why must a logo work in a single color?","opts":["Color logos are illegal in print","Single-color logos load faster online","Clients cannot see color on phones","It must stay clear on stamps, receipts, and low-cost one-color printing"],"correct":3,"exp":"Real-world reproduction, stamps, engraving, cheap printing, often allows only one color, so the mark must survive it."},{"q":"Vector graphics are ideal for logos because they:","opts":["Scale to any size without losing sharpness","Contain more pixels than photos","Only open in Canva","Are always black and white"],"correct":0,"exp":"Vectors are defined mathematically, so the same file stays crisp on a business card or a billboard."},{"q":"How many refined logo concepts do professionals typically present to a client?","opts":["Exactly one, to avoid confusion","Around three strong options","At least fifteen options","None until final payment"],"correct":1,"exp":"Three refined concepts give the client meaningful choice without overwhelming them."},{"q":"A brand color must be recorded as:","opts":["A verbal description like \"deep red\"","A photo of the color","Exact values such as HEX for digital and CMYK for print","A crayon sample"],"correct":2,"exp":"Exact color codes guarantee the brand looks identical across every screen and printer."},{"q":"What belongs in a brand guidelines document?","opts":["The client's tax records","Passwords for social media accounts","Weekly sales targets","Logo usage rules, color codes, fonts, and application examples"],"correct":3,"exp":"Guidelines document how to use the identity correctly so the brand stays consistent everywhere."},{"q":"How many fonts does a typical small-business brand system need?","opts":["About two, one for headings, one for body text","At least six for variety","Only decorative script fonts","A new font for every design"],"correct":0,"exp":"Two well-paired fonts keep the brand consistent and readable; too many fonts create visual chaos."},{"q":"What is the purpose of a mockup in a brand presentation?","opts":["To hide design flaws","To show the design realistically applied to real-world items like signs and shirts","To reduce the design's file size","To replace the brand guidelines"],"correct":1,"exp":"Mockups let clients emotionally see their brand in the real world, which sells the concept."},{"q":"When should a designer hand over editable source files to a client?","opts":["Before the first meeting","Immediately after the first draft","Never under any circumstances","After final payment, along with the agreed final deliverables"],"correct":3,"exp":"Review files (PNG/PDF) go out during feedback; editable source files transfer once the project is fully paid."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Patricia is an incredible teacher. I came with no design skills and left with a professional portfolio. I now design all my business's social media content myself, saving money on freelancers. This course is worth every penny."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":4,"text":"The Canva modules are outstanding, I designed a complete brand identity for my shop in week 2. The Photoshop section is advanced but the pace is manageable. Best graphic design training available in Liberia."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"I started freelancing immediately after Module 2. By the end of the course I had 5 paying clients. The brand identity project module gave me a real product to show clients. Patricia's real-world experience shines through every lesson."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":5,"text":"The design principles module fundamentally changed how I see the world. I now notice professional vs amateur design everywhere. The skills from this course have directly improved our church's marketing and outreach materials."}],"faqs":[{"q":"Do I need artistic talent to take this course?","a":"Not at all. Graphic design is a learnable skill. This course teaches you the principles and tools that make design systematic, not just talent-based."},{"q":"Is Canva free?","a":"Canva has a free version that covers most of this course. We also use some Canva Pro features (available free with a 30-day trial). Professional accounts cost about $13/month."},{"q":"Do I need to buy Photoshop?","a":"Adobe Photoshop requires a subscription (about $21/month) but Adobe offers a free 7-30 day trial which is sufficient to complete the course modules."},{"q":"Can I make money with graphic design in Liberia?","a":"Absolutely. Liberian businesses, churches, NGOs, and political campaigns constantly need flyers, social media graphics, and brand identities. Freelance design income is very achievable."}]};
COURSES_DB['android'] = {"id":"android","title":"Android App Development for Beginners","shortDesc":"For aspiring mobile developers, learn Kotlin and Android Studio from scratch, build three complete apps across the modules, and publish your own app on the Google Play Store by the end of the course.","category":"Mobile Development","icon":"📱","gradient":"linear-gradient(135deg,#15803d,#16a34a)","instructor":"Emmanuel Roberts","instructorTitle":"Senior Android Developer & Mobile Tech Educator","instructorBio":"Emmanuel Roberts has 8 years of Android development experience and has published 12 apps on the Google Play Store. He leads TIH's mobile development curriculum and has mentored over 800 app developers across West Africa.","rating":4.7,"reviewCount":421,"students":"1,650+","duration":"40h","level":"Intermediate","price":"FREE","origPrice":"$220","isFree":true,"badge":"free","certId":"TIH-2026-AD-0031","learn":["Set up Android Studio and understand the Android development environment","Write Kotlin code from scratch, variables, functions, classes, and logic","Build Android UI with XML layouts: buttons, text fields, lists, and navigation","Connect your app to the internet and work with APIs and JSON data","Store data locally using SQLite and SharedPreferences","Implement RecyclerView for smooth list and grid displays","Handle user permissions, notifications, and background tasks","Publish your completed app to the Google Play Store"],"requirements":["Basic computer skills and comfort using a computer","A computer with at least 8GB RAM to run Android Studio","No prior programming experience needed, Kotlin basics are taught from scratch"],"about":["Africa has over 600 million smartphone users, and mobile apps are transforming commerce, healthcare, agriculture, and government services across the continent. Learning to build Android apps puts you at the forefront of this transformation.","This course takes a project-first approach, you build a new app in every module, progressively adding features and complexity. By the end, you will have built 3 complete apps and published one live on the Google Play Store.","Whether you want to build apps for your business, start a career as a mobile developer, or create solutions for Liberian communities, this course gives you the complete foundation. No programming experience is required, we start from the absolute beginning with Kotlin."],"modules":[{"title":"Module 1: Android & Kotlin Foundations","icon":"📱","meta":"4 lessons · 44 min","lessons":[{"t":"1.1 Android Ecosystem & Setting Up Android Studio","d":"11:00","v":"2lwmKjkz-DE"},{"t":"1.2 Kotlin Basics: Variables, Types, Functions & Logic","d":"12:00","v":"wCwCsJSCy8Y"},{"t":"1.3 Your First App: Hello Liberia! UI & Activities","d":"12:00","v":"2LWSxWsPUCY"},{"t":"📝 Quiz: Android & Kotlin Foundations","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Building Android UIs","icon":"🖼️","meta":"4 lessons · 46 min","lessons":[{"t":"2.1 XML Layouts: Views, Buttons, TextViews & EditTexts","d":"12:00","v":"ISbyj5nFIUk"},{"t":"2.2 Navigation: Multiple Screens & Intent Passing Data","d":"11:30","v":"TwVzuHhQfbk"},{"t":"2.3 RecyclerView: Lists, Grids & Custom Adapters","d":"13:00","v":"Oc4MDMHRzwY"},{"t":"📝 Quiz: Android UI Development","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Local Storage, Internet APIs & App Permissions","icon":"🔌","meta":"4 lessons · 48 min","lessons":[{"t":"3.1 Local Data Storage with SharedPreferences & SQLite","d":"12:00","v":"l9ui4Lfgr-E"},{"t":"3.2 Connecting to the Internet: APIs, Retrofit & JSON","d":"13:00","v":"gaPoV4z5wng"},{"t":"3.3 Permissions, Notifications & Background Tasks","d":"12:00","v":"bHlLYhSrXvc"},{"t":"🛠️ Project: Build a News Reader App","d":"Project","isProject":true}]},{"title":"Module 4: Testing, Material Design & Google Play Publishing","icon":"🏆","meta":"4 lessons · 42 min","lessons":[{"t":"4.1 Testing, Debugging & Performance Optimization","d":"11:00","v":"_5LgIrd4O5g"},{"t":"4.2 Material Design: Beautiful, Professional Android UI","d":"10:30","v":"BEvOBTaYUm0"},{"t":"4.3 Publishing Your App to Google Play Store","d":"11:00","v":"WOKrelHPefc"},{"t":"📝 Quiz: Testing, Material Design & Publishing","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Modern Android, Jetpack Compose, Architecture & Room","icon":"🧩","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Jetpack Compose: Building UI the Modern Way","d":"Video + notes","v":"l7hGtIzGRRM"},{"t":"5.2 MVVM Architecture & Coroutines: Apps That Scale","d":"Video + notes","v":"EQvLP5BThZ0"},{"t":"5.3 Room Database: Robust Offline Storage","d":"Video + notes","v":"bOd3wO0uFr8"},{"t":"📝 Quiz: Jetpack Compose, Architecture & Room","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Firebase, Monetization & Your Developer Career","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Firebase: Adding a Cloud Backend Without a Server","d":"Video + notes","v":"7kzttk9lj3U"},{"t":"6.2 Monetization: Earning From Your Apps in African Markets","d":"Video + notes","v":"ZIWuTgbQiQg"},{"t":"6.3 The Capstone & Your Android Career Path","d":"Video + notes","v":"TrHILjGEEvY"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Android & Kotlin Foundations","moduleNum":1,"unlocks":3,"questions":[{"q":"What programming language is recommended for Android development?","opts":["Java only","Swift","Kotlin","Python"],"correct":2,"exp":"Kotlin is Google's officially recommended language for Android development since 2017."},{"q":"Android Studio is:","opts":["A type of Android phone","The official IDE for developing Android applications","A Google Play Store feature","An Android game"],"correct":1,"exp":"Android Studio is the official Integrated Development Environment (IDE) for Android app development."},{"q":"An \"Activity\" in Android is:","opts":["A background service","A database table","A single screen with a user interface","A network request"],"correct":2,"exp":"An Activity represents a single screen in an Android app, the fundamental UI unit."},{"q":"What is an APK file?","opts":["A Kotlin source code file","An Android Package, the installation file for Android apps","An audio file","A project configuration file"],"correct":1,"exp":"APK (Android Package Kit) is the file format Android uses to distribute and install apps."},{"q":"In Kotlin, \"val\" is used to declare:","opts":["A variable that can change","A function","An immutable (read-only) variable","A class"],"correct":2,"exp":"val declares an immutable variable in Kotlin, its value cannot be changed after assignment."},{"q":"In Kotlin, which keyword declares a variable whose value can change later?","opts":["val","var","const","let"],"correct":1,"exp":"var declares a mutable variable that can be reassigned, while val is read-only after assignment."},{"q":"Which keyword defines a function in Kotlin?","opts":["function","def","fun","void"],"correct":2,"exp":"Kotlin functions are declared with the fun keyword, e.g. fun greet(name: String)."},{"q":"Which Activity lifecycle method is called first, where you usually set up the screen?","opts":["onCreate()","onDestroy()","onStop()","onPause()"],"correct":0,"exp":"onCreate() runs when the activity is created, the place to call setContentView and initialize the UI."},{"q":"What is the role of the AndroidManifest.xml file?","opts":["It stores the app's images","It contains the Kotlin business logic","It styles the app's buttons","It declares the app's components, permissions, and metadata to the Android system"],"correct":3,"exp":"The manifest tells Android about your activities, required permissions, app name, and icon."},{"q":"In Kotlin, what does the ? in a type like String? mean?","opts":["The variable is a constant","The variable is nullable, it may hold null","The variable is private","The variable is a list"],"correct":1,"exp":"Kotlin's null safety marks nullable types with ?, forcing you to handle null and preventing crashes."}]},"mod2":{"title":"Quiz: Android UI Development","moduleNum":2,"unlocks":3,"questions":[{"q":"RecyclerView is used to display:","opts":["A single image","Large scrollable lists of data efficiently","Video content","Web pages"],"correct":1,"exp":"RecyclerView efficiently displays large lists by recycling view items as they scroll off screen."},{"q":"An Intent in Android is used for:","opts":["Storing data","Navigating between activities and passing data","Network requests","Database queries"],"correct":1,"exp":"Intents are messaging objects used to navigate between screens and pass data in Android."},{"q":"XML in Android development is used for:","opts":["Writing Kotlin logic","Defining UI layouts and views","Database configuration","API communication"],"correct":1,"exp":"XML layout files define the visual structure and attributes of Android UI components."},{"q":"What is a ConstraintLayout?","opts":["A database table","A networking library","A flexible Android layout that positions views relative to each other or the parent","A Kotlin function"],"correct":2,"exp":"ConstraintLayout creates flat, efficient UI layouts by constraining view positions to other views."},{"q":"ViewModel in Android architecture is used to:","opts":["Draw the UI","Store and manage UI-related data that survives configuration changes","Handle network requests","Manage app permissions"],"correct":1,"exp":"ViewModel survives screen rotations and holds UI data so it doesn't get lost on configuration changes."},{"q":"A LinearLayout arranges its child views:","opts":["Randomly across the screen","Only in overlapping stacks","In a single row or column depending on its orientation attribute","In a circular pattern"],"correct":2,"exp":"LinearLayout stacks children vertically or horizontally based on android:orientation."},{"q":"How do you pass a value like a username from one Activity to another?","opts":["Save it in the manifest","Use putExtra() on the Intent and read it with getStringExtra() in the next Activity","Write it into strings.xml at runtime","Use a RecyclerView"],"correct":1,"exp":"Intent extras carry key-value data between screens, putExtra to send, getExtra to receive."},{"q":"What is the job of a RecyclerView Adapter?","opts":["Managing the phone's battery","Requesting internet permissions","Storing data in SQLite","Binding each data item to a list item view as the user scrolls"],"correct":3,"exp":"The Adapter creates ViewHolders and binds your data to each row, letting RecyclerView recycle views efficiently."},{"q":"Which component shows a short popup message like \"Saved!\" at the bottom of the screen?","opts":["A Toast","A Fragment","An Intent","A ConstraintLayout"],"correct":0,"exp":"Toast.makeText(...).show() displays a brief, non-blocking message to the user."},{"q":"Which view lets the user type text into your app?","opts":["TextView","ImageView","EditText","Button"],"correct":2,"exp":"EditText is the input field view; TextView only displays text without accepting input."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"What does Retrofit do in Android?","opts":["Manages database operations","Creates a type-safe HTTP client for consuming REST APIs","Handles UI animations","Manages app permissions"],"correct":1,"exp":"Retrofit makes it easy to consume REST APIs by converting HTTP API calls into Kotlin interfaces."},{"q":"SharedPreferences is best for storing:","opts":["Large amounts of data","Images","Small key-value data like settings and user preferences","Complex relational data"],"correct":1,"exp":"SharedPreferences stores small amounts of primitive data as key-value pairs persistently."},{"q":"To publish on Google Play, you need:","opts":["A Google Developer account ($25 one-time fee)","A Google Workspace subscription","An Apple developer account","A paid Android Studio license"],"correct":0,"exp":"A Google Play Developer account costs a one-time $25 fee and lets you publish unlimited apps."},{"q":"Material Design is:","opts":["A physical design textbook","Google's design system for creating consistent, beautiful Android UIs","A Kotlin library","An app testing framework"],"correct":1,"exp":"Material Design is Google's comprehensive design system with guidelines, components, and patterns."},{"q":"What is a Fragment in Android?","opts":["A broken activity","A reusable portion of UI within an activity","A type of intent","A database record"],"correct":1,"exp":"Fragments are modular, reusable sections of UI that can be combined within activities."},{"q":"In Kotlin, what is the difference between val and var?","opts":["val is read-only after assignment; var can be reassigned","val is for numbers; var is for text","var is deprecated in modern Kotlin","They behave identically"],"correct":0,"exp":"val declares immutable references while var declares mutable ones, prefer val where possible."},{"q":"Which file declares your app's activities and required permissions to the Android system?","opts":["build.gradle only","strings.xml","AndroidManifest.xml","colors.xml"],"correct":2,"exp":"The manifest registers components and permissions so Android knows what your app contains and needs."},{"q":"Why does RecyclerView \"recycle\" views?","opts":["To reduce APK download size","To reuse a small pool of item views while scrolling, saving memory and keeping lists smooth","To delete old data automatically","To encrypt list contents"],"correct":1,"exp":"Reusing off-screen views instead of creating thousands keeps long lists fast on low-RAM devices."},{"q":"Which library converts REST API calls into type-safe Kotlin interface methods?","opts":["Room","Logcat","AdMob","Retrofit"],"correct":3,"exp":"Retrofit maps HTTP endpoints to interface functions, handling JSON conversion with a converter like Gson or Moshi."},{"q":"Your app needs the user's location. What must happen first?","opts":["The app must be paid","Nothing, location is always available","The permission must be declared in the manifest and requested from the user at runtime","The phone must be rooted"],"correct":2,"exp":"Dangerous permissions like location require both a manifest declaration and an explicit runtime request."},{"q":"Long-running work like a network call should never run on the main thread because:","opts":["It would freeze the UI and can trigger an ANR error","The main thread has no internet access","Google Play charges extra for it","Kotlin forbids functions on the main thread"],"correct":0,"exp":"The main thread draws the UI; blocking it freezes the app, so slow work belongs in coroutines."},{"q":"In Jetpack Compose, UI updates happen when:","opts":["The developer calls findViewById","Observed state values change, triggering recomposition","The user reinstalls the app","The XML file is edited"],"correct":1,"exp":"Compose is declarative: it re-renders composables automatically when the state they read changes."},{"q":"Which Compose element replaces most XML styling attributes like padding and width?","opts":["The manifest","A DAO","An Intent filter","Modifier chains such as Modifier.padding(16.dp).fillMaxWidth()"],"correct":3,"exp":"Modifiers configure size, spacing, and behavior of composables in plain Kotlin."},{"q":"In MVVM, what is the View's only job?","opts":["Querying the database directly","Making Retrofit calls","Displaying state and passing user actions to the ViewModel","Signing the release build"],"correct":2,"exp":"Keeping views logic-free makes apps testable and lets UI change without touching business rules."},{"q":"Which Room component holds your SQL operations like @Insert and @Query?","opts":["The DAO interface","The Entity class","The Application class","The Manifest"],"correct":0,"exp":"DAOs declare database operations; Room generates the implementation and validates SQL at compile time."},{"q":"What makes an offline-first design ideal for apps used in Liberia?","opts":["It removes the need for any database","It makes the app free to publish","It only works on the newest phones","The UI reads from the local database instantly, syncing with the network when a connection exists"],"correct":3,"exp":"Users on unreliable connections still get instant, working apps, with fresh data syncing opportunistically."},{"q":"Which Firebase service provides ready-made secure login, including phone number sign-in?","opts":["Crashlytics","Firebase Authentication","Cloud Messaging","AdMob"],"correct":1,"exp":"Firebase Auth handles account creation and sign-in flows, including phone auth popular in West Africa."},{"q":"Cloud Firestore stores data as:","opts":["XML layout files","APK archives","Documents grouped into collections, synced in real time","Bitmap images only"],"correct":2,"exp":"Firestore's document-collection model syncs across devices in real time and supports offline persistence."},{"q":"Under Google Play policy, selling digital in-app content (like premium features) must use:","opts":["Google Play Billing (in-app purchases)","Cash on delivery","Direct bank transfer only","A separate website with no connection to the app"],"correct":0,"exp":"Play policy requires Play Billing for digital goods; mobile money suits physical goods and real-world services."},{"q":"For a job or freelance client, the strongest proof of your Android skills is:","opts":["A screenshot of Android Studio","Memorizing every Kotlin keyword","A long list of courses with no projects","A published, working app on Google Play plus readable code on GitHub"],"correct":3,"exp":"A live app proves you can carry a product from idea to release, the exact ability employers and clients pay for."}]},"mod4":{"title":"Quiz: Testing, Material Design & Publishing","moduleNum":4,"questions":[{"q":"What is Logcat in Android Studio?","opts":["A tool that streams system and app log messages for debugging","A Kotlin animation library","The app store review page","A layout editor"],"correct":0,"exp":"Logcat displays real-time logs, exceptions, and your own Log.d messages, the first place to look when debugging."},{"q":"What is the Android Emulator used for?","opts":["Compressing APK files","Running and testing your app on a virtual device without a physical phone","Publishing apps to Google Play","Designing app icons"],"correct":1,"exp":"The emulator simulates real devices so you can test different screen sizes and Android versions."},{"q":"A unit test in Android development verifies:","opts":["The phone's battery health","The Play Store listing","That a small piece of logic, like a function, behaves correctly","The color scheme of the app"],"correct":2,"exp":"Unit tests check individual functions and classes automatically, catching bugs before users do."},{"q":"What causes an ANR (Application Not Responding) error?","opts":["Using too many colors","Publishing without screenshots","Missing app icons","Blocking the main (UI) thread with long-running work like network calls"],"correct":3,"exp":"Heavy work on the main thread freezes the UI; long tasks belong on background threads or coroutines."},{"q":"In Material Design, a FloatingActionButton (FAB) is used for:","opts":["The single most important action on a screen, like composing or adding","Displaying advertisements","Closing the app","Showing the battery level"],"correct":0,"exp":"The FAB is a prominent circular button promoting the screen's primary action."},{"q":"Material Design elevation refers to:","opts":["The app's version number","How high the phone is held","Shadow depth that shows which surfaces are raised above others","The screen brightness"],"correct":2,"exp":"Elevation uses shadows to communicate hierarchy, cards and FABs sit visually above the background."},{"q":"What is an Android App Bundle (AAB)?","opts":["A folder of screenshots","The publishing format Google Play requires, from which optimized APKs are generated per device","A Kotlin compression library","A type of emulator"],"correct":1,"exp":"Google Play requires .aab uploads and delivers smaller, device-optimized APKs to each user."},{"q":"Before uploading a release build, you must sign your app with:","opts":["A screenshot of your ID card","Your Gmail password","A Google Maps API key","A keystore containing your private signing key"],"correct":3,"exp":"Signing with a keystore proves app updates come from you, losing it can lock you out of updates, so back it up."},{"q":"What do versionCode and versionName represent?","opts":["versionCode is an internal increasing number for updates; versionName is the version users see","Both are shown to users identically","versionCode is the app's price; versionName is the developer's name","They set the minimum screen size"],"correct":0,"exp":"Play Store requires a higher versionCode for every update; versionName (like 1.2) is the human-readable label."},{"q":"What does a complete Google Play Store listing require?","opts":["Only the AAB file and nothing else","A paid advertising campaign","App title, description, screenshots, an icon, and a privacy policy where required","A minimum of 1,000 pre-registered users"],"correct":2,"exp":"A full listing with visuals, descriptions, and policy compliance is required before Google reviews and publishes your app."}]},"mod5":{"title":"Quiz: Jetpack Compose, Architecture & Room","moduleNum":5,"questions":[{"q":"What annotation marks a function as a Compose UI building block?","opts":["@Entity","@Composable","@Override","@Query"],"correct":1,"exp":"@Composable functions declare UI in Jetpack Compose and can be combined to build full screens."},{"q":"In Compose, which composable stacks its children vertically?","opts":["Row","Box","Column","LazyRow"],"correct":2,"exp":"Column arranges children top to bottom; Row is horizontal; Box overlaps children."},{"q":"Which Compose component replaces RecyclerView for efficient scrolling lists?","opts":["LazyColumn","TextField","Toast","ConstraintSet"],"correct":0,"exp":"LazyColumn renders only visible items, doing RecyclerView's job without adapters or ViewHolders."},{"q":"What does remember { mutableStateOf(0) } create?","opts":["A database table","A network request","A new Activity","Observable state that triggers UI redraws when its value changes"],"correct":3,"exp":"Compose watches mutableStateOf values and automatically recomposes UI that reads them."},{"q":"In MVVM, where should business logic and screen state live?","opts":["Inside the XML layout","In the ViewModel","In the AndroidManifest","Inside the Button's onClick only"],"correct":1,"exp":"The ViewModel holds state and logic, keeping the View simple and surviving rotations."},{"q":"What is a repository's role in app architecture?","opts":["Drawing the user interface","Managing app permissions","Deciding where data comes from, API, database, or cache, and supplying it to ViewModels","Storing the signing keystore"],"correct":2,"exp":"Repositories hide data sources behind one interface, so ViewModels don't care if data came from Room or Retrofit."},{"q":"The suspend keyword on a Kotlin function means:","opts":["It can pause and resume inside a coroutine without blocking the main thread","It is deprecated and unsafe","It runs only when the app is closed","It cannot return a value"],"correct":0,"exp":"suspend functions perform long work cooperatively inside coroutines, keeping the UI responsive."},{"q":"Why launch coroutines with viewModelScope in a ViewModel?","opts":["It makes network calls unnecessary","It runs code on the Play Store servers","It doubles the app's speed automatically","Work is automatically cancelled when the ViewModel is cleared, preventing leaks and crashes"],"correct":3,"exp":"viewModelScope ties coroutine lifetimes to the screen, cleaning up when the user navigates away."},{"q":"In Room, what does the @Entity annotation define?","opts":["A database table modeled as a Kotlin data class","A network endpoint","An animation","A Compose theme"],"correct":0,"exp":"Each @Entity class becomes a table, with its properties as columns."},{"q":"A Room DAO query returning Flow<List<Sale>> means the UI:","opts":["Must be refreshed manually with a button","Receives updated results automatically whenever the table changes","Only works while online","Can never show more than one sale"],"correct":1,"exp":"Flow streams emit fresh query results on every change, keeping the UI in sync with the database."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"I built my first Android app in week 1. By the end of the course I published an app to Google Play that helps Monrovia market vendors list their goods. Emmanuel is an excellent teacher, patient and very knowledgeable."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"This course is the real deal. The Kotlin fundamentals are taught so clearly I was writing functions on day 2. The API module opened my eyes to what apps can do. I now have a career roadmap that didn't exist before TIH."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":4,"text":"The course is excellent though challenging. The project module is outstanding, building a real news reader app forced me to apply everything I learned. I now feel confident calling myself an Android developer."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":5,"text":"I took this course wanting to build an app for my church. By Module 3 I had already built it and published it. Over 200 church members now use the app I created. The course ROI is incredible."}],"faqs":[{"q":"Do I need programming experience?","a":"No! We teach Kotlin from absolute scratch. If you completed our Computer Literacy course, you have everything needed to start this course."},{"q":"What kind of computer do I need?","a":"Android Studio requires at least 8GB RAM (16GB recommended) and 4GB free disk space. Windows, Mac, and Linux all work. We provide an optimization guide for slower computers."},{"q":"Can I publish apps to earn money?","a":"Yes! Google Play allows you to sell apps, use in-app purchases, and run ads. Many graduates earn income through their apps. We cover monetization strategies in the final module."},{"q":"What comes after this course?","a":"We recommend our Advanced Android course covering Firebase, Jetpack Compose, and enterprise Android patterns. Or explore our Cross-Platform development course with Flutter."}]};
COURSES_DB['marketing'] = {"id":"marketing","title":"Digital Marketing Professional Certificate","shortDesc":"For business owners, marketers, and freelancers, master SEO, Facebook and Google advertising, email marketing, and analytics to grow any Liberian or African business online and measure real results.","category":"Digital Marketing","icon":"📢","gradient":"linear-gradient(135deg,#b45309,#f59e0b)","instructor":"Grace Johnson","instructorTitle":"Digital Marketing Director & Growth Strategist","instructorBio":"Grace Johnson has led digital marketing for brands in Liberia, Ghana, and Nigeria for over 12 years. She has generated over $5M in client revenue through digital campaigns and trained over 2,100 marketers at TIH Academy.","rating":4.9,"reviewCount":890,"students":"2,100+","duration":"34h","level":"Intermediate","price":"FREE","origPrice":"$180","isFree":true,"badge":"free","certId":"TIH-2026-DM-0095","learn":["Develop a comprehensive digital marketing strategy for any business","Grow organic reach through Search Engine Optimization (SEO)","Build and manage professional social media presence on all major platforms","Run profitable paid advertising on Facebook, Instagram, and Google","Create compelling content that attracts and converts audiences","Use Google Analytics to measure and optimize marketing performance","Build and grow an email marketing list with high open rates","Execute an end-to-end digital marketing campaign with real results"],"requirements":["Basic computer and internet skills","A business, brand, or personal project to apply marketing skills to (recommended)","No prior marketing experience needed, this course starts with fundamentals"],"about":["Digital marketing is the most accessible path to growing a business in Africa today. With over 500 million internet users across the continent, digital channels offer unprecedented reach at a fraction of traditional advertising costs, if you know how to use them.","This course covers the complete digital marketing ecosystem: from SEO and content marketing that drives free organic traffic, to paid social media ads that can target any audience, to email marketing and analytics. You will build real campaigns, not just learn theory.","Whether you run a business, work in marketing, or want to start a freelance digital marketing career, this course gives you skills that are immediately applicable and commercially valuable. Our graduates manage marketing for top Liberian businesses and international brands."],"modules":[{"title":"Module 1: Digital Marketing Strategy & Content","icon":"📢","meta":"4 lessons · 40 min","lessons":[{"t":"1.1 Digital Marketing Fundamentals & the Customer Journey","d":"10:00","v":"iRjXccj4yRo"},{"t":"1.2 Content Marketing: Creating Content That Converts","d":"11:00","v":"gqRdIEIlzNs"},{"t":"1.3 Social Media Strategy: Platform Selection & Brand Voice","d":"10:30","v":"8LX60gToxrM"},{"t":"📝 Quiz: Digital Marketing Strategy","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: SEO & Organic Growth","icon":"🔍","meta":"4 lessons · 42 min","lessons":[{"t":"2.1 SEO Foundations: How Google Ranks Websites","d":"10:30","v":"WR_5_gJVA2c"},{"t":"2.2 Keyword Research & On-Page SEO","d":"11:30","v":"VPDe8XL7Mh8"},{"t":"2.3 Link Building & Technical SEO Essentials","d":"10:30","v":"C5ddo63kHHI"},{"t":"📝 Quiz: SEO & Organic Marketing","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Paid Advertising & Email Marketing","icon":"💰","meta":"4 lessons · 46 min","lessons":[{"t":"3.1 Facebook & Instagram Ads: Audience Targeting & Campaigns","d":"13:00","v":"-CsBl3tv-X0"},{"t":"3.2 Google Ads: Search, Display & Performance Max","d":"12:00","v":"u0r3y1q0fLQ"},{"t":"3.3 Email Marketing: List Building, Automation & Sequences","d":"11:30","v":"2fBxrhV3Nk0"},{"t":"🛠️ Project: Full Digital Marketing Campaign","d":"Project","isProject":true}]},{"title":"Module 4: Analytics, Optimization & Career","icon":"🏆","meta":"4 lessons · 38 min","lessons":[{"t":"4.1 Google Analytics 4: Measuring What Matters","d":"11:00","v":"mKu6FI53BxE"},{"t":"4.2 A/B Testing & Conversion Rate Optimization","d":"9:30","v":"xGpwhYiDCSg"},{"t":"4.3 Digital Marketing Career & Freelancing in Africa","d":"9:00","v":"1pejHrRIzAY"},{"t":"📝 Quiz: Analytics, Optimization & Career","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Mobile-First & WhatsApp Marketing for African Audiences","icon":"📱","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 WhatsApp Business Marketing: Catalogs, Broadcasts & Customer Care","d":"Video + notes","v":"mGJyCH5BIi8"},{"t":"5.2 Social Commerce & Mobile Money: Selling Where Your Customers Already Are","d":"Video + notes","v":"K6AEFYA5QuM"},{"t":"5.3 Influencer, Community & Offline-to-Online Marketing","d":"Video + notes","v":"yLNSQyExhTU"},{"t":"📝 Quiz: Mobile-First & WhatsApp Marketing","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Launching Your Digital Marketing Career & Agency","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Building a Results-Driven Portfolio & Case Studies","d":"Video + notes","v":"gxz13n0CGzo"},{"t":"6.2 Winning Clients: Pitching, Pricing & Freelance Business Setup","d":"Video + notes","v":"RwqyuFnFzII"},{"t":"6.3 Capstone Project: Running a Full Campaign End-to-End & Reporting Like a Pro","d":"Video + notes","v":"lviXtSN-iUw"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Digital Marketing Strategy","moduleNum":1,"unlocks":3,"questions":[{"q":"What is a \"target audience\" in marketing?","opts":["Everyone in the world","The specific group most likely to buy your product or service","Your competitors","Your existing customers only"],"correct":1,"exp":"A target audience is the specific demographic and psychographic group your marketing is designed to reach."},{"q":"The \"marketing funnel\" describes:","opts":["A data visualization tool","The stages customers go from awareness to purchase","A social media algorithm","An advertising platform"],"correct":1,"exp":"The marketing funnel (Awareness → Interest → Decision → Action) models the customer journey."},{"q":"Content marketing primarily generates:","opts":["Immediate sales only","Long-term organic traffic and brand authority","Paid ad impressions","Negative feedback"],"correct":1,"exp":"Content marketing builds trust, drives organic search traffic, and generates leads over time."},{"q":"A \"call to action\" (CTA) in marketing is:","opts":["A customer complaint","Instruction prompting the audience to take a specific next step","A type of advertisement","A marketing analytics report"],"correct":1,"exp":"CTAs like \"Shop Now\", \"Sign Up Free\", or \"Learn More\" drive measurable audience action."},{"q":"What is brand voice?","opts":["A voiceover in ads","The consistent personality, tone, and style a brand uses across all communications","A marketing budget","A social media algorithm"],"correct":1,"exp":"A consistent brand voice builds recognition and trust across all customer touchpoints."},{"q":"What is a buyer persona?","opts":["A legal document describing your customers","A semi-fictional profile of your ideal customer based on research and data","A list of everyone who has bought from you","A social media advertising account"],"correct":1,"exp":"A buyer persona summarizes your ideal customer's demographics, goals, and pain points so you can tailor messaging to them."},{"q":"At the awareness stage of the marketing funnel, the best content is:","opts":["Aggressive discount offers and checkout pages","Educational content that introduces the problem and your brand","Contract terms and invoices","Post-purchase support articles"],"correct":1,"exp":"Awareness-stage prospects are just discovering their problem, so helpful educational content builds trust before you sell."},{"q":"When choosing which social media platform to focus on, the most important factor is:","opts":["Which platform has the newest features","Which platform your competitors ignore completely","Where your target audience actually spends their time","Which platform is cheapest to design graphics for"],"correct":2,"exp":"Platform selection should follow your audience, marketing where your customers already are beats chasing trends."},{"q":"Evergreen content is content that:","opts":["Is only about environmental topics","Stays relevant and useful for a long time after publishing","Must be updated every single day","Can only be published in video format"],"correct":1,"exp":"Evergreen content, like how-to guides, keeps attracting traffic for months or years without constant updating."},{"q":"Engagement rate on social media measures:","opts":["How fast your page loads","How many ads you have purchased","The total number of accounts you follow","Interactions like likes, comments, and shares relative to your reach or followers"],"correct":3,"exp":"Engagement rate shows how actively your audience responds to content, which is a stronger health signal than follower count alone."}]},"mod2":{"title":"Quiz: SEO & Organic Marketing","moduleNum":2,"unlocks":3,"questions":[{"q":"SEO stands for:","opts":["Social Engagement Optimization","Search Engine Optimization","Site Experience Overview","Sponsored Engagement Outreach"],"correct":1,"exp":"SEO improves a website's visibility in search engine results pages (SERPs) without paid ads."},{"q":"What is a \"keyword\" in SEO?","opts":["A password for your website","Words or phrases people type into search engines","A type of social media post","A website security feature"],"correct":1,"exp":"Keywords are search terms you optimize your content for to rank higher in search results."},{"q":"Backlinks are:","opts":["Links on your website to other sites","Links from other websites pointing to your site","Broken links","Social media links"],"correct":1,"exp":"Backlinks from reputable sites signal authority to Google and boost your search rankings."},{"q":"Page loading speed affects:","opts":["Only social media performance","SEO rankings and user experience","Only desktop users","Only paid ads"],"correct":1,"exp":"Google uses page speed as a ranking factor, and slow sites have higher bounce rates."},{"q":"\"Organic\" traffic means:","opts":["Traffic from social media only","Visitors who came from unpaid search results","Paid advertising traffic","Email newsletter traffic"],"correct":1,"exp":"Organic traffic arrives through unpaid search results, it's free once you rank well."},{"q":"A long-tail keyword is:","opts":["A longer, more specific search phrase with lower volume but higher intent","Any keyword with more than one million searches","A keyword written at the end of an article","A paid advertising keyword only"],"correct":0,"exp":"Long-tail keywords like 'affordable catering services in Paynesville' attract fewer but far more ready-to-buy searchers."},{"q":"The title tag of a web page is important for SEO because:","opts":["It controls the page's loading speed","It appears as the clickable headline in search results and signals the page topic to Google","It hides content from competitors","It automatically builds backlinks"],"correct":1,"exp":"The title tag is a major on-page ranking signal and heavily influences whether searchers click your result."},{"q":"For a shop in Monrovia that serves local customers, the most impactful free SEO action is:","opts":["Buying backlinks from foreign websites","Creating and optimizing a Google Business Profile listing","Removing all images from the website","Publishing content only in foreign languages"],"correct":1,"exp":"A complete Google Business Profile helps local businesses appear in map results when nearby customers search."},{"q":"Search intent refers to:","opts":["The goal a person has when typing a query, such as learning, comparing, or buying","The number of times a keyword is searched","How quickly Google indexes a page","The location of the search engine's servers"],"correct":0,"exp":"Matching content to search intent, informational, navigational, or transactional, is essential for ranking and converting."},{"q":"Keyword stuffing, repeating a keyword unnaturally many times, leads to:","opts":["Guaranteed first-page rankings","Faster page loading","Lower rankings because Google penalizes manipulative, unreadable content","Automatic featured snippets"],"correct":2,"exp":"Google's algorithms detect keyword stuffing and demote pages that sacrifice readability for manipulation."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"What is the Facebook Pixel?","opts":["A Facebook design tool","A code snippet tracking website visitor actions to improve ad targeting","A Facebook business account type","A social media scheduling tool"],"correct":1,"exp":"The Facebook Pixel tracks website behavior so you can retarget visitors and optimize ad delivery."},{"q":"Google Analytics is used to:","opts":["Create websites","Measure website traffic, user behavior, and conversion performance","Manage social media","Run Google Ads"],"correct":1,"exp":"Google Analytics provides detailed data on how visitors find, engage with, and convert on your site."},{"q":"Email open rate is:","opts":["The percentage of emails delivered","The percentage of email recipients who opened an email","The number of emails sent","The email click-through rate"],"correct":1,"exp":"Open rate measures the percentage of delivered emails that recipients actually opened."},{"q":"A/B testing in marketing is:","opts":["Testing two versions of a product physically","Comparing two versions of an ad or page to see which performs better","A security testing method","An analytics report type"],"correct":1,"exp":"A/B testing provides data-driven insights on which marketing elements produce better results."},{"q":"ROAS stands for:","opts":["Rate Of Ad Spending","Return On Ad Spend","Reach Of Audience Segment","Revenue Of Advertising System"],"correct":1,"exp":"ROAS measures how much revenue you earn for every dollar spent on advertising."},{"q":"Which sequence correctly orders the classic marketing funnel?","opts":["Action, Decision, Interest, Awareness","Awareness, Interest, Decision, Action","Interest, Awareness, Action, Decision","Decision, Awareness, Interest, Action"],"correct":1,"exp":"Customers move from first hearing about you (awareness) through interest and decision to the final action of buying."},{"q":"A buyer persona is most useful for:","opts":["Filing business taxes correctly","Tailoring messages, content, and targeting to your ideal customer","Designing a company logo","Calculating shipping costs"],"correct":1,"exp":"Personas keep every campaign focused on the real needs, habits, and pain points of the customer who actually buys."},{"q":"Which of these actions most directly improves organic search rankings?","opts":["Buying more Facebook ads","Earning backlinks from reputable websites and matching content to search intent","Posting more WhatsApp Status updates","Increasing your product prices"],"correct":1,"exp":"Authority signals like quality backlinks plus intent-matched content are core drivers of organic rankings."},{"q":"For a Paynesville salon that serves nearby customers, local SEO success mostly depends on:","opts":["An optimized Google Business Profile with reviews and accurate details","Ranking for global English keywords","Having the most expensive website design","Posting only on international forums"],"correct":0,"exp":"Local map visibility comes primarily from a complete, review-rich Google Business Profile."},{"q":"The main purpose of the Meta (Facebook) Pixel is to:","opts":["Design ad images automatically","Track website visitor actions so you can retarget and optimize ads","Increase your page's follower count directly","Translate ads into local languages"],"correct":1,"exp":"The Pixel records site behavior, enabling retargeting audiences and conversion-optimized ad delivery."},{"q":"If you spend $50 on ads and generate $200 in tracked revenue, your ROAS is:","opts":["25%","2x","4x","$150"],"correct":2,"exp":"ROAS is revenue divided by ad spend: 200 divided by 50 equals 4, meaning $4 earned per $1 spent."},{"q":"An email welcome sequence is:","opts":["A series of automated emails sent to new subscribers to build trust and drive a first action","A single yearly newsletter","A list of unsubscribed contacts","A spam filtering technique"],"correct":0,"exp":"Automated welcome sequences engage subscribers when interest is highest, typically producing the best open and conversion rates."},{"q":"In GA4, which metric best shows whether marketing is producing business value?","opts":["Total page views alone","Conversions from defined key events like purchases or leads","The number of countries in your reports","Average session duration alone"],"correct":1,"exp":"Traffic metrics are context; conversion events tied to business goals measure real marketing value."},{"q":"The correct discipline for A/B testing is to:","opts":["Change one variable, run to sufficient sample size, then act on the data","Trust your first day of results","Test five changes simultaneously in one variation","Only test when campaigns are failing"],"correct":0,"exp":"Single-variable tests with adequate data isolate cause and effect and prevent random noise from driving decisions."},{"q":"Why is WhatsApp Business especially powerful for Liberian small businesses?","opts":["It replaces the need for any products","Customers already live on WhatsApp, and tools like catalogs and quick replies turn chats into sales","It guarantees viral posts","It only works for large corporations"],"correct":1,"exp":"WhatsApp meets West African customers in their daily habit and equips businesses to sell professionally inside chat."},{"q":"In the social commerce flow, the recommended way to receive payment from most Liberian customers is:","opts":["Bank wire transfers only","Orange Money or MTN MoMo mobile money transfers","Foreign checks","Store credit points"],"correct":1,"exp":"Mobile money is the trusted, widely adopted payment rail that makes chat-based selling practical in West Africa."},{"q":"The main reason to prefer micro-influencers over celebrities for a small business campaign is:","opts":["They have larger audiences","Higher audience trust and engagement at a much lower cost","They never require any agreement","Platforms promote them for free"],"correct":1,"exp":"Micro-influencers' close audience relationships convert well, and their fees fit small-business budgets."},{"q":"A professional marketing case study must include:","opts":["Only your certificate and course grades","The client's challenge, your strategy, and measurable results with timeframes","Guesses about what probably happened","A list of tools you have heard about"],"correct":1,"exp":"Challenge-strategy-results with real numbers is the format that proves competence to future clients and employers."},{"q":"A monthly retainer arrangement means the client pays:","opts":["Once, for a single deliverable","A recurring fee for ongoing marketing management each month","Only when sales double","Nothing until year end"],"correct":1,"exp":"Retainers provide freelancers stable recurring income in exchange for continuous management and reporting."},{"q":"In the capstone campaign, tracking with UTM links and a lead log matters because:","opts":["It makes ads cheaper automatically","It lets you attribute results to specific channels and report real performance to the client","Platforms require it before posting","It hides your strategy from competitors"],"correct":1,"exp":"Attribution and record-keeping turn campaign activity into evidence, the foundation of optimization and professional reporting."}]},"mod4":{"title":"Quiz: Analytics, Optimization & Career","moduleNum":4,"questions":[{"q":"In Google Analytics 4, user actions such as clicks, scrolls, and purchases are recorded as:","opts":["Sessions","Events","Cookies","Campaigns"],"correct":1,"exp":"GA4 uses an event-based model where every interaction, from a page view to a purchase, is tracked as an event."},{"q":"A 'conversion' in digital marketing is:","opts":["Any visit to your website","Changing your brand colors","A desired action completed by a user, such as a purchase or sign-up","Translating content into another language"],"correct":2,"exp":"Conversions are the valuable actions you define, purchases, form submissions, calls, that campaigns aim to produce."},{"q":"UTM parameters added to a link allow you to:","opts":["Make the link load faster","Identify exactly which campaign, source, and medium sent each visitor","Encrypt the destination page","Block competitors from clicking the link"],"correct":1,"exp":"UTM tags like utm_source and utm_campaign let analytics tools attribute traffic to specific marketing efforts."},{"q":"If a landing page gets 500 visitors and 25 of them sign up, the conversion rate is:","opts":["25%","0.5%","20%","5%"],"correct":3,"exp":"Conversion rate is conversions divided by visitors: 25 divided by 500 equals 0.05, or 5%."},{"q":"When running an A/B test, you should change:","opts":["One element at a time so you know what caused the difference","Every element at once to save time","Nothing, both versions must be identical","Only the test that is already winning"],"correct":0,"exp":"Testing a single variable, like the headline or button color, isolates the cause of any performance change."},{"q":"Ending an A/B test after only a handful of visitors is risky because:","opts":["Google will penalize your website","The sample is too small for the result to be statistically reliable","A/B tests legally require 90 days","Small tests cost more money"],"correct":1,"exp":"Small samples produce random-looking wins; reliable decisions need enough data to reach statistical significance."},{"q":"A KPI (Key Performance Indicator) is:","opts":["A type of paid advertisement","A measurable value that shows progress toward a specific business goal","A social media platform","A website hosting plan"],"correct":1,"exp":"KPIs like cost per lead or ROAS keep marketing focused on outcomes that matter, not vanity numbers."},{"q":"Conversion Rate Optimization (CRO) focuses on:","opts":["Buying more traffic at any cost","Getting a higher percentage of existing visitors to take the desired action","Reducing the number of pages on a website","Increasing follower counts on social media"],"correct":1,"exp":"CRO improves results from traffic you already have, often through better copy, design, and page speed."},{"q":"A high bounce rate on a landing page usually suggests:","opts":["The page perfectly matches visitor expectations","Visitors are converting too quickly","The page content or experience does not match what visitors expected","The server is located too far away"],"correct":2,"exp":"When visitors leave without engaging, the message, offer, or load speed likely fails to meet their expectations."},{"q":"For a freelance digital marketer in West Africa, the strongest tool for winning new clients is:","opts":["A portfolio of documented campaign results with real numbers","A very long list of software subscriptions","Promising guaranteed first-place Google rankings","Working only for free forever"],"correct":0,"exp":"Documented results, traffic growth, ROAS, leads generated, prove your skills far better than promises or certificates alone."}]},"mod5":{"title":"Quiz: Mobile-First & WhatsApp Marketing","moduleNum":5,"questions":[{"q":"The main advantage of the WhatsApp Business app over personal WhatsApp is:","opts":["It sends messages faster","It offers business tools like catalogs, labels, greeting messages, and quick replies","It works without any internet connection","It automatically runs paid advertisements"],"correct":1,"exp":"WhatsApp Business adds professional tools, catalog, automated greetings, labels, and quick replies, designed for selling."},{"q":"A WhatsApp broadcast list differs from a group because:","opts":["Broadcasts can only contain photos","Recipients receive the message individually and cannot see other recipients","Groups are limited to five members","Broadcasts require a paid subscription"],"correct":1,"exp":"Broadcasts deliver a message privately to each contact who has saved your number, feeling personal rather than public."},{"q":"WhatsApp labels are best used to:","opts":["Decorate messages with colors for fun","Organize chats by stage, such as new customer, order pending, and paid","Block unwanted contacts automatically","Translate messages into other languages"],"correct":1,"exp":"Labels act as a simple CRM, ensuring orders and follow-ups are tracked and no sale is forgotten."},{"q":"In the West African social commerce flow taught in this module, payment is most commonly completed via:","opts":["International credit cards on a website","Mobile money transfers such as Orange Money or MTN MoMo","Postal money orders","Cryptocurrency wallets"],"correct":1,"exp":"Mobile money is the dominant trusted digital payment method for Liberian consumers, making it central to social selling."},{"q":"The biggest barrier to social commerce sales in African markets is:","opts":["Customers dislike photos of products","Fear of being scammed when paying before delivery","Too many delivery riders available","Social platforms banning all selling"],"correct":1,"exp":"Trust is the main obstacle, which is why testimonials, delivery photos, and consistent branding are so important."},{"q":"Which practice best builds buyer trust for a social commerce business?","opts":["Changing your business name frequently","Posting customer testimonials and real delivery photos consistently","Deleting all customer comments","Only accepting full payment weeks before delivery"],"correct":1,"exp":"Visible social proof, reviews, testimonials, delivery evidence, directly counters the fear of online scams."},{"q":"A micro-influencer is:","opts":["A creator with a smaller but highly engaged audience, roughly 1,000 to 20,000 followers","Any celebrity with millions of followers","A paid advertising manager at Meta","A robot account that posts automatically"],"correct":0,"exp":"Micro-influencers offer high trust and engagement at affordable rates, often outperforming celebrities for small businesses."},{"q":"Giving each influencer a unique promo code allows you to:","opts":["Pay them less money","Measure exactly how many sales each influencer generates","Hide your prices from competitors","Avoid delivering products to their followers"],"correct":1,"exp":"Unique codes attribute sales to specific influencers, turning influencer marketing into measurable performance marketing."},{"q":"An example of offline-to-online bridging for a Liberian business is:","opts":["Removing your phone number from flyers","Mentioning your WhatsApp number in radio spots and printing it on receipts","Closing your physical shop permanently","Only marketing to customers overseas"],"correct":1,"exp":"Feeding offline audiences like radio listeners and market foot traffic into digital channels multiplies every marketing effort."},{"q":"Asking every new customer 'How did you hear about us?' helps you:","opts":["Identify which marketing channel delivers customers most cheaply","Increase your product prices automatically","Comply with international tax law","Make conversations longer for engagement"],"correct":0,"exp":"Simple source-tracking reveals which channels actually drive sales so you can invest budget where it works."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Grace Johnson is a phenomenal instructor. I landed a remote digital marketing job within 2 months of completing this course. The Facebook Ads module alone was worth 10 times the course price, I immediately ran profitable campaigns."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"I use everything from this course every single day in my business. Organic reach is up 400% and my paid ads now have positive ROAS. Grace teaches with real results and real numbers. Absolutely life-changing course."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"The SEO module transformed my blog from zero to 1,000 monthly organic visitors in 3 months. The email marketing section gave me tools to build a subscriber list that is now my most valuable business asset."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Comprehensive coverage of every important digital marketing channel. The campaign project in Module 3 was excellent practical experience. I now manage marketing for two businesses in addition to my own, the skills are immediately monetizable."}],"faqs":[{"q":"Do I need a business to take this course?","a":"No, but having a project to apply your learning to (a business, nonprofit, personal brand, or side project) will dramatically accelerate your results."},{"q":"How much do Facebook and Google Ads cost?","a":"You can start with as little as $5/day. This course teaches you to make every dollar count with proper targeting and testing so you don't waste budget."},{"q":"Will this help me get a marketing job?","a":"Yes. Digital marketing is one of the fastest-growing career fields in Africa. Our certificate plus your campaign portfolio from this course makes you highly competitive for marketing roles."},{"q":"Is this course updated for current platforms?","a":"Yes. Digital marketing changes rapidly and TIH updates this course quarterly. Enrolled students get all updates free, including new modules on emerging platforms and AI in marketing."}]};
COURSES_DB['cybersecurity'] = {"id":"cybersecurity","title":"Cybersecurity Fundamentals & Ethical Hacking","shortDesc":"For IT and security-minded learners, understand how cyber attacks work, test systems ethically with Kali Linux, and prepare for CompTIA Security+ and CEH exams.","category":"Cybersecurity","icon":"🔒","gradient":"linear-gradient(135deg,#7f1d1d,#e31e24)","instructor":"Emmanuel Duo","instructorTitle":"Certified Ethical Hacker & Cybersecurity Consultant","instructorBio":"Emmanuel Duo holds a CEH (Certified Ethical Hacker) and CISSP certification with 10 years in cybersecurity consulting for banks, government agencies, and NGOs across West Africa. He has secured over 50 organizations from cyber threats.","rating":4.8,"reviewCount":389,"students":"1,100+","duration":"36h","level":"Intermediate","price":"FREE","origPrice":"$200","isFree":true,"badge":"free","certId":"TIH-2026-CS-0038","learn":["Understand the cybersecurity landscape and common threat types","Set up and use Kali Linux for security testing","Perform network scanning and vulnerability assessment","Understand and demonstrate common attack techniques ethically","Implement firewalls, VPNs, and network security controls","Conduct web application security testing","Apply security incident response procedures","Prepare for industry certifications: CompTIA Security+ and CEH"],"requirements":["Basic networking knowledge (IP addresses, DNS, HTTP) is helpful but not required","Computer with at least 8GB RAM to run virtual machines","Strong ethical commitment, this course is for defensive and educational purposes only"],"about":["Cybercrime costs African businesses over $3.5 billion annually, and the demand for cybersecurity professionals far exceeds supply across the continent. This course prepares you to fill that gap with practical, hands-on security skills.","Using a learn-by-doing approach with real tools (Kali Linux, Nmap, Wireshark, Metasploit), you will understand how attacks work so you can prevent and detect them. Every technique is taught in controlled environments for ethical, defensive purposes.","This course is designed for IT professionals seeking security specialization, system administrators, developers wanting to build secure software, and anyone seriously considering a cybersecurity career. Our graduates work for banks, telcos, and government agencies across West Africa."],"modules":[{"title":"Module 1: Cybersecurity Fundamentals","icon":"🔒","meta":"4 lessons · 42 min","lessons":[{"t":"1.1 Cybersecurity Landscape: Threats, Actors & Attack Vectors","d":"11:00","v":"4lwiQ5hXwCo"},{"t":"1.2 Networking Fundamentals for Security: TCP/IP, DNS & Ports","d":"12:00","v":"ltBWJIhcjpA"},{"t":"1.3 Cryptography, Passwords & Authentication Security","d":"11:00","v":"kb_scuDUHls"},{"t":"📝 Quiz: Cybersecurity Fundamentals","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Network & System Security","icon":"🛡️","meta":"4 lessons · 46 min","lessons":[{"t":"2.1 Setting Up Kali Linux & Security Lab Environment","d":"12:00","v":"wX75Z-4MEoM"},{"t":"2.2 Network Scanning & Reconnaissance with Nmap","d":"12:00","v":"HPDgPg4aWqs"},{"t":"2.3 Firewalls, IDS/IPS & Network Defense Strategies","d":"12:30","v":"AwEZP2KQPJ8"},{"t":"📝 Quiz: Network Security","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Ethical Hacking & Penetration Testing","icon":"⚔️","meta":"4 lessons · 48 min","lessons":[{"t":"3.1 Ethical Hacking Methodology & Legal Framework","d":"11:00","v":"9DrnMjs5UVA"},{"t":"3.2 Vulnerability Assessment & Exploitation Basics","d":"13:00","v":"x43N_p0QGXU"},{"t":"3.3 Web Application Security: OWASP Top 10","d":"13:00","v":"Jzr0Jdnq_EI"},{"t":"🛠️ Project: Penetration Test Report on a Lab Environment","d":"Project","isProject":true}]},{"title":"Module 4: Incident Response & Career","icon":"🏆","meta":"4 lessons · 40 min","lessons":[{"t":"4.1 Security Incident Response & Digital Forensics Basics","d":"11:00","v":"Is2RcF0FJL4"},{"t":"4.2 Security Compliance: GDPR, ISO 27001 & African Data Laws","d":"10:00","v":"V7qVZD1z9pA"},{"t":"4.3 Cybersecurity Certifications & Career Pathways (CEH, Security+)","d":"9:30","v":"pOfCmL1YRIQ"},{"t":"📝 Quiz: Incident Response & Career","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Cloud, Mobile & Data Security in Practice","icon":"☁️","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Cloud Security Fundamentals & the Shared Responsibility Model","d":"Video + notes","v":"Qt9lhzFhW_c"},{"t":"5.2 Mobile & Mobile Money Security","d":"Video + notes","v":"4PJPWC8qWG0"},{"t":"5.3 Data Protection, Backups & Business Continuity","d":"Video + notes","v":"cEb79PGWCL8"},{"t":"📝 Quiz: Cloud, Mobile & Data Security","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Building a Professional Security Practice & Career","icon":"🎯","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Security Frameworks, Risk Management & Threat Modeling","d":"Video + notes","v":"rEnJYNkUde0"},{"t":"6.2 Building Your Home Lab, Certifications & Cybersecurity Career","d":"Video + notes","v":"v7BNtpw53AA"},{"t":"6.3 Capstone Project: End-to-End Security Assessment & Professional Report","d":"Video + notes","v":"3Kq1MIfTWCE"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Cybersecurity Fundamentals","moduleNum":1,"unlocks":3,"questions":[{"q":"What is a \"threat actor\" in cybersecurity?","opts":["A security software company","An individual or group that carries out malicious cyber activities","A cybersecurity certification","A network monitoring tool"],"correct":1,"exp":"Threat actors range from individual hackers to organized crime groups and state-sponsored attackers."},{"q":"What is phishing?","opts":["A type of network protocol","Fraudulent communications that trick victims into revealing sensitive information","A firewall configuration technique","A type of encryption"],"correct":1,"exp":"Phishing uses deceptive emails or messages to steal credentials, financial data, or install malware."},{"q":"Encryption is used to:","opts":["Speed up data transfer","Convert readable data into an unreadable format to protect it","Compress files","Delete sensitive data"],"correct":1,"exp":"Encryption converts plaintext into ciphertext, making data unreadable without the decryption key."},{"q":"Two-Factor Authentication (2FA) adds security by:","opts":["Requiring two passwords","Requiring a second verification method beyond your password","Encrypting your password","Logging all login attempts"],"correct":1,"exp":"2FA combines something you know (password) with something you have (phone code) or are (biometrics)."},{"q":"A VPN primarily does what?","opts":["Speeds up your internet","Blocks all ads","Encrypts your internet connection and hides your IP address","Provides free cloud storage"],"correct":2,"exp":"A VPN creates an encrypted tunnel for your internet traffic, protecting privacy especially on public Wi-Fi."},{"q":"The CIA triad in cybersecurity stands for:","opts":["Central Intelligence Access","Confidentiality, Integrity, and Availability","Control, Isolation, and Authentication","Cryptography, Internet, and Access"],"correct":1,"exp":"The CIA triad, Confidentiality, Integrity, and Availability, is the foundational model for evaluating security controls."},{"q":"Malware that encrypts a victim's files and demands payment to restore them is called:","opts":["Adware","Ransomware","A rootkit","A keylogger"],"correct":1,"exp":"Ransomware locks or encrypts data and demands payment, and it has hit banks and hospitals across West Africa."},{"q":"Social engineering attacks succeed primarily by:","opts":["Breaking strong encryption keys","Manipulating people into breaking security procedures","Overloading network hardware","Exploiting outdated firewalls only"],"correct":1,"exp":"Social engineering targets human psychology, trust, fear, urgency, rather than technical flaws."},{"q":"Hashing a password before storing it is important because:","opts":["It makes the password load faster","It stores a one-way value so the original password is not kept in plain text","It encrypts the whole hard drive","It shares the password with administrators"],"correct":1,"exp":"Hashing stores an irreversible fingerprint of the password, so a database breach does not directly expose the passwords."},{"q":"In the TCP/IP model, which port is used by default for secure HTTPS web traffic?","opts":["Port 21","Port 25","Port 443","Port 3389"],"correct":2,"exp":"HTTPS uses port 443 by default; knowing common ports is essential for scanning and firewall configuration."}]},"mod2":{"title":"Quiz: Network Security","moduleNum":2,"unlocks":3,"questions":[{"q":"What does Nmap do?","opts":["Creates network diagrams","Scans networks to discover hosts, open ports, and services","Encrypts network traffic","Blocks malicious websites"],"correct":1,"exp":"Nmap is a network exploration tool that discovers devices and services on a network."},{"q":"A firewall primarily works by:","opts":["Scanning for viruses","Monitoring and controlling network traffic based on security rules","Encrypting all data","Backing up data automatically"],"correct":1,"exp":"Firewalls filter network traffic using rules to allow legitimate traffic and block threats."},{"q":"What is a DMZ in networking?","opts":["A dangerous military zone","A subnet that exposes internet-facing services while protecting the internal network","A type of encryption","A wireless security protocol"],"correct":1,"exp":"A DMZ (Demilitarized Zone) isolates public-facing servers from the secure internal network."},{"q":"What does IDS stand for?","opts":["Internet Data Service","Intrusion Detection System","Integrated Defense Software","Internet Domain Security"],"correct":1,"exp":"An IDS monitors network or system activities for malicious behavior and policy violations."},{"q":"What is the purpose of penetration testing?","opts":["To destroy a competitor's system","To find and fix security vulnerabilities before attackers exploit them","To test internet speed","To monitor employee activity"],"correct":1,"exp":"Pen testing simulates real attacks to identify vulnerabilities so they can be remediated proactively."},{"q":"In an Nmap scan, a port reported as 'open' means:","opts":["The port is blocked by a firewall","An application is actively listening and accepting connections on that port","The host is completely offline","The port has been permanently disabled"],"correct":1,"exp":"An open port indicates a listening service, which is a potential entry point that should be reviewed and secured."},{"q":"The difference between an IDS and an IPS is that:","opts":["An IDS only detects and alerts, while an IPS can actively block malicious traffic","An IPS is older technology","An IDS encrypts traffic and an IPS decrypts it","There is no functional difference"],"correct":0,"exp":"An IDS detects and alerts on threats; an IPS sits inline and can automatically block them."},{"q":"Network segmentation improves security by:","opts":["Making the network faster only","Dividing a network into zones so a breach in one area cannot easily spread to others","Removing all firewalls","Giving every device the same access rights"],"correct":1,"exp":"Segmentation limits lateral movement, containing attackers within one segment rather than the whole network."},{"q":"Wireshark is primarily used to:","opts":["Encrypt hard drives","Capture and analyze network packets in detail","Manage user passwords","Design network cables"],"correct":1,"exp":"Wireshark captures live traffic so analysts can inspect packets, troubleshoot, and detect suspicious activity."},{"q":"The principle of 'least privilege' means:","opts":["Giving all users administrator rights for convenience","Granting each user or process only the access needed to do its job","Removing all user accounts","Allowing access only during business hours"],"correct":1,"exp":"Least privilege minimizes the damage an attacker or mistake can cause by restricting unnecessary access."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"The OWASP Top 10 refers to:","opts":["The top 10 cybersecurity companies","The top 10 most critical web application security risks","The top 10 hacking tools","The top 10 security certifications"],"correct":1,"exp":"OWASP Top 10 is the authoritative list of the most critical security vulnerabilities in web applications."},{"q":"SQL Injection is:","opts":["Adding SQL data to a spreadsheet","An attack injecting malicious SQL code into a database query to manipulate or steal data","A type of database backup","A SQL optimization technique"],"correct":1,"exp":"SQL injection exploits insufficient input validation to manipulate database queries and steal data."},{"q":"What is digital forensics?","opts":["Designing digital artwork","The process of recovering and analyzing digital evidence for legal proceedings","Deleting digital records","Creating database backups"],"correct":1,"exp":"Digital forensics involves collecting, preserving, and analyzing digital evidence in support of investigations."},{"q":"ISO 27001 is:","opts":["A type of firewall","An international standard for information security management systems","A hacking tool","A type of network protocol"],"correct":1,"exp":"ISO 27001 specifies requirements for establishing and maintaining an information security management system."},{"q":"A \"zero-day vulnerability\" is:","opts":["A vulnerability that is zero risk","A security flaw unknown to the vendor and with no available patch","A vulnerability patched on day zero","A network configuration error"],"correct":1,"exp":"Zero-days are especially dangerous because no patch exists, attackers can exploit them freely until disclosed."},{"q":"The CIA triad's three components are:","opts":["Control, Investigation, Authorization","Confidentiality, Integrity, and Availability","Cryptography, Internet, Access","Certification, Intrusion, Analysis"],"correct":1,"exp":"Confidentiality, Integrity, and Availability form the core objectives every security control aims to uphold."},{"q":"Which attack manipulates people rather than exploiting software?","opts":["SQL injection","Social engineering","Buffer overflow","Port scanning"],"correct":1,"exp":"Social engineering, including phishing and smishing, targets human trust and behavior instead of technical flaws."},{"q":"In an Nmap scan, an 'open' port indicates:","opts":["A service is listening and accepting connections","The host is offline","The port is blocked","Encryption has failed"],"correct":0,"exp":"Open ports reveal listening services that represent potential entry points to assess and secure."},{"q":"The principle of least privilege states that:","opts":["Everyone should be an administrator","Each user or process should have only the access it needs","Passwords should be shared","Access should never expire"],"correct":1,"exp":"Least privilege limits the potential damage from compromised accounts or mistakes by minimizing access."},{"q":"The OWASP Top 10 is:","opts":["A list of the ten best antivirus programs","A list of the most critical web application security risks","The ten fastest networks","A certification exam"],"correct":1,"exp":"The OWASP Top 10 catalogs the most critical web app vulnerabilities, such as injection and broken access control."},{"q":"In the cloud shared responsibility model, misconfigured public storage buckets are:","opts":["Always the provider's fault","The customer's responsibility and a common breach cause","Impossible to exploit","A provider feature, not a risk"],"correct":1,"exp":"Configuring storage access is the customer's job, and leaving buckets public is a frequent breach cause."},{"q":"SIM swap fraud primarily threatens:","opts":["Printed documents","Mobile money and accounts protected by SMS one-time passwords","Wired desktop networks only","Physical door locks"],"correct":1,"exp":"By hijacking a phone number, attackers intercept OTPs to seize mobile money and banking accounts."},{"q":"The 3-2-1 backup rule is designed mainly to protect against:","opts":["Slow internet","Data loss from disasters and ransomware","Weak passwords","Software licensing costs"],"correct":1,"exp":"Multiple copies, on different media, with an offsite or offline copy, ensure recovery even after ransomware or disaster."},{"q":"During incident response, the containment phase aims to:","opts":["Assign blame","Stop the incident from spreading and limit damage","Publish the breach online","Delete all evidence"],"correct":1,"exp":"Containment isolates affected systems to prevent an attack from expanding while the team investigates."},{"q":"Risk is best expressed as a combination of:","opts":["Speed and cost","Likelihood and impact","Users and passwords","Ports and protocols"],"correct":1,"exp":"Risk = Likelihood x Impact lets professionals prioritize the threats that matter most to the business."},{"q":"The NIST Cybersecurity Framework organizes security into which five functions?","opts":["Identify, Protect, Detect, Respond, Recover","Scan, Attack, Defend, Report, Repeat","Plan, Build, Test, Ship, Monitor","Encrypt, Backup, Delete, Restore, Audit"],"correct":0,"exp":"The NIST CSF's five functions, Identify, Protect, Detect, Respond, Recover, structure a complete security program."},{"q":"Maintaining chain of custody in digital forensics ensures that:","opts":["Evidence remains admissible and its handling is documented","Evidence is deleted quickly","Only one tool is used","Data is made public"],"correct":0,"exp":"Documenting who handled evidence and when preserves integrity so it holds up in legal proceedings."},{"q":"Why should penetration testers work only on systems they own or have written permission to test?","opts":["It is faster","Unauthorized testing is illegal and unethical","Tools require it technically","It uses less bandwidth"],"correct":1,"exp":"Testing without explicit authorization is a crime; ethics and permission are the foundation of the profession."},{"q":"A SOC analyst's core daily responsibility is to:","opts":["Write marketing copy","Monitor alerts and logs to detect and respond to threats","Repair printers","Manage payroll"],"correct":1,"exp":"SOC analysts provide real-time monitoring and response, a common and valuable entry point into security careers."},{"q":"The most important deliverable of a professional penetration test is:","opts":["A screenshot of a terminal","A structured report with prioritized findings, evidence, and remediation recommendations","A list of tools installed","A social media post"],"correct":1,"exp":"The report translates technical findings into prioritized, actionable guidance, that is what clients pay for."}]},"mod4":{"title":"Quiz: Incident Response & Career","moduleNum":4,"questions":[{"q":"The correct order of the main incident response phases is:","opts":["Recovery, Detection, Preparation, Containment","Preparation, Detection & Analysis, Containment, Eradication & Recovery, Lessons Learned","Containment, Preparation, Lessons Learned, Detection","Detection, Recovery, Preparation, Containment"],"correct":1,"exp":"The standard lifecycle runs Preparation, Detection and Analysis, Containment, Eradication and Recovery, then Lessons Learned."},{"q":"In digital forensics, maintaining 'chain of custody' means:","opts":["Encrypting all evidence permanently","Documenting who handled evidence, when, and how, to keep it admissible","Deleting evidence after analysis","Sharing evidence publicly online"],"correct":1,"exp":"Chain of custody records preserve evidence integrity so it can stand up in legal proceedings."},{"q":"The primary goal of the 'containment' phase is to:","opts":["Identify who to blame","Stop the incident from spreading and limit further damage","Immediately delete all logs","Notify the media"],"correct":1,"exp":"Containment isolates affected systems to prevent an attack from expanding while investigation continues."},{"q":"Why should forensic analysts work on a copy (image) of a disk rather than the original?","opts":["Copies are faster to search","To preserve the original evidence unaltered and maintain its integrity","Originals cannot be read by tools","Copies use less storage"],"correct":1,"exp":"Working on a verified image protects the original evidence from accidental modification, keeping it legally sound."},{"q":"Under many data protection laws, including the GDPR, organizations must:","opts":["Ignore breaches under a certain size","Notify authorities of qualifying data breaches within a defined timeframe","Store all data indefinitely","Never encrypt personal data"],"correct":1,"exp":"GDPR requires notifying the supervisory authority of qualifying breaches, generally within 72 hours."},{"q":"ISO 27001 helps an organization by providing:","opts":["A single antivirus program","A framework for an Information Security Management System (ISMS)","Free penetration testing tools","A list of hackers to avoid"],"correct":1,"exp":"ISO 27001 defines requirements for establishing, operating, and improving an ISMS across an organization."},{"q":"A SOC (Security Operations Center) analyst primarily:","opts":["Designs marketing campaigns","Monitors, detects, and responds to security events in real time","Writes company payroll","Installs office furniture"],"correct":1,"exp":"SOC analysts watch alerts and logs to detect and respond to threats as they happen, a common entry-level security role."},{"q":"The CompTIA Security+ certification is best described as:","opts":["An advanced management-only certification","A vendor-neutral, entry-level certification covering core security concepts","A programming language certification","A hardware repair certification"],"correct":1,"exp":"Security+ validates foundational security knowledge and is a common first certification for security careers."},{"q":"A SIEM tool is used to:","opts":["Collect, correlate, and analyze log data from across an organization to detect threats","Physically lock server rooms","Replace all firewalls","Design company logos"],"correct":0,"exp":"A SIEM aggregates and correlates logs, giving analysts centralized visibility to spot attacks quickly."},{"q":"The most important first step when you discover an active security incident is to:","opts":["Turn off all computers immediately without notes","Follow the incident response plan and begin documenting everything","Post about it on social media","Ignore it until the next business day"],"correct":1,"exp":"Following a prepared plan and documenting actions ensures a calm, effective, and legally defensible response."}]},"mod5":{"title":"Quiz: Cloud, Mobile & Data Security","moduleNum":5,"questions":[{"q":"Under the cloud shared responsibility model, the customer is generally responsible for:","opts":["The physical security of the data centers","Securing their data, user accounts, and access configurations","Maintaining the provider's server hardware","Cooling the data center"],"correct":1,"exp":"Providers secure the infrastructure, while customers must secure their own data, identities, and configurations."},{"q":"A very common cause of cloud data breaches is:","opts":["The cloud provider's hardware failing","Misconfigured storage buckets left publicly accessible","Too much encryption","Using multi-factor authentication"],"correct":1,"exp":"Publicly exposed storage and other misconfigurations by the customer cause many high-profile cloud breaches."},{"q":"In cloud environments, identity and access management (IAM) is important because:","opts":["Identity has become the primary security perimeter","It makes servers run faster","It replaces the need for backups","It designs the user interface"],"correct":0,"exp":"With resources accessible over the internet, controlling who can access what is the central cloud security challenge."},{"q":"SIM swap fraud works by:","opts":["Encrypting the victim's phone","Transferring a victim's phone number to an attacker's SIM to intercept one-time passwords","Installing antivirus software","Speeding up mobile data"],"correct":1,"exp":"By hijacking the phone number, attackers receive OTPs and can take over banking and mobile money accounts."},{"q":"'Smishing' refers to:","opts":["Phishing carried out through SMS or messaging apps","A type of encryption","A firewall rule","A backup strategy"],"correct":0,"exp":"Smishing is phishing via text or WhatsApp, often impersonating a bank or mobile money service to steal PINs."},{"q":"A key rule for protecting a mobile money account is to:","opts":["Share your PIN with the telecom agent for safety","Never share your PIN or one-time password with anyone","Turn off transaction alerts","Use the same PIN as your friends"],"correct":1,"exp":"PINs and OTPs must stay private; legitimate providers never ask you to reveal them."},{"q":"The 3-2-1 backup rule recommends:","opts":["3 passwords, 2 firewalls, 1 antivirus","3 copies of data, on 2 media types, with 1 copy offsite or offline","Backing up 3 times per day only","Keeping 3 users and 2 admins"],"correct":1,"exp":"The 3-2-1 rule ensures redundancy and an offsite or offline copy that ransomware cannot reach."},{"q":"Why is an offline or immutable backup especially valuable against ransomware?","opts":["It is cheaper than online storage","Ransomware that spreads through the network cannot encrypt a disconnected or unchangeable copy","It loads faster","It requires no testing"],"correct":1,"exp":"An air-gapped or immutable backup stays safe even if ransomware compromises connected systems."},{"q":"Data classification helps an organization by:","opts":["Deleting all old data","Identifying which data is sensitive so protection can be prioritized","Making all data public","Encrypting only public brochures"],"correct":1,"exp":"Classification lets you apply the strongest controls to the most sensitive data instead of treating everything the same."},{"q":"The Recovery Time Objective (RTO) defines:","opts":["How much data you can afford to lose","How quickly systems must be restored after a disruption","The number of backups to keep","The encryption strength required"],"correct":1,"exp":"RTO sets the target time to restore operations, while RPO sets how much recent data loss is acceptable."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Emmanuel Duo is a world-class instructor. The hands-on lab environment made learning to hack (ethically!) completely safe and practical. I passed my CompTIA Security+ exam 2 weeks after finishing this course."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"This course opened my eyes to how vulnerable most systems are. I immediately applied the knowledge to harden my company's network. The OWASP module was particularly revelatory. Excellent investment for any IT professional."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":4,"text":"Comprehensive and well-structured. The penetration testing project was challenging and rewarding. I now consult for small businesses on cybersecurity. The certificate carries real weight with Liberian organizations taking security seriously."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":5,"text":"Best cybersecurity training available in West Africa. Emmanuel teaches with real-world examples that make concepts stick. The course prepared me thoroughly for my CEH certification. Highly recommended for anyone in IT."}],"faqs":[{"q":"Is this course legal and ethical?","a":"Yes. All techniques are taught in controlled lab environments for defensive and educational purposes. We emphasize ethics and legal compliance throughout, and require students to agree to an ethical use pledge."},{"q":"What certifications can this help me prepare for?","a":"This course prepares you for CompTIA Security+, CEH (Certified Ethical Hacker), and provides a foundation for CISSP. We recommend these certifications to complement your TIH certificate."},{"q":"Do I need cybersecurity experience?","a":"Basic networking knowledge is helpful but not required. We provide a networking primer in Module 1. IT professionals and developers will advance faster, but beginners can succeed with dedication."},{"q":"What careers does cybersecurity lead to?","a":"Security Analyst, Penetration Tester, SOC Analyst, Security Engineer, and CISO are all in high demand across Africa. Average salaries are significantly above general IT roles."}]};
COURSES_DB['entrepreneurship'] = {"id":"entrepreneurship","title":"Entrepreneurship & Startup Launch Program","shortDesc":"For first-time and experienced entrepreneurs, validate your idea, write a fundable business plan, access grants and investors, and register and launch your business in Liberia.","category":"Entrepreneurship","icon":"💡","gradient":"linear-gradient(135deg,#92400e,#f59e0b)","instructor":"Thomas Bility","instructorTitle":"Serial Entrepreneur & Startup Mentor","instructorBio":"Thomas Bility has founded 4 businesses in Liberia and trained entrepreneurs across West Africa for over 15 years. He has helped secure over $2M in funding for Liberian startups and is a regular advisor at startup competitions regionally.","rating":4.8,"reviewCount":598,"students":"2,400+","duration":"30h","level":"All Levels","price":"FREE","origPrice":"$150","isFree":true,"badge":"free","certId":"TIH-2026-EP-0083","learn":["Validate business ideas quickly and cheaply before investing resources","Develop a comprehensive business plan and model canvas","Conduct market research and competitive analysis in the African market","Build financial projections and understand startup financial statements","Identify and access funding sources: grants, loans, investors, and bootstrapping","Register your business and understand legal structures in Liberia","Build and pitch your business to investors and partners","Implement growth strategies to scale your business sustainably"],"requirements":["No prior business experience needed, we guide you from the very beginning","A business idea (or willingness to develop one during the course)","Commitment to completing the business plan project in each module"],"about":["Liberia and West Africa are full of entrepreneurial opportunity, but most business ideas never become businesses because founders lack the knowledge and tools to take them from idea to execution. This course bridges that gap.","Drawing on real Liberian and African business case studies, this course takes you through every stage of the startup journey: idea validation, business modeling, legal setup, financial planning, fundraising, marketing, and scaling. No theory without action.","By the end of this program, you will have a complete, fundable business plan and the confidence to launch and grow your business. Thousands of graduates have used this course to start businesses that now employ people and contribute to Liberia's economy."],"modules":[{"title":"Module 1: Idea to Business Opportunity","icon":"💡","meta":"4 lessons · 38 min","lessons":[{"t":"1.1 Entrepreneurial Mindset & Opportunity Recognition","d":"9:00","v":"4hshq-o0vSI"},{"t":"1.2 Idea Validation: Testing Before You Invest","d":"10:30","v":"Th8JoIan4dg"},{"t":"1.3 Market Research & the African Consumer","d":"10:00","v":"KCEWgq8S9gM"},{"t":"📝 Quiz: Entrepreneurship Foundations","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Business Planning & Legal Setup","icon":"📋","meta":"4 lessons · 42 min","lessons":[{"t":"2.1 Business Model Canvas & Value Proposition","d":"11:00","v":"ReM1uqmVfP0"},{"t":"2.2 Writing a Compelling Business Plan","d":"12:00","v":"XK9XYa5-MCw"},{"t":"2.3 Legal Structures & Business Registration in Liberia","d":"11:00","v":"fj6zbwAXpzE"},{"t":"📝 Quiz: Business Planning & Models","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Funding & Financial Management","icon":"💰","meta":"4 lessons · 44 min","lessons":[{"t":"3.1 Startup Funding Options: Grants, Loans, Angels & VC","d":"11:30","v":"Cw58F0k8BDg"},{"t":"3.2 Financial Projections, Cash Flow & Break-Even Analysis","d":"12:00","v":"7Ljc6NoNg6M"},{"t":"3.3 Grant Writing & Investor Pitch Preparation","d":"11:30","v":"Tk-RdCFSrKU"},{"t":"🛠️ Project: Complete Business Plan & Pitch Deck","d":"Project","isProject":true}]},{"title":"Module 4: Launch, Growth & Scale","icon":"🏆","meta":"4 lessons · 38 min","lessons":[{"t":"4.1 Go-to-Market Strategy & First Customers","d":"10:00","v":"UWqzT95Lkno"},{"t":"4.2 Growth Hacking & Scaling Strategies for African Markets","d":"10:00","v":"8_6uU6KgexE"},{"t":"4.3 Building a Team & Leadership for Entrepreneurs","d":"9:00","v":"HL80lXafRL0"},{"t":"📝 Quiz: Launch, Growth & Scale","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Sales, Operations & Managing a Growing Business","icon":"⚙️","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Sales Skills & Building a Repeatable Sales Process","d":"Video + notes","v":"hZI83oKyDq0"},{"t":"5.2 Operations, Systems & Delivering Consistent Quality","d":"Video + notes","v":"hFJQjlMEcqk"},{"t":"5.3 Financial Management, Pricing & Managing People","d":"Video + notes","v":"Wzwpou8d7v4"},{"t":"📝 Quiz: Sales, Operations & Management","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Scaling to a Sustainable Enterprise","icon":"🌱","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Growth Strategy, Partnerships & Regional Expansion","d":"Video + notes","v":"4OO3MXzqNII"},{"t":"6.2 Building Resilience, Culture & Good Governance","d":"Video + notes","v":"9B-gyOi8CZs"},{"t":"6.3 Capstone Project: Your Enterprise Growth Plan & Investor-Ready Pitch","d":"Video + notes","v":"71TriLlszpU"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Entrepreneurship Foundations","moduleNum":1,"unlocks":3,"questions":[{"q":"What is \"idea validation\"?","opts":["Legally registering a business idea","Testing whether your business idea solves a real problem people will pay for","Writing a business plan","Registering a trademark"],"correct":1,"exp":"Validation tests your assumptions cheaply before spending significant time or money on an idea."},{"q":"A \"minimum viable product\" (MVP) is:","opts":["The most expensive version of your product","The smallest version of your product that allows you to test your core assumption","A government business license","Your final product"],"correct":1,"exp":"An MVP lets you gather real customer feedback with minimal investment before full development."},{"q":"Market research helps you understand:","opts":["Only your competitors","Your target customers, market size, competition, and opportunities","Only your product features","Your company's financial position"],"correct":1,"exp":"Market research reveals whether sufficient demand exists and how to position against competition."},{"q":"What is the \"value proposition\" of a business?","opts":["The monetary value of a company","The clear statement of how your product solves customer problems better than alternatives","Your pricing strategy","Your company mission statement"],"correct":1,"exp":"A strong value proposition clearly answers \"Why should customers choose you over every alternative?\""},{"q":"Bootstrapping a business means:","opts":["Starting with venture capital investment","Funding your business from your own savings and revenue without outside investors","Borrowing money from a bank","Crowdfunding from the public"],"correct":1,"exp":"Bootstrapping maintains full ownership and control but requires very careful financial management."},{"q":"A 'pain point' in entrepreneurship refers to:","opts":["The cost of registering a business","A specific problem or frustration that customers experience and will pay to solve","The difficulty of raising money","A physical injury from working"],"correct":1,"exp":"Strong businesses are built by solving real customer pain points people are willing to pay to remove."},{"q":"The best way to validate an idea before building it is to:","opts":["Spend your entire savings on inventory first","Talk to real potential customers about their problems and willingness to pay","Register a trademark immediately","Rent a large office"],"correct":1,"exp":"Direct customer conversations reveal real demand cheaply, long before you commit money to building."},{"q":"A 'problem worth solving' for a business is usually one that is:","opts":["Rare, minor, and occasional","Frequent, painful, and something people already try to solve","Only interesting to the founder","Impossible for anyone to fix"],"correct":1,"exp":"Frequent, painful problems that people already spend time or money on signal a viable market opportunity."},{"q":"When conducting market research for a product aimed at Monrovia market traders, the most reliable insight comes from:","opts":["Guessing based on your own preferences","Visiting the markets and interviewing traders directly","Copying a business plan from another country","Reading only global statistics"],"correct":1,"exp":"Primary research, observing and interviewing actual target customers, gives far more accurate insight than assumptions."},{"q":"An 'early adopter' is:","opts":["A customer who only buys well-established products","A customer willing to try a new product early despite it being imperfect","An investor who funds late-stage companies","A competitor who copies your idea"],"correct":1,"exp":"Early adopters give crucial feedback and first revenue, helping you refine the product before mass-market launch."}]},"mod2":{"title":"Quiz: Business Planning & Models","moduleNum":2,"unlocks":3,"questions":[{"q":"The Business Model Canvas was developed by:","opts":["Peter Drucker","Alex Osterwalder","Steve Jobs","Michael Porter"],"correct":1,"exp":"Alex Osterwalder created the Business Model Canvas as a strategic template for developing business models."},{"q":"A business plan's executive summary should be:","opts":["50+ pages long","A brief overview of the entire business plan (1-2 pages)","Only for investors","A list of all products"],"correct":1,"exp":"The executive summary is the first thing investors read, it must capture the essence concisely."},{"q":"What is a \"sole proprietorship\"?","opts":["A business with multiple owners","The simplest business structure owned and operated by one person","A government enterprise","A non-profit organization"],"correct":1,"exp":"Sole proprietorships are simplest to set up but offer no personal liability protection."},{"q":"A SWOT analysis examines:","opts":["Sales, Wages, Operations, Technology","Strengths, Weaknesses, Opportunities, Threats","Success, Work, Outcomes, Tactics","Strategy, Workforce, Objectives, Timeline"],"correct":1,"exp":"SWOT helps businesses understand internal capabilities and external market factors."},{"q":"What is \"cash flow\" in business?","opts":["Your bank account balance","The net amount of cash moving in and out of your business over a period","Your total revenue","Your profit margin"],"correct":1,"exp":"Positive cash flow, more coming in than going out, is essential for business survival."},{"q":"In the Business Model Canvas, 'revenue streams' describe:","opts":["The costs of running the business","How the business earns money from its customer segments","The employees on payroll","The office location"],"correct":1,"exp":"Revenue streams define how and from whom the business captures value, such as sales, subscriptions, or fees."},{"q":"A limited liability company (LLC) primarily protects owners by:","opts":["Guaranteeing the business will be profitable","Separating personal assets from business debts and liabilities","Removing the need to pay any taxes","Preventing all competition"],"correct":1,"exp":"An LLC creates a legal separation so owners' personal assets are generally shielded from business debts."},{"q":"In Liberia, formally registering your business is important because it:","opts":["Is only needed for foreign companies","Enables you to open a business bank account, access formal contracts, and qualify for many grants","Guarantees customers automatically","Removes the need for record keeping"],"correct":1,"exp":"Registration unlocks bank accounts, formal contracts, and eligibility for grants and government tenders."},{"q":"The 'key activities' block of the Business Model Canvas captures:","opts":["The most important things the business must do to make its model work","The company's holiday schedule","The founder's personal hobbies","The competitors' weaknesses"],"correct":0,"exp":"Key activities are the essential tasks, like production, service delivery, or a platform, that make the business function."},{"q":"A strong value proposition should focus on:","opts":["A long list of technical features","The specific benefit and problem solved for the customer","The founder's personal story only","The lowest possible price always"],"correct":1,"exp":"Customers buy outcomes; a value proposition should clearly state the benefit and the problem it solves for them."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Angel investors are:","opts":["Government grant providers","High-net-worth individuals who invest personal funds in early-stage startups","Bank loan officers","Family and friends who help the business"],"correct":1,"exp":"Angel investors typically invest $25K-$500K in early-stage companies in exchange for equity."},{"q":"Break-even analysis shows:","opts":["When your product will launch","The point at which revenue equals total costs and you start making profit","Your maximum possible revenue","Your competition's pricing"],"correct":1,"exp":"Break-even analysis shows how many units or what revenue level is needed to cover all costs."},{"q":"A \"go-to-market\" strategy defines:","opts":["Your company's office location","How you will reach your target customers and bring your product to market","Your product development roadmap","Your employee hiring plan"],"correct":1,"exp":"A go-to-market strategy covers target segments, distribution channels, pricing, and marketing."},{"q":"What is \"equity\" in startup funding?","opts":["A type of business loan","Ownership share in a company given to investors in exchange for capital","A government grant","A type of business license"],"correct":1,"exp":"Equity funding gives investors ownership stakes, unlike loans, it doesn't require repayment."},{"q":"Scaling a business means:","opts":["Reducing the business size","Growing revenue significantly without proportional increases in costs","Hiring more employees","Launching in a new location"],"correct":1,"exp":"True scaling grows revenue while keeping costs relatively fixed, dramatically increasing profitability."},{"q":"Idea validation is best done by:","opts":["Spending all your savings on stock first","Talking to real potential customers about their problems and willingness to pay","Registering a trademark","Renting a big office"],"correct":1,"exp":"Validation tests demand cheaply through customer conversations before committing significant time or money."},{"q":"A minimum viable product (MVP) is:","opts":["The most expensive version of a product","The simplest version that tests your core assumption with real customers","A finished, polished product","A government license"],"correct":1,"exp":"An MVP gathers real feedback with minimal investment before building the full product."},{"q":"A strong value proposition primarily communicates:","opts":["A long list of features","The specific benefit and problem solved for the customer","The founder's biography","The cheapest possible price"],"correct":1,"exp":"Customers buy outcomes, so the value proposition must state the benefit and problem it solves."},{"q":"Registering a business formally in Liberia helps because it:","opts":["Guarantees customers","Enables a business bank account, formal contracts, and grant eligibility","Removes all taxes","Prevents competition"],"correct":1,"exp":"Formal registration unlocks banking, contracts, and access to grants and tenders."},{"q":"Why is cash flow watched more closely than profit alone?","opts":["Profit does not matter","A profitable business can still fail if it runs out of cash before customers pay","Cash flow is easier to ignore","They are exactly the same thing"],"correct":1,"exp":"Bills are paid with cash on hand, so a cash shortfall can sink even a profitable business."},{"q":"Break-even analysis tells a founder:","opts":["The company's brand color","The revenue or unit level needed to cover all costs before earning profit","The number of employees to hire","The best office location"],"correct":1,"exp":"Break-even shows the point where revenue equals total costs, a key figure for planning and pricing."},{"q":"Equity funding differs from a loan in that equity:","opts":["Must be repaid with interest on a schedule","Gives investors an ownership share and does not require repayment","Is only available from banks","Is a type of grant"],"correct":1,"exp":"Equity exchanges ownership for capital and, unlike a loan, carries no repayment obligation."},{"q":"A consultative sales approach means:","opts":["Talking non-stop about your product","Asking questions to understand the customer's need, then showing how you solve it","Pressuring an immediate decision","Only ever offering the lowest price"],"correct":1,"exp":"Understanding the customer's real need first builds trust and leads to more sales in relationship-driven markets."},{"q":"Standard Operating Procedures (SOPs) mainly help a growing business by:","opts":["Making quality depend on one person","Documenting repeatable steps so quality stays consistent and staff train quickly","Raising prices automatically","Eliminating customers"],"correct":1,"exp":"SOPs keep service consistent and speed up training as the business grows beyond the founder."},{"q":"Value-based pricing sets prices according to:","opts":["Only material costs","The benefit and outcome delivered to the customer","The cheapest rival's price","A random figure"],"correct":1,"exp":"Value-based pricing captures how much the outcome is worth to customers, protecting healthy margins."},{"q":"The golden rule of scaling is to:","opts":["Push maximum volume immediately","Strengthen systems, cash, and team before increasing volume","Avoid all partnerships","Never reinvest profit"],"correct":1,"exp":"Scaling multiplies whatever exists, so weak systems must be fixed before growth amplifies the chaos."},{"q":"The safest source of capital to fund growth is usually:","opts":["High-interest debt","Reinvested profit from the business","Selling all your equity at once","Ignoring funding entirely"],"correct":1,"exp":"Reinvested profit funds growth without debt or dilution, making it the lowest-risk source when available."},{"q":"Building a strong company culture matters because it:","opts":["Is irrelevant to small businesses","Sets the shared values and standards that guide the team when the founder is absent","Only applies to foreign companies","Replaces the need for products"],"correct":1,"exp":"Culture acts as the business's operating system, preserving quality and integrity as the team grows."},{"q":"A business that cannot run without the founder is:","opts":["Ideal and highly valuable","Fragile and hard to sell, so processes should be documented and authority delegated","Guaranteed to scale easily","Immune to crises"],"correct":1,"exp":"Reducing founder dependence through documented systems and delegation makes a business resilient and sellable."},{"q":"In a capstone growth plan's funding ask, an investor most wants to see:","opts":["A vague request for 'as much as possible'","Exactly how much is needed, what it will buy, and the return it will generate","Only the founder's personal story","A promise of guaranteed riches"],"correct":1,"exp":"A specific, outcome-linked funding ask shows the founder understands the numbers and can turn capital into returns."}]},"mod4":{"title":"Quiz: Launch, Growth & Scale","moduleNum":4,"questions":[{"q":"A go-to-market strategy defines:","opts":["Only the price of your product","How you will reach target customers and deliver your product to market","The office building you will rent","Your personal salary"],"correct":1,"exp":"A go-to-market strategy covers target segments, channels, pricing, and messaging to acquire first customers."},{"q":"Customer acquisition cost (CAC) measures:","opts":["The price a customer pays","The average amount you spend to gain one new customer","The cost of your inventory","Your total revenue"],"correct":1,"exp":"CAC tells you what each new customer costs to acquire, which must stay below what that customer is worth."},{"q":"'Product-market fit' means:","opts":["Your product has the nicest packaging","Your product satisfies a strong market demand, shown by customers buying and returning","Your product is cheaper than all rivals","You have registered your business"],"correct":1,"exp":"Product-market fit is the point where a product clearly meets real demand, evidenced by traction and repeat use."},{"q":"Word-of-mouth referrals are especially valuable in Liberian markets because:","opts":["They are expensive to generate","Personal trust strongly influences buying decisions, making recommendations powerful and low-cost","They only work for large companies","They require paid advertising"],"correct":1,"exp":"In trust-driven markets, a satisfied customer's recommendation converts new buyers cheaply and effectively."},{"q":"Customer lifetime value (CLV) represents:","opts":["The total revenue a customer generates over their entire relationship with your business","The cost of one product","A one-time purchase only","Your monthly rent"],"correct":0,"exp":"CLV captures the full value of a customer over time, guiding how much you can invest to acquire and keep them."},{"q":"The difference between growth and true scaling is that scaling:","opts":["Always requires hiring hundreds of staff","Grows revenue significantly without a proportional increase in costs","Means reducing your customer base","Is only about opening new shops"],"correct":1,"exp":"Scaling increases revenue while keeping costs relatively fixed, sharply improving profitability."},{"q":"A pilot or soft launch before a full launch helps a founder to:","opts":["Avoid ever getting feedback","Test the offer with a small group and fix problems before scaling up","Spend the entire marketing budget at once","Skip talking to customers"],"correct":1,"exp":"A soft launch surfaces real-world problems on a small scale so they can be fixed before a costly full rollout."},{"q":"When building a first team, an entrepreneur should prioritize:","opts":["Hiring friends regardless of skill","Hiring for the roles most critical to delivering value, with clear responsibilities","Hiring as many people as possible immediately","Never delegating any task"],"correct":1,"exp":"Early hires should fill the most business-critical gaps with clear roles, since each hire is costly and impactful."},{"q":"A common reason startups fail during growth is:","opts":["Growing too slowly and carefully","Scaling before achieving product-market fit or before systems can support the growth","Listening too much to customers","Keeping costs too low"],"correct":1,"exp":"Scaling prematurely amplifies unsolved problems and burns cash before the business is truly ready to grow."},{"q":"For an African market startup, a growth channel that is often low-cost and highly effective is:","opts":["Expensive television advertising only","WhatsApp, referrals, and community networks","International print magazines","Billboards in other countries"],"correct":1,"exp":"Messaging apps, referrals, and community networks reach customers where they already are at very low cost."}]},"mod5":{"title":"Quiz: Sales, Operations & Management","moduleNum":5,"questions":[{"q":"The most effective approach to selling in relationship-driven markets is to:","opts":["Talk continuously about your product features","Ask questions, listen to the customer's real need, and show how you solve it","Pressure the customer to decide immediately","Offer the lowest price and nothing else"],"correct":1,"exp":"Consultative selling, understanding the customer's need first, builds the trust that closes sales in West African markets."},{"q":"A sales pipeline helps an entrepreneur by:","opts":["Guaranteeing every lead will buy","Tracking prospects through stages so follow-up becomes systematic","Removing the need to talk to customers","Setting the product's price"],"correct":1,"exp":"A pipeline turns selling into a trackable process, ensuring follow-up rather than relying on memory or luck."},{"q":"Most sales are won by:","opts":["Giving up after one contact","Following up consistently, since many buyers say yes only after several contacts","Never mentioning price","Avoiding objections entirely"],"correct":1,"exp":"Persistence in polite follow-up is where most sales are made, yet many sellers quit after a single attempt."},{"q":"When a customer says 'it's too expensive', the best response is to:","opts":["Immediately give up","Restate the value in the customer's terms and offer proof or options","Insult the customer","Raise the price further"],"correct":1,"exp":"Price objections usually signal unclear value, so reframing benefits and offering proof addresses the real concern."},{"q":"Standard Operating Procedures (SOPs) are valuable because they:","opts":["Make quality depend on one person","Document repeatable steps so quality stays consistent and training is fast","Increase prices automatically","Replace the need for customers"],"correct":1,"exp":"SOPs capture how tasks should be done, keeping quality consistent and making it easy to train new staff."},{"q":"Separating business and personal money is important because it:","opts":["Is required only for large corporations","Lets you accurately track business performance and profit","Makes the business look bigger","Removes the need to record sales"],"correct":1,"exp":"Separate accounts reveal the business's true financial health and prevent personal spending from hiding losses."},{"q":"Why can a profitable business still fail?","opts":["Because profit is unimportant","If it runs out of cash before customers pay, poor cash flow can sink it","Because it has too many customers","Because it keeps records"],"correct":1,"exp":"Profit on paper does not pay bills today; cash flow problems can bankrupt an otherwise profitable business."},{"q":"A key danger of competing only on being the cheapest is that:","opts":["Customers will always be loyal","Someone can always undercut you, and thin margins starve the business","It guarantees high profit","It removes the need for quality"],"correct":1,"exp":"A race to the bottom on price destroys margins and leaves no room to reinvest or survive shocks."},{"q":"Value-based pricing sets the price according to:","opts":["Only the cost of materials","The benefit and outcome the product delivers to the customer","The cheapest competitor's price","A random guess"],"correct":1,"exp":"Value-based pricing captures how much the solution is worth to the customer, often allowing healthier margins."},{"q":"A good leadership habit when managing early employees is to:","opts":["Keep all expectations unspoken","Set clear written responsibilities, pay fairly and on time, and give specific feedback","Never delegate any task","Praise privately and criticize publicly"],"correct":1,"exp":"Clear expectations, fair timely pay, and constructive feedback build a trusted, productive early team."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Thomas Bility brings real Liberian business experience to every lesson. After this course I registered my business, secured a $15,000 grant, and now employ 8 people. The business plan project was the foundation for everything."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"I had been sitting on my business idea for 3 years. This course gave me the tools, confidence, and roadmap to finally launch. Six months later my business is profitable. The funding module opened doors I didn't know existed."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"The most practical entrepreneurship training I have ever seen. Thomas doesn't teach from textbooks, he teaches from real Liberian business experience. The pitch deck project prepared me perfectly for investor meetings."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Excellent course structure. The MVP validation approach saved me from investing in a business idea that wouldn't have worked. The market research tools are invaluable for anyone starting a business in rural Liberia."}],"faqs":[{"q":"Do I need money to start a business before taking this course?","a":"No. One of the core lessons is how to validate and start a business with minimal capital. Many successful Liberian businesses started with under $500."},{"q":"Will this help me access grants?","a":"Yes. The grant writing module specifically covers major grants available to Liberian entrepreneurs including USAID, World Bank, and Tony Elumelu Foundation programs."},{"q":"Is this course for people with no business experience?","a":"This course is designed for everyone from first-time entrepreneurs to experienced business owners wanting to scale. The content is structured to benefit all levels."},{"q":"How practical is this course?","a":"Every module includes a hands-on project. By course end you will have a complete business plan, financial projections, pitch deck, and go-to-market strategy, ready for execution."}]};
COURSES_DB['project-mgmt'] = {"id":"project-mgmt","title":"Project Management Professional Certificate","shortDesc":"For professionals in any sector, learn PMBOK and Agile frameworks, build Gantt charts and risk registers, lead project teams, and prepare for the globally recognized PMP certification examination.","category":"Project Management","icon":"📋","gradient":"linear-gradient(135deg,#064e3b,#047857)","instructor":"Dr. Mary Weah","instructorTitle":"Certified PMP & Organizational Strategy Consultant","instructorBio":"Dr. Mary Weah holds PMP and PRINCE2 certifications with 18 years managing large-scale projects for UN agencies, World Bank programs, and Liberian government ministries. She is TIH's Business & Management curriculum lead.","rating":4.9,"reviewCount":478,"students":"3,200+","duration":"32h","level":"All Levels","price":"FREE","origPrice":"$200","isFree":true,"badge":"free","certId":"TIH-2026-PM-0127","learn":["Understand the 5 project management process groups and 10 knowledge areas","Create project charters, scope statements, and work breakdown structures","Build project schedules using Gantt charts and critical path method","Develop and manage project budgets and cost controls","Identify, assess, and manage project risks proactively","Lead project teams and manage stakeholder communication","Apply Agile and Scrum frameworks for flexible project delivery","Prepare effectively for the PMP certification examination"],"requirements":["No prior project management experience needed","Basic computer and email communication skills","Professional work experience (any field) is helpful but not required"],"about":["Every organization, businesses, NGOs, government agencies, and international development organizations, needs people who can successfully manage projects. Project management is one of the most transferable and universally valued professional skills.","This course combines the traditional PMBOK framework used in PMP certification preparation with Agile/Scrum methodologies increasingly demanded by modern organizations. Both are taught with real African project examples: infrastructure, health programs, NGO initiatives, and business projects.","Graduates have passed PMP exams, secured project manager roles at major organizations including UN agencies and World Bank-funded programs, and successfully delivered multimillion-dollar projects in Liberia and across Africa."],"modules":[{"title":"Module 1: PM Fundamentals & Project Initiation","icon":"📋","meta":"4 lessons · 40 min","lessons":[{"t":"1.1 What is Project Management? Processes & Knowledge Areas","d":"10:30","v":"iopMMoHstJM"},{"t":"1.2 Project Charter & Stakeholder Identification","d":"10:30","v":"SPj-Luod9tI"},{"t":"1.3 Scope Management: WBS & Requirements","d":"11:00","v":"PyR2VLP3xnA"},{"t":"📝 Quiz: PM Fundamentals & Initiation","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Planning, Schedule, Budget & Risk","icon":"📅","meta":"4 lessons · 46 min","lessons":[{"t":"2.1 Project Scheduling: Gantt Charts & Critical Path Method","d":"12:00","v":"YDxAKKVdMVM"},{"t":"2.2 Budget Estimation & Cost Management","d":"11:30","v":"EyPFi0YO32M"},{"t":"2.3 Risk Management: Identification, Assessment & Response","d":"12:00","v":"r1szmmkUPH8"},{"t":"📝 Quiz: Project Planning","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Execution, Monitoring & Agile","icon":"⚡","meta":"4 lessons · 44 min","lessons":[{"t":"3.1 Project Execution: Leading Teams & Managing Quality","d":"11:00","v":"1rQT1R3S2BQ"},{"t":"3.2 Monitoring & Controlling: EVM, KPIs & Status Reporting","d":"12:00","v":"boIRGwGJ-Ds"},{"t":"3.3 Agile & Scrum: Sprints, Backlogs & Stand-ups","d":"12:00","v":"KmEMtUzMlIk"},{"t":"🛠️ Project: Full Project Plan for a Real Initiative","d":"Project","isProject":true}]},{"title":"Module 4: Closure, Communication & PMP Prep","icon":"🏆","meta":"4 lessons · 38 min","lessons":[{"t":"4.1 Project Closure & Lessons Learned","d":"9:30","v":"gSOdc2Y5tTk"},{"t":"4.2 Stakeholder Communication & Change Management","d":"10:00","v":"bV9yUQV6D60"},{"t":"4.3 PMP Exam Preparation & Professional Development","d":"10:00","v":"vzqDTSZOTic"},{"t":"📝 Quiz: Closure, Communication & PMP Prep","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: PM Tools & Managing Donor-Funded Projects","icon":"🛠️","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Project Management Software: Trello, Asana & MS Project","d":"Video + notes","v":"C5b_4aFeF2E"},{"t":"5.2 Donor-Funded Projects: Logframes, Work Plans & Compliance","d":"Video + notes","v":"00Rbll3ZNk0"},{"t":"5.3 Procurement, Contracts & Financial Stewardship","d":"Video + notes","v":"ktSzxVEnTZ8"},{"t":"📝 Quiz: PM Tools & Donor-Funded Projects","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Your Project Management Career","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Building Your PM Portfolio & Case Studies","d":"Video + notes","v":"521iU9T4TBg"},{"t":"6.2 From Projects to Programs: PMOs & Program Management","d":"Video + notes","v":"fAC7up3jc3k"},{"t":"6.3 Your PM Career: Jobs, Interviews & Certification Roadmap","d":"Video + notes","v":"UQ71PhWRDEQ"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: PM Fundamentals & Initiation","moduleNum":1,"unlocks":3,"questions":[{"q":"What are the 5 project management process groups?","opts":["Plan, Design, Build, Test, Deploy","Initiating, Planning, Executing, Monitoring & Controlling, Closing","Start, Middle, End, Review, Archive","Scope, Time, Cost, Quality, Risk"],"correct":1,"exp":"PMBOK defines these 5 process groups as the fundamental lifecycle of any project."},{"q":"A project charter does what?","opts":["Defines all project activities in detail","Formally authorizes the project and defines high-level scope, objectives, and stakeholders","Lists every project team member","Contains the detailed budget breakdown"],"correct":1,"exp":"The project charter is the official authorization document that gives the PM authority to manage the project."},{"q":"WBS stands for:","opts":["Work Budget Schedule","Work Breakdown Structure","Weekly Business Summary","Work-Based Specification"],"correct":1,"exp":"A WBS decomposes the project scope into smaller, manageable deliverables and work packages."},{"q":"Who is a \"stakeholder\" in project management?","opts":["Only the project manager","Only the client","Anyone who has an interest in or is affected by the project outcomes","Only the project team members"],"correct":2,"exp":"Stakeholders include clients, sponsors, team members, end users, regulators, and the community."},{"q":"Project scope creep refers to:","opts":["The project finishing ahead of schedule","Uncontrolled growth of project scope beyond what was originally defined","The project going under budget","Team members leaving the project"],"correct":1,"exp":"Scope creep is a primary cause of project failure, it must be controlled through formal change management."},{"q":"What distinguishes a project from ongoing operations?","opts":["A project is always more expensive","A project is temporary with a defined beginning and end, producing a unique result","A project never involves a team","A project is only found in the construction industry"],"correct":1,"exp":"Projects are temporary and unique; operations are continuous and repetitive, like daily payroll processing."},{"q":"The 'triple constraint' in project management refers to the balance between:","opts":["People, politics, and paperwork","Vision, mission, and values","Scope, time, and cost","Planning, executing, and closing"],"correct":2,"exp":"Changing any one of scope, time, or cost forces adjustments in the others, with quality at the center of the triangle."},{"q":"Who typically signs and issues the project charter?","opts":["The project sponsor or senior management","The newest team member","An external auditor","The end users of the deliverable"],"correct":0,"exp":"The sponsor authorizes the project and gives the project manager formal authority through the charter."},{"q":"A power/interest grid is used during initiation to:","opts":["Calculate electricity costs for the project office","Classify stakeholders so you can plan how closely to manage and engage each one","Rank team members by seniority","Estimate the project budget"],"correct":1,"exp":"Stakeholders with high power and high interest must be managed closely; others are kept satisfied, informed, or monitored."},{"q":"In scope management, 'requirements gathering' means:","opts":["Buying materials before the project starts","Hiring the project team","Writing the final project report","Systematically collecting and documenting what stakeholders need the project to deliver"],"correct":3,"exp":"Techniques like interviews, workshops, and surveys capture stakeholder needs before scope is defined, preventing costly rework later."}]},"mod2":{"title":"Quiz: Project Planning","moduleNum":2,"unlocks":3,"questions":[{"q":"The Critical Path Method (CPM) identifies:","opts":["The most expensive project activities","The longest sequence of dependent activities determining the shortest project duration","The most risky activities","Activities that can be done in parallel"],"correct":1,"exp":"The critical path is the longest path through the project network, delay any task on it and the whole project is delayed."},{"q":"A Gantt chart shows:","opts":["Project budget distribution","Project schedule as a horizontal bar chart showing tasks over time","Risk probability matrix","Stakeholder communication plan"],"correct":1,"exp":"Gantt charts are the most widely used scheduling tool, showing tasks, durations, and dependencies visually."},{"q":"A project risk register contains:","opts":["Financial transactions","Identified risks, their probability, impact, and planned responses","Team member performance reviews","Project change requests"],"correct":1,"exp":"The risk register is a living document tracking all identified risks and mitigation strategies throughout the project."},{"q":"Earned Value Management (EVM) measures:","opts":["Employee satisfaction","Project performance against scope, schedule, and budget simultaneously","Marketing effectiveness","Stakeholder engagement"],"correct":1,"exp":"EVM provides objective metrics on whether a project is on time, within budget, and delivering planned scope."},{"q":"A contingency reserve in project budgeting is:","opts":["The total project budget","Extra budget set aside to address identified risks if they occur","The management fee","Profit margin"],"correct":1,"exp":"Contingency reserves cover identified risks. Management reserves cover unforeseen risks outside approved scope."},{"q":"In a project schedule, 'float' (or slack) is:","opts":["The amount of time an activity can be delayed without delaying the project finish date","The extra budget for emergencies","The time the team spends in meetings","The gap between two milestones"],"correct":0,"exp":"Activities on the critical path have zero float, any delay to them delays the entire project."},{"q":"Bottom-up estimating produces a project cost estimate by:","opts":["Copying the budget of a similar past project","Asking senior management for a single total figure","Estimating each work package in the WBS and summing them upward","Multiplying team size by project duration"],"correct":2,"exp":"Bottom-up estimating is slower but far more accurate because every work package is costed individually."},{"q":"A probability and impact matrix helps a project team to:","opts":["Schedule team meetings","Prioritize risks so the most serious ones get response plans first","Track actual expenses against budget","Assign tasks to team members"],"correct":1,"exp":"Plotting each risk by likelihood and consequence separates critical red-zone risks from minor ones."},{"q":"Transferring a risk means:","opts":["Ignoring the risk and hoping it never happens","Changing the project plan so the risk can no longer occur","Reducing the probability of the risk through early action","Shifting the financial impact to a third party, for example through insurance or a fixed-price contract"],"correct":3,"exp":"Transfer does not eliminate the risk, it moves the consequence to another party, usually for a fee or premium."},{"q":"A milestone in a project schedule is:","opts":["A significant point or event with zero duration, such as approval of a deliverable","The longest task in the project","A weekly team meeting","A payment made to a supplier"],"correct":0,"exp":"Milestones mark progress checkpoints, they consume no time or resources but signal key achievements."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"In Scrum, a \"Sprint\" is:","opts":["A sprint meeting","A fixed-length iteration (usually 2-4 weeks) in which a usable product increment is delivered","A type of project report","The project kickoff meeting"],"correct":1,"exp":"Sprints are the heart of Scrum, short, time-boxed cycles delivering working product increments."},{"q":"What does a Scrum Master do?","opts":["Manages the project budget","Assigns tasks to developers","Serves the team by removing obstacles and facilitating Scrum processes","Acts as the product owner"],"correct":2,"exp":"The Scrum Master is a servant-leader who coaches the team, removes impediments, and protects the process."},{"q":"Project lessons learned are documented:","opts":["Only when the project fails","At project closure to capture knowledge for future projects","Only by the project manager","During the planning phase"],"correct":1,"exp":"Lessons learned capture what went well, what went wrong, and recommendations to improve future projects."},{"q":"Change management in projects involves:","opts":["Replacing project team members","A formal process for evaluating and approving changes to approved project scope/schedule/budget","Updating the project charter only","Informal verbal approvals"],"correct":1,"exp":"Formal change control prevents scope creep and ensures all changes are evaluated for impact before approval."},{"q":"What is a project closure document?","opts":["The initial project proposal","Formal documentation that the project is complete, deliverables accepted, and resources released","The monthly status report","The risk register update"],"correct":1,"exp":"The closure document is the formal sign-off that the project is complete and accepted by stakeholders."},{"q":"During which process group is the project charter created?","opts":["Initiating","Executing","Monitoring and Controlling","Closing"],"correct":0,"exp":"The charter is produced in Initiating, it authorizes the project before detailed planning begins."},{"q":"The lowest level of a WBS, where work is estimated and assigned, is called a:","opts":["Milestone","Work package","Sprint","Charter"],"correct":1,"exp":"Work packages are the smallest WBS elements, small enough to estimate cost and duration reliably."},{"q":"If an activity on the critical path is delayed by three days and nothing else changes, the project finish date will:","opts":["Stay the same because of float","Move earlier by three days","Slip by three days","Depend on the budget"],"correct":2,"exp":"Critical path activities have zero float, so any delay passes directly to the project end date."},{"q":"In Earned Value Management, a Cost Performance Index (CPI) below 1.0 means:","opts":["The project is under budget","The project is ahead of schedule","The project has no risks","The project is over budget, each dollar spent earns less than a dollar of work"],"correct":3,"exp":"CPI = EV/AC; a value below 1.0 signals cost inefficiency that needs corrective action."},{"q":"'Mitigating' a risk means:","opts":["Taking early action to reduce its probability or impact","Buying insurance against it","Accepting it and doing nothing","Deleting it from the risk register"],"correct":0,"exp":"Mitigation reduces the threat itself, unlike transfer (shift it) or acceptance (live with it)."},{"q":"In Scrum, the product backlog is:","opts":["The list of team members","A prioritized, evolving list of everything that might be needed in the product","The record of past sprint failures","The project budget document"],"correct":1,"exp":"The Product Owner maintains and prioritizes the backlog; the team pulls top items into each sprint."},{"q":"The daily stand-up meeting in Scrum should:","opts":["Last two hours and cover all project issues","Be held only when problems occur","Be short (about 15 minutes) and focus on progress, plans, and blockers","Replace all other project documentation"],"correct":2,"exp":"The stand-up is a time-boxed synchronization meeting, not a status report to management."},{"q":"A stakeholder with high power but low interest in your project should be:","opts":["Ignored completely","Managed closely with daily meetings","Removed from the stakeholder register","Kept satisfied without overwhelming them with detail"],"correct":3,"exp":"The power/interest grid says keep such stakeholders satisfied; over-communicating wastes their time and yours."},{"q":"In a logframe, 'assumptions' describe:","opts":["External conditions outside project control that must hold for success","The project manager's personal beliefs","The activities the team will perform","The donor's funding schedule"],"correct":0,"exp":"Assumptions like 'roads remain passable' link logframe levels, if they fail, the results chain breaks."},{"q":"A donor project's burn rate compares:","opts":["Fuel consumption against vehicle mileage","Staff turnover against recruitment","Budget spent against time elapsed in the project","Risks identified against risks closed"],"correct":2,"exp":"Burn rate is the standard quick check on whether spending matches implementation progress."},{"q":"Which purchase situation calls for an RFQ rather than an RFP?","opts":["Designing a national health information system","Conducting a complex baseline research study","Hiring a strategy consulting firm","Buying 50 standard office chairs at the best price"],"correct":3,"exp":"RFQs suit simple, clearly specified goods where price is the deciding factor."},{"q":"A program differs from a project because a program:","opts":["Is always smaller and cheaper","Coordinates multiple related projects to achieve benefits none could deliver alone","Has no defined objectives","Never involves stakeholders"],"correct":1,"exp":"Programs manage related projects together and focus on overall benefits realization."},{"q":"A supportive PMO primarily provides:","opts":["Templates, training, and lessons-learned resources to project teams","Direct command over all company staff","External audit services to donors","Legal representation in court"],"correct":0,"exp":"Supportive PMOs act as a resource center; controlling and directive PMOs add progressively more authority."},{"q":"The strongest way to present a past project in a job interview is to:","opts":["Say you worked very hard on it","List the names of everyone on the team","Describe it using Situation, Task, Action, and measurable Results, supported by portfolio documents","Explain that the project had no problems at all"],"correct":2,"exp":"The STAR method plus real artifacts (charter, Gantt chart, risk register) gives verifiable evidence of competence."},{"q":"Which certification tests PMBOK knowledge but does NOT require years of project experience, making it ideal right after this course?","opts":["PMP","PRINCE2 Practitioner (senior level)","PgMP","CAPM"],"correct":3,"exp":"CAPM is PMI's entry-level credential, a natural next step while you accumulate the hours needed for PMP."}]},"mod4":{"title":"Quiz: Closure, Communication & PMP Prep","moduleNum":4,"questions":[{"q":"Administrative closure of a project includes:","opts":["Starting the next project immediately","Finalizing documentation, releasing resources, and archiving project records","Deleting all project files to save storage","Renegotiating the project budget"],"correct":1,"exp":"Closure formally ends the project: records are archived, contracts closed, and team members released to new work."},{"q":"Why should project records be archived at closure?","opts":["To hide mistakes from auditors","Because donors always demand paper copies","So future projects can reuse estimates, templates, and lessons as organizational process assets","To make the final report look longer"],"correct":2,"exp":"Archived records become organizational process assets that make every future project faster and smarter."},{"q":"The best time to capture lessons learned is:","opts":["Throughout the project, with a formal review at closure","Only after the certificate is issued","Only if the project fails","Five years after the project ends"],"correct":0,"exp":"Capturing lessons continuously prevents them from being forgotten; the closure review consolidates them."},{"q":"A communications management plan defines:","opts":["Only the project manager's phone number","The project scope and budget","Who needs what information, when, in what format, and through which channel","The salaries of the communication team"],"correct":2,"exp":"Matching the right information to the right stakeholder at the right frequency prevents confusion and conflict."},{"q":"An example of 'push' communication is:","opts":["A stakeholder browsing the project website","Emailing a weekly status report to stakeholders","Storing documents on a shared drive for anyone to read","A team member asking a question in person"],"correct":1,"exp":"Push communication is sent to recipients (email, reports); pull communication requires recipients to retrieve it themselves."},{"q":"A Change Control Board (CCB) exists to:","opts":["Punish team members who request changes","Review, approve, or reject proposed changes to the approved project baseline","Write the original project charter","Manage the organization's HR policies"],"correct":1,"exp":"The CCB provides formal governance so that every change is assessed for impact on scope, schedule, and cost."},{"q":"When stakeholders resist a change the project introduces, the leader should first:","opts":["Communicate the reasons for the change and listen to their concerns","Remove the resisters from the organization","Cancel the change immediately","Keep the change secret until it is complete"],"correct":0,"exp":"Most resistance comes from fear or lack of information; honest two-way communication is the proven first response."},{"q":"To sit the PMP exam, PMI requires candidates to have:","opts":["A PhD in management","Documented project experience plus 35 hours of project management education","Ten years of experience as a CEO","A letter from a government ministry"],"correct":1,"exp":"PMI requires 36-60 months of experience (depending on degree) plus 35 contact hours, a course like this one counts toward them."},{"q":"The three domains of the current PMP exam are:","opts":["Hardware, Software, and Networks","Initiation, Execution, and Closing","Finance, Marketing, and Operations","People, Process, and Business Environment"],"correct":3,"exp":"The PMP exam content outline weights People (42%), Process (50%), and Business Environment (8%)."},{"q":"Formal acceptance of deliverables at closure is important because it:","opts":["Confirms in writing that the customer agrees the work meets requirements, protecting both parties","Allows the team to skip quality checks","Guarantees the team a bonus","Replaces the need for a contract"],"correct":0,"exp":"Written sign-off proves the deliverable was accepted as complete, essential when disputes or payment questions arise later."}]},"mod5":{"title":"Quiz: PM Tools & Donor-Funded Projects","moduleNum":5,"questions":[{"q":"In Trello, a project is organized as:","opts":["A spreadsheet with formulas","A board containing lists (such as To Do, Doing, Done) filled with task cards","A slideshow of milestones","A single shared text document"],"correct":1,"exp":"Trello implements the kanban method: cards move across lists to show task progress visually."},{"q":"A key advantage of Microsoft Project over a simple task board is that it can:","opts":["Send WhatsApp messages","Work without any project plan","Automatically calculate the critical path and track baseline versus actual dates","Replace the project team"],"correct":2,"exp":"MS Project is full scheduling software, dependencies, resource leveling, baselines, and critical path analysis."},{"q":"In a logframe, the results chain runs in which order, from work performed to long-term change?","opts":["Activities, Outputs, Outcomes, Goal","Goal, Budget, Staff, Report","Indicators, Assumptions, Risks, Costs","Outputs, Activities, Goal, Outcomes"],"correct":0,"exp":"Activities produce outputs, outputs lead to outcomes, and outcomes contribute to the long-term goal."},{"q":"In a logframe, 'means of verification' refers to:","opts":["The donor's bank account","The project manager's opinion of progress","The signatures on the project charter","The evidence sources, registers, surveys, reports, used to measure each indicator"],"correct":3,"exp":"Every indicator must name where its data will come from, or it cannot be credibly measured."},{"q":"A project has spent 25% of its budget at the 60% point of its timeline. Its burn rate suggests:","opts":["The project is performing perfectly","Implementation is likely behind schedule and the donor will ask questions","The project should immediately buy vehicles to spend faster","The budget was too small"],"correct":1,"exp":"A burn rate far below time elapsed usually signals delayed activities, donors monitor this closely."},{"q":"A no-cost extension is:","opts":["An approved extension of the project timeline without additional funding","Free office space from the government","A discount negotiated with suppliers","An automatic right whenever a project is late"],"correct":0,"exp":"It must be formally requested and approved before the end date, it adds time, not money."},{"q":"An RFP (Request for Proposals) is most appropriate when:","opts":["Buying fuel at the cheapest price","The purchase is complex and technical approach matters as much as cost","The supplier is a relative of the director","The purchase is below the smallest threshold"],"correct":1,"exp":"RFPs suit complex services where offers are scored on methodology and qualifications, not price alone."},{"q":"The 'three-quote rule' in procurement exists to:","opts":["Triple the project budget","Ensure three staff sign every cheque","Demonstrate genuine competition and fair pricing for purchases above a threshold","Guarantee the most expensive supplier wins"],"correct":2,"exp":"Comparing at least three written quotations proves the buyer sought competitive, fair prices."},{"q":"Under a fixed-price contract, the risk of cost overruns is mainly carried by:","opts":["The donor","The project beneficiaries","The government","The supplier or contractor"],"correct":3,"exp":"The supplier agreed to deliver for a set price, so cost increases eat into their margin, not the project budget."},{"q":"Segregation of duties means:","opts":["Splitting the team into departments","No single person should request, approve, and receive the same purchase","Keeping finance staff in a separate building","Dividing the budget equally among staff"],"correct":1,"exp":"Separating these roles is the most basic internal control against fraud and error in project finances."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Dr. Weah is the best PM instructor I have ever encountered. After this course I passed my PMP exam on the first attempt. I now manage a $3M World Bank project in Liberia. This course was the foundation for my entire career change."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"The combination of PMBOK and Agile in one course is brilliant. The Scrum module prepared me for my tech company role perfectly. Dr. Weah uses real African project examples which make everything immediately relevant and applicable."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"I manage health projects for an international NGO and this course transformed my approach completely. The risk management and EVM modules are outstanding. My project delivery rates improved dramatically after applying these tools."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Excellent comprehensive course. The full project plan assignment pushed me to apply every concept from the course in one integrated deliverable. I showed the plan in a job interview and was hired immediately. Highly recommended."}],"faqs":[{"q":"Will this prepare me for the PMP certification?","a":"Yes! This course aligns with PMBOK Guide 7th edition and covers all major PMP exam domains. We recommend additional practice exams after completing the course."},{"q":"Do I need project management experience?","a":"No prior PM experience is required. The course builds your knowledge from the ground up. Having any work experience (in any field) provides helpful context."},{"q":"What industries use project management?","a":"Every industry: construction, healthcare, NGOs, government, banking, technology, agriculture, and more. Every organization that runs projects needs project managers."},{"q":"How does this course cover Agile and Scrum?","a":"Module 3 covers Agile fundamentals and Scrum in depth, including sprints, backlogs, retrospectives, and roles. This prepares you for both traditional PM and modern agile environments."}]};
COURSES_DB['office'] = {"id":"office","title":"Microsoft Office Mastery: Word, Excel & PowerPoint","shortDesc":"For job seekers and professionals, go beyond basics to master advanced Word, Excel, and PowerPoint features like mail merge, pivot tables, and slide masters.","category":"Computer Fundamentals","icon":"💼","gradient":"linear-gradient(135deg,#d97706,#f59e0b)","instructor":"Samuel Doe","instructorTitle":"Microsoft Certified Trainer & Productivity Expert","instructorBio":"Samuel Doe is a Microsoft Certified Trainer (MCT) with 15 years teaching Office productivity to businesses, government agencies, and NGOs across Liberia. He has helped over 5,000 professionals master the Microsoft Office suite.","rating":4.8,"reviewCount":943,"students":"4,800+","duration":"28h","level":"Beginner","price":"FREE","origPrice":"$120","isFree":true,"badge":"free","certId":"TIH-2026-MO-0156","learn":["Create professional documents, reports, and CVs in Microsoft Word","Use advanced Word features: styles, tables of contents, mail merge","Build spreadsheets with essential Excel formulas and functions","Create pivot tables and charts to analyze and visualize data","Design compelling presentations in Microsoft PowerPoint","Use PowerPoint animations, slide masters, and presentation techniques","Collaborate using Microsoft 365 OneDrive, Teams, and SharePoint","Improve productivity with keyboard shortcuts and workflow automation"],"requirements":["Basic computer skills, ability to use a keyboard and mouse","Microsoft Office 2016 or later (or Microsoft 365 subscription)","No prior Office experience needed, this course covers all three applications completely"],"about":["Microsoft Office is the most widely used productivity software suite in the world. In Liberia and across Africa, proficiency in Word, Excel, and PowerPoint is required for virtually every office job. This course builds that proficiency comprehensively.","Going beyond basic skills, this course teaches advanced features that separate proficient users from true Office masters, mail merge, pivot tables, data analysis, slide masters, and Microsoft 365 collaboration tools that are increasingly standard in modern workplaces.","Whether you are preparing for a job interview, looking to perform better at work, or wanting to start freelancing as an Office trainer or virtual assistant, this course gives you everything you need. Our graduates consistently report immediate career advancement from these skills."],"modules":[{"title":"Module 1: Microsoft Word, Professional Documents","icon":"📄","meta":"4 lessons · 42 min","lessons":[{"t":"1.1 Word Interface, Formatting & Document Structure","d":"10:30","v":"EuWTrvT_YyY"},{"t":"1.2 Professional CVs, Letters & Reports with Styles","d":"12:00","v":"3eIlHtHDGDs"},{"t":"1.3 Tables, Images, Mail Merge & Advanced Features","d":"12:00","v":"rGG-In7PAEk"},{"t":"📝 Quiz: Microsoft Word","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Microsoft Excel, Data & Analysis","icon":"📊","meta":"4 lessons · 46 min","lessons":[{"t":"2.1 Excel Essentials: Formulas, Functions & Formatting","d":"12:00","v":"7_vMFvnGTlc"},{"t":"2.2 VLOOKUP, IF Statements & Essential Data Functions","d":"12:30","v":"bsuP2dD3rec"},{"t":"2.3 Pivot Tables, Charts & Dashboard Creation","d":"13:00","v":"9NUjHBNWe9M"},{"t":"📝 Quiz: Microsoft Excel","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Microsoft PowerPoint, Presentations","icon":"🎞️","meta":"4 lessons · 40 min","lessons":[{"t":"3.1 PowerPoint Fundamentals: Layouts, Themes & Master Slides","d":"10:00","v":"QiVSIvB1xis"},{"t":"3.2 Advanced Animations, Transitions & Multimedia","d":"11:00","v":"cwPaqUC1jT4"},{"t":"3.3 Data Visualization & Charts in PowerPoint","d":"10:00","v":"ycyySK5bdRg"},{"t":"🛠️ Project: Professional Business Presentation","d":"Project","isProject":true}]},{"title":"Module 4: Microsoft 365 & Productivity Mastery","icon":"🏆","meta":"4 lessons · 36 min","lessons":[{"t":"4.1 Microsoft 365: OneDrive, Teams & SharePoint Collaboration","d":"10:00","v":"nbhZE_mza2g"},{"t":"4.2 Keyboard Shortcuts & Productivity Optimization","d":"9:00","v":"u0--Ye7bUP4"},{"t":"4.3 Microsoft Outlook: Professional Email & Calendar Management","d":"9:00","v":"TzNQkMTHKuM"},{"t":"📝 Quiz: Microsoft 365 & Productivity Mastery","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Advanced Excel, Power Functions, Clean Data & Automation","icon":"⚡","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 XLOOKUP, INDEX-MATCH & Named Ranges","d":"Video + notes","v":"4wQ0KmttgcQ"},{"t":"5.2 Data Cleaning & Validation: Trustworthy Spreadsheets","d":"Video + notes","v":"oT4emh72fuA"},{"t":"5.3 Automation: Power Query & Macro Basics","d":"Video + notes","v":"DQPHzp2ezpw"},{"t":"📝 Quiz: Advanced Excel & Automation","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Office Skills at Work & Beyond","icon":"🏆","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Capstone Part 1: The Professional Report in Word","d":"Video + notes","v":"VFMPLeC7h0I"},{"t":"6.2 Capstone Part 2: Excel Dashboard & Executive Briefing in PowerPoint","d":"Video + notes","v":"S0i4CdKi1i4"},{"t":"6.3 Careers: MOS Certification, Virtual Assistant Work & Freelancing","d":"Video + notes","v":"Y5waTxDKZ3c"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Microsoft Word","moduleNum":1,"unlocks":3,"questions":[{"q":"What is the purpose of \"Styles\" in Microsoft Word?","opts":["To change text color only","To apply consistent formatting throughout a document and enable automatic table of contents","To add animations","To insert images"],"correct":1,"exp":"Styles ensure consistent formatting and allow Word to automatically generate tables of contents."},{"q":"Mail Merge in Word is used to:","opts":["Send emails directly from Word","Create personalized letters or emails from a single template using data from a list","Merge multiple documents into one","Merge comments from multiple reviewers"],"correct":1,"exp":"Mail Merge creates personalized letters, certificates, or emails for multiple recipients from one template."},{"q":"What does Ctrl+Z do in Office applications?","opts":["Save the document","Undo the last action","Close the window","Zoom in"],"correct":1,"exp":"Ctrl+Z is the universal Undo shortcut across all Microsoft Office applications."},{"q":"A \"header\" in a Word document appears:","opts":["Only on the first page","At the top of every page","Only on odd pages","At the bottom of every page"],"correct":1,"exp":"Headers appear at the top of every page and typically contain document title, page number, or company name."},{"q":"What is a table of contents?","opts":["A list of database tables","An automatically generated navigation list of document headings and page numbers","A spreadsheet in Word","A bibliography list"],"correct":1,"exp":"Word can auto-generate a table of contents from heading styles, updated with one click."},{"q":"What is the difference between a page break and a section break in Word?","opts":["They are identical features","A page break starts a new page; a section break creates a new section that can have its own margins, orientation, headers, and page numbering","A section break can only be used once per document","A page break deletes the current page"],"correct":1,"exp":"Section breaks let one document mix layouts, for example a landscape budget table inside a portrait report."},{"q":"The Format Painter tool in Word is used to:","opts":["Insert pictures into a document","Change the page color","Copy formatting from one piece of text and apply it to another","Paint shapes and diagrams"],"correct":2,"exp":"Format Painter copies fonts, sizes, colors, and spacing in one click, double-click it to apply the format multiple times."},{"q":"To place an image beside a paragraph so text flows around it, you should adjust the image's:","opts":["Text wrapping setting (for example Square or Tight)","File size","Color saturation","Alt text"],"correct":0,"exp":"Text wrapping options control how text flows around a picture, In Line, Square, Tight, Behind, or In Front."},{"q":"Find and Replace (Ctrl+H) is most useful for:","opts":["Replacing images with charts","Changing the document theme","Translating a document into another language","Correcting a repeated word or name throughout an entire document in one action"],"correct":3,"exp":"Find and Replace fixes every occurrence at once, for example changing 'Monrovia Office' to 'Monrovia Branch' across 40 pages."},{"q":"Saving a Word document as a PDF is recommended when:","opts":["You want the recipient to easily edit the text","You need to keep editing it daily","You are sharing a final version that must look identical on any device and not be easily altered","Your computer has no storage space"],"correct":2,"exp":"PDF preserves exact layout and fonts, making it the standard format for final CVs, letters, and reports."}]},"mod2":{"title":"Quiz: Microsoft Excel","moduleNum":2,"unlocks":3,"questions":[{"q":"Which Excel formula finds the highest value in a range?","opts":["=HIGH(A1:A10)","=LARGEST(A1:A10)","=MAX(A1:A10)","=TOP(A1:A10)"],"correct":2,"exp":"=MAX(range) returns the largest value in a specified range of cells."},{"q":"What does the IF function do?","opts":["Imports files","Returns one value if a condition is TRUE and another if it is FALSE","Counts cells","Filters data"],"correct":1,"exp":"IF(condition, value_if_true, value_if_false) is one of the most versatile Excel functions."},{"q":"A pivot table is primarily used to:","opts":["Create presentations","Summarize, analyze, and explore patterns in large datasets","Format cells with colors","Create data entry forms"],"correct":1,"exp":"Pivot tables instantly summarize thousands of rows of data with drag-and-drop simplicity."},{"q":"Cell referencing in Excel: $A$1 means:","opts":["A relative reference","An absolute reference (always refers to column A, row 1 regardless of where copied)","An invalid reference","A named range"],"correct":1,"exp":"The $ signs lock the column and row references, essential for formulas that need to stay fixed when copied."},{"q":"What is conditional formatting?","opts":["Formatting only the first row","Rules that automatically apply colors or icons to cells based on their values","Manual color coding","A type of Excel chart"],"correct":1,"exp":"Conditional formatting highlights data patterns, exceptions, and trends automatically based on rules you set."},{"q":"VLOOKUP is designed to:","opts":["Search for a value in the first column of a table and return a value from another column in the same row","Count the number of visible rows","Validate email addresses","Lock cells against editing"],"correct":0,"exp":"VLOOKUP(lookup_value, table, column_number, FALSE) pulls matching data, like finding a student's grade from an ID number."},{"q":"Which formula counts how many cells in A1:A50 contain the word 'Paid'?","opts":["=SUM(A1:A50,\"Paid\")","=COUNTIF(A1:A50,\"Paid\")","=IF(A1:A50=\"Paid\")","=TOTAL(A1:A50)"],"correct":1,"exp":"COUNTIF counts cells meeting one condition, essential for tracking payments, attendance, or status columns."},{"q":"The small square at the bottom-right corner of a selected cell (the fill handle) lets you:","opts":["Delete the worksheet","Change the cell color","Merge cells together","Drag to copy a formula or continue a series like months or numbers"],"correct":3,"exp":"Dragging the fill handle auto-fills series (Jan, Feb, Mar...) and copies formulas down thousands of rows in seconds."},{"q":"Freeze Panes in Excel is used to:","opts":["Prevent anyone from editing the file","Keep header rows or columns visible while scrolling through large datasets","Stop formulas from recalculating","Cool down an overheating laptop"],"correct":1,"exp":"Freezing the top row keeps column titles visible as you scroll, vital when working with hundreds of records."},{"q":"Which chart type is best for showing how a single total is divided into proportional parts?","opts":["Line chart","Scatter chart","Pie chart","Histogram"],"correct":2,"exp":"Pie charts show parts of a whole; line charts show trends over time; column charts compare categories."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"In PowerPoint, a \"slide master\" is:","opts":["The first slide in a presentation","A template controlling the design and layout of all slides for consistent branding","The presenter's control panel","The largest slide in a deck"],"correct":1,"exp":"Slide masters ensure brand consistency across all slides, change the master and every slide updates."},{"q":"What is OneDrive in Microsoft 365?","opts":["A USB flash drive","Microsoft's cloud storage service for storing and sharing files from anywhere","An email service","A presentation tool"],"correct":1,"exp":"OneDrive gives every Microsoft 365 user cloud storage accessible from any device for file backup and sharing."},{"q":"Microsoft Teams is primarily used for:","opts":["Creating presentations","Team communication, video meetings, and collaboration on Microsoft 365 files","Managing spreadsheets","Website creation"],"correct":1,"exp":"Microsoft Teams is the hub for modern workplace collaboration, chat, meetings, calls, and file sharing in one place."},{"q":"Which keyboard shortcut saves a file in any Office application?","opts":["Ctrl+P","Ctrl+S","Ctrl+W","Ctrl+N"],"correct":1,"exp":"Ctrl+S instantly saves the current file, a habit all Office users should develop to avoid losing work."},{"q":"What does \"track changes\" in Word allow?","opts":["Saving document history","Showing all edits made to a document so reviewers can accept or reject changes","Tracking file storage size","Comparing two documents automatically"],"correct":1,"exp":"Track Changes shows all edits visually, enabling collaborative review and approval workflows."},{"q":"Why should headings in a long Word report be created with heading styles rather than manual bold text?","opts":["Manual bold text is invisible when printed","Styles enable the automatic table of contents, navigation pane, and one-click consistent formatting","Word deletes manually formatted headings","Styles make the file smaller"],"correct":1,"exp":"Every automated document feature, TOC, navigation, cross-references, depends on real heading styles."},{"q":"To start page numbering at 1 on the first body page while the front matter uses roman numerals, you need:","opts":["Two separate documents","A macro","Section breaks separating front matter from the body","A special printer setting"],"correct":2,"exp":"Section breaks let each section carry its own numbering format and starting number, the professional report standard."},{"q":"A mail merge requires two components:","opts":["A template document and a data source such as an Excel list of recipients","A printer and a scanner","Two computers on a network","A PDF and a PowerPoint file"],"correct":0,"exp":"The template holds fixed text plus merge fields; the data source supplies each recipient's details."},{"q":"In Excel, =IF(B2>=70,\"Pass\",\"Fail\") will display:","opts":["Always Pass","The number 70","An error message","Pass when B2 is 70 or more, otherwise Fail"],"correct":3,"exp":"IF tests a condition and returns one value when true and another when false, the foundation of spreadsheet logic."},{"q":"When you copy the formula =A2*$B$1 down a column, what happens?","opts":["Both references stay fixed","A2 changes with each row while $B$1 stays fixed on cell B1","Both references change with each row","The formula becomes text"],"correct":1,"exp":"Relative references adjust when copied; the absolute reference $B$1 keeps pointing at one cell, such as a tax rate."},{"q":"The fastest way to summarize 5,000 rows of sales by county and month is:","opts":["Typing totals with a calculator","Sorting and adding manually with SUM for each group","Printing the sheet and highlighting rows","Inserting a pivot table and dragging county and month into its areas"],"correct":3,"exp":"Pivot tables aggregate thousands of rows in seconds with drag-and-drop, no formulas needed."},{"q":"A slicer connected to a pivot table provides:","opts":["Clickable buttons that filter the pivot table and its charts interactively","Automatic spelling correction","A backup of the workbook","Password protection"],"correct":0,"exp":"Slicers give dashboards their interactive filtering, one click shows results for a chosen month or branch."},{"q":"Editing the slide master changes:","opts":["Only the current slide","The design of all slides based on it, ensuring consistent fonts, colors, and logos","Only the presenter's notes","The order of slides"],"correct":1,"exp":"The slide master controls layout inheritance, fix branding once and every slide follows."},{"q":"A well-designed presentation slide should:","opts":["Contain your full script in small text","Use as many animation effects as possible","Carry one main idea with large readable text and a supporting visual","Have a different font on every slide"],"correct":2,"exp":"One idea per slide with readable text keeps the audience listening to you instead of reading."},{"q":"Presenter View in PowerPoint shows the audience:","opts":["Your speaker notes and timer","Only the current slide, while your screen shows notes, timer, and the next slide","Your email inbox","The slide master"],"correct":1,"exp":"Presenter View separates what you see from what the audience sees, rehearse with it before every important talk."},{"q":"Storing a team's project documents on SharePoint rather than one person's laptop matters because:","opts":["Laptops cannot open Word files","SharePoint files print faster","SharePoint deletes old files automatically","The documents remain accessible to the team with permissions and version history, even if staff leave"],"correct":3,"exp":"Organizational knowledge should live in shared, governed storage, not walk out the door with one employee."},{"q":"XLOOKUP's if_not_found argument is useful because it:","opts":["Speeds up the calculation","Replaces the #N/A error with a friendly message like Not Found","Automatically corrects the lookup value's spelling","Deletes rows with missing data"],"correct":1,"exp":"Handling missing matches gracefully keeps reports clean and tells users what actually happened."},{"q":"Applying Data Validation to a data-entry sheet is best described as:","opts":["Preventing errors at entry instead of cleaning them afterwards","A way to make the sheet colorful","A method of hiding formulas","A replacement for saving the file"],"correct":0,"exp":"Validation rules and dropdowns stop bad data before it exists, prevention beats cure."},{"q":"After building a Power Query that combines monthly branch files, next month you should:","opts":["Rebuild the query from scratch","Add the new file to the source folder and click Refresh All","Retype the data manually to be safe","Convert the workbook to PDF first"],"correct":1,"exp":"Power Query replays its recorded steps on new data automatically, that refresh is the whole point of automation."},{"q":"What makes the MOS certification particularly credible to employers?","opts":["It is awarded automatically after watching videos","It never expires and requires no exam","It is a proctored, hands-on exam performed inside the real Office applications","It is only available to university graduates"],"correct":2,"exp":"Because candidates must perform real tasks in Word, Excel, or PowerPoint under exam conditions, MOS verifies skill rather than claims."}]},"mod4":{"title":"Quiz: Microsoft 365 & Productivity Mastery","moduleNum":4,"questions":[{"q":"Co-authoring in Microsoft 365 means:","opts":["Two people signing a document","Multiple people editing the same OneDrive or SharePoint file at the same time, seeing each other's changes live","Emailing a file back and forth","Printing two copies of a document"],"correct":1,"exp":"Files stored in the cloud can be edited simultaneously, no more 'final_v7_REAL.docx' email chains."},{"q":"Version history in OneDrive and SharePoint allows you to:","opts":["See who is online in Teams","Change your password","View and restore earlier versions of a file after unwanted changes","Compress files to save space"],"correct":2,"exp":"Version history is your safety net, restore yesterday's version of a report even after someone overwrote it."},{"q":"The main difference between OneDrive and SharePoint is:","opts":["OneDrive is personal file storage while SharePoint hosts shared team and organizational sites","OneDrive is free while SharePoint costs extra per file","OneDrive only stores photos","SharePoint only works offline"],"correct":0,"exp":"Save personal working files to OneDrive; put team documents on SharePoint so they belong to the organization, not one person."},{"q":"In Outlook, BCC should be used when:","opts":["You want all recipients to see each other's addresses","The email is urgent","You are replying to your manager only","Sending to many external recipients whose addresses should stay hidden from each other"],"correct":3,"exp":"BCC protects recipient privacy, essential when emailing a mailing list of clients or applicants."},{"q":"An Outlook rule can automatically:","opts":["Write replies using your voice","Move incoming messages that meet conditions (like a sender or keyword) into a specific folder","Delete your calendar","Change your email address"],"correct":1,"exp":"Rules keep a busy inbox organized, for example, filing every message from a donor into its project folder."},{"q":"A professional email signature should include:","opts":["Your name, title, organization, and contact details","Your favorite quotes and multiple decorative images","Your personal bank account details","Nothing, signatures are unprofessional"],"correct":0,"exp":"A clean signature identifies you and makes it easy for contacts to reach you, set it once in Outlook settings."},{"q":"In Microsoft Teams, a 'channel' is:","opts":["A private phone line","A dedicated space within a team for conversations and files about one topic or project","A television station","A type of emoji"],"correct":1,"exp":"Channels organize a team's work by topic, for example Finance, Field Reports, and General within one NGO team."},{"q":"Sending a link to a file on OneDrive instead of attaching the file means:","opts":["The recipient can never open it","The email will be rejected","Everyone works on one up-to-date copy and you can control permissions","The file is automatically printed"],"correct":2,"exp":"Shared links avoid duplicate copies and let you set view-only or edit access, and revoke it later."},{"q":"Which shortcut switches between open applications in Windows?","opts":["Ctrl+B","Alt+Tab","Ctrl+P","F7"],"correct":1,"exp":"Alt+Tab jumps between Word, Excel, and your browser instantly, a core habit of fast office workers."},{"q":"When sending a meeting invitation in Outlook, the calendar invite automatically:","opts":["Books flights for attendees","Deletes conflicting emails","Prints an agenda","Adds the meeting to recipients' calendars when they accept, with time, location, or Teams link"],"correct":3,"exp":"Calendar invites replace back-and-forth scheduling emails and can include a Teams meeting link for remote attendees."}]},"mod5":{"title":"Quiz: Advanced Excel & Automation","moduleNum":5,"questions":[{"q":"One advantage XLOOKUP has over VLOOKUP is that XLOOKUP:","opts":["Can return values from a column to the left of the lookup column","Only works on numbers","Requires counting columns manually","Is available in every Excel version since 1995"],"correct":0,"exp":"XLOOKUP searches in any direction and points directly at the return range, unlike VLOOKUP's rightward-only, column-counting design."},{"q":"In the combination INDEX-MATCH, what does MATCH return?","opts":["The value itself","The position of a value within a range","The color of the cell","The number of matches found"],"correct":1,"exp":"MATCH finds the position; INDEX then returns the value at that position, together forming a flexible lookup."},{"q":"A named range improves a workbook by:","opts":["Making files smaller","Encrypting the data","Automatically charting the data","Making formulas readable, like =SUM(Salaries) instead of =SUM(D2:D200)"],"correct":3,"exp":"Named ranges make formulas self-explanatory, reducing errors and helping colleagues understand your work."},{"q":"The TRIM function is used to:","opts":["Shorten a document's page count","Delete duplicate rows","Remove extra spaces from text, which often cause lookups to fail","Cut a chart to fit a slide"],"correct":2,"exp":"Invisible extra spaces are a classic cause of #N/A lookup errors, TRIM removes them."},{"q":"Before using Remove Duplicates on important data you should:","opts":["Keep a copy of the raw data on another sheet","Print the file first","Email the file to your manager","Convert all text to uppercase"],"correct":0,"exp":"Professional practice is never to destroy raw data, clean a working copy so the original remains traceable."},{"q":"A Data Validation dropdown list on a County column ensures that:","opts":["The column sorts itself alphabetically","Only approved county names can be entered, eliminating spelling errors","The column is hidden from other users","Each county appears only once"],"correct":1,"exp":"Validation prevents bad data at the point of entry, far cheaper than cleaning it later."},{"q":"The main benefit of Power Query over manual copy-paste consolidation is:","opts":["It changes cell colors automatically","It works without opening Excel","It makes presentations from data","Recorded transformation steps replay automatically on new data with one refresh"],"correct":3,"exp":"Power Query records steps once and reapplies them to fresh data, turning hours of monthly work into a click."},{"q":"A recorded macro is best suited for:","opts":["Repetitive formatting and workflow routines you perform the same way each time","Creative writing tasks","Sending mobile money payments","Designing logos"],"correct":0,"exp":"Macros replay recorded actions exactly, so consistent repetitive routines are the ideal use case."},{"q":"An Excel file containing macros is saved with which extension?","opts":[".xlsx",".pdf",".xlsm",".docm"],"correct":2,"exp":".xlsm marks a macro-enabled workbook; Excel applies extra security because macros can carry malicious code."},{"q":"Why does Excel warn you before enabling macros from an unknown source?","opts":["Macros always slow the computer down","Macros can contain malicious code, so only trusted files should have them enabled","Macros expire after 30 days","Macros only run on licensed printers"],"correct":1,"exp":"Macro malware is a real attack method, enable macros only in files from people and systems you trust."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"I knew the basics before this course but Samuel took me to a completely new level. The advanced Excel module specifically, pivot tables and VLOOKUP, got me promoted to a data reporting role. Excellent investment."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"The mail merge module alone saved me 4 hours of work every month. The PowerPoint slide master section transformed my presentations from amateur to professional overnight. My clients now specifically comment on presentation quality."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"Most comprehensive Office training available in Liberia. I learned features in this course that I didn't know existed after 5 years using Office. The Microsoft 365 collaboration module is now essential knowledge in every workplace."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":4,"text":"Very practical course. The keyboard shortcuts module doubled my productivity. I now teach these skills to junior staff at my organization. The certificate is a strong addition to any CV in the Liberian job market."}],"faqs":[{"q":"Do I need to buy Microsoft Office?","a":"Microsoft 365 Personal costs about $70/year and includes all apps plus 1TB OneDrive storage. A free 30-day trial covers the entire course. Many employers also provide Office licenses."},{"q":"Is this different from the Computer Literacy course?","a":"The Computer Literacy course covers Office at a basic introductory level. This course goes into advanced features of each application comprehensively, it's the deep-dive version."},{"q":"Will Office skills help me get a job?","a":"Almost every office job in Liberia requires Word, Excel, and PowerPoint proficiency. Listing Microsoft Office competency on your CV is table stakes for administrative, finance, and management roles."},{"q":"Does this cover Google Workspace too?","a":"This course focuses on Microsoft Office specifically. If you need Google Workspace skills, our Data Analytics course covers Google Sheets in detail."}]};
COURSES_DB['leadership'] = {"id":"leadership","title":"Business Leadership Masterclass","shortDesc":"For emerging and experienced leaders, develop emotional intelligence, build high-performing teams, lead change, and create a personal leadership plan that drives lasting impact.","category":"Leadership","icon":"🎯","gradient":"linear-gradient(135deg,#78350f,#b45309)","instructor":"Dr. Mary Weah","instructorTitle":"Business Strategy Consultant & Executive Coach","instructorBio":"Dr. Mary Weah holds an MBA and PhD in Organizational Leadership with 20 years advising C-suite executives, government ministers, and NGO directors across West Africa. She is TIH's highest-rated instructor and a leading voice on African leadership.","rating":4.9,"reviewCount":341,"students":"2,700+","duration":"28h","level":"All Levels","price":"FREE","origPrice":"$180","isFree":true,"badge":"free","certId":"TIH-2026-LD-0099","learn":["Understand your personal leadership style and how to develop it intentionally","Build high-performing teams and motivate people toward shared goals","Communicate with executive presence and influence stakeholders effectively","Lead through change and guide organizations through transformation","Apply strategic thinking and decision-making frameworks","Manage conflict, build consensus, and negotiate effectively","Develop emotional intelligence and self-awareness as a leader","Create a personal leadership development plan for continued growth"],"requirements":["No formal leadership experience required, this course develops leaders at all levels","An openness to honest self-assessment and personal growth","Some work experience (professional, community, or organizational) is helpful"],"about":["Leadership is the most critical capability gap in African organizations today. Technical skills get you hired, but leadership skills determine how far you go and how much impact you have. This masterclass develops both the strategic and human dimensions of exceptional leadership.","Drawing on globally proven leadership frameworks (situational leadership, emotional intelligence, transformational leadership) applied to African organizational contexts, this course is both rigorous and immediately practical. Every concept is applied to real leadership situations you face.","Whether you lead 2 people or 2,000, in business, government, civil society, or your community, this course will transform how you lead. Our graduates hold positions from team leader to CEO and consistently credit this course as a turning point in their leadership journey."],"modules":[{"title":"Module 1: Leadership Foundations & Self-Awareness","icon":"🎯","meta":"4 lessons · 38 min","lessons":[{"t":"1.1 What is Leadership? Styles, Theories & the African Context","d":"9:30","v":"tYW6X5qwnMw"},{"t":"1.2 Self-Assessment: Your Leadership Strengths & Gaps","d":"10:00","v":"Q-JClqIR5a4"},{"t":"1.3 Emotional Intelligence: The Foundation of Effective Leadership","d":"10:00","v":"kKbTi9_1lTg"},{"t":"📝 Quiz: Leadership Foundations","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Team Leadership & People Management","icon":"👥","meta":"4 lessons · 42 min","lessons":[{"t":"2.1 Building High-Performing Teams: Selection, Trust & Culture","d":"11:00","v":"L4UTybPoyn4"},{"t":"2.2 Motivation, Delegation & Accountability","d":"11:30","v":"SI6cOkDOoyE"},{"t":"2.3 Managing Conflict & Building Consensus","d":"11:00","v":"o0w1941xkjY"},{"t":"📝 Quiz: Team Leadership","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Strategic Leadership & Communication","icon":"📡","meta":"4 lessons · 44 min","lessons":[{"t":"3.1 Strategic Thinking & Decision-Making Frameworks","d":"11:30","v":"LerIITWNgvI"},{"t":"3.2 Executive Communication & Stakeholder Influence","d":"11:30","v":"0X1FiNxlHh0"},{"t":"3.3 Leading Change & Organizational Transformation","d":"12:00","v":"AAZgoKAqGE0"},{"t":"🛠️ Project: Personal Leadership Development Plan","d":"Project","isProject":true}]},{"title":"Module 4: Ethical Leadership, Cross-Cultural Leading & Developing Future Leaders","icon":"🏆","meta":"4 lessons · 36 min","lessons":[{"t":"4.1 Ethical Leadership & Corporate Governance","d":"9:30","v":"XjiRF_6cvcA"},{"t":"4.2 Leading Across Cultures & Generations","d":"9:00","v":"cyGuic7_ivo"},{"t":"4.3 Building Leadership Legacy & Developing Future Leaders","d":"9:00","v":"f8uw94S-yc4"},{"t":"📝 Quiz: Ethical Leadership & Leading Across Cultures","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Coaching, Feedback & Performance Leadership","icon":"🗣️","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Coaching Skills: The GROW Model & Powerful Questions","d":"Video + notes","v":"_TMM0lhukBg"},{"t":"5.2 Feedback That Builds People: The SBI Model & Feedback Culture","d":"Video + notes","v":"t3GjwVWapGo"},{"t":"5.3 Managing Performance & Difficult Conversations","d":"Video + notes","v":"GsRgHt4IIBU"},{"t":"📝 Quiz: Coaching, Feedback & Performance","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Crisis Leadership & Your Leadership Brand","icon":"🧭","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Leading Through Crisis & Uncertainty","d":"Video + notes","v":"eBXm0_8-rwU"},{"t":"6.2 Your Personal Leadership Brand & Executive Career","d":"Video + notes","v":"mBRHe1sRiZM"},{"t":"6.3 Capstone Project: Leading a Real Initiative & Measuring Your Impact","d":"Video + notes","v":"_zAiKx69kE0"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Leadership Foundations","moduleNum":1,"unlocks":3,"questions":[{"q":"What differentiates a leader from a manager?","opts":["Leaders have higher salaries","Leaders inspire people toward a vision while managers oversee processes and systems","Leaders are more qualified","Leaders only work in large organizations"],"correct":1,"exp":"Management is about efficiency; leadership is about effectiveness, inspiring people toward meaningful change."},{"q":"Emotional Intelligence (EQ) in leadership includes:","opts":["Technical expertise only","Self-awareness, self-regulation, empathy, and social skills","High academic qualifications","Physical fitness"],"correct":1,"exp":"EQ is widely considered more important than IQ for leadership effectiveness, especially in people management."},{"q":"Transformational leadership focuses on:","opts":["Maintaining the status quo through rules","Inspiring followers to exceed expected performance by appealing to higher ideals","Transactional rewards only","Authoritative command and control"],"correct":1,"exp":"Transformational leaders create vision and inspire intrinsic motivation to achieve extraordinary results."},{"q":"What is \"servant leadership\"?","opts":["Leaders who serve food to their team","A leadership philosophy where the leader's primary goal is to serve others and enable their growth","Weak leadership that lacks authority","Leadership only in nonprofit organizations"],"correct":1,"exp":"Servant leaders put their people first, Robert Greenleaf's concept is highly effective in African community contexts."},{"q":"Self-awareness in leadership means:","opts":["Knowing all technical skills","Having an accurate understanding of your own strengths, weaknesses, emotions, and impact on others","Being self-centered","Having high confidence regardless of feedback"],"correct":1,"exp":"Self-aware leaders make better decisions, build stronger relationships, and develop more effectively."},{"q":"Situational leadership theory teaches that effective leaders:","opts":["Use one consistent style in every situation","Adapt their style, directing, coaching, supporting, or delegating, to the readiness of each team member","Always delegate everything","Lead only when the situation is favorable"],"correct":1,"exp":"A new employee may need directing while an experienced one thrives on delegation, the leader flexes, not the follower."},{"q":"In emotional intelligence, self-regulation refers to:","opts":["Controlling other people's emotions","Following government regulations","Managing your own impulses and emotions so you respond thoughtfully rather than react","Suppressing all feelings at work"],"correct":2,"exp":"Leaders who pause before reacting under pressure build trust; explosive reactions destroy it."},{"q":"The Ubuntu philosophy often cited in African leadership emphasizes:","opts":["Individual achievement above all","Strict hierarchy and command","Leading only through formal authority","Shared humanity, 'I am because we are', grounding leadership in community and mutual care"],"correct":3,"exp":"Ubuntu frames leadership as service to collective wellbeing, resonating deeply with West African organizational culture."},{"q":"A leader with a 'blind spot' is someone who:","opts":["Has a weakness or behavior others can see but they themselves cannot","Cannot read reports","Refuses to attend meetings","Works only at night"],"correct":0,"exp":"Blind spots are revealed through honest feedback and tools like 360-degree reviews, which is why self-aware leaders actively seek input."},{"q":"Which statement about leadership and formal position is most accurate?","opts":["Only people with titles can lead","Leadership requires a government appointment","Leadership is influence, a person without any title can lead through example, initiative, and credibility","Leadership automatically comes with promotion"],"correct":2,"exp":"Influence, not position, defines leadership; many people hold titles yet lead no one, while others lead powerfully without titles."}]},"mod2":{"title":"Quiz: Team Leadership","moduleNum":2,"unlocks":3,"questions":[{"q":"Psychological safety in a team means:","opts":["A physically safe workplace","Team members feel safe to take risks, speak up, and be vulnerable without fear of punishment","Having a safe storage room","Using secure communication tools"],"correct":1,"exp":"Google's Project Aristotle found psychological safety to be the #1 factor in high-performing teams."},{"q":"Effective delegation requires:","opts":["Doing everything yourself to ensure quality","Assigning tasks with clear expectations, authority, and support for the person to succeed","Only assigning easy tasks","Micromanaging every step"],"correct":1,"exp":"Delegation develops team members, frees leadership bandwidth, and builds organizational capability."},{"q":"The best approach to managing conflict is:","opts":["Ignoring conflicts until they resolve themselves","Addressing conflicts directly, early, and with focus on interests rather than positions","Always siding with the senior person","Letting the team vote on every conflict"],"correct":1,"exp":"Interest-based conflict resolution finds solutions that address the underlying needs of all parties."},{"q":"A high-performing team is characterized by:","opts":["Having the most talented individuals","Clear shared purpose, trust, complementary skills, and mutual accountability","The highest salaries","Working the most hours"],"correct":1,"exp":"Team performance is about dynamics and synergy, diverse teams with trust and shared purpose outperform collections of stars."},{"q":"Accountability in leadership means:","opts":["Blaming others for failures","Taking responsibility for outcomes, yours and your team's, and creating a culture of ownership","Punishing poor performance harshly","Setting performance goals only"],"correct":1,"exp":"Accountable leaders model responsibility, create clarity, and build cultures where people own their commitments."},{"q":"According to Tuckman's model, teams typically develop through which sequence of stages?","opts":["Forming, Storming, Norming, Performing","Planning, Doing, Checking, Acting","Hiring, Training, Working, Retiring","Storming, Forming, Performing, Norming"],"correct":0,"exp":"New teams form, clash as they storm, settle norms, and only then perform, leaders should expect and manage the storm."},{"q":"Intrinsic motivation comes from:","opts":["Salary increases only","Fear of punishment","Pressure from supervisors","Internal drivers such as purpose, mastery, and pride in meaningful work"],"correct":3,"exp":"Money matters, but purpose and growth sustain effort long after a pay raise is forgotten."},{"q":"When delegating, a leader should delegate:","opts":["Only the tasks nobody wants","The authority and information needed to complete the task, not just the task itself","The blame if things fail","Tasks without explaining the expected outcome"],"correct":1,"exp":"Responsibility without authority sets people up to fail; real delegation transfers ownership with support."},{"q":"A practical first step for building trust in a new team is:","opts":["Keeping information secret to maintain power","Testing members with impossible deadlines","Consistently doing what you say you will do, starting with small commitments","Avoiding all difficult conversations"],"correct":2,"exp":"Trust is built through reliability, kept promises, however small, compound into credibility."},{"q":"In interest-based conflict resolution, a 'position' differs from an 'interest' because:","opts":["A position is what someone demands, while an interest is the underlying need behind the demand","Positions are always financial","Interests are only for managers","There is no real difference"],"correct":0,"exp":"Two staff may both demand the same office (positions) but need quiet and client access respectively (interests), interests can often both be met."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Strategic thinking involves:","opts":["Only focusing on today's operational problems","Understanding the big picture, anticipating future trends, and making decisions aligned with long-term goals","Making the fastest possible decisions","Following industry best practices exactly"],"correct":1,"exp":"Strategic leaders balance short-term execution with long-term vision and environmental awareness."},{"q":"Change management in organizations requires leaders to:","opts":["Announce changes and expect immediate compliance","Create urgency, build a coalition, communicate a clear vision, and enable quick wins","Implement changes secretly to avoid resistance","Delay change until everyone agrees"],"correct":1,"exp":"Kotter's 8-Step Change Model shows that successful change requires a structured, people-centered approach."},{"q":"Executive presence is best described as:","opts":["Physical height and appearance","The combination of gravitas, communication skills, and appearance that conveys confidence and inspires trust","Wearing expensive clothing","Having a corner office"],"correct":1,"exp":"Executive presence is a learnable skill combining confidence, clarity, decisiveness, and authentic authority."},{"q":"Ethical leadership primarily means:","opts":["Following all company rules exactly","Leading with integrity, making decisions based on values, fairness, and transparency regardless of pressure","Only following religious principles","Avoiding all risks"],"correct":1,"exp":"Ethical leaders build organizations where people trust leadership and take pride in the organization's reputation."},{"q":"Building leadership legacy means:","opts":["Having the most impressive job title","Developing other leaders who continue and expand your positive impact beyond your tenure","Staying in a position as long as possible","Building personal wealth through leadership positions"],"correct":1,"exp":"The greatest leaders are judged by the next generation of leaders they develop and the lasting change they create."},{"q":"A leader using situational leadership would give a brand-new intern:","opts":["More direction and closer instruction than an experienced senior officer","Full delegation with no check-ins","Exactly the same treatment as everyone else","Only written policies to read"],"correct":0,"exp":"Style follows readiness: low experience calls for directing and coaching, high competence earns delegation."},{"q":"A leader who receives upsetting news and pauses to respond calmly rather than exploding is demonstrating:","opts":["Weak authority","Self-regulation, a core emotional intelligence competency","Indecisiveness","Avoidance of responsibility"],"correct":1,"exp":"Self-regulation converts emotional reaction into thoughtful response, a defining EQ skill for leaders."},{"q":"During Tuckman's storming stage, an effective leader should:","opts":["Disband the team immediately","Punish anyone who disagrees","Ignore the conflict until it disappears","Expect the conflict, surface it openly, and guide the team toward shared norms"],"correct":3,"exp":"Storming is a normal development stage; teams that never work through it never reach performing."},{"q":"Delegating a task while withholding the authority and information needed to complete it results in:","opts":["Faster delivery","Stronger accountability","Setting the person up to fail while responsibility stays unclear","Automatic skill development"],"correct":2,"exp":"Real delegation transfers ownership with authority and support, otherwise it is merely assigning blame in advance."},{"q":"Two department heads both demand the organization's only vehicle next week. An interest-based leader first:","opts":["Gives it to the more senior head","Asks what each actually needs to accomplish, since the underlying needs may both be met another way","Removes the vehicle from both","Lets them argue until one gives up"],"correct":1,"exp":"Positions clash; interests often coexist, one may need document delivery that a motorbike courier could handle."},{"q":"In Kotter's change model, creating 'short-term wins' matters because they:","opts":["Replace the need for a vision","Allow the leader to declare the change finished early","End the need for communication","Provide visible proof the change is working, sustaining momentum and silencing doubters"],"correct":3,"exp":"Early visible wins convert skeptics and energize supporters through the long middle of any transformation."},{"q":"A procurement officer's brother submits a bid for a contract she will help evaluate. She should:","opts":["Declare the conflict of interest and withdraw from evaluating that bid","Evaluate it but score it slightly lower to be safe","Keep quiet since family ties are normal","Reject the bid without process"],"correct":0,"exp":"Declaring and stepping aside protects the process, the organization, and her own reputation simultaneously."},{"q":"An organization where staff are afraid to report wrongdoing will most likely:","opts":["Become more efficient","Have fewer real problems","Suffer growing hidden problems until they explode publicly","Attract more donors"],"correct":2,"exp":"Suppressing bad news does not eliminate it, ethical leaders protect truth-tellers so problems surface early."},{"q":"When a Liberian team begins working with new international partners, high cultural intelligence looks like:","opts":["Insisting the partners adopt local norms entirely","Abandoning all local practices immediately","Avoiding interaction to prevent misunderstandings","Observing differences curiously, asking questions, and adapting communication on both sides"],"correct":3,"exp":"CQ is active adaptation and mutual learning, neither surrender nor rigidity."},{"q":"In a GROW coaching conversation, exploring 'Reality' means asking:","opts":["What is actually happening now and what have you already tried?","What is your five-year dream?","Which option will you commit to?","Who should be blamed for this?"],"correct":0,"exp":"Reality grounds the conversation in facts and prior attempts before options are generated."},{"q":"Which feedback statement follows the SBI model correctly?","opts":["You are the laziest person on this team","Everyone thinks you have an attitude problem","During Friday's field visit, when you arrived an hour late, the community meeting started without our data and we lost credibility","You must simply try harder next time"],"correct":2,"exp":"Situation (Friday's visit), behavior (arrived an hour late), impact (lost credibility), factual, specific, and discussable."},{"q":"The primary purpose of monthly one-to-one check-ins is to:","opts":["Catch staff making mistakes","Replace all team meetings","Surface progress, obstacles, and support needs continuously so reviews hold no surprises","Satisfy donor reporting requirements"],"correct":2,"exp":"Continuous conversation makes performance management developmental rather than an annual ambush."},{"q":"In the first hours of an organizational crisis, the leader's ordering of priorities should begin with:","opts":["People's safety, then a fixed communication rhythm, then operational decisions","Protecting equipment and inventory first","Finding who caused the crisis","Drafting the press release before checking on staff"],"correct":0,"exp":"People first, then structured communication, trust built in those hours determines everything after."},{"q":"'Deciding at 70% information' during a crisis means:","opts":["Guessing randomly to appear decisive","Making timely decisions with reasonable information because waiting for certainty is itself a costly decision","Letting 70% of staff vote","Delaying all decisions until data is complete"],"correct":1,"exp":"Crises punish paralysis; leaders act on good-enough information, moving fast on reversible calls and carefully on irreversible ones."},{"q":"The strongest evidence of a leader's brand and readiness for promotion is:","opts":["Confident self-description in interviews","Seniority and years served alone","An impressive job title on a business card","A portfolio of measured results, people developed, and documented initiatives, told through STAR stories"],"correct":3,"exp":"Evidence beats assertion, documented impact and grown people are the currency of leadership careers."}]},"mod4":{"title":"Quiz: Ethical Leadership & Leading Across Cultures","moduleNum":4,"questions":[{"q":"A conflict of interest exists when:","opts":["Two staff members disagree in a meeting","A leader's personal interests could improperly influence their official decisions, such as awarding a contract to a relative","A budget has competing priorities","Two departments want the same vehicle"],"correct":1,"exp":"Conflicts of interest must be declared openly so decisions remain, and appear, impartial."},{"q":"Corporate governance primarily concerns:","opts":["The design of company logos","Daily supervision of junior staff","The systems by which organizations are directed and held accountable, including board oversight of management","Government ownership of companies"],"correct":2,"exp":"Governance structures, boards, audits, policies, ensure leaders act in the organization's interest, not their own."},{"q":"An employee who reports serious wrongdoing inside their organization through proper channels is called:","opts":["A whistleblower","A saboteur","A consultant","An auditor"],"correct":0,"exp":"Ethical leaders protect whistleblowers, because organizations that punish truth-tellers soon hear no truth at all."},{"q":"When facing pressure to approve an improper payment to 'speed things up', an ethical leader should:","opts":["Approve it if the amount is small","Approve it but keep no record","Ask a junior staff member to handle it instead","Refuse, document the request, and follow the organization's reporting procedure"],"correct":3,"exp":"Integrity is tested precisely when refusal is costly; small compromises establish a price for larger ones."},{"q":"Cultural intelligence (CQ) is best defined as:","opts":["Knowing facts about many countries","Speaking several languages fluently","The capability to function effectively across different cultural contexts by observing, adapting, and learning","Preferring international staff over local staff"],"correct":2,"exp":"CQ combines knowledge, motivation, and behavioral flexibility, critical when Liberian teams work with international partners."},{"q":"In a high power-distance culture, junior staff may hesitate to challenge a leader's ideas. A wise leader responds by:","opts":["Deliberately inviting dissenting views and rewarding those who speak up","Assuming silence means full agreement","Speaking more forcefully so staff comply faster","Only consulting other senior leaders"],"correct":0,"exp":"Where hierarchy discourages open challenge, leaders must actively create safe channels for honest input or decisions go untested."},{"q":"When leading a team spanning older and younger generations, effective leaders:","opts":["Apply the communication style of the oldest member to everyone","Learn each person's preferences and flex between channels and styles rather than stereotyping by age","Separate the generations into different teams","Require all communication in writing only"],"correct":1,"exp":"Generational labels are starting points, not rules, leaders adapt to individuals while bridging style differences."},{"q":"Succession planning means:","opts":["Planning the leader's retirement party","Writing a will for company property","Deliberately identifying and developing people who can fill key roles when current holders move on","Promoting only family members"],"correct":2,"exp":"Organizations that depend on one irreplaceable person are fragile; succession planning is legacy work done early."},{"q":"The most effective way to develop a future leader on your team is to:","opts":["Tell them to observe you silently for five years","Protect them from all difficult assignments","Wait until they are promoted before developing them","Give them stretch assignments with real responsibility, plus coaching and honest feedback"],"correct":3,"exp":"People grow through challenge supported by guidance, experience plus reflection, not observation alone."},{"q":"Transparency in ethical leadership means:","opts":["Sharing decisions, criteria, and information openly so people can understand and scrutinize how choices are made","Publishing every staff member's salary on social media","Having glass office walls","Telling everyone everything regardless of confidentiality"],"correct":0,"exp":"Transparency is openness about how and why decisions are made, balanced with legitimate confidentiality, it builds durable trust."}]},"mod5":{"title":"Quiz: Coaching, Feedback & Performance","moduleNum":5,"questions":[{"q":"The core discipline of coaching, as opposed to mentoring or training, is:","opts":["Sharing your own experience in detail","Asking questions that help the person find their own answers rather than giving them","Correcting mistakes immediately","Providing written manuals"],"correct":1,"exp":"Coaches unlock thinking through questions; answers people reach themselves are owned more deeply."},{"q":"In the GROW model, the letters stand for:","opts":["Goal, Reality, Options, Will","Guide, Review, Order, Work","Goal, Rules, Obstacles, Wisdom","Growth, Resources, Output, Wins"],"correct":0,"exp":"GROW moves from desired outcome through current reality and possible options to a committed action."},{"q":"Which is the most powerful coaching question?","opts":["Did you finish the report?","Don't you think you should ask finance first?","What options have you considered?","Why are you always late with this?"],"correct":2,"exp":"Powerful questions are open and curious; closed or leading questions hide advice or accusation."},{"q":"In the SBI feedback model, the B stands for describing:","opts":["The person's character and attitude","Your feelings about the person","The organization's budget","The specific observable behavior, without interpretation"],"correct":3,"exp":"Describing observable behavior, not judging character, is what keeps feedback factual and non-threatening."},{"q":"Which statement is a correct SBI-style feedback opening?","opts":["You are unreliable and unprofessional","In Monday's staff meeting, when you presented the field data with clear charts, the county team immediately approved the plan","Everyone says you have a bad attitude","You need to change or face consequences"],"correct":1,"exp":"It names the situation, the observable behavior, and the impact, and it shows SBI works for positive feedback too."},{"q":"When a leader receives critical feedback in front of the team, the best response is to:","opts":["Defend each point immediately","Identify who complained and address them later","Listen fully, ask a clarifying question, thank the person, and visibly act on what is valid","Ignore it to preserve authority"],"correct":2,"exp":"How leaders receive feedback determines whether they keep hearing the truth."},{"q":"A SMART performance objective is:","opts":["Ambitious and deliberately vague to allow flexibility","Set secretly by the supervisor","Changed weekly to keep staff alert","Specific, measurable, achievable, relevant, and time-bound"],"correct":3,"exp":"SMART objectives make performance discussions factual, both parties can see whether the target was met."},{"q":"Why should performance never be a surprise at the annual review?","opts":["Because regular monthly check-ins should have surfaced issues and progress long before","Because annual reviews are illegal","Because staff should review themselves only","Because surprises are culturally acceptable"],"correct":0,"exp":"Continuous check-ins mean the annual review confirms what both already know, fairness requires no ambushes."},{"q":"Before responding to underperformance, a leader should first diagnose its cause because:","opts":["Diagnosis delays the uncomfortable conversation","It transfers responsibility to HR","A skills gap, a personal crisis, and a motivation problem each require completely different responses","All underperformance has the same solution"],"correct":2,"exp":"Training fixes skill gaps, flexibility helps crises, expectations address motivation, the wrong remedy fixes nothing."},{"q":"A fair performance improvement plan should include:","opts":["Only verbal warnings with no record","An immediate salary cut","A vague promise to do better","Written expectations, support provided, review dates, and clear consequences over a defined period such as 30-90 days"],"correct":3,"exp":"Written, time-bound plans with support and follow-through protect both the employee and the organization."}]}},"reviews":[{"name":"Fatima Kamara","loc":"Monrovia, Liberia","date":"May 2026","bg":"#002868","init":"FK","rating":5,"text":"Dr. Weah is simply magnificent. This course fundamentally changed how I lead my team. The emotional intelligence module showed me blind spots I never knew I had. My team's performance and morale have both improved dramatically."},{"name":"Joseph Blamo","loc":"Buchanan, Liberia","date":"April 2026","bg":"#E31E24","init":"JB","rating":5,"text":"I have taken leadership training from international consultants at 3 times the price of this course, nothing has been as practical and immediately applicable. The African context throughout makes this course uniquely relevant and valuable."},{"name":"Mary Kolie","loc":"Gbarnga, Liberia","date":"March 2026","bg":"#10b981","init":"MK","rating":5,"text":"The strategic thinking module gave me tools I use in every major decision. The personal leadership development plan was a transformative exercise. I now mentor 5 younger women in leadership because of the inspiration this course gave me."},{"name":"Thomas Sirleaf","loc":"Harper, Maryland County","date":"June 2026","bg":"#7c3aed","init":"TS","rating":5,"text":"One of the most valuable learning experiences of my career. Dr. Weah combines academic rigor with deep practical wisdom. I was promoted to Regional Director 4 months after completing this course. The timing was not a coincidence."}],"faqs":[{"q":"Is this course only for people who already lead teams?","a":"No. This course is valuable at every career stage. Many of the most impactful leadership skills, like emotional intelligence and strategic thinking, are best developed early in your career."},{"q":"How is African leadership different?","a":"African organizations often blend formal authority with community values, elder respect, and Ubuntu philosophy. Dr. Weah addresses these unique dynamics throughout the course rather than simply transplanting Western frameworks."},{"q":"What if I lead a small team or community organization?","a":"This course is directly applicable to any group of people, 2 to 2,000. The principles of trust, vision, accountability, and development apply equally to a village committee or a multinational corporation."},{"q":"Will this help me get promoted?","a":"Leadership skills are the most commonly cited factor in promotion decisions. This course improves your communication, decision-making, team management, and strategic thinking, all criteria by which advancement is assessed."}]};
COURSES_DB['grant-writing'] = {"id":"grant-writing","title":"Grant Writing & Fundraising","shortDesc":"Find donors, write winning proposals, and manage grants professionally, build logic models, budgets, and M&E plans that unlock funding from USAID, EU, and foundations in Liberia.","category":"Business & Fundraising","icon":"💰","gradient":"linear-gradient(135deg,#065f46,#10b981)","instructor":"Miatta S. Freeman","instructorTitle":"Grants & Partnerships Director, West Africa Impact Alliance","instructorBio":"Miatta S. Freeman has raised over $4.2 million for Liberian and West African NGOs, winning grants from USAID, the EU, UNDP, and the Mastercard Foundation. Based in Monrovia, she has trained hundreds of community organizations from Paynesville to Ganta in professional proposal development.","rating":4.8,"reviewCount":486,"students":"3,200+","duration":"30h","level":"Intermediate","price":"FREE","origPrice":"$150","isFree":true,"badge":"free","certId":"TIH-2026-GRW-0001","learn":["Understand how grants work and who funds projects in Liberia, USAID, EU, UNDP, Mastercard Foundation and more","Find real, current grant opportunities using free online databases and donor websites","Read calls for proposals correctly and judge your organization's eligibility before you apply","Build a logic model and theory of change that clearly connects activities to impact","Write compelling, data-backed needs statements about your community","Set SMART objectives and design activities donors can measure and trust","Prepare professional grant budgets in USD and LRD with realistic unit costs","Write, submit, and follow up on a complete proposal, and manage donor relationships after you win"],"requirements":["Comfortable reading and writing English at a professional level (grant proposals are written documents)","Access to a computer or smartphone with internet, a computer is strongly recommended for the capstone proposal","Basic familiarity with Word and Excel, or completion of the TIH Computer Literacy course"],"about":["Every year, millions of dollars in grant funding flows into Liberia and West Africa from donors like USAID, the European Union, UNDP, UNICEF, the Mastercard Foundation, and the Open Society Foundations. Yet many community organizations in Monrovia, Paynesville, Buchanan, and beyond never win a single grant, not because their work lacks value, but because nobody taught them how to write a proposal the way donors expect. This course fixes that.","You will move step by step through the full grant cycle: understanding who funds what, finding live opportunities, checking eligibility, building a logic model and theory of change, writing needs statements and SMART objectives, budgeting in both USD and Liberian dollars, drafting the full narrative, planning monitoring and evaluation, and managing the donor relationship after submission. The capstone challenges you to write a complete, realistic $10,000 grant proposal you can adapt and actually submit.","This is an intermediate course built on real West African examples, real donor names, real budget lines priced in Liberian markets, real reporting expectations. Whether you run a youth group in Gbarnga, a women's cooperative in Kakata, or an NGO in Sinkor, by the end you will have a fundable proposal in your hands and the confidence to keep winning."],"modules":[{"title":"Module 1: The Grant Landscape, Donors, Opportunities & Eligibility","icon":"🌍","meta":"4 lessons · 31 min","lessons":[{"t":"1.1 What Grants Are & Who Funds Them: USAID, EU, UNDP & Foundations","d":"10:00","v":"GMsl-wR-wmM"},{"t":"1.2 Finding Grant Opportunities: Databases, Calls & Donor Websites","d":"11:30","v":"tL6V3hNdbVY"},{"t":"1.3 Eligibility & Donor Priorities: Reading a Call for Proposals","d":"9:00","v":"VCvIlKM39-w"},{"t":"📝 Quiz: The Grant Landscape","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Designing a Fundable Project","icon":"🧩","meta":"4 lessons · 32 min","lessons":[{"t":"2.1 Logic Models & Theory of Change: From Inputs to Impact","d":"12:00","v":"lYi30bL0AMo"},{"t":"2.2 Writing a Compelling Needs Statement with Real Data","d":"10:30","v":"GH7lLHcshqQ"},{"t":"2.3 SMART Objectives & Activities Donors Can Measure","d":"9:30","v":"ENxQLZO0sRw"},{"t":"📝 Quiz: Project Design Essentials","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Budgets & the Full Proposal","icon":"✍️","meta":"3 lessons · 27 min","lessons":[{"t":"3.1 Grant Budgeting: Unit Costs, USD/LRD & What Donors Will Pay For","d":"13:00","v":"0nIf9hqrBzc"},{"t":"3.2 Writing the Full Proposal Narrative, Step by Step","d":"14:00","v":"ByQRri_LTUE"},{"t":"🛠️ Capstone: Write a Full $10,000 Grant Proposal","d":"Project","isProject":true}]},{"title":"Module 4: M&E, Submission & Donor Relations","icon":"🏆","meta":"3 lessons · 21 min","lessons":[{"t":"4.1 Monitoring & Evaluation Plans: Indicators, Targets & Reporting","d":"11:00","v":"Yp9VxTWMj7g"},{"t":"4.2 Submission, Follow-Up & Building Long-Term Donor Relationships","d":"9:30","v":"emhvQrFbNBA"},{"t":"📝 Quiz: M&E, Submission & Donor Relations","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Grant Management & Donor Compliance","icon":"📋","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Understanding Grant Agreements & Compliance Rules","d":"Video + notes","v":"mW4JgyCQ8EI"},{"t":"5.2 Financial Management: Receipts, Records & Spending in USD & LRD","d":"Video + notes","v":"a1uKxBaq3Jk"},{"t":"5.3 Donor Reporting: Narrative & Financial Reports That Build Trust","d":"Video + notes","v":"hvFx_gocMug"},{"t":"📝 Quiz: Grant Management & Compliance","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Funding Diversification & Your Grant Writing Career","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Diversifying Funding: Consortia, Corporate Sponsors & Crowdfunding","d":"Video + notes","v":"_OQ-qVLkJ0Y"},{"t":"6.2 Working as a Grant Writing Consultant in Liberia","d":"Video + notes","v":"_1PAOSCbzqE"},{"t":"6.3 Your Grant Writing Portfolio & Five-Year Fundraising Strategy","d":"Video + notes","v":"cyRF479o1iU"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: The Grant Landscape","moduleNum":1,"unlocks":3,"questions":[{"q":"A grant is best described as:","opts":["A loan you must repay with interest","Non-repayable funding given for a specific purpose with conditions","A salary paid by government","A donation with no rules attached"],"correct":1,"exp":"Grants are non-repayable, but they come with conditions, you must deliver the agreed project and report on how the money was used."},{"q":"Which of these donors is a UN agency active in Liberia?","opts":["Mastercard Foundation","USAID","UNDP","Open Society Foundations"],"correct":2,"exp":"UNDP is the United Nations Development Programme. USAID is a US government agency, while Mastercard Foundation and Open Society are private foundations."},{"q":"The BEST place to find current grant opportunities is:","opts":["Waiting for donors to call your office","Donor websites, newsletters, and databases like fundsforNGOs and Grants.gov","Facebook rumors","Asking friends only"],"correct":1,"exp":"Serious grant seekers check donor websites and free databases regularly and subscribe to donor newsletters so opportunities come to their inbox."},{"q":"A call for proposals says applicants must be registered NGOs with 3+ years of audited accounts. Your Paynesville youth group registered last year. You should:","opts":["Apply anyway and hope nobody checks","Fake the registration date","Partner as a sub-grantee under an eligible NGO or skip this call","Complain to the donor"],"correct":2,"exp":"Never waste time on calls where you are ineligible. Partnering with an established NGO as a sub-grantee is a legitimate way for young organizations to build a track record."},{"q":"Donor priorities matter because:","opts":["Donors fund any good idea","Donors only fund projects that match their published strategy and focus areas","Priorities are just suggestions","Priorities only apply to big NGOs"],"correct":1,"exp":"A donor focused on girls' education will not fund a road project no matter how well written. Matching your project to donor priorities is the first rule of grant writing."},{"q":"What is the main difference between a grant and a contract?","opts":["A grant supports your proposed project idea, while a contract pays you to deliver services the funder specifies","A contract is always larger than a grant","Grants must be repaid while contracts are free money","Only governments issue grants while only companies issue contracts"],"correct":0,"exp":"With a grant the donor funds your project idea; with a contract the funder defines the exact deliverables and buys them from you like a service."},{"q":"The Mastercard Foundation, which funds youth employment programs in West Africa, is an example of:","opts":["A UN agency","A bilateral government donor","A private philanthropic foundation","A commercial bank"],"correct":2,"exp":"Mastercard Foundation is a private foundation, unlike bilateral donors such as USAID or multilateral agencies such as UNDP."},{"q":"A donor announces a Request for Applications (RFA) with a deadline of 30 September. The wisest approach is to:","opts":["Start writing on 29 September since donors always extend deadlines","Read the full RFA early, plan backwards from the deadline, and submit at least a day before","Email the donor asking them to summarize the document for you","Submit a proposal you wrote for a different donor without changes"],"correct":1,"exp":"Serious applicants read the call immediately, build a work plan backwards from the deadline, and never gamble on last-minute submission or extensions."},{"q":"A concept note differs from a full proposal because a concept note is:","opts":["A longer document with complete annexes and audited accounts","A short 2-3 page summary of the project idea used to test donor interest first","The legal contract you sign after winning","A financial report submitted after the project ends"],"correct":1,"exp":"Many donors first request a brief concept note; only shortlisted organizations are invited to develop the full proposal, saving everyone time."},{"q":"Before applying to many US government or EU calls, organizations often must first:","opts":["Buy shares in the donor agency","Hire an international lawyer","Register on the donor's official portal or system and obtain required registration numbers","Open a bank account in Washington or Brussels"],"correct":2,"exp":"Donors like USAID and the EU require advance registration on their systems (for example SAM.gov or the EU Funding & Tenders portal), which can take weeks, so register early."}]},"mod2":{"title":"Quiz: Project Design Essentials","moduleNum":2,"unlocks":3,"questions":[{"q":"In a logic model, training 50 women in Kakata to use Excel is an example of:","opts":["An impact","An input","An activity","A long-term outcome"],"correct":2,"exp":"Activities are the things your project actually does. Inputs are resources, outputs are direct products, and outcomes/impact are the changes that result."},{"q":"A theory of change explains:","opts":["Your organization's history","How and why your activities will lead to the change you want to see","Your budget in detail","Who sits on your board"],"correct":1,"exp":"A theory of change is the 'if we do X, then Y will happen, because Z' story that connects activities to results."},{"q":"The strongest needs statement:","opts":["Says your NGO has no money","Uses verifiable data about the community problem, like LISGIS statistics","Uses emotional language only","Describes your office equipment needs"],"correct":1,"exp":"Donors fund community problems, not organizational shortfalls. Evidence from sources like LISGIS, WHO, or your own baseline survey makes the need credible."},{"q":"Which objective is SMART?","opts":["Help young people in Liberia","Improve education somehow","Train 120 out-of-school youth in Paynesville in digital skills, with 70% passing certification, by December 2026","Do many trainings"],"correct":2,"exp":"It is Specific, Measurable (120 youth, 70% pass rate), Achievable, Relevant, and Time-bound (by December 2026)."},{"q":"Objectives differ from goals because objectives are:","opts":["Longer and vaguer","Specific, measurable steps toward the broader goal","Only about money","Written after the project ends"],"correct":1,"exp":"The goal is the big-picture change; objectives are the concrete, measurable milestones that add up to it."},{"q":"In a logic model, '150 youth in Gbarnga complete digital skills training' is an example of:","opts":["An input","An output","An assumption","An impact"],"correct":1,"exp":"Outputs are the direct, countable products of your activities; outcomes and impact describe the changes those outputs later produce."},{"q":"Which of these belongs in the 'inputs' column of a logic model?","opts":["Reduced youth unemployment in Nimba County","Funds, trainers, laptops, and a training venue","Improved test scores after six months","Community members feeling more hopeful"],"correct":1,"exp":"Inputs are the resources you invest, money, staff, equipment, and facilities, before any activity happens."},{"q":"In project design, an 'assumption' is:","opts":["A guess about the donor's mood","An external condition that must hold true for your logic to work, such as schools staying open","The total budget amount","A promise that the project cannot fail"],"correct":1,"exp":"Assumptions are outside conditions your theory of change depends on; naming them honestly shows donors you have analyzed the risks."},{"q":"Why should a needs statement include baseline data, such as the current literacy rate in your target community?","opts":["It fills space to meet the page limit","It lets you later prove the change your project created by comparing results to the starting point","Donors never actually read statistics","Baseline data replaces the need for a budget"],"correct":1,"exp":"A baseline defines the starting point; without it, neither you nor the donor can measure how much the situation improved."},{"q":"Your objective is to improve maternal health knowledge, but your activity list includes building a football pitch. This proposal has a problem because:","opts":["Football is not allowed in grant projects","Every activity must clearly contribute to an objective, and this one does not","The activity is too cheap","Donors prefer basketball projects"],"correct":1,"exp":"Reviewers check alignment: activities that do not logically serve an objective weaken the whole design and signal careless planning."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"In a grant budget, paying a trainer $50 per day for 10 days is best shown as:","opts":["One lump sum with no explanation","Unit cost x quantity: $50 x 10 days = $500","A hidden cost inside 'miscellaneous'","An LRD figure with no exchange rate"],"correct":1,"exp":"Donors expect unit-cost budgeting. Show the unit, rate, and quantity, and if you budget in LRD, state the exchange rate used."},{"q":"Which cost would MOST donors refuse to fund?","opts":["Venue rental for community training","Personal expenses unrelated to the project","Project staff salaries","Monitoring visits to project sites"],"correct":1,"exp":"Only costs necessary for delivering the project are eligible. Personal or unrelated expenses are ineligible and can get an organization blacklisted."},{"q":"An indicator like 'number of youth completing training, disaggregated by gender' belongs in your:","opts":["Cover letter","Monitoring & Evaluation plan","Bank statement","Organizational chart"],"correct":1,"exp":"The M&E plan lists indicators, baselines, targets, data sources, and who collects the data, it shows donors you can prove your results."},{"q":"You submitted a proposal to a donor a month ago and heard nothing. The professional next step is:","opts":["Send an angry message","Send a brief, polite follow-up email confirming receipt and offering more information","Give up on grants forever","Submit the same proposal ten more times"],"correct":1,"exp":"A short, courteous follow-up shows professionalism. Donor relationships are long-term, how you behave when you lose matters as much as when you win."},{"q":"After winning a grant, the MOST important way to keep the donor's trust is:","opts":["Spend fast and explain later","Deliver activities as agreed, keep receipts, and submit honest, on-time reports","Avoid communication until the end","Change the project without telling anyone"],"correct":1,"exp":"Faithful implementation, clean financial records, and timely honest reporting turn a one-time grant into a long-term funding relationship."},{"q":"Which pairing of donor and type is correct?","opts":["USAID, private foundation","UNDP, multilateral UN agency","Mastercard Foundation, bilateral government donor","European Union, susu club"],"correct":1,"exp":"UNDP is a multilateral UN agency; USAID is a bilateral government donor and Mastercard Foundation is a private foundation."},{"q":"The first question to ask before writing any proposal is:","opts":["Which font looks most impressive","Does our project match this donor's priorities and are we eligible under this call","How can we make the budget as large as possible","Which photos to put on the cover"],"correct":1,"exp":"Fit and eligibility come first, a beautiful proposal for the wrong donor or an ineligible applicant is wasted work."},{"q":"In the results chain, 'trained youth gain employment and household income rises' is best classified as:","opts":["An input","An activity","An outcome","A receipt"],"correct":2,"exp":"Outcomes are the changes in people's lives that follow from outputs, employment and income changes go beyond simply completing training."},{"q":"A needs statement for a water project in Grand Bassa is strongest when it:","opts":["Cites specific data, such as the share of households without safe water, from credible sources","Says water is generally important to life","Focuses on the NGO's need for a new vehicle","Uses only emotional stories with no figures"],"correct":0,"exp":"Verifiable community data, from LISGIS, WHO, or your own baseline survey, makes the problem concrete and credible to reviewers."},{"q":"Which budget line would a donor question as poorly justified?","opts":["Trainer fees: US$50 x 10 days = US$500","'Miscellaneous: US$2,000' with no breakdown","Venue rental: US$40 x 5 sessions = US$200","Participant transport: LD 1,000 x 120 participants at a stated exchange rate"],"correct":1,"exp":"Large unexplained 'miscellaneous' lines signal weak planning; every significant cost should show units, rates, and quantities."},{"q":"An M&E plan promises 'number of women completing tailoring training, verified by attendance registers and certificates.' The 'attendance registers and certificates' part is the:","opts":["Baseline","Means of verification","Theory of change","Exchange rate"],"correct":1,"exp":"Means of verification name the evidence sources that prove each indicator was achieved."},{"q":"After signing a grant agreement, the document that legally controls your project is:","opts":["The signed grant agreement and its approved budget","Your original concept note","Your organization's brochure","The donor's website homepage"],"correct":0,"exp":"The agreement replaces the proposal as the governing document, its dates, budget, and conditions are binding."},{"q":"You discover a project purchase was made without the required three quotations. The right response is to:","opts":["Hide the file before the audit","Document what happened, inform the donor if required, and fix the procurement process going forward","Blame the vendor publicly","Delete the expense from the records"],"correct":1,"exp":"Transparency plus corrective action preserves trust; concealment converts a process error into potential fraud."},{"q":"In financial reporting, spending should be presented:","opts":["As one single total with no detail","Against each approved budget line, showing budgeted, actual, and remaining amounts","Only in Liberian dollars with no rate stated","Only when the donor makes a site visit"],"correct":1,"exp":"Line-by-line comparison of budget versus actual spending, with exchange rates documented, is the standard donors expect."},{"q":"A no-cost extension changes:","opts":["The project end date without adding new money","The donor's name on the agreement","The total grant amount upward","Your registration status"],"correct":0,"exp":"A no-cost extension gives more time to finish activities using the same approved budget, request it well before the end date."},{"q":"Why is joining a consortium as a sub-grantee valuable for a young Liberian organization?","opts":["It guarantees you will never be audited","It removes the need for any financial records","It builds funding access, systems, and a verifiable track record for future direct grants","It allows you to ignore donor priorities"],"correct":2,"exp":"Sub-granting under an experienced lead partner is a recognized pathway to capacity and credibility for later direct funding."},{"q":"A telecom company sponsoring your youth event will most likely expect:","opts":["A 60-page academic proposal","Visibility, branding at the event and photos for its CSR reporting","Repayment of the sponsorship with interest","Ownership of your organization"],"correct":1,"exp":"Corporate sponsors seek brand visibility and community goodwill; pitches to them should be short, specific, and brandable."},{"q":"Charging a client 10% of any grant won, instead of a fee for your work, is:","opts":["The international standard for consultants","Required by USAID","Considered unethical percentage-based compensation that professional fundraising bodies prohibit","Only allowed for proposals above one million dollars"],"correct":2,"exp":"Professional codes such as the AFP's bar commission-based fundraising fees; consultants charge flat fees, day rates, or retainers instead."},{"q":"A healthy funding mix for an NGO means:","opts":["Getting all money from one generous donor forever","No single funding source dominating the budget, with several source types developed","Refusing all corporate money on principle","Depending entirely on crowdfunding"],"correct":1,"exp":"Diversification, keeping any single source below roughly half of income, protects the organization when one funder exits."},{"q":"The best evidence of your grant writing skill to show an employer in Monrovia is:","opts":["A portfolio with a complete sample proposal, logic model, budget, and M&E framework","A verbal promise that you write well","A list of donors you once heard about","A photograph of your certificate frame"],"correct":0,"exp":"A portfolio of real work samples proves capability instantly and is exactly what hiring managers for grants roles ask to see."}]},"mod4":{"title":"Quiz: M&E, Submission & Donor Relations","moduleNum":4,"questions":[{"q":"In an M&E plan, a 'baseline' is:","opts":["The final result at the end of the project","The value of an indicator measured before the project starts","The donor's total budget","The lowest salary on the team"],"correct":1,"exp":"The baseline captures the situation before your intervention so that change can be measured against it."},{"q":"A 'target' in an M&E plan is:","opts":["The specific value you commit to achieving by a set date, such as 300 farmers trained by month 12","The name of the community you work in","A random number chosen to impress donors","The amount of money left at the end"],"correct":0,"exp":"Targets state exactly what an indicator should reach and by when, allowing progress to be judged objectively."},{"q":"Which is the strongest indicator for a training project?","opts":["People feel happier about learning","Percentage of trainees scoring 70% or higher on the post-training assessment, disaggregated by gender","The project is going well","Many community members attended something"],"correct":1,"exp":"Good indicators are specific, measurable, and disaggregated where relevant, vague statements cannot be verified."},{"q":"'Means of verification' in an M&E framework refers to:","opts":["The exchange rate used in the budget","The documents or sources that prove each indicator, such as attendance sheets and test records","The donor's bank details","Your organization's slogan"],"correct":1,"exp":"Means of verification tell the donor exactly where evidence for each indicator will come from, registers, surveys, photos, or reports."},{"q":"The key difference between monitoring and evaluation is:","opts":["Monitoring is continuous tracking during implementation, while evaluation judges results at set points like midterm or endline","Monitoring is done by donors only and evaluation by police","Evaluation happens every day while monitoring happens once","There is no difference at all"],"correct":0,"exp":"Monitoring is the routine collection of progress data; evaluation steps back to assess relevance, effectiveness, and impact at key moments."},{"q":"Why do donors ask for data disaggregated by gender, age, or disability?","opts":["To make reports longer","To see who actually benefits and whether the project reaches vulnerable groups fairly","Because computers require it","To reduce the project budget"],"correct":1,"exp":"Disaggregation reveals whether women, youth, or persons with disabilities are truly included, a core accountability question for donors."},{"q":"Just before submitting a proposal, the most professional final step is to:","opts":["Add ten extra pages of history about your organization","Check the submission checklist: required annexes, signatures, format, page limits, and the exact deadline time zone","Change the budget totals without updating the narrative","Send it from a friend's personal email with no cover message"],"correct":1,"exp":"Many strong proposals are disqualified on technicalities, missing annexes, wrong format, or late submission, so the final checklist matters."},{"q":"Your proposal is rejected. The most valuable professional response is to:","opts":["Politely thank the donor and request reviewer feedback to strengthen your next application","Post an angry message about the donor on Facebook","Resubmit the identical proposal the next day","Stop applying for grants permanently"],"correct":0,"exp":"Feedback from reviewers is free expert advice; organizations that learn from rejection and stay courteous often win the next round."},{"q":"How do you know when project reports are due to a donor?","opts":["Reports are only needed if the donor calls to complain","The grant agreement states the reporting schedule, such as quarterly narrative and financial reports","You choose whatever dates suit you after spending the money","Reports are never actually required"],"correct":1,"exp":"The grant agreement is the source of truth: it defines report types, formats, and deadlines, and missing them damages your record."},{"q":"A donor program officer plans a site visit to your project in Buchanan. You should:","opts":["Cancel all activities so the site looks quiet","Prepare records, beneficiary lists, and let them see real activities and speak freely with participants","Only show them a PowerPoint in a hotel","Coach beneficiaries to exaggerate results"],"correct":1,"exp":"Site visits build trust when donors see genuine work and honest records; staged or blocked visits destroy credibility fast."}]},"mod5":{"title":"Quiz: Grant Management & Compliance","moduleNum":5,"questions":[{"q":"A grant agreement is best understood as:","opts":["A friendly letter with no legal force","A legally binding contract that governs what you may do with the funds","A copy of your original proposal","A receipt for money received"],"correct":1,"exp":"Once signed, the agreement, not your proposal, legally defines the project, budget, dates, and rules you must follow."},{"q":"You want to move 25% of the training budget line into transport. Most donor agreements require you to:","opts":["Request written donor approval before making a change that large","Make the change quietly and explain it later if asked","Cancel the entire grant","Move the money and delete the old budget"],"correct":0,"exp":"Small movements between lines are often allowed, but changes beyond the flexibility limit (commonly around 10%) need prior written approval."},{"q":"Money spent two weeks before the official grant start date is usually:","opts":["Automatically doubled by the donor","Eligible if the receipt looks neat","Ineligible, because costs must fall within the grant period","Charged to next year's budget"],"correct":2,"exp":"Costs incurred outside the agreement's start and end dates are typically ineligible, no matter how project-related they are."},{"q":"For purchases above the donor's procurement threshold, standard practice is to:","opts":["Buy from a relative to keep money in the family","Collect and document multiple quotations and justify the supplier selected","Pay cash with no paperwork to save time","Let the youngest staff member decide alone"],"correct":1,"exp":"Documented competitive quotations show the donor that funds were spent fairly and at reasonable market prices."},{"q":"The 'audit trail' for a grant expense runs:","opts":["From the donor's website to your Facebook page","From the bank statement through your records to a receipt and an approved budget activity","From memory to memory","From the receipt straight to the trash after reporting"],"correct":1,"exp":"Every expense should be traceable from bank to cashbook to supporting document to activity, that unbroken chain is the audit trail."},{"q":"You pay LD 5,000 for venue chairs when the grant reports in USD. Best practice is to:","opts":["Report it as exactly US$5,000","Leave it out of the report since it was in LRD","Guess a round dollar figure","Convert using a documented exchange rate for that date and note the rate on the voucher"],"correct":3,"exp":"Recording the actual rate used for each LRD transaction keeps conversions honest and survives audit checks."},{"q":"A market vendor cannot give a formal receipt for training refreshments. You should:","opts":["Complete a payment voucher with date, amount, purpose, and the payee's signature or thumbprint","Record nothing and hope the auditor forgets","Write a fake receipt from a shop in town","Pay double so it feels official"],"correct":0,"exp":"Donors accept properly approved payment vouchers where formal receipts do not exist; what they cannot accept is missing or falsified documentation."},{"q":"Separation of duties means:","opts":["Staff work in separate buildings","The person requesting money is not the same person who approves and records the payment","Only the director may touch money","Finance staff never speak to program staff"],"correct":1,"exp":"Splitting request, approval, and recording between different people protects funds and protects honest staff from suspicion."},{"q":"Heavy rains will delay your final activities past the grant end date. The professional move is to:","opts":["Backdate the activity reports","Spend the money on something faster instead","Request a no-cost extension from the donor well before the end date","Say nothing and return the unspent funds secretly"],"correct":2,"exp":"A no-cost extension keeps the same budget but extends time, and donors grant them routinely when asked early with a clear reason."},{"q":"The most common donor complaint about reports is that:","opts":["They arrive too early","The narrative and financial reports do not match each other","They contain too many attendance sheets","The font is too large"],"correct":1,"exp":"Donors read both reports side by side; activities described must align with costs charged, so review them together before submitting."}]}},"reviews":[{"name":"Korpo Weah","loc":"Paynesville, Liberia","date":"April 2026","bg":"#065f46","init":"KW","rating":5,"text":"I lead a small women's savings group and we had never won anything before. Using the logic model and budget templates from this course, we won a $7,500 grant from a UNDP small grants window to expand our soap-making business. Miatta explains donor language in a way ordinary Liberians can understand."},{"name":"Emmanuel Togba","loc":"Ganta, Nimba County","date":"May 2026","bg":"#E31E24","init":"ET","rating":5,"text":"Our youth agriculture group in Ganta applied three times before and failed every time. After this course I rewrote our needs statement with real LISGIS data and fixed our budget with proper unit costs. We just signed our first grant agreement worth $10,000. This free course paid for itself many times over."},{"name":"Bendu Sherman","loc":"Sinkor, Monrovia","date":"March 2026","bg":"#7c3aed","init":"BS","rating":5,"text":"I work for a local NGO and was always afraid of the M&E section. The module on indicators and reporting changed everything, our program officer at the embassy praised our last report. I have since been promoted to Grants Officer with a salary increase. Thank you TIH."},{"name":"Prince Dolo","loc":"Buchanan, Grand Bassa","date":"June 2026","bg":"#0369a1","init":"PD","rating":4,"text":"The capstone was hard work but worth it. I wrote a full proposal for a school sanitation project in Buchanan and used it to apply to two foundations. One shortlisted us and requested a site visit. My only wish is for more videos on EU applications specifically, but the fundamentals here are excellent."}],"faqs":[{"q":"Is this course really free, and do I get a certificate?","a":"Yes, completely free, no credit card required. When you pass the final assessment you receive a verifiable TIH certificate (ID format TIH-2026-GRW-XXXX) that you can show to employers, NGOs, and donor-funded projects hiring grants staff."},{"q":"Do I need to work for a registered NGO to benefit?","a":"No. The course serves NGO staff, community group leaders, students, and freelancers. Grant writing is also a paid skill, many Liberian organizations hire consultants to write proposals, and this course prepares you for that work."},{"q":"Will this help me win grants specifically in Liberia?","a":"Yes. Every module uses West African examples: donors active in Liberia (USAID, EU, UNDP, UNICEF, Mastercard Foundation), budgets in USD and LRD, mobile money considerations, and the realities of community projects in Monrovia and the counties."},{"q":"How long does the course take and what is the capstone?","a":"About 20 hours total, most learners finish in 3-4 weeks studying an hour a day. The capstone asks you to write a complete, realistic $10,000 grant proposal (needs statement, logic model, objectives, budget, and M&E plan) that you can adapt and submit to a real donor."}]};
COURSES_DB['financial-literacy'] = {"id":"financial-literacy","title":"Financial Literacy: Master Your Money & Build Wealth","shortDesc":"Learn to budget in both USD and LRD, save through susu clubs and banks, use Orange Money and MTN MoMo safely, borrow wisely, and start building wealth, practical money skills for real Liberian life.","category":"Business & Finance","icon":"🏦","gradient":"linear-gradient(135deg,#0f766e,#14b8a6)","instructor":"Hawa Konneh","instructorTitle":"Financial Inclusion Specialist & Former Microfinance Officer, Monrovia","instructorBio":"Hawa Konneh spent 12 years as a microfinance and savings-group officer in Monrovia and Bong County, helping over 5,000 market traders, susu club members, and small business owners manage money across USD and LRD. She has trained financial literacy facilitators for NGOs across West Africa and designed this course around the real money challenges Liberian families face every day.","rating":4.8,"reviewCount":892,"students":"5,600+","duration":"28h","level":"All Levels","price":"FREE","origPrice":"$95","isFree":true,"badge":"free","certId":"TIH-2026-FIN-0001","learn":["Set clear financial goals and build a healthy money mindset","Create a realistic monthly budget in both USD and LRD","Track every expense using your phone, a notebook, or free apps","Use Orange Money and Lonestar Cell MTN MoMo safely and spot fraud before it happens","Save consistently through susu clubs, bank accounts, and personal savings plans","Open and manage a bank account in Liberia with confidence","Borrow wisely, avoid dangerous debt, and understand loans and interest","Build an emergency fund and a 6-month financial plan for your family"],"requirements":["No prior financial knowledge needed, we start from the very beginning","A phone or notebook to practice budgeting and expense tracking exercises","Willingness to honestly examine your own income and spending habits"],"about":["Money touches every part of life in Liberia, from paying school fees and buying rice, to sending mobile money to family upcountry, to saving for a business at Waterside or Red Light Market. Yet most of us were never taught how money actually works. This course changes that. It is built specifically for the Liberian and West African reality: two currencies, cash-heavy markets, susu clubs, mobile money, and family responsibilities.","You will learn step by step how to set financial goals, budget in USD and LRD, track your spending, protect yourself from Orange Money and MoMo fraud, save through both traditional susu clubs and formal banks, borrow without falling into debt traps, and take your first steps toward investing and building business capital.","Whether you are a student, a market trader, a motorbike rider, an office worker, or a parent managing a household, these skills will put money under your control instead of the other way around. The course is completely free, and you earn a verifiable TIH certificate when you pass the final assessment."],"modules":[{"title":"Module 1: Money Mindset & Budgeting Basics","icon":"💰","meta":"4 lessons · 32 min","lessons":[{"t":"1.1 Money Mindset & Setting Financial Goals","d":"10:00","v":"2uNvA48yvv0"},{"t":"1.2 Budgeting Basics: Managing USD & LRD Together","d":"12:30","v":"Pau88PAPD7Q"},{"t":"1.3 Tracking Your Expenses Every Day","d":"9:00","v":"ZmthxqxuFQI"},{"t":"📝 Quiz: Money Mindset & Budgeting","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Mobile Money, Saving & Banking","icon":"📱","meta":"4 lessons · 31 min","lessons":[{"t":"2.1 Mobile Money Mastery & Fraud Protection (Orange Money & MTN MoMo)","d":"11:00","v":"2C7u8onP7t4"},{"t":"2.2 Saving Strategies & Susu Clubs","d":"10:30","v":"nQEEQKgX6hg"},{"t":"2.3 Banking in Liberia: Accounts, Requirements & Choosing a Bank","d":"9:30","v":"guAaA1-CxT4"},{"t":"📝 Quiz: Mobile Money, Saving & Banking","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Debt, Credit & Borrowing Wisely","icon":"🤝","meta":"3 lessons · 22 min","lessons":[{"t":"3.1 Debt & Borrowing Wisely: Good Debt vs Bad Debt","d":"12:00","v":"wSqtotgaNAc"},{"t":"3.2 Building Credit & Understanding Loans","d":"10:00","v":"IFxzKqMFeE0"},{"t":"🛠️ Capstone: Create Your 6-Month Budget & Savings Plan","d":"Project","isProject":true}]},{"title":"Module 4: Investing & Planning Your Future","icon":"🏆","meta":"3 lessons · 24 min","lessons":[{"t":"4.1 Introduction to Investing & Building Business Capital","d":"13:00","v":"qIw-yFC-HNU"},{"t":"4.2 Financial Planning for Family & Emergencies","d":"11:00","v":"s3v2nNT7Um8"},{"t":"📝 Quiz: Investing & Planning Your Future","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Money & Small Business, Making Your Income Grow","icon":"🛒","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 From Savings to Startup: Raising & Protecting Business Capital","d":"Video + notes","v":"USkACkbmRi4"},{"t":"5.2 Pricing, Profit & Simple Record-Keeping for Traders","d":"Video + notes","v":"LCW387dqgvA"},{"t":"5.3 Beyond the Basics: Agent Banking, Microfinance & Village Savings Groups","d":"Video + notes","v":"CbEeC8xXdZ8"},{"t":"📝 Quiz: Small Business Money Skills","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Protecting Wealth & Leading Your Family's Financial Future","icon":"🛡️","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Insurance & Protecting What You Build","d":"Video + notes","v":"i4FAekxeS_o"},{"t":"6.2 Land, Housing & Long-Term Assets in Liberia","d":"Video + notes","v":"AWof6O0vp3o"},{"t":"6.3 Your Complete Family Financial Plan & Teaching Money Skills","d":"Video + notes","v":"ZbtgBp4X3ZE"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Money Mindset & Budgeting","moduleNum":1,"unlocks":3,"questions":[{"q":"A SMART financial goal is:","opts":["A wish to be rich someday","Specific, measurable, and has a deadline","Only for people with bank accounts","Something you keep secret from family"],"correct":1,"exp":"SMART goals are Specific, Measurable, Achievable, Relevant, and Time-bound, e.g. 'Save US$150 for school fees by December.'"},{"q":"Why should a Liberian budget track USD and LRD separately?","opts":["LRD is not real money","Exchange rates change, so mixing them hides your true spending","Banks only accept USD","It looks more professional"],"correct":1,"exp":"Because the LRD/USD rate moves, recording each currency separately shows exactly what you earn and spend in each."},{"q":"In the 50/30/20 budgeting guide, the 20 percent goes to:","opts":["Entertainment","Rent and food","Savings and paying off debt","Mobile phone credit"],"correct":2,"exp":"50% covers needs, 30% covers wants, and 20% goes to savings and debt repayment, adjust the split to fit your income."},{"q":"The BEST first step to control spending is:","opts":["Stop eating out forever","Write down every expense for at least one week","Borrow to cover gaps","Hide money from yourself"],"correct":1,"exp":"You cannot fix what you cannot see. Tracking every expense, even small chargers-of-scratch-card purchases, reveals where money leaks."},{"q":"A 'need' in your budget is:","opts":["New clothes for a party","Rice, rent, transport to work, and school fees","DSTV subscription","Weekend entertainment"],"correct":1,"exp":"Needs are essentials for living and earning, food, shelter, transport, education. Wants come after needs are covered."},{"q":"A motorbike rider in Ganta earns a different amount every day. The smartest way for him to budget is to:","opts":["Skip budgeting because his income is irregular","Base the budget on his lowest typical monthly income and save the extra from good months","Base the budget on his best month ever","Spend everything daily and start fresh tomorrow"],"correct":1,"exp":"Budgeting on your lowest reliable income means essentials are always covered, and strong weeks build savings instead of lifestyle."},{"q":"'Pay yourself first' means:","opts":["Buy something nice before paying any bills","Move a set amount into savings as soon as income arrives, before spending on anything else","Pay your own salary double","Refuse to help family members"],"correct":1,"exp":"Treating savings as the first 'bill' you pay guarantees you save consistently instead of saving only what accidentally remains."},{"q":"Which of these is a 'want' rather than a 'need' for a market trader in Paynesville?","opts":["Transport to reach her market table","Rice for the family","A new smartphone upgrade when her current phone works fine","Her children's school fees"],"correct":2,"exp":"Needs keep you living and earning; an upgrade to a working phone is a want that should wait until needs and savings are covered."},{"q":"How often should you review and adjust your budget?","opts":["Never, a budget is fixed forever","Only when you get a new job","Every month, comparing what you planned with what you actually spent","Once every five years"],"correct":2,"exp":"A monthly review shows where the plan and reality differ, prices change, especially with moving LRD/USD rates, so the budget stays realistic."},{"q":"Why do small daily purchases like cold water, scratch cards, and snacks matter in a budget?","opts":["They are too small to ever matter","Repeated small spending adds up to large monthly amounts that quietly drain your income","They are automatically free after the first purchase","Only purchases above US$10 count as spending"],"correct":1,"exp":"LD 200 a day on small items is roughly LD 6,000 a month, tracking reveals these leaks so you can redirect some of it to savings."}]},"mod2":{"title":"Quiz: Mobile Money, Saving & Banking","moduleNum":2,"unlocks":3,"questions":[{"q":"Someone calls claiming to be Orange Money support and asks for your PIN to 'reverse a wrong transfer.' You should:","opts":["Give the PIN so they can fix it","Give half the PIN only","Hang up, no real agent ever asks for your PIN","Send them money first"],"correct":2,"exp":"Orange Money and Lonestar Cell MTN staff NEVER ask for your PIN. Anyone requesting it is a fraudster, hang up and report."},{"q":"Before sending mobile money you should always:","opts":["Send quickly before network fails","Confirm the recipient's name shown on the screen matches who you intend to pay","Share your PIN with the agent","Use someone else's SIM"],"correct":1,"exp":"Both Orange Money and MTN MoMo display the recipient's registered name before you confirm, checking it prevents costly wrong transfers."},{"q":"In a susu club, members:","opts":["Borrow from a bank together","Contribute a fixed amount regularly and take turns receiving the pooled lump sum","Invest in foreign stocks","Pay interest to the government"],"correct":1,"exp":"A susu is a rotating savings club, everyone contributes each cycle and one member at a time receives the full pool."},{"q":"The biggest risk of a susu club compared to a bank is:","opts":["It builds discipline","A dishonest member or keeper can run away with the money","It has no paperwork","Meetings take time"],"correct":1,"exp":"Susu clubs rely on trust. Join only with people you know well, keep written records, and never put all your savings in one susu."},{"q":"To open a basic bank account in Liberia you typically need:","opts":["A university degree","Valid ID (voter card, passport, or national ID), a small opening deposit, and sometimes a reference","US$1,000 minimum","Property documents"],"correct":1,"exp":"Most Liberian banks require valid identification, a passport photo, a small opening deposit, and basic personal details."},{"q":"A mobile money agent tells you the transfer fee is 'whatever you can add on top.' You should:","opts":["Pay whatever the agent demands to be polite","Check the official Orange Money or MTN MoMo fee chart, since fees are fixed and published","Refuse to ever use mobile money again","Give the agent your PIN so they can calculate it"],"correct":1,"exp":"Mobile money fees are official, published rates, an agent inventing extra charges is overcharging you, and you can report them."},{"q":"You receive an SMS with a verification code for your mobile money account, and a caller asks you to read it out. You should:","opts":["Read it quickly before it expires","Send it by SMS instead of reading it aloud","Never share it, codes and PINs let someone take over your account","Share it only if the caller sounds official"],"correct":2,"exp":"One-time codes are keys to your account; fraudsters trick people into reading them out to hijack accounts and steal balances."},{"q":"The main difference between a savings account and a current (checking) account is:","opts":["A savings account is designed for keeping money and may earn interest, while a current account is built for frequent transactions","Savings accounts are only for foreigners","Current accounts are illegal in Liberia","There is no difference at all"],"correct":0,"exp":"Choose a savings account to grow money you rarely touch, and a current account for regular business payments and withdrawals."},{"q":"The best way to protect members of a susu club is to:","opts":["Keep written records of every contribution and payout, with clear rules agreed by all members","Rely on the keeper's memory alone","Let one person hold the money with no records","Change the rules secretly whenever needed"],"correct":0,"exp":"Written ledgers, agreed rules, and transparency at every meeting prevent the confusion and disputes that break susu clubs."},{"q":"Compared to keeping cash at home, a bank account offers:","opts":["Guaranteed doubling of your money each year","Protection from theft and fire, a transaction record, and a history that can help you qualify for loans","No advantages at all","Freedom from ever budgeting again"],"correct":1,"exp":"Banked money is safer than cash under a mattress, and your account history becomes evidence of income when you later seek credit."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Which is an example of GOOD debt?","opts":["Borrowing for a party","A loan to buy stock for your market table that sells at a profit","Borrowing to gamble","Daily loans for snacks"],"correct":1,"exp":"Good debt finances something that grows your income or value, like business inventory that earns more than the loan costs."},{"q":"Before taking any loan you should FIRST:","opts":["Sign quickly before the offer expires","Calculate the total repayment including interest and compare it to your income","Tell nobody","Take the biggest amount offered"],"correct":1,"exp":"Always compute the full cost, principal plus interest and fees, and confirm your budget can carry the repayment before signing."},{"q":"An emergency fund should ideally cover:","opts":["One day of spending","3 to 6 months of essential expenses","Your entire lifetime","Only funeral costs"],"correct":1,"exp":"Three to six months of essentials protects your family from job loss, sickness, or sudden expenses without borrowing."},{"q":"The safest way to grow money for a future business is:","opts":["Keep all cash under the mattress","Join every susu in town","Combine a bank savings account, a trusted susu, and reinvesting small profits","Send it to a stranger promising to double it"],"correct":2,"exp":"Diversifying between formal savings and trusted community savings, while avoiding 'double your money' scams, grows capital safely."},{"q":"This course teaches you to:","opts":["Get rich overnight","Control your money through budgeting, safe saving, wise borrowing, and planning","Avoid all banks forever","Print money"],"correct":1,"exp":"Financial literacy means making informed decisions, budgeting, saving, borrowing wisely, and planning, so money serves your goals."},{"q":"A family earning in both USD and LRD should budget by:","opts":["Ignoring the LRD income as too small","Recording each currency separately and noting the exchange rate when converting","Converting everything at a rate they imagine","Keeping no records since rates change anyway"],"correct":1,"exp":"Separate tracking with documented rates shows true income and spending in Liberia's two-currency reality."},{"q":"The 'pay yourself first' habit means savings are:","opts":["Whatever accidentally remains at month end","Moved aside immediately when income arrives, before other spending","Only possible for salaried workers","Taken from borrowed money"],"correct":1,"exp":"Saving first makes savings a fixed commitment instead of a leftover that rarely survives the month."},{"q":"A caller says your mobile money account will be blocked unless you confirm your PIN immediately. This is:","opts":["A standard security check from the operator","A fraud attempt, operators never ask for your PIN, so hang up and report","A reason to send them a small fee","Something to handle by giving an old PIN"],"correct":1,"exp":"Urgency plus a PIN request is the classic scam pattern; no legitimate Orange Money or MTN staff ever needs your PIN."},{"q":"Compared with keeping all savings in one susu, spreading money across a bank account, a trusted susu, and business stock:","opts":["Reduces the damage any single failure can cause","Guarantees losses in all three places","Is illegal under Liberian law","Only works for the wealthy"],"correct":0,"exp":"Diversification is protection, one dishonest keeper, one bank issue, or one slow market cannot take everything."},{"q":"Which borrowing decision follows the rules of good debt?","opts":["A loan for a proven market business whose extra profit comfortably exceeds the repayment","A loan for a birthday celebration","A loan taken without knowing the total repayment","A daily loan for snacks and phone credit"],"correct":0,"exp":"Good debt funds income growth and is taken only after calculating that earnings can carry the full repayment."},{"q":"Anyone promising to double your money in two weeks with no risk is offering:","opts":["A normal savings account","A scam that will eventually collapse and take your money","A government bond","A susu with better rules"],"correct":1,"exp":"Guaranteed fast doubling is the signature of Ponzi-style fraud, high promised return always carries high risk or hidden theft."},{"q":"The main reason to keep an emergency fund in an accessible savings account rather than in goods or land is:","opts":["Goods and land are always worthless","Emergencies need money within hours, and assets take time to sell","Banks pay double for emergency money","Land cannot legally be sold in Liberia"],"correct":1,"exp":"The emergency fund's job is speed, safe, reachable cash that prevents borrowing when crisis strikes."},{"q":"A new trader collects LD 12,000 in sales but spent LD 10,500 on stock, transport, and fees. Her profit is:","opts":["LD 12,000","LD 10,500","LD 1,500","Impossible to know"],"correct":2,"exp":"Profit is sales minus all costs, LD 12,000 minus LD 10,500 leaves LD 1,500, however heavy the cash bag felt."},{"q":"Restocking first, setting aside replacement cost whenever goods sell, protects a business from:","opts":["Having too many customers","Eating the capital until there is nothing left to sell","Paying market table fees","Keeping any records"],"correct":1,"exp":"Replacing stock before spending profit keeps the business engine running instead of shrinking with every sale."},{"q":"In a VSLA, member savings grow mainly because:","opts":["The government tops up every box","The pooled fund is lent to members at agreed interest, and earnings are shared at cycle end","Members receive foreign stock dividends","The cash box magically multiplies money"],"correct":1,"exp":"Interest paid on member loans grows the common fund, which is shared out according to each member's savings shares."},{"q":"An insurance premium is:","opts":["The regular payment you make so the insurer covers defined losses","The payout you receive after a loss","A penalty for late claims","A type of bank loan"],"correct":0,"exp":"You pay small premiums into the risk pool; a claim after a covered loss is what the pool pays back out."},{"q":"Before paying for land in Liberia, the essential steps include:","opts":["Paying quickly in cash before another buyer appears","Verifying the deed, checking for disputes, surveying boundaries, and using written witnessed agreements","Trusting the seller's word if he is well dressed","Skipping the survey to save money"],"correct":1,"exp":"Deed verification, dispute checks, a licensed survey, and documented payment protect savings from double sales and contested plots."},{"q":"For an informal worker with no NASSCORP pension, realistic retirement planning centers on:","opts":["Hoping children will manage everything","Building income-producing assets like rentable property, a durable business, and long-term savings","Spending fully while young","Waiting for a lottery win"],"correct":1,"exp":"Without formal pensions, assets that generate income in old age are the retirement plan, built gradually through disciplined saving."},{"q":"A fixed monthly 'family support' line in the budget helps because it:","opts":["Ends all contact with extended family","Turns unpredictable family requests into a planned, dignified amount the budget can carry","Doubles automatically each month","Replaces the need for an emergency fund"],"correct":1,"exp":"Planning for family obligations honors Liberian family values while protecting the household's goals from endless unplanned pressure."},{"q":"The complete family financial plan built in this course connects:","opts":["Only your bank account and nothing else","Current income and debts, written goals with dates, a monthly budget, debt rules, protection, and regular review dates","A single lucky investment","Secret accounts hidden from your spouse"],"correct":1,"exp":"A real plan is a living document, situation, goals, budget engine, debt rules, protection, and a review rhythm the family follows together."}]},"mod4":{"title":"Quiz: Investing & Planning Your Future","moduleNum":4,"questions":[{"q":"The key difference between saving and investing is:","opts":["Saving stores money safely for goals, while investing puts money to work for growth with some risk","Saving is illegal without a license","Investing always guarantees profit","They are exactly the same activity"],"correct":0,"exp":"Savings protect and accumulate; investments, like business stock or equipment, aim to grow money but carry risk of loss."},{"q":"In investing, higher promised returns generally come with:","opts":["Lower risk","Government guarantees","Higher risk of losing your money","No risk if a friend recommends it"],"correct":2,"exp":"Risk and return travel together, anyone promising huge returns with zero risk is hiding something."},{"q":"A man in town promises to double any money you give him within two weeks. This is most likely:","opts":["A registered bank product","A Ponzi-style scam that pays early people with later people's money until it collapses","A government empowerment program","A safe susu variation"],"correct":1,"exp":"'Double your money fast' schemes collapse by design; early payouts are bait, and most participants lose everything."},{"q":"Diversification means:","opts":["Putting all your money into the single best option","Spreading your money across different places and ventures so one failure cannot wipe you out","Only investing in foreign countries","Changing banks every week"],"correct":1,"exp":"Splitting savings between a bank, a trusted susu, and business stock means no single problem destroys all your capital."},{"q":"A trader makes LD 8,000 profit this month. The choice most likely to grow her business is to:","opts":["Spend it all on a celebration","Reinvest part of the profit in more stock while saving a portion","Lend it all to a stranger for interest","Hide it in the roof and forget it"],"correct":1,"exp":"Reinvested profit compounds the business, and saving a share builds the cushion, celebration can come from the wants budget."},{"q":"Where should an emergency fund be kept?","opts":["Locked in goods that take months to sell","Somewhere safe but quickly accessible, like a savings account or mobile money wallet","Lent out to friends so it grows","In a land purchase far from town"],"correct":1,"exp":"Emergencies do not wait, the fund must be safe from daily temptation yet reachable within hours, not months."},{"q":"The purpose of insurance is to:","opts":["Make you rich when nothing happens","Transfer the cost of big rare disasters to an insurer in exchange for a small regular payment","Replace the need to save","Guarantee you will never fall sick"],"correct":1,"exp":"Insurance trades a small premium for protection against losses, like health costs or fire, that could otherwise destroy your finances."},{"q":"School fees are due every September. Good family financial planning means:","opts":["Borrowing at high interest every August","Saving a fixed amount toward fees each month across the whole year","Waiting to see if the school forgets","Selling household assets each year"],"correct":1,"exp":"Predictable expenses should be saved for monthly in advance, turning a September crisis into a routine, planned payment."},{"q":"If prices in the market rise every year, cash hidden at home for a long time will:","opts":["Buy less than before, because inflation eats its value","Automatically grow in value","Stay exactly the same in buying power","Turn into USD by itself"],"correct":0,"exp":"Inflation quietly reduces what idle cash can buy, one reason long-term money should be saved or invested productively."},{"q":"The safest first source of capital for a new small business is usually:","opts":["A high-interest loan from an informal lender","Your own savings, possibly boosted by a susu payout","Money from a 'double it' scheme","Skipping rent payments for a year"],"correct":1,"exp":"Starting with saved capital keeps you debt-free while you learn; borrowed money adds pressure before the business has proven itself."}]},"mod5":{"title":"Quiz: Small Business Money Skills","moduleNum":5,"questions":[{"q":"A complete startup cost list for a small market business should include:","opts":["Only the first stock of goods","One-time equipment costs, first stock, and a survival cushion for the early months","Just the cost of a celebration for the opening","Whatever number a friend suggests"],"correct":1,"exp":"Counting equipment, stock, and one to two months of running costs prevents the collapse that hits businesses which only budget for stock."},{"q":"A family member gives you LD 30,000 toward your new business. The wisest step is to:","opts":["Assume it is a free gift and say nothing","Agree clearly, preferably in writing, whether it is a gift, a loan, or a share in the business","Return it because family money is always trouble","Spend it before they change their mind"],"correct":1,"exp":"Unspoken expectations about family money destroy both businesses and relationships, clarity at the start protects everyone."},{"q":"'Eating the capital' means:","opts":["Investing profits into new stock","Spending the money meant for restocking on household needs until the business cannot continue","Buying food wholesale for resale","Feeding customers for free"],"correct":1,"exp":"When stock money leaks into daily consumption, the business shrinks with every sale, separation of business and personal money prevents this."},{"q":"The best defense against mixing business and personal money is to:","opts":["Keep separate wallets or accounts and pay yourself a fixed allowance from the business","Keep everything in one pocket to stay simple","Never spend anything on your family","Let a relative hold all the money"],"correct":0,"exp":"Separate purses plus a fixed personal allowance let the family benefit from the business without silently consuming its capital."},{"q":"You buy sachets at LD 50 each, and transport, fees, and spoilage add LD 10 per sachet. Selling at LD 55 means:","opts":["A healthy profit of LD 5 per sachet","Breaking exactly even","Losing LD 5 on every sachet sold","A profit that depends on the weather"],"correct":2,"exp":"True unit cost is LD 60 once hidden costs are added, so LD 55 is below cost, pricing must cover every cost before profit begins."},{"q":"Profit is best defined as:","opts":["The total cash collected in a day","Sales minus all business costs","The size of your cash bag at closing","Whatever remains after one purchase"],"correct":1,"exp":"Heavy daily sales can still hide a loss, only after subtracting restocking, transport, and fees do you see real profit."},{"q":"Why is a credit page one of the most important records for a market trader?","opts":["It replaces the need for any other record","Unrecorded customer credit quietly drains stock and is easily forgotten or disputed","It is required before opening a bank account","Customers pay faster when there are no records"],"correct":1,"exp":"Goods taken on credit are your money in someone's pocket; writing name, amount, and date protects it from memory and dispute."},{"q":"When using a banking or mobile money agent, you should:","opts":["Leave before the SMS confirmation to save time","Use registered agents, wait for the confirmation message, and count money at the counter","Hand your phone and PIN to the agent to speed things up","Only visit agents at night"],"correct":1,"exp":"Registered agents, confirmed transactions, and counting on the spot are the habits that keep agent banking safe and disputable."},{"q":"Before taking a group microfinance loan, the most important thing to understand is:","opts":["The color of the institution's logo","The total repayment with all fees, and that group members may have to cover a member who defaults","Whether other members are your tribe","How to avoid ever repaying"],"correct":1,"exp":"Group lending means shared responsibility, know the full cost and the default rules before you sign for yourself and, effectively, others."},{"q":"A VSLA differs from a rotating susu because a VSLA:","opts":["Has no rules or records at all","Lends the pooled savings to members at interest and shares out the grown fund at the end of the cycle","Sends all money to the government","Only accepts US dollars"],"correct":1,"exp":"In a VSLA the fund earns interest through member loans and is shared out by savings shares at cycle end, unlike a susu's simple rotation."}]}},"reviews":[{"name":"Princess Doe","loc":"Paynesville, Liberia","date":"April 2026","bg":"#0f766e","init":"PD","rating":5,"text":"I sell at Red Light Market and I always wondered where my profit was going. After the budgeting and expense tracking lessons, I found I was losing over LD 4,000 every week on small small things. In three months I saved enough to add a second table of goods. This course is pure gold for market women."},{"name":"Emmanuel Togba","loc":"Monrovia, Liberia","date":"March 2026","bg":"#E31E24","init":"ET","rating":5,"text":"The mobile money fraud lesson saved me real money. One week after finishing it, a man called pretending to be Orange Money support asking for my PIN to reverse a transfer. I recognized the scam immediately and reported him. I also finally opened my first bank account using the checklist from Module 2."},{"name":"Musu Kollie","loc":"Kakata, Margibi County","date":"May 2026","bg":"#10b981","init":"MK","rating":5,"text":"Our susu club used to run on memory alone and we had plenty confusion. I used what I learned to set up written records and clear rules for our 12 members. Nobody has missed a payment since. The capstone project also gave me a real 6-month savings plan for my children's school fees."},{"name":"Abraham Freeman","loc":"Ganta, Nimba County","date":"June 2026","bg":"#7c3aed","init":"AF","rating":4,"text":"As a motorbike rider my income changes every day, and I thought budgeting was only for salary people. This course showed me how to budget with irregular income in both LRD and USD. I now have my first emergency fund, one month of expenses saved, and I am working toward three. Very practical teaching."}],"faqs":[{"q":"Is this course really free?","a":"Yes, 100% free. TIH believes financial literacy is a basic life skill every Liberian deserves, regardless of income. There are no hidden fees and no credit card is required."},{"q":"I don't have a bank account or much money. Can I still benefit?","a":"Absolutely, this course is designed for you. It starts with skills that need no bank account: goal setting, budgeting, expense tracking, mobile money safety, and susu savings. Banking is covered step by step for when you are ready."},{"q":"Does the course use Liberian examples or foreign ones?","a":"Every module is grounded in Liberian reality: budgeting across USD and LRD, Orange Money and Lonestar Cell MTN MoMo, susu clubs, Monrovia market trading, and banking requirements in Liberia. Video lessons are supplemented with locally focused reading notes."},{"q":"How long does it take and is the certificate recognized?","a":"Most learners finish in 3-4 weeks studying about an hour a day. Your TIH certificate includes a unique verification code (TIH-2026-FIN-0001 series) that employers, NGOs, and microfinance institutions can confirm online."}]};
COURSES_DB['english-success'] = {"id":"english-success","title":"English for Academic & Professional Success","shortDesc":"Master the formal English that opens doors, write winning scholarship essays, prepare for IELTS with proven band strategies, and speak with confidence in interviews.","category":"Language & Communication","icon":"🗣️","gradient":"linear-gradient(135deg,#4338ca,#6366f1)","instructor":"Hawa D. Cooper","instructorTitle":"English Language & Test Prep Lead, Tolbert Innovation Hub","instructorBio":"Hawa D. Cooper is a British Council-trained English instructor and former lecturer at the University of Liberia with an IELTS band 8.5. Over the past decade she has coached hundreds of Liberian and West African students to IELTS success and helped them win scholarships to universities in India, Cyprus, and Turkey.","rating":4.8,"reviewCount":612,"students":"3,200+","duration":"30h","level":"Intermediate","price":"FREE","origPrice":"$150","isFree":true,"badge":"free","certId":"TIH-2026-ENG-0001","learn":["Switch confidently between Liberian conversational English and formal international English","Apply the grammar rules that matter most in formal writing, tenses, agreement, and articles","Structure clear academic essays with strong thesis statements and paragraphs","Write scholarship personal statements and motivation letters that stand out","Understand the IELTS exam format, band scores, and how to set a realistic target","Use proven tactics for IELTS and TOEFL listening and reading sections","Plan and write high-scoring IELTS Writing Task 2 essays under time pressure","Communicate professionally in emails, workplace settings, and job interviews"],"requirements":["Intermediate English ability, a WASSCE English pass or equivalent everyday fluency is enough","A notebook and a device with internet access for video lessons and writing practice","Willingness to write, record yourself speaking, and practice aloud every week"],"about":["English is the official language of Liberia, yet many bright WASSCE graduates lose scholarships, jobs, and admission offers because the formal English expected by international examiners, universities, and employers differs from the Liberian English we speak every day at home and in the market. This course bridges that exact gap. It was built for Liberian and West African youth who already communicate in English but need to write, test, and interview at an international standard.","Across four modules you will move from register and grammar fundamentals to academic essay writing, scholarship personal statements, complete IELTS preparation, listening, reading, writing, and speaking, and finally professional emails and job interview English. Every lesson uses examples drawn from real Liberian life: applying from Monrovia, writing to admissions offices abroad, and interviewing with NGOs and companies at home.","TIH students use these exact skills to win placements at our partner destinations in India, Cyprus, and Turkey, and to secure competitive roles in Liberia. Whether your goal is an IELTS band 6.5, a Türkiye Burslari scholarship, or simply emails your boss admires, this free course gives you a clear, practical path, finishing with a capstone project and a verified TIH certificate."],"modules":[{"title":"Module 1: Foundations of Formal English","icon":"✍️","meta":"4 lessons · 33 min","lessons":[{"t":"1.1 Professional vs Conversational English: Knowing When to Switch","d":"10:00","v":"4AetJ7xJTdw"},{"t":"1.2 Grammar Essentials for Formal Writing","d":"12:00","v":"BBVsrdwuLeE"},{"t":"1.3 Academic Essay Structure: Thesis, Body & Conclusion","d":"11:00","v":"tBAbIobh3uo"},{"t":"📝 Quiz: Formal English Foundations","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Scholarship Writing & IELTS Foundations","icon":"🎓","meta":"4 lessons · 35 min","lessons":[{"t":"2.1 Scholarship Personal Statements & Motivation Letters","d":"12:00","v":"ZNOJ1RSJa4c"},{"t":"2.2 IELTS Overview: Format, Band Scores & Setting Your Target","d":"9:30","v":"zBLsjez-D3s"},{"t":"2.3 IELTS & TOEFL Listening and Reading Tactics","d":"13:00","v":"q8qmJeBxk4Q"},{"t":"📝 Quiz: Scholarships & IELTS Basics","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: IELTS Writing & Confident Speaking","icon":"🎤","meta":"3 lessons · 24 min","lessons":[{"t":"3.1 IELTS Writing Task Strategies: Planning to Band 7","d":"14:00","v":"gsEmGSVU7cA"},{"t":"3.2 Speaking Confidently: Fluency & Pronunciation for International Audiences","d":"10:00","v":"edmfgGseslg"},{"t":"🛠️ Capstone: Record Your 3-Minute Professional Introduction","d":"Project","isProject":true}]},{"title":"Module 4: Professional Communication & Career English","icon":"💼","meta":"3 lessons · 24 min","lessons":[{"t":"4.1 Professional Emails & Workplace Communication","d":"11:00","v":"3Tu1jN65slw"},{"t":"4.2 Job Interview English: Presenting Yourself with Impact","d":"12:30","v":"GlN51CS_udI"},{"t":"📝 Quiz: Professional Communication & Career English","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Business English in the Workplace","icon":"📊","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Writing Reports, Memos & Meeting Minutes","d":"Video + notes","v":"ralOdKh2eAw"},{"t":"5.2 Presentations & Public Speaking in Professional English","d":"Video + notes","v":"A2TwNWiYIMI"},{"t":"5.3 Meetings, Negotiations & Phone or Video Call English","d":"Video + notes","v":"-3mFnAk9sbw"},{"t":"📝 Quiz: Business English in the Workplace","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Career Capstone, Your Professional English Portfolio","icon":"💼","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 CVs & Cover Letters That Win Interviews","d":"Video + notes","v":"PAthQKLhBTs"},{"t":"6.2 Networking English: LinkedIn & Professional Relationships","d":"Video + notes","v":"u03GxFNE-5Y"},{"t":"6.3 Your Professional English Portfolio & Lifelong Improvement Plan","d":"Video + notes","v":"xi2aBP0LnV4"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Formal English Foundations","moduleNum":1,"unlocks":3,"questions":[{"q":"Which sentence is most appropriate in a scholarship application letter?","opts":["I beg you yah, please give me the scholarship.","I would be grateful for the opportunity to be considered for this scholarship.","Gimme the scholarship, I really need it bad.","This scholarship thing, I want it plenty."],"correct":1,"exp":"Formal writing uses polite, complete standard-English sentences. Expressions common in Liberian conversation, like 'I beg you yah', are warm at home but too informal for examiners and admissions officers."},{"q":"In formal academic writing, contractions like 'don't' and 'can't' should be:","opts":["Used as often as possible","Written out in full as 'do not' and 'cannot'","Replaced with slang","Used only in the conclusion"],"correct":1,"exp":"Writing contractions out in full instantly makes your essays and letters sound more formal and professional."},{"q":"A thesis statement in an academic essay is:","opts":["The last sentence of the essay","A list of every point you will make","The central argument, usually stated in the introduction","A famous quotation"],"correct":2,"exp":"The thesis statement appears in the introduction and tells the reader exactly what position your essay will argue."},{"q":"Every strong body paragraph should begin with:","opts":["A joke to entertain the reader","A topic sentence stating the paragraph's main idea","A rhetorical question","The word 'Furthermore'"],"correct":1,"exp":"A topic sentence announces the paragraph's main idea, then explanation and evidence follow, the pattern international examiners look for."},{"q":"A Liberian student writes 'She can come to class every day' to describe a habit. In international formal English this is best written as:","opts":["She comes to class every day.","She can coming to class every day.","She be coming to class every day.","She could came to class every day."],"correct":0,"exp":"Liberian English often uses habitual 'can', but international standard English uses the simple present tense for habits, a small switch that raises your writing score."},{"q":"Which sentence shows correct subject-verb agreement for formal writing?","opts":["The list of required documents are on the website.","The list of required documents is on the website.","The list of required documents be on the website.","The list of required documents am on the website."],"correct":1,"exp":"The true subject is 'list' (singular), not 'documents', so the verb must be 'is', a classic agreement trap in formal writing."},{"q":"In a formal essay, the best replacement for 'a lot of problems' is:","opts":["plenty plenty problems","loads of wahala","numerous problems","problems too much"],"correct":2,"exp":"Formal register prefers precise words like 'numerous', 'significant', or 'considerable' over conversational fillers like 'a lot of'."},{"q":"The conclusion of an academic essay should:","opts":["Introduce a brand-new argument to surprise the reader","Restate the thesis in fresh words and summarize the main points","Apologize for any weaknesses in the essay","Repeat the introduction word for word"],"correct":1,"exp":"A strong conclusion reinforces the thesis and synthesizes the argument, new points belong in body paragraphs, not the ending."},{"q":"Which sentence uses articles correctly?","opts":["She is student at the University of Liberia.","She is a student at University of Liberia.","She is a student at the University of Liberia.","She is the student at a University of Liberia."],"correct":2,"exp":"'A student' introduces her role, and institutional names beginning with 'University of...' take 'the', small article choices examiners notice."},{"q":"Which linking word correctly introduces a contrast between two ideas?","opts":["Furthermore","However","Similarly","Therefore"],"correct":1,"exp":"'However' signals contrast; 'furthermore' adds, 'similarly' compares, and 'therefore' shows result, using them precisely lifts your writing band."}]},"mod2":{"title":"Quiz: Scholarships & IELTS Basics","moduleNum":2,"unlocks":3,"questions":[{"q":"The most important rule for a scholarship motivation letter is:","opts":["Use the same letter for every application","Make it as long as possible","Tailor it to the specific scholarship and program","Focus only on your financial need"],"correct":2,"exp":"Selection committees instantly recognize generic letters. Tailoring each letter to the specific scholarship, such as Study in India or Türkiye Burslari, dramatically improves your chances."},{"q":"Your overall IELTS band score is calculated by:","opts":["Taking your highest section score","Averaging the four section scores and rounding to the nearest half band","Adding all four scores together","Using only your Writing score"],"correct":1,"exp":"Listening, Reading, Writing and Speaking each get a band from 0 to 9; the overall band is their average rounded to the nearest half band."},{"q":"In the IELTS Listening test, misspelling a correct answer means:","opts":["You still get full marks","You get half a mark","The answer is marked wrong","The examiner corrects it for you"],"correct":2,"exp":"Answers must be spelled correctly when transferred, so spelling practice is a direct way to protect your Listening and Reading marks."},{"q":"Most university scholarship programs in India, Cyprus, and Turkey typically ask for an IELTS band around:","opts":["9.0 only","6.0 to 6.5","3.0","There is no English requirement anywhere"],"correct":1,"exp":"A band of 6.0 to 6.5 meets the entry requirement for most partner universities, which makes it a realistic first target for a strong WASSCE graduate."},{"q":"The best tactic for IELTS Reading is to:","opts":["Read every word of every passage slowly","Skim for the main idea, then scan for keywords in the questions","Answer questions without reading the passage","Memorize academic articles beforehand"],"correct":1,"exp":"Skimming and scanning let you find answers within the 60-minute limit, reading every word slowly means running out of time."},{"q":"The strongest opening for a scholarship personal statement is:","opts":["Since childhood I have always dreamed of studying abroad.","A specific personal moment, such as teaching your first computer class in Paynesville, that shows your motivation","A dictionary definition of education","A list of every certificate you own"],"correct":1,"exp":"Committees read 'since childhood' openings thousands of times; a concrete, personal scene instantly makes your statement memorable and real."},{"q":"The difference between IELTS Academic and IELTS General Training is that:","opts":["Academic is for university admission, while General Training suits migration and some work purposes","Academic has no Speaking section","General Training is scored out of 100","Only Academic is offered in Africa"],"correct":0,"exp":"University applicants, including to India, Cyprus, and Turkey, almost always need IELTS Academic; check which version your program requires before booking."},{"q":"In IELTS Listening, the smartest use of the time before each section plays is to:","opts":["Close your eyes and relax","Read ahead through the questions and predict the kind of answer each needs","Count the other candidates in the room","Review the previous section's answers only"],"correct":1,"exp":"Previewing questions tells you what to listen for, a number, a name, a date, so the answer registers the moment you hear it."},{"q":"In True/False/Not Given reading questions, 'Not Given' means:","opts":["The statement contradicts the passage","The statement matches the passage exactly","The passage contains no information to confirm or deny the statement","The question itself contains a mistake"],"correct":2,"exp":"'Not Given' traps candidates who use outside knowledge, answer only from what the passage actually states."},{"q":"A motivation letter for a Türkiye Burslari scholarship becomes convincing when it:","opts":["Connects your specific goals to named features of the program and how you will use the training back home","Focuses mainly on how poor your family is","Uses the most complicated vocabulary possible","Repeats your CV line by line"],"correct":0,"exp":"Selection panels fund fit and purpose, showing exactly why this program serves your goals, and Liberia's needs, beats sympathy or big words."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"IELTS Writing Task 2 requires an essay that is:","opts":["At least 250 words, formal in style, completed in about 40 minutes","Exactly 100 words with bullet points","Written in slang to sound natural","At least 1,000 words with no time limit"],"correct":0,"exp":"Task 2 demands at least 250 words in a formal style within roughly 40 minutes, planning for five minutes first keeps your essay organized."},{"q":"The subject line of a professional email should be:","opts":["Left blank to create suspense","Written in all capital letters","Short, specific, and clear about the purpose","A friendly greeting like 'Hello my friend!'"],"correct":2,"exp":"A clear, specific subject line, such as 'Application for Program Assistant Position', tells a busy reader exactly why you are writing."},{"q":"The strongest structure for answering 'Tell me about yourself' in an interview is:","opts":["Reciting your entire life story from childhood","Present role and skills, relevant past experience, then future goals tied to the job","Talking only about your family and home county","Asking the interviewer to read your CV instead"],"correct":1,"exp":"The present-past-future structure keeps your answer focused, relevant, and under two to three minutes, exactly what interviewers and scholarship panels want."},{"q":"When speaking English for IELTS or interviews, examiners reward:","opts":["Speaking as fast as possible","A perfect British accent only","Clear pronunciation, fluency, and organized ideas, your Liberian accent is not a problem","Long silences to appear thoughtful"],"correct":2,"exp":"IELTS scores intelligibility, fluency, vocabulary and grammar, not accent. A clear, confident Liberian voice can absolutely earn band 7 and above."},{"q":"The biggest mistake in a scholarship personal statement is:","opts":["Telling a specific personal story","Copying a generic template found online","Explaining why the specific program fits your goals","Mentioning concrete achievements"],"correct":1,"exp":"Committees read thousands of applications and spot copied templates immediately. Specific, honest stories from your own life in Liberia are what win scholarships."},{"q":"Which sentence best demonstrates formal professional register?","opts":["We are writing to request further information regarding the vacancy.","We beg you small small for the job info.","Send the job info quick quick.","That job thing, we want to hear more."],"correct":0,"exp":"Formal register uses complete standard structures like 'to request further information regarding', precise, polite, and contraction-free."},{"q":"A body paragraph in an academic essay should contain:","opts":["Several unrelated ideas to show range","One main idea introduced by a topic sentence and supported with explanation and evidence","Only questions for the reader","The full conclusion of the essay"],"correct":1,"exp":"One controlled idea per paragraph, topic sentence, then support, is the pattern examiners and admissions readers expect."},{"q":"Which transition correctly shows a result?","opts":["However, enrollment increased.","Similarly, enrollment increased.","Therefore, enrollment increased.","Although, enrollment increased."],"correct":2,"exp":"'Therefore' signals consequence; 'however' contrasts and 'similarly' compares, precise connectors raise writing scores."},{"q":"A student applying to a university in Cyprus should normally book:","opts":["IELTS General Training","IELTS Academic","No test, since universities never check English","Any test with the cheapest fee"],"correct":1,"exp":"University admission almost always requires the Academic version, confirming the required test and score before booking saves money and time."},{"q":"In IELTS Reading, a statement is 'Not Given' when:","opts":["The passage clearly supports it","The passage clearly contradicts it","The passage contains no information about it either way","The statement is too long to read"],"correct":2,"exp":"Answering from the passage alone, not from your own knowledge, is the discipline this question type tests."},{"q":"The strongest scholarship personal statement relies on:","opts":["A template praised in a WhatsApp group","Specific true stories and achievements connected to the named program's features","Maximum sympathy about hardship with no goals","The most complicated vocabulary available"],"correct":1,"exp":"Committees fund fit and evidence, your real story, linked to why this program serves your goals, beats templates and sympathy."},{"q":"You must email a hiring manager whose name you do not know. The correct greeting is:","opts":["'Hey there!'","'Dear Hiring Manager,'","'My dear friend,'","No greeting at all"],"correct":1,"exp":"'Dear Hiring Manager' or 'Dear Sir/Madam' is the professional fallback when research cannot surface a name."},{"q":"Using BCC is appropriate when you want to:","opts":["Make the email arrive faster","Send to many recipients without revealing their addresses to each other","Show everyone who else received the message","Mark the email as urgent"],"correct":1,"exp":"BCC hides the recipient list, protecting privacy in mass emails, while CC keeps recipients openly visible."},{"q":"In a STAR interview answer, the 'R' requires you to describe:","opts":["The rules of the organization","The measurable result your action produced","Your reasons for leaving past jobs","The names of your references"],"correct":1,"exp":"Ending with the result, ideally with a number, like enrollment rising 40%, is what turns a story into evidence."},{"q":"The recommendations in a field report should be:","opts":["Hidden in the middle of long paragraphs","Numbered, specific, and actionable with clear next steps","Left out so the manager decides everything","Written as rhetorical questions"],"correct":1,"exp":"Decision-makers act on clear, numbered recommendations, the report section most likely to be read and remembered."},{"q":"During a presentation to donors, the best slide design uses:","opts":["Every word of your script pasted onto slides","Few words in large fonts, with you delivering the detail aloud","Tiny fonts to fit more information","No structure so it feels natural"],"correct":1,"exp":"Slides support the speaker, audiences cannot read dense text and listen at once, so keep slides lean and carry the message yourself."},{"q":"A colleague proposes a plan you believe will miss deadline. The professional meeting response is:","opts":["'I see the benefit of your approach; however, I am concerned about the timeline, could we consider adding a buffer?'","'That plan will fail like your last one.'","Silence in the meeting, then criticism afterward","'Whatever the majority wants.'"],"correct":0,"exp":"Acknowledge, then raise the concern with a constructive alternative, disagreement aimed at the idea, never the person."},{"q":"On a CV, the stronger bullet is:","opts":["'Responsible for training activities.'","'Was there when trainings happened.'","'Trained 85 youth in digital skills across 3 communities, with 78% earning certification.'","'Did many things in the training area.'"],"correct":2,"exp":"Action verbs plus numbers turn duties into achievements, the language pattern recruiters reward in a thirty-second scan."},{"q":"A proper LinkedIn connection request to someone you heard speak at a forum should:","opts":["Be sent with no message so it looks casual","Immediately ask them to find you a job","Briefly introduce yourself, mention the genuine connection point, and politely ask to connect","Include your full CV pasted into the message"],"correct":2,"exp":"Three sentences, who you are, the real link, the courteous request, start professional relationships; demands for favors end them."},{"q":"The main purpose of a professional English portfolio is to:","opts":["Decorate your bookshelf","Provide dated, concrete proof of your writing and speaking skills to employers and scholarship panels","Replace the need to ever improve again","Store other people's sample documents"],"correct":1,"exp":"A portfolio of your own CV, essays, reports, and recordings turns 'I communicate well' from a claim into demonstrated evidence."}]},"mod4":{"title":"Quiz: Professional Communication & Career English","moduleNum":4,"questions":[{"q":"You are emailing Mr. Johnson, a program manager you have never met. The correct greeting is:","opts":["Hey Johnson!","Dear Mr. Johnson,","Yo boss man,","Hello my dear,"],"correct":1,"exp":"'Dear' plus title and surname is the safe formal greeting for a first professional contact; casual greetings come only after a relationship forms."},{"q":"A professional way to close a formal email is:","opts":["Love always, Sarah","Catch you later!","Best regards, Sarah Kollie","Bye bye oo"],"correct":2,"exp":"'Best regards', 'Sincerely', or 'Kind regards' followed by your full name closes formal emails appropriately."},{"q":"Before clicking send on an important email, you should:","opts":["Proofread it, check the recipient address, and confirm any attachment is actually attached","Add more exclamation marks for energy","Send it immediately before you lose courage","Forward it to all your contacts for luck"],"correct":0,"exp":"A one-minute check for errors, correct recipients, and missing attachments protects your professional reputation every single time."},{"q":"You disagree with a decision your supervisor announced by email. The professional response is to:","opts":["Reply-all with your complaints in capital letters","Say nothing and complain to colleagues","Write a respectful reply or request a meeting, stating your concern with reasons and a suggested alternative","Resign the same day"],"correct":2,"exp":"Professional English disagrees with ideas, not people, calm reasons plus a constructive alternative keeps respect on both sides."},{"q":"The difference between CC and BCC in email is:","opts":["CC recipients are visible to everyone, while BCC recipients are hidden from other recipients","BCC makes the email more urgent","CC deletes the email after reading","They are different fonts"],"correct":0,"exp":"Use CC to keep others openly informed and BCC to protect recipient privacy, mixing them up can embarrass you or expose contacts."},{"q":"The STAR method for answering interview questions stands for:","opts":["Smile, Talk, Agree, Repeat","Situation, Task, Action, Result","Study, Test, Apply, Retry","Start, Talk, Ask, Rest"],"correct":1,"exp":"STAR structures your example answers: the situation you faced, your task, the action you took, and the measurable result, clear and complete."},{"q":"When an interviewer asks about your weakness, the strongest answer:","opts":["Claims you have no weaknesses at all","Names a real but manageable weakness and the concrete steps you are taking to improve it","Lists every fault you have ever had","Blames former employers for your weaknesses"],"correct":1,"exp":"Honest self-awareness plus visible improvement, 'I used to miss deadlines, so I now plan backwards with reminders', shows maturity."},{"q":"When the interviewer asks 'Do you have any questions for us?', you should:","opts":["Say no to end the interview quickly","Ask only about salary and vacation days","Ask one or two prepared questions about the role, team, or expectations for success","Ask the interviewer personal questions"],"correct":2,"exp":"Thoughtful prepared questions show genuine interest and research, saying 'no questions' reads as indifference."},{"q":"Within a day or two after a job interview, it is professional to:","opts":["Send a brief thank-you email restating your interest and one strength you offer","Call the office every hour for a decision","Post the interview questions on Facebook","Visit the interviewer's home to follow up"],"correct":0,"exp":"A short, polite thank-you note keeps your name fresh and demonstrates exactly the professional communication the job requires."},{"q":"When sending your CV by email, best practice is to:","opts":["Paste the entire CV into the subject line","Attach it with a clear file name like 'Sarah_Kollie_CV.pdf' and mention the attachment in your message","Send it with no message at all","Name the file 'document1_final_final.doc'"],"correct":1,"exp":"A professional file name and a sentence noting the attachment make you easy to find in a folder of hundreds of applicants."}]},"mod5":{"title":"Quiz: Business English in the Workplace","moduleNum":5,"questions":[{"q":"The recommendations section of a workplace report should contain:","opts":["Vague hopes that things improve","Numbered, specific actions the reader can take, such as procuring equipment before a set date","A repeat of the introduction","Personal complaints about colleagues"],"correct":1,"exp":"Reports exist to support decisions, specific, actionable, numbered recommendations are what managers act on."},{"q":"A memo subject line should read like:","opts":["'Important Information'","'Please Read!!!'","'Revised Office Opening Hours from 1 August'","'Memo'"],"correct":2,"exp":"A specific subject tells busy readers instantly what the memo concerns, vague subjects get ignored or lost."},{"q":"Good meeting minutes must always capture:","opts":["Every word spoken by every person","Decisions made and action points with a responsible person and deadline","The chair's tone of voice","Only the jokes and side conversations"],"correct":1,"exp":"Minutes are the meeting's official memory, decisions and owned, dated actions matter more than a word-for-word transcript."},{"q":"The 'tell them three times' presentation structure means:","opts":["Repeating your name three times","Previewing your points, delivering them, then summarizing them","Giving the same presentation on three days","Asking three people to present with you"],"correct":1,"exp":"Preview, deliver, summarize, this rhythm helps any audience follow and remember your message."},{"q":"Which phrase correctly signposts your final section in a presentation?","opts":["'This brings me to my final point...'","'Anyway, whatever, next thing...'","'I am almost done suffering through this...'","'Small time remaining!'"],"correct":0,"exp":"Fixed signposting phrases steer the audience through your structure and mark you as a prepared professional speaker."},{"q":"An audience member asks a question you cannot answer. The professional response is to:","opts":["Invent a convincing figure on the spot","Pretend not to hear the question","Thank them, admit you do not have the answer now, and commit to sending it after checking","Tell them the question is not important"],"correct":2,"exp":"An honest 'I will confirm and follow up today' preserves credibility, a guessed figure that proves wrong destroys it."},{"q":"The agree-then-pivot pattern for disagreeing in meetings sounds like:","opts":["'That idea is completely wrong.'","'I see your point about the timeline; however, my concern is the budget.'","'You always say the same thing.'","'Let us not discuss this ever.'"],"correct":1,"exp":"Acknowledging the other view before raising your concern lets you disagree with the idea while keeping respect with the person."},{"q":"In a negotiation, instead of a flat 'No', a professional says:","opts":["'Never contact us again.'","'That is beyond what we can do at this stage, but we could offer an alternative.'","'No, and that is final.'","Nothing, just silence"],"correct":1,"exp":"Conditional, door-open language protects the relationship and keeps the negotiation alive for a workable middle ground."},{"q":"The connection breaks while a partner abroad is speaking on a call. You should say:","opts":["Nothing, and guess what they said","'I am sorry, the line broke up. Could you repeat the last part?'","'Your English is too fast for me, goodbye.'","'Please send a letter by post instead.'"],"correct":1,"exp":"Repair phrases are normal professional tools worldwide, guessing at missed information causes far worse embarrassment later."},{"q":"After decisions are made on a video call, best practice is to:","opts":["Trust everyone's memory of the call","Confirm the decisions and action points in a follow-up email","Record the call secretly","Wait for someone else to mention it next month"],"correct":1,"exp":"A written follow-up turns spoken agreements into a shared record, 'said on a call' is forgotten, but an email endures."}]}},"reviews":[{"name":"Princess Weah","loc":"Sinkor, Monrovia","date":"February 2026","bg":"#4338ca","init":"PW","rating":5,"text":"I took IELTS twice before and stayed on band 5.5. After finishing this course and following Ms. Cooper's writing strategies, I scored an overall band 7.0! My admission to a university in Cyprus is now confirmed. The lesson on Liberian English versus formal English opened my eyes completely."},{"name":"Emmanuel Dolo","loc":"Paynesville, Liberia","date":"March 2026","bg":"#E31E24","init":"ED","rating":5,"text":"The motivation letter module is gold. I rewrote my personal statement using the exact structure taught here and won a Study in India scholarship for my engineering degree. Two of my friends from my WASSCE class are now taking the course because of my result."},{"name":"Musu Fahnbulleh","loc":"Kakata, Margibi County","date":"April 2026","bg":"#10b981","init":"MF","rating":5,"text":"I was not applying abroad, I just wanted a better job here. The email and interview modules changed how I present myself. Last month I passed an interview with an international NGO in Monrovia and got the program assistant role. The capstone recording exercise gave me real confidence."},{"name":"Abraham Togba","loc":"Ganta, Nimba County","date":"May 2026","bg":"#7c3aed","init":"AT","rating":4,"text":"Studying from Nimba with limited data was my worry, but the lessons are short and practical. I scored band 6.5 on my first IELTS attempt and my Türkiye Burslari application has moved to the interview stage. I wish there were more speaking practice partners, but the content itself is excellent."}],"faqs":[{"q":"I already speak English every day in Liberia. Why do I need this course?","a":"Liberian English is rich and expressive, but international examiners, universities, and employers expect formal standard English with different grammar, vocabulary, and tone. This course teaches you exactly where the two differ and how to switch confidently, without losing your own voice."},{"q":"Will this course fully prepare me for the IELTS exam?","a":"It covers the complete IELTS foundation: format, band scoring, and strategies for all four papers, with extra depth on Writing Task 2 and Speaking. Combine it with the free official practice tests we link in each lesson, and most students are exam-ready in 6 to 10 weeks."},{"q":"Do scholarships to India, Cyprus, and Turkey always require IELTS?","a":"Requirements vary. Some partner universities accept a WASSCE English pass or their own English interview, while others require IELTS 6.0 to 6.5. This course prepares you for all three paths, the test, the written application, and the interview, so no requirement catches you off guard."},{"q":"Is the certificate useful if I stay and work in Liberia?","a":"Yes. Strong formal English is one of the most requested skills by employers and NGOs in Monrovia and across the counties. Your TIH certificate carries a unique verification code that Liberian employers can confirm instantly, and the email and interview skills apply to any job application at home."}]};
COURSES_DB['agritech'] = {"id":"agritech","title":"AgriTech & Digital Agriculture","shortDesc":"See how phones, apps, and smart tools can transform farming in Liberia, from digital farm records and crop planning to selling produce online, mobile money, drones, and sensors.","category":"Agriculture & Technology","icon":"🌾","gradient":"linear-gradient(135deg,#3f6212,#84cc16)","instructor":"Kormassa Dolo","instructorTitle":"Agronomist & AgriTech Consultant, Central Agricultural Research Institute (CARI) Alumna","instructorBio":"Kormassa Dolo is a Liberian agronomist trained at Cuttington University and CARI in Suakoko, Bong County. She has spent over a decade helping smallholder rice, cassava, and vegetable farmers in Lofa, Bong, and Nimba counties adopt digital tools, from spreadsheet record keeping to WhatsApp marketing, and has consulted for agribusinesses across West Africa.","rating":4.8,"reviewCount":412,"students":"2,900+","duration":"27h","level":"Beginner","price":"FREE","origPrice":"$95","isFree":true,"badge":"free","certId":"TIH-2026-AGR-0001","learn":["Understand what AgriTech is and how it can transform Liberian farming","Keep accurate digital farm records using free phone apps and spreadsheets","Plan crops using weather forecasts and market price data","Use mobile apps and SMS services to get farming advice and market prices","Apply low-cost precision methods for soil, plant spacing, and inputs","Reduce post-harvest losses with proper handling and storage technology like hermetic bags","Sell farm produce online using WhatsApp Business and Facebook Marketplace","Manage farm money with mobile money, budgets, and simple agribusiness plans"],"requirements":["No farming or technology experience required, everything starts from the basics","A smartphone with WhatsApp (a basic phone works for the SMS and mobile money lessons)","Interest in farming, agribusiness, or helping farmers in your community"],"about":["Agriculture employs the majority of Liberians, yet most of our farmers still work without records, without market information, and without technology. Meanwhile, a young farmer in Kenya checks market prices by SMS and a rice processor like Fabrar Rice in Liberia uses modern milling and packaging to compete with imported rice. This course closes that gap, it shows Liberian and West African youth how simple, affordable technology can make farming more profitable and less risky.","You will learn practical digital skills built for our reality: keeping farm records on a phone, planning cassava and vegetable planting around the rainy season and Monrovia market prices, storing rice in hermetic bags so weevils do not eat your profit, selling greens and peppers to Monrovia buyers on WhatsApp, and receiving payment safely with Lonestar MTN Mobile Money or Orange Money. Every example uses Liberian crops, rice, cassava, rubber, cocoa, and vegetables, and real markets like Red Light and Duala.","Whether you farm in Lofa, run a small garden in Paynesville, or dream of starting an agribusiness, this course gives you a complete foundation. You will finish with a capstone project, a digital farm record and marketing plan you can use immediately, plus a verified TIH certificate recognized by employers, NGOs, and agricultural programs."],"modules":[{"title":"Module 1: AgriTech Foundations & Farm Data","icon":"🌾","meta":"4 lessons · 34 min","lessons":[{"t":"1.1 What is AgriTech? Why It Matters for Liberia","d":"10:00","v":"ev-4uQzdTXI"},{"t":"1.2 Digital Farm Record Keeping with Phone Apps & Spreadsheets","d":"11:30","v":"QijsZjlvxh4"},{"t":"1.3 Smart Crop Planning with Weather & Market Data","d":"12:00","v":"l8nFgIhK7bw"},{"t":"📝 Quiz: AgriTech Foundations","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Digital Tools for the Field","icon":"📱","meta":"4 lessons · 32 min","lessons":[{"t":"2.1 Mobile Apps & SMS Services for Farmers","d":"9:30","v":"yoeVcRlj1WI"},{"t":"2.2 Precision Basics: Soil, Spacing & Inputs on a Budget","d":"12:30","v":"GcPdvSj6CbE"},{"t":"2.3 Post-Harvest Handling & Storage Technology","d":"10:00","v":"dsYo9rBPQGo"},{"t":"📝 Quiz: Digital Tools for the Field","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Selling & Managing Farm Money Online","icon":"💰","meta":"3 lessons · 20 min","lessons":[{"t":"3.1 Selling Farm Produce Online: WhatsApp Business & Facebook Marketplace","d":"11:00","v":"gHfEm1z-3iY"},{"t":"3.2 Farm Finance & Mobile Money for Agribusiness","d":"9:00","v":"pun14jec_Xk"},{"t":"🛠️ Capstone: Build a Digital Farm Record & Marketing Plan","d":"Project","isProject":true}]},{"title":"Module 4: Agri-Entrepreneurship & The Future","icon":"🏆","meta":"3 lessons · 26 min","lessons":[{"t":"4.1 Agri-Entrepreneurship & Value Addition","d":"12:00","v":"EEcy1swBlRo"},{"t":"4.2 Drones, Sensors & The Future of Farming","d":"14:00","v":"qwNVNE83Udo"},{"t":"📝 Quiz: Agri-Entrepreneurship & The Future of Farming","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Value Chains, Cooperatives & Market Access","icon":"🚛","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Liberia's Crop Value Chains: From Farm Gate to Final Buyer","d":"Video + notes","v":"XyGtTvH_NXY"},{"t":"5.2 Cooperatives, Aggregation & Selling Together","d":"Video + notes","v":"sdMZ_HCAGO4"},{"t":"5.3 Quality, Grading & Winning Better Prices","d":"Video + notes","v":"niYA0qrUJiE"},{"t":"📝 Quiz: Value Chains, Cooperatives & Market Access","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Your Agribusiness Plan & Career","icon":"🎓","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Writing a Farm Business Plan That Wins Financing","d":"Video + notes","v":"WUvWHlCsDk4"},{"t":"6.2 Working with Extension Services, NGOs & Agri Programs","d":"Video + notes","v":"BHoG5zhPj7Y"},{"t":"6.3 Your AgriTech Portfolio: Presenting Your Capstone & Growing Your Career","d":"Video + notes","v":"WgqAejCz2gM"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: AgriTech Foundations","moduleNum":1,"unlocks":3,"questions":[{"q":"What is AgriTech?","opts":["Only expensive tractors and machines","Using technology and data to improve farming","A government farming program","A type of fertilizer"],"correct":1,"exp":"AgriTech means applying technology, from simple phone apps to sensors, to make farming more productive and profitable."},{"q":"Why is farm record keeping important for a Liberian farmer?","opts":["It is required by law","It shows which crops make profit and helps when applying for loans","It makes the farm look bigger","Records replace the need to sell produce"],"correct":1,"exp":"Records reveal your real costs and profits, and banks and microfinance institutions ask for them before giving agribusiness loans."},{"q":"Which free tool can a farmer use to keep digital records on a smartphone?","opts":["A drone","Google Sheets or a notes app","A satellite dish","A television"],"correct":1,"exp":"Free apps like Google Sheets work on most smartphones and can track planting dates, expenses, and sales."},{"q":"When planning crops, a smart farmer in Lofa County should check:","opts":["Only what neighbors are planting","Rainy season timing and Monrovia market prices","The color of the soil only","Nothing, just plant anytime"],"correct":1,"exp":"Combining weather patterns (rainy season is roughly May to October) with market demand helps you plant the right crop at the right time."},{"q":"A farmer sells cassava for LRD 15,000 but spent LRD 9,000 on inputs and transport. Her profit is:","opts":["LRD 15,000","LRD 9,000","LRD 6,000","LRD 24,000"],"correct":2,"exp":"Profit = sales minus costs. LRD 15,000 - LRD 9,000 = LRD 6,000. Records make this calculation possible."},{"q":"A farmer in Bong County wants to know if her vegetable garden made money last season. The most reliable way to find out is to:","opts":["Ask her neighbors how their farms did","Compare her recorded sales against her recorded expenses","Count how many bags she harvested","Check whether she still has money in her pocket"],"correct":1,"exp":"Only written records of both sales and expenses reveal true profit, memory and harvest size alone can hide losses like transport and input costs."},{"q":"Which column set makes the MOST useful simple farm record spreadsheet?","opts":["Date, activity, cost, income, and notes","Only the names of workers","Only the weather each day","Photos of the farm without any numbers"],"correct":0,"exp":"Date, activity, cost, income, and notes capture everything needed to calculate profit and review decisions later."},{"q":"Liberia's main rainy season, which drives most crop planning, runs roughly from:","opts":["December to February","January to March","May to October","Only during the Christmas season"],"correct":2,"exp":"Liberia's rains fall roughly May to October, so planting calendars for rice, cassava, and vegetables are planned around this window."},{"q":"Why can vegetables like peppers often earn MORE per acre during the dry season in Liberia?","opts":["Vegetables refuse to grow in the rainy season","Supply is lower while demand stays high, so market prices rise","Transport is free in the dry season","Buyers only visit farms when it is dry"],"correct":1,"exp":"When fewer farmers can supply fresh vegetables in the dry season, prices at markets like Red Light rise, dry-season gardening with simple irrigation captures that premium."},{"q":"A farmer notices from two seasons of records that groundnuts always lose money on her soil. The smart data-driven decision is to:","opts":["Plant even more groundnuts to recover the loss","Stop keeping records since they bring bad news","Shift that land to a crop her records show is profitable","Blame the market women for the losses"],"correct":2,"exp":"The whole point of farm data is better decisions, records that expose a losing enterprise let you reallocate land to what actually earns."}]},"mod2":{"title":"Quiz: Digital Tools for the Field","moduleNum":2,"unlocks":3,"questions":[{"q":"Why are SMS and USSD services useful for rural farmers in West Africa?","opts":["They require expensive smartphones","They work on basic phones without internet","They only work in cities","They are only for banks"],"correct":1,"exp":"SMS and USSD services like market price alerts work on any phone, even without internet, vital in rural Liberia."},{"q":"What is the low-cost first step of precision farming?","opts":["Buying a drone","Testing your soil and using correct plant spacing","Hiring more workers","Planting as many seeds as possible"],"correct":1,"exp":"Knowing your soil and spacing plants correctly costs little but significantly improves yields and reduces wasted inputs."},{"q":"What is a hermetic storage bag used for?","opts":["Carrying water to the farm","Storing grain airtight so insects and mold cannot destroy it","Covering seedlings from sun","Packaging produce for WhatsApp photos"],"correct":1,"exp":"Hermetic bags seal out air and moisture, protecting stored rice and other grains from weevils and mold without chemicals."},{"q":"Applying fertilizer only where and when crops need it helps you:","opts":["Spend more money","Reduce costs and avoid damaging the soil","Grow crops without water","Avoid keeping records"],"correct":1,"exp":"Targeted input use, a core precision principle, cuts costs and protects long-term soil health."},{"q":"A big cause of post-harvest loss for Liberian rice farmers is:","opts":["Too much sunlight during growth","Poor drying and storage allowing pests and mold","Selling too quickly","Using mobile money"],"correct":1,"exp":"Much of Liberia's harvest is lost after harvest, proper drying and airtight storage protect both food and income."},{"q":"Before rice can be stored safely in any bag, it must first be:","opts":["Painted with chemicals","Dried properly to a safe moisture level","Mixed with sand to add weight","Left in the open field for a month"],"correct":1,"exp":"Grain stored wet will mold and rot even in a good bag, thorough drying on tarpaulins or raised platforms must come before storage."},{"q":"A USSD service is one that a farmer uses by:","opts":["Downloading a large app from the Play Store","Dialing a short code like *123# on any phone","Connecting a satellite dish","Visiting a cyber café to browse websites"],"correct":1,"exp":"USSD works by dialing short codes and shows menus on any phone with network signal, no internet or smartphone required."},{"q":"Recommended plant spacing matters mainly because crowded plants:","opts":["Compete for light, water, and nutrients, lowering the yield of each plant","Grow faster than well-spaced plants","Never suffer from pests","Need no weeding at all"],"correct":0,"exp":"Overcrowded plants fight each other for sunlight, water, and soil nutrients, so total usable yield often drops even though more seeds were planted."},{"q":"A simple low-cost way to learn what your soil needs before buying fertilizer is to:","opts":["Guess based on the most expensive fertilizer available","Apply every type of fertilizer at once","Get a basic soil test or advice from an extension officer such as through CARI or the Ministry of Agriculture","Taste the soil"],"correct":2,"exp":"A basic soil test or extension advice tells you what your soil actually lacks, so you buy only the inputs that will pay for themselves."},{"q":"Storing dried grain on a raised platform instead of directly on the ground helps because it:","opts":["Makes the bags easier for rats to reach","Keeps moisture from the floor out of the grain and improves airflow","Hides the grain from buyers","Ripens the grain faster"],"correct":1,"exp":"Ground moisture soaks upward into sacks and causes mold, raising bags on pallets or poles keeps grain dry and easier to inspect."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"Which tool lets a farmer create a product catalog with prices that customers can browse?","opts":["A USSD code","WhatsApp Business","A calculator app","FM radio"],"correct":1,"exp":"WhatsApp Business includes a free catalog feature, perfect for showing vegetables or rice with LRD prices to Monrovia buyers."},{"q":"Why is mobile money like Lonestar MTN MoMo or Orange Money useful for agribusiness?","opts":["It replaces farming","Buyers can pay instantly and safely without carrying cash","It grows crops faster","It is only for salaries"],"correct":1,"exp":"Mobile money lets a buyer in Monrovia pay a farmer in Nimba instantly, creating a payment record and reducing cash risk."},{"q":"What is value addition?","opts":["Increasing the farm size","Processing raw produce into higher-value products, like cassava into gari","Adding more workers","Raising prices without changes"],"correct":1,"exp":"Value addition, like Fabrar Rice milling and packaging Liberian rice, turns raw crops into products that earn far more."},{"q":"Drones and sensors help modern farmers mainly by:","opts":["Replacing all farm workers","Monitoring crop health and targeting water and inputs precisely","Scaring away customers","Making farming more expensive with no benefit"],"correct":1,"exp":"Drones and sensors gather field data so farmers can spot problems early and apply inputs only where needed."},{"q":"The digital farm record and marketing plan you built in the capstone helps you:","opts":["Decorate your phone","Track profit, plan crops, and reach buyers, and support loan applications","Avoid paying transport","Replace the need for good seeds"],"correct":1,"exp":"A complete record and marketing plan is the foundation of a professional agribusiness, proof of profitability for lenders and a roadmap for growth."},{"q":"Which combination best describes the complete modern Liberian agripreneur toolkit taught in this course?","opts":["Expensive machinery and imported seeds only","Farming without any written plans","Guesswork, cash-only sales, and roadside storage","Digital records, market and weather data, safe storage, online selling, and mobile money"],"correct":3,"exp":"The course's core system links records, data-driven planning, post-harvest protection, digital marketing, and mobile money into one profitable workflow."},{"q":"A farmer wants planting advice but has only a basic phone with no internet. Which channel can still reach her?","opts":["YouTube tutorials","Facebook Marketplace","Email newsletters with photos","SMS and USSD advisory services"],"correct":3,"exp":"SMS and USSD work on any phone with network signal, which is why they remain the backbone of farmer information services in rural West Africa."},{"q":"Paddy rice should be dried to roughly what moisture level before safe long-term storage?","opts":["Around 30%","Around 13-14%","Exactly 50%","Moisture level does not matter for storage"],"correct":1,"exp":"Rice stored above safe moisture (roughly 13-14%) molds and spoils, proper drying is the non-negotiable first step before bagging."},{"q":"Which sequence correctly orders a cassava value chain?","opts":["Processor, consumer, farmer, transporter","Consumer, processor, farmer, input supplier","Input supplier, farmer, aggregator, processor, retailer, consumer","Retailer, input supplier, consumer, farmer"],"correct":2,"exp":"Value flows from inputs through production, aggregation, processing, and retail to the consumer, with margin added at each link."},{"q":"The main reason cooperatives get better prices than individual smallholders is:","opts":["Buyers are legally forced to pay cooperatives more","Cooperative crops grow faster","Cooperatives are exempt from transport costs","Volume and organization give them bargaining power with large buyers"],"correct":3,"exp":"Aggregated volume, consistent quality, and organized logistics attract serious buyers and enable real negotiation."},{"q":"Mixing high-quality and poor-quality cocoa beans in one bag usually means:","opts":["The whole bag is priced down toward the poorest beans in it","The buyer pays an average of world prices","Quality has no effect on cocoa prices","The bag sells at the high-quality price"],"correct":0,"exp":"Buyers grade on the worst they find, separating grades protects the premium your best beans deserve."},{"q":"In a farm business plan, the financial section should be built primarily from:","opts":["Round numbers that sound impressive","Your actual recorded costs, sales, and profit from farm records","Figures copied from another farmer's plan","Whatever amount the grant offers"],"correct":1,"exp":"Lenders and grant reviewers trust numbers backed by real records, your spreadsheet is your evidence."},{"q":"A break-even calculation tells a farmer:","opts":["The government-set price for her crop","The exact day rain will fall","How much she must sell before the enterprise stops losing money","Which neighbor is most profitable"],"correct":2,"exp":"Break-even is the sales point where income covers all costs, below it you lose, above it every sale is profit."},{"q":"CARI in Suakoko, Bong County is important to Liberian farmers mainly as:","opts":["A rubber export company","A mobile network operator","A commercial bank for agriculture","The national agricultural research institute providing improved varieties and practices"],"correct":3,"exp":"CARI researches and releases improved rice, cassava, and vegetable varieties and trains farmers and extension workers."},{"q":"NGO agriculture projects often hire field enumerators. The digital skill most relevant to that job from this course is:","opts":["Collecting structured field data with phone forms and reporting in spreadsheets","Repairing tractors","Printing paper posters","Flying passenger aircraft"],"correct":0,"exp":"Enumerators gather farm data using mobile form tools and summarize it in spreadsheets, exactly the record and data skills you practiced."},{"q":"Selling stored grain a few months AFTER harvest season often earns more because:","opts":["Grain becomes heavier in storage","Prices typically rise once the harvest glut passes and supply tightens","Buyers disappear at harvest time","Storage removes transport costs"],"correct":1,"exp":"At harvest everyone sells and prices dip; safe hermetic storage lets you wait for the leaner months when prices recover."},{"q":"A WhatsApp Business catalog beats posting produce photos in random group chats because it:","opts":["Works without a phone","Automatically waters the farm","Presents organized products with prices that buyers browse anytime, building a professional image","Blocks other farmers from selling"],"correct":2,"exp":"A catalog is a permanent, organized shopfront, buyers browse, compare, and order without you re-posting daily."},{"q":"Which risk-management practice belongs in the 'risks and solutions' section of a Liberian farm business plan?","opts":["Ignoring pests until they appear","Selling the farm if problems arise","Assuming rain will always fall on time","Staggered planting dates and stored grain to manage weather and price swings"],"correct":3,"exp":"Concrete mitigation, staggering planting, storing to ride out price dips, shows reviewers you have planned for reality, not luck."},{"q":"Mobile money records of customer payments help an agribusiness owner because they:","opts":["Create a verifiable income history useful for loans and business decisions","Hide income from the business plan","Make produce ripen faster","Replace the need for good produce"],"correct":0,"exp":"Every mobile money transaction is a dated, provable record of revenue, powerful evidence for lenders and for tracking your own growth."},{"q":"The ultimate purpose of your complete AgriTech portfolio, records, catalog, business plan, and certificate, is to:","opts":["Decorate a Google Drive folder","Provide verifiable proof of your skills to lenders, buyers, NGOs, and employers","Replace the need to farm well","Keep your phone storage full"],"correct":1,"exp":"The portfolio converts your learning into evidence, the difference between claiming skills and proving them to anyone who can fund or hire you."}]},"mod4":{"title":"Quiz: Agri-Entrepreneurship & The Future of Farming","moduleNum":4,"questions":[{"q":"Turning raw cassava into packaged gari or fufu flour is an example of:","opts":["Crop rotation","Value addition","Land preparation","Contract farming"],"correct":1,"exp":"Processing and packaging raw produce into a finished product is value addition, it multiplies what each tuber of cassava can earn."},{"q":"Why does milled, cleaned, and packaged Liberian rice compete better against imported rice than raw paddy does?","opts":["Packaged rice never expires","Packaging makes rice grow faster","Buyers pay more for a convenient, clean, ready-to-cook product they trust","Imported rice is illegal in Liberia"],"correct":2,"exp":"Processors like Fabrar Rice succeed because consumers pay for cleanliness, convenience, and consistent quality, that margin goes to whoever adds the value."},{"q":"An agri-entrepreneur differs from a subsistence farmer mainly because the entrepreneur:","opts":["Never touches the soil personally","Only grows imported crops","Owns more land by definition","Treats the farm as a business with records, plans, and target markets"],"correct":3,"exp":"Agri-entrepreneurship is a mindset: producing deliberately for a market, tracking profit, and reinvesting, regardless of farm size."},{"q":"In agriculture, drones are most commonly used to:","opts":["Survey fields from above to spot crop stress, pests, and flooding early","Plant seeds one by one","Replace rainfall","Carry harvested crops to market"],"correct":0,"exp":"A drone camera covers hectares in minutes, revealing problem spots, yellowing, waterlogging, pest damage, that walking the field might miss."},{"q":"A soil moisture sensor helps a vegetable farmer save money by:","opts":["Showing exactly when irrigation is needed instead of watering on guesswork","Killing insects in the soil","Predicting market prices","Advertising produce to buyers"],"correct":0,"exp":"Sensors report real soil conditions, so water, fuel for pumps, and labor are spent only when plants actually need them."},{"q":"Before investing in a cassava processing business, the FIRST question an agri-entrepreneur should answer is:","opts":["How to avoid keeping records","What color to paint the machines","Who will buy the product, at what price, and in what quantity","Which uniform workers will wear"],"correct":2,"exp":"Market first, machines second, value addition only pays when there are confirmed buyers at a price above your production cost."},{"q":"Simple value addition a smallholder can start with almost no machinery includes:","opts":["Exporting frozen goods in refrigerated ships","Constructing a supermarket","Building a rubber tire factory","Sorting, cleaning, and attractively packaging produce in labeled bags"],"correct":3,"exp":"Even sorting, cleaning, grading, and honest labeled packaging can raise prices 20-50% with almost no capital investment."},{"q":"Satellite weather and vegetation data matter for African farmers because they can:","opts":["Give early warning of drought or heavy rain so farmers adjust plans in time","Physically water the crops","Guarantee prices at Red Light market","Replace the need for soil and seeds"],"correct":0,"exp":"Satellite-based forecasts and alerts, often delivered by SMS, help farmers time planting, drying, and harvest to avoid weather losses."},{"q":"A young Liberian who cannot afford a drone but wants to enter precision agriculture should FIRST:","opts":["Wait until drones become free","Master data skills, records, GPS mapping apps, and interpreting field information","Abandon agriculture for another sector","Buy the cheapest toy drone available"],"correct":1,"exp":"The valuable skill is turning field data into decisions, free GPS and mapping apps plus solid record keeping are the real entry point."},{"q":"The strongest business reason to process rubber or cocoa closer to the farm gate is that:","opts":["Foreign factories cannot process cocoa","Raw exports always earn the most","More of the final product's value stays with Liberian producers and workers","Processing removes the need for buyers"],"correct":2,"exp":"When crops leave raw, most profit is captured abroad, local processing keeps jobs and margin inside Liberia's economy."}]},"mod5":{"title":"Quiz: Value Chains, Cooperatives & Market Access","moduleNum":5,"questions":[{"q":"A value chain describes:","opts":["The fence around a farm","The rope used to tie produce bags","The journey of a crop from inputs and farm through processing and trading to the final consumer","A list of fertilizer prices"],"correct":2,"exp":"The value chain covers every link, inputs, production, aggregation, processing, transport, retail, with cost and margin added at each step."},{"q":"Why does raw cassava pressure farmers into accepting low prices?","opts":["Buyers refuse to purchase cassava","Cassava has no market in Liberia","Cassava is illegal to store","Fresh tubers spoil within days, so farmers must sell fast or lose everything"],"correct":3,"exp":"Perishability destroys bargaining power, processing cassava into gari or fufu flour removes the time pressure and raises value."},{"q":"Which crop's price to Liberian smallholders moves with the world commodity market through buyers supplying processors like Firestone?","opts":["Bitterball","Rubber","Sweet potato greens","Okra"],"correct":1,"exp":"Rubber cup lump prices track the global rubber market, so checking current prices before selling protects farmers from being underpaid."},{"q":"The MAIN price advantage of farmers selling through a cooperative is that they can:","opts":["Skip paying transport forever","Avoid drying their crops","Offer large volumes and negotiate instead of accepting whatever one middleman offers","Sell without any quality checks"],"correct":2,"exp":"Aggregated volume attracts bigger buyers and creates real negotiating power that no individual smallholder has alone."},{"q":"A shared Google Sheets register in a cooperative mainly prevents:","opts":["Pests from entering the store","Buyers from asking questions","Rain from falling on the harvest","Disputes, by recording each member's deliveries and payments transparently"],"correct":3,"exp":"Transparent digital records of who delivered what and who was paid what remove the mistrust that breaks many farmer groups."},{"q":"Properly fermented and dried cocoa beans earn a premium because:","opts":["Exporters and chocolate makers pay more for flavor quality and reject moldy or smoky beans","Fermented beans weigh three times more","Fermentation makes beans grow larger on the tree","Dried beans are cheaper to produce than wet ones"],"correct":0,"exp":"Fermentation develops the flavor buyers pay for, and correct drying prevents mold, poorly prepared beans face rejection or deep discounts."},{"q":"Why should a farmer grade produce into first and second quality before selling?","opts":["Second-quality produce is always thrown away","Mixing grades makes the whole lot sell at the LOWEST quality's price","Buyers require exactly two bags of everything","Grading makes the harvest heavier"],"correct":1,"exp":"One bad handful sets the price for the whole bag, separating grades lets your best produce earn its true value."},{"q":"Drying rice or cocoa directly on bare ground is bad practice because it:","opts":["Is required by exporters","Turns the crop a better color","Dries the crop too quickly","Picks up soil, stones, and moisture that lower the grade and price"],"correct":3,"exp":"Bare-ground drying contaminates produce with sand, stones, and dampness, tarpaulins or raised platforms protect the grade."},{"q":"Five neighboring farmers agree to dry to one standard, bag identically, and sell the same day. This is an example of:","opts":["Value addition through processing","Aggregation for collective selling","Precision irrigation","Crop rotation"],"correct":1,"exp":"Pooling standardized produce for a joint sale is aggregation, the seed of a cooperative, no formal registration needed to start."},{"q":"The best digital way to build a quality track record buyers can trust is to:","opts":["Copy another farmer's photos into your catalog","Delete records after every sale","Photograph your process and log each lot's practices and grade in your farm spreadsheet","Tell buyers verbally that your crop is the best"],"correct":2,"exp":"Dated photos and recorded grades create verifiable proof of consistent quality, strong evidence in negotiations with processors and NGO buyers."}]}},"reviews":[{"name":"Korto Weah","loc":"Voinjama, Lofa County","date":"March 2026","bg":"#3f6212","init":"KW","rating":5,"text":"My family grows rice and I never knew our real profit until this course. I set up a Google Sheets record and found we were losing money on transport. This season I organized shared transport with neighbors and stored paddy in hermetic bags, we saved almost LRD 40,000. Every young farmer in Lofa should take this."},{"name":"Emmanuel Gonlepa","loc":"Ganta, Nimba County","date":"April 2026","bg":"#84cc16","init":"EG","rating":5,"text":"I started a WhatsApp Business catalog for my pepper and bitterball garden after Module 3. Now I have regular buyers from Ganta and even two restaurants in Monrovia who pay me through Mobile Money before I even harvest. My income has more than doubled in three months."},{"name":"Musu Fahnbulleh","loc":"Kakata, Margibi County","date":"May 2026","bg":"#0891b2","init":"MF","rating":5,"text":"The value addition lesson changed my thinking. Instead of selling raw cassava at Red Light, I now process it into fufu flour and package it in small bags. The capstone project became my real business plan and I used it to win a small youth agribusiness grant."},{"name":"Abraham Togba","loc":"Gbarnga, Bong County","date":"June 2026","bg":"#7c3aed","init":"AT","rating":4,"text":"I am an agriculture student at Cuttington and this course taught practical things my classes never covered, checking weather data before planting and using SMS market services. The certificate verification impressed the NGO where I now intern as a farmer field assistant."}],"faqs":[{"q":"Do I need to own a farm to take this course?","a":"No. This course is for anyone interested in agriculture, students, aspiring agri-entrepreneurs, extension workers, or family members who help on a farm. The skills also prepare you for jobs with NGOs and agribusinesses."},{"q":"Will these tools work in rural areas with poor internet?","a":"Yes. The course emphasizes tools that work in low-connectivity settings, SMS and USSD services on basic phones, offline spreadsheet apps, and mobile money which works without internet. Lessons can be downloaded when you have connection."},{"q":"Is this course really free and do I get a certificate?","a":"Completely free, no hidden costs. When you pass the final assessment you receive a TIH certificate with a unique verification code (TIH-2026-AGR series) that employers, NGOs, and agricultural programs can verify online."},{"q":"Which crops does the course cover?","a":"Examples focus on Liberia's main crops, rice, cassava, vegetables, rubber, and cocoa, but every method (record keeping, storage, online selling, mobile money) applies to any crop or livestock enterprise in West Africa."}]};
COURSES_DB['healthtech'] = {"id":"healthtech","title":"Healthcare Technology & Telehealth","shortDesc":"Digital skills for modern health work, electronic records, telehealth, patient follow-up, and health data privacy, built for Liberian clinics and community health workers.","category":"Health & Technology","icon":"🏥","gradient":"linear-gradient(135deg,#9f1239,#f43f5e)","instructor":"Dr. Musu Kollie-Nagbe","instructorTitle":"Health Informatics Specialist & Digital Health Consultant, Monrovia","instructorBio":"Dr. Musu Kollie-Nagbe is a Liberian health informatics specialist who served in the Ministry of Health data systems team during the 2014-2016 Ebola response and later supported DHIS2 reporting rollouts across county health teams. She has trained nurses, physician assistants, and community health assistants at JFK Medical Center, Redemption Hospital, and rural facilities in Bong, Nimba, and Lofa to move from paper to digital workflows.","rating":4.8,"reviewCount":318,"students":"2,300+","duration":"27h","level":"Beginner","price":"FREE","origPrice":"$150","isFree":true,"badge":"free","certId":"TIH-2026-HLT-0001","learn":["Explain what digital health is and why it matters for African health systems","Compare electronic health records with paper systems and plan a safe transition","Build digital patient intake forms using Google Forms and KoboToolbox","Conduct professional telehealth consultations by phone, video, and chat","Run patient follow-up programs using SMS and WhatsApp on Lonestar and Orange networks","Protect patient privacy and confidentiality when handling digital health data","Understand how DHIS2 and community health worker tools support MOH reporting","Use simple digital tools to manage clinic appointments, records, and drug inventory"],"requirements":["No prior health informatics or IT experience needed, this course starts from the basics","Access to a smartphone or computer with internet (mobile data on Lonestar or Orange is enough)","Helpful but not required: experience in or interest in a clinic, hospital, pharmacy, or community health role"],"about":["Health care in Liberia and across West Africa is going digital. From DHIS2 reporting at county health teams to WhatsApp follow-up between community health assistants and district supervisors, the health workers who can use digital tools are the ones being hired, promoted, and trusted with bigger responsibilities. Yet most facilities, from JFK Medical Center in Sinkor to small clinics in Lofa and Grand Gedeh, still run on paper records that get lost, damaged, or duplicated.","This course teaches you the practical digital skills that health facilities actually need: replacing paper registers with electronic records, building digital patient intake forms with free tools like Google Forms and KoboToolbox, running remote consultations by phone and video, following up with patients over SMS and WhatsApp, protecting patient confidentiality, and tracking drug inventory so clinics stop running out of essential medicines. Every lesson uses real Liberian examples, including the hard lessons the country learned about health data during the Ebola crisis.","Whether you are a nurse, physician assistant, community health assistant (CHA), pharmacy worker, records clerk, health sciences student, or a tech-minded person who wants to serve the health sector, this free course gives you a verified certificate and a capstone project you can show to employers, county health teams, and NGOs."],"modules":[{"title":"Module 1: Foundations of Digital Health","icon":"🏥","meta":"4 lessons · 34 min","lessons":[{"t":"1.1 Introduction to Health Technology & Digital Health in Africa","d":"11:00","v":"_EqfLDZc28Q"},{"t":"1.2 Electronic Health Records vs Paper Systems","d":"9:30","v":"HoWvf76JdX8"},{"t":"1.3 Digital Patient Intake Forms with Google Forms & KoboToolbox","d":"13:00","v":"9ewgr1BD0Rw"},{"t":"📝 Quiz: Digital Health Foundations","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Telehealth & Mobile Health in Practice","icon":"📱","meta":"4 lessons · 31 min","lessons":[{"t":"2.1 Telehealth Fundamentals & Remote Consultations","d":"10:00","v":"2xuNOPU3zhg"},{"t":"2.2 mHealth: SMS & WhatsApp for Patient Follow-Up","d":"12:00","v":"Qus5MFg-tDk"},{"t":"2.3 Health Data Privacy & Confidentiality Basics","d":"8:30","v":"Lfhl0ip14CI"},{"t":"📝 Quiz: Telehealth & Patient Privacy","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Digital Tools for Community & Public Health","icon":"🧑‍⚕️","meta":"3 lessons · 21 min","lessons":[{"t":"3.1 Community Health Worker Digital Tools & DHIS2 Awareness","d":"11:30","v":"V0Nt395JQQg"},{"t":"3.2 Health Information for Patients: Fighting Misinformation Online","d":"9:00","v":"n4ga1YzwWNY"},{"t":"🛠️ Capstone: Design a Digital Patient Intake & Telehealth Workflow","d":"Project","isProject":true}]},{"title":"Module 4: Clinic Operations & Your Health Tech Career","icon":"🏆","meta":"3 lessons · 25 min","lessons":[{"t":"4.1 Digital Tools for Clinic Management & Inventory","d":"14:00","v":"WOXrMOzK_A4"},{"t":"4.2 Careers in Health Tech & Telemedicine in West Africa","d":"10:30","v":"SkzILojGPos"},{"t":"📝 Quiz: Clinic Operations & Health Tech Careers","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Health Data, Reporting & Quality in Practice","icon":"📊","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Health Indicators & the Reporting Chain: From Register to DHIS2","d":"Video + notes","v":"MRLAyC5L2Rg"},{"t":"5.2 Data Quality: Making Health Data Accurate, Complete & Timely","d":"Video + notes","v":"GWiiZWb69Sw"},{"t":"5.3 Analyzing Clinic Data with Spreadsheets: From Numbers to Decisions","d":"Video + notes","v":"aofsdpjvK7w"},{"t":"📝 Quiz: Health Data, Reporting & Quality","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Leading Digital Change in Your Facility","icon":"🎓","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Planning a Paper-to-Digital Project: Scope, Pilot & Rollout","d":"Video + notes","v":"NAFSRKYJTjM"},{"t":"6.2 Bringing People Along: Training Colleagues & Managing Resistance","d":"Video + notes","v":"7oqFhxXHI7A"},{"t":"6.3 Your Health Tech Portfolio & Career Roadmap","d":"Video + notes","v":"_5nWyEAFl2M"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Digital Health Foundations","moduleNum":1,"unlocks":3,"questions":[{"q":"Digital health is best described as:","opts":["Only robots performing surgery","Using digital technology to improve health services and information","Replacing all doctors with apps","Selling medicine online"],"correct":1,"exp":"Digital health means using technology, records, phones, data systems, to improve how health care is delivered and managed."},{"q":"A major weakness of paper-only records at a facility like Redemption Hospital is:","opts":["They are too easy to search","They can be lost, damaged, or misfiled and are hard to share","They update automatically","They require electricity"],"correct":1,"exp":"Paper registers can be destroyed by fire or water, misfiled, or lost, and only one person can use a paper file at a time."},{"q":"A key health data lesson from Liberia's 2014-2016 Ebola response was:","opts":["Data does not matter in an outbreak","Slow, paper-based case reporting delayed the response, fast digital reporting saves lives","Only foreign experts should handle data","Radios replaced the need for records"],"correct":1,"exp":"During Ebola, delays in moving paper case reports slowed contact tracing. Faster digital reporting helped turn the outbreak around."},{"q":"Which free tool is well suited for a clinic intake form that must also work offline in the field?","opts":["KoboToolbox","Photoshop","AutoCAD","Premiere Pro"],"correct":0,"exp":"KoboToolbox is free, built for low-connectivity settings, and lets you collect form data offline and sync later."},{"q":"An electronic health record (EHR) is:","opts":["A printed patient card","A digital version of a patient's health information that authorized staff can access","A type of X-ray machine","A government ID card"],"correct":1,"exp":"An EHR stores patient history, visits, medications, and results digitally so authorized health workers can find and update them quickly."},{"q":"A nurse needs to find a returning patient's last blood pressure reading. With a well-organized EHR she can:","opts":["Search the patient's name and see the reading in seconds","Only find it by asking the patient to remember","Wait for the paper file to be carried from another building","Recreate the record from scratch every visit"],"correct":0,"exp":"Fast search and retrieval is a core EHR advantage, history that took minutes or hours to find on paper appears in seconds."},{"q":"When moving a clinic from paper to digital records, a safe transition plan should:","opts":["Burn the paper records on day one","Run paper and digital side by side for a period while staff are trained","Let each nurse invent her own filing system","Digitize nothing until every computer is brand new"],"correct":1,"exp":"A parallel period with training protects patient care while staff gain confidence, sudden switches without backup risk losing critical information."},{"q":"Which is an advantage Google Forms offers a small Liberian clinic building a patient intake form?","opts":["It requires an expensive annual license","It is free and automatically collects responses into a spreadsheet","It only works on hospital mainframe computers","It prints paper forms by itself"],"correct":1,"exp":"Google Forms costs nothing and feeds every submission into a Google Sheet, giving clinics instant, searchable intake data."},{"q":"Well-designed digital intake forms reduce data entry errors mainly by:","opts":["Letting staff type anything in any field","Using required fields, dropdown choices, and checks so wrong entries are caught immediately","Removing all questions from the form","Asking every question twice"],"correct":1,"exp":"Required fields and constrained choices (like dropdowns for sex or county) prevent blanks, misspellings, and impossible values at the moment of entry."},{"q":"Compared with a paper register, digital records help a busy facility like JFK because multiple authorized staff can:","opts":["Access the same patient's information at the same time from different rooms","Take the only copy home","Change diagnoses without any trace","Avoid writing anything at all"],"correct":0,"exp":"A paper file can be in only one place at once; a digital record can be viewed simultaneously by the lab, the pharmacy, and the consulting room."}]},"mod2":{"title":"Quiz: Telehealth & Patient Privacy","moduleNum":2,"unlocks":3,"questions":[{"q":"Telehealth means:","opts":["Watching health TV shows","Delivering health services and consultations remotely using phones or the internet","Only hospital-to-hospital video calls","A type of health insurance"],"correct":1,"exp":"Telehealth uses calls, video, and messaging to deliver consultations, follow-up, and health education at a distance."},{"q":"A good use of SMS in patient care is:","opts":["Posting patient diagnoses publicly","Sending appointment and medication reminders","Replacing all physical examinations","Advertising unrelated products"],"correct":1,"exp":"Simple SMS reminders on Lonestar or Orange networks measurably improve appointment attendance and medication adherence."},{"q":"Before discussing a patient's condition on WhatsApp, a health worker should:","opts":["Post it in a community group to get advice fast","Get consent, use private one-to-one messages, and follow facility policy","Add the patient's photo for clarity","Share it with family friends"],"correct":1,"exp":"Patient information must stay confidential: get consent, never use public groups, and follow your facility's communication policy."},{"q":"Patient confidentiality means:","opts":["Hiding information from the patient","Sharing patient information only with those authorized to provide their care","Deleting all patient records yearly","Never writing anything down"],"correct":1,"exp":"Confidentiality protects patients' trust, their information is shared only with authorized caregivers on a need-to-know basis."},{"q":"A patient in rural Grand Gedeh has a basic phone with no internet. The best telehealth channel is:","opts":["4K video conference","Voice call or SMS on the mobile network","Email with attachments","A mobile app download"],"correct":1,"exp":"Effective telehealth matches the channel to the patient, voice calls and SMS work on any phone and any network signal."},{"q":"During a phone consultation, the health worker should START by:","opts":["Confirming the patient's identity and getting consent to proceed","Prescribing medicine immediately","Asking the patient to send money","Putting the patient on hold indefinitely"],"correct":0,"exp":"Verifying identity and consent protects both patient and provider, you must know who you are treating and that they agree to a remote consultation."},{"q":"Which situation is NOT appropriate for telehealth alone and needs urgent in-person referral?","opts":["A routine medication refill question","A patient with severe chest pain and difficulty breathing","A follow-up on a healed wound","General health education about handwashing"],"correct":1,"exp":"Emergencies like severe chest pain and breathing difficulty need immediate physical care, telehealth's job is to recognize red flags and refer fast."},{"q":"A clinic wants to remind 60 hypertension patients about monthly check-ups. The most efficient ethical approach is:","opts":["Posting the patient list in a public Facebook group","Sending each consenting patient an individual SMS reminder","Announcing patient names over community radio","Waiting for patients to remember on their own"],"correct":1,"exp":"Individual SMS to patients who consented delivers the reminder privately, public posts or broadcasts would breach confidentiality."},{"q":"A strong password practice for a phone or computer holding patient data is:","opts":["Using 1234 so colleagues can guess it easily","Sharing one password openly across the whole community","A unique password or PIN kept secret, with the screen locked when unattended","Writing the password on the device itself"],"correct":2,"exp":"Device locks and secret, unique passwords are the first line of defense, an unlocked phone full of patient messages is a privacy breach waiting to happen."},{"q":"If a health worker's phone containing patient WhatsApp conversations is stolen, the FIRST professional step is to:","opts":["Hope nobody looks at it","Report it to the supervisor or facility so accounts can be secured and risks assessed","Buy a new phone and say nothing","Post about the theft on social media with patient details"],"correct":1,"exp":"Prompt reporting lets the facility secure accounts, log out sessions remotely, and manage any confidentiality risk, silence makes the breach worse."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"MOH Liberia and county health teams primarily use DHIS2 to:","opts":["Play training videos","Collect, aggregate, and report national health data","Pay staff salaries","Order ambulances"],"correct":1,"exp":"DHIS2 is the national health management information system, facilities report indicators that guide planning and supplies."},{"q":"A false health cure is going viral on WhatsApp. The best response is:","opts":["Forward it quickly to warn people","Check official sources like MOH Liberia or WHO, then share the correct information without forwarding the rumor","Ignore all health information forever","Argue with strangers in every group"],"correct":1,"exp":"Verify with official sources first. Forwarding a rumor, even to debunk it, helps it spread; share the verified facts instead."},{"q":"Digital inventory tracking helps a clinic mainly by:","opts":["Making the pharmacy look modern","Preventing stockouts and expiry of essential medicines","Replacing the pharmacist","Increasing drug prices"],"correct":1,"exp":"A simple digital stock tracker shows what is running low or expiring, so clinics reorder on time and avoid dangerous stockouts."},{"q":"When designing a digital patient intake workflow, the FIRST step is to:","opts":["Buy expensive servers","Map the current paper process and the exact data the clinic collects","Delete all old records","Print more forms"],"correct":1,"exp":"You digitize a process, not just a form, first understand what data is collected, by whom, and where it flows."},{"q":"This course prepares you to:","opts":["Perform surgery","Apply practical digital skills, records, intake forms, telehealth, follow-up, and data privacy, in health settings","Repair hospital generators","Replace the Ministry of Health"],"correct":1,"exp":"You now have employable digital health skills and a capstone project to show clinics, county health teams, and NGOs."},{"q":"A clinic wants intake data collected in a village with no network coverage, synced later in town. The best tool from this course is:","opts":["KoboToolbox, because it collects offline and syncs when connected","A live video call platform","An online-only survey site","FM radio"],"correct":0,"exp":"KoboToolbox was built for low-connectivity field data collection, record offline, then sync when signal returns."},{"q":"The single most important rule before conducting any telehealth consultation is to:","opts":["Use the most expensive video platform available","Confirm the patient's identity and consent","Ask for payment upfront","Record the call secretly"],"correct":1,"exp":"Identity verification and consent are the ethical and safety foundation of every remote consultation, regardless of channel."},{"q":"Sharing a patient's diagnosis in a WhatsApp group of health workers who are NOT involved in that patient's care violates:","opts":["Only rules about photos","Network operator policies only","The need-to-know principle of confidentiality","No rules, since they are all health workers"],"correct":2,"exp":"Confidentiality is need-to-know: being a health worker does not entitle anyone to information about patients they do not care for."},{"q":"In DHIS2 terms, a facility's monthly report contributes to:","opts":["Individual patient prescriptions","Staff salary negotiations only","Television advertising","The national aggregated health data used for planning and resource allocation"],"correct":3,"exp":"DHIS2 aggregates facility indicator data upward so counties and the MOH can plan supplies, staffing, and programs."},{"q":"A facility reports 200 outpatient visits but its register recount shows 156. The data quality dimension failing here is:","opts":["Accuracy","Timeliness","Confidentiality","Connectivity"],"correct":0,"exp":"When the reported figure does not match the source register, the data is inaccurate, the report must reflect what was actually recorded."},{"q":"Penta 3 coverage is a key indicator because it measures:","opts":["The age of the facility building","Children completing their third pentavalent vaccine dose","The number of beds in a facility","Ambulance fuel consumption"],"correct":1,"exp":"Penta 3 tracks immunization series completion, a core child health indicator reported monthly by Liberian facilities."},{"q":"Stock of ACT malaria treatment falls to its reorder level in September, just as the rainy season peaks. The clinic should:","opts":["Stop testing patients for malaria","Borrow expired stock from storage","Place the resupply order immediately","Wait until stock reaches zero"],"correct":2,"exp":"The reorder level exists so supply arrives before stockout, waiting for zero during peak malaria season risks patient lives."},{"q":"The ratio of ANC 4 to ANC 1 attendances primarily measures:","opts":["The number of deliveries at home","Vaccine cold chain performance","Pharmacy profits","How well women who start antenatal care are retained through four visits"],"correct":3,"exp":"Comparing fourth visits to first visits reveals retention in antenatal care, low ratios point to follow-up gaps that reminders can address."},{"q":"When launching a new digital intake system, running paper and digital in parallel during the pilot protects the facility because:","opts":["No patient data is lost if the new system fails or confuses staff","It doubles the clinic's income","It removes the need for training","Paper automatically corrects digital errors"],"correct":0,"exp":"A parallel safety net means teething problems in the pilot never cost the facility real patient information."},{"q":"A pilot should be judged against:","opts":["How many features the software has","Success measures defined before it started, like intake time and record completeness","Whether the tool looks modern","The opinion of one senior staff member only"],"correct":1,"exp":"Pre-defined measures make the pilot an honest test, you compare real outcomes, not impressions, before deciding to roll out."},{"q":"A respected nurse learns the new system quickly and helps colleagues daily. In change management terms she is a:","opts":["Vendor","Regulator","Champion","Auditor"],"correct":2,"exp":"Champions are trusted peers who support adoption from within, often more effective than top-down instruction."},{"q":"The most effective format for training busy clinic staff on a new digital tool is:","opts":["A three-hour theory lecture with no devices","A memo posted on the wall with no demonstration","Sending staff a software manual by email","Short hands-on practice at the actual service point with the actual device"],"correct":3,"exp":"Adults learn digital tools by doing, brief, practical sessions in the real work context beat lectures and manuals."},{"q":"When building a portfolio intake form to show employers, the data inside it must be:","opts":["Invented sample data, never real patient information","Copied from your facility's real register","Real names but with ages removed","Photos of actual patient files"],"correct":0,"exp":"Using real patient data in a portfolio is a confidentiality breach, sample data shows the same skill while demonstrating your professionalism."},{"q":"Which set of roles most directly matches the skills from this course for job seekers in Liberia's health sector?","opts":["Customs officer, harbor pilot, air traffic controller","Health records clerk, M&E assistant, field enumerator, telehealth support agent","Surgeon, anesthesiologist, radiologist","Civil engineer, land surveyor, architect"],"correct":1,"exp":"Records, data collection, reporting, analysis, and telehealth communication map directly onto these growing digital health roles."},{"q":"A facility's missed-appointment rate fell after introducing SMS reminders. The strongest way to report this at the county review meeting is:","opts":["Reading the entire appointment register aloud","Waiting a year before mentioning it","A before-and-after chart with the actual rates and the action taken","A verbal claim that things feel better"],"correct":2,"exp":"Evidence presented as a simple before-after comparison, data, action, result, is how improvements get recognized and scaled."}]},"mod4":{"title":"Quiz: Clinic Operations & Health Tech Careers","moduleNum":4,"questions":[{"q":"A simple digital drug inventory tracker should record, at minimum:","opts":["Only the color of each medicine box","Item name, quantity received, quantity dispensed, balance, and expiry date","Only the names of patients who collect drugs","The pharmacist's daily schedule"],"correct":1,"exp":"Tracking receipts, dispensing, running balance, and expiry is what lets a clinic reorder on time and pull expiring stock first."},{"q":"The 'first expiry, first out' (FEFO) rule means a pharmacy should:","opts":["Dispense the stock that expires soonest before newer stock","Throw away the newest stock first","Dispense drugs in alphabetical order","Keep expired drugs on the shelf as backup"],"correct":0,"exp":"FEFO ensures medicines are used before they expire, cutting waste, a digital tracker with expiry dates makes it easy to follow."},{"q":"A reorder level (minimum stock level) for malaria medicine tells the clinic:","opts":["The price of the medicine","The quantity at which a new order must be placed to avoid a stockout","How many patients have malaria","When to close the pharmacy"],"correct":1,"exp":"When stock falls to the reorder level, there is just enough left to cover demand while the new supply arrives, order at that point, not after running out."},{"q":"A simple digital appointment book (even a shared spreadsheet or calendar) helps a clinic mainly by:","opts":["Reducing crowding and long waits by spreading patients across time slots","Making patients arrive at random times","Replacing all clinical staff","Increasing missed appointments"],"correct":0,"exp":"Scheduled slots smooth patient flow, shorten queues, and make follow-up reminders possible, a major service upgrade at nearly zero cost."},{"q":"Which task is a typical duty of a health facility data clerk or health information officer in Liberia?","opts":["Performing surgical operations","Compiling facility registers into accurate monthly reports for the county health team","Driving the ambulance","Setting national health policy alone"],"correct":1,"exp":"Data clerks turn daily registers into the accurate, timely monthly reports that flow to county health teams and DHIS2, a growing career path."},{"q":"Which growing career combines clinical knowledge with digital skills taught in this course?","opts":["Health informatics and monitoring & evaluation (M&E) roles with facilities and NGOs","Deep sea fishing","Commercial airline piloting","Gold mining supervision"],"correct":0,"exp":"Health informatics, M&E, and digital health coordinator roles are expanding across West Africa as facilities and NGOs digitize."},{"q":"A clinic's spreadsheet shows amoxicillin stock: received 500, dispensed 380. The balance the tracker should show is:","opts":["880","500","120","380"],"correct":2,"exp":"Balance = received minus dispensed: 500 - 380 = 120, and if 120 is at or below the reorder level, it is time to order."},{"q":"When applying for a health tech-related job, the strongest evidence of your skills is:","opts":["Saying you are good with computers","A capstone project and verifiable certificate showing real forms, trackers, or workflows you built","A long list of hobbies","Memorizing the names of software companies"],"correct":1,"exp":"Employers trust demonstrated work, a working intake form or inventory tracker plus a verifiable certificate beats unsupported claims."},{"q":"Telemedicine services in West Africa increasingly hire nurses and physician assistants to:","opts":["Conduct structured remote consultations and triage by phone, chat, and video","Only clean the office","Replace mobile network engineers","Manufacture smartphones"],"correct":0,"exp":"Remote triage and consultation roles are among the fastest-growing clinical jobs, exactly the telehealth skills practiced in Module 2."},{"q":"Why should a clinic track expiry dates digitally rather than relying on memory?","opts":["Expired drugs become stronger over time","A sortable expiry column reveals at a glance what to use or redistribute before losses occur","Memory is always perfectly reliable","Expiry dates change daily"],"correct":1,"exp":"Sorting stock by expiry date makes hidden near-expiry items visible in seconds, preventing both waste and the danger of dispensing expired medicine."}]},"mod5":{"title":"Quiz: Health Data, Reporting & Quality","moduleNum":5,"questions":[{"q":"In health reporting, an indicator is best defined as:","opts":["Any rumor about a disease","A precisely defined, countable measure of health services or health status","The name of a hospital department","A type of medical instrument"],"correct":1,"exp":"Indicators like ANC 1 or Penta 3 have exact definitions so that every facility counts the same thing the same way."},{"q":"The correct order of Liberia's routine health data reporting chain is:","opts":["WhatsApp group, radio announcement, register","DHIS2, register, county team, tally sheet","Daily register, monthly facility summary, DHIS2 entry, county review, national aggregation","National level first, then facilities copy the numbers down"],"correct":2,"exp":"Data moves upward: service-point registers feed monthly summaries, which enter DHIS2 and are reviewed at county then national level."},{"q":"A facility reports 120 confirmed malaria cases but only 95 cases tested. This signals a problem of:","opts":["Good performance worth celebrating","Patient confidentiality","Timeliness","Internal consistency, since confirmed cases cannot exceed tested cases"],"correct":3,"exp":"Confirmed cases are a subset of tested cases, more confirmed than tested is logically impossible and flags a recording or compilation error."},{"q":"A report that contains correct numbers but arrives three weeks after the deadline fails on:","opts":["Timeliness","Accuracy","Confidentiality","Legibility"],"correct":0,"exp":"Late data cannot inform this month's supply and response decisions, timeliness is a quality dimension in its own right."},{"q":"The most reliable way to tally daily services is to:","opts":["Copy last month's numbers","Record each service as it happens during the day","Reconstruct the day from memory after closing","Estimate based on how busy it felt"],"correct":1,"exp":"Real-time tallying captures reality; end-of-day memory reconstruction is where undercounts and guesses creep in."},{"q":"ANC 1 was 80 and ANC 4 was 20 last quarter. The ANC completion picture tells the facility that:","opts":["Too many women attended ANC","The data must be deleted","All women completed their visits","Only about a quarter of women who started antenatal care reached the fourth visit, follow-up needs strengthening"],"correct":3,"exp":"20 of 80 is 25% completion, a signal to strengthen follow-up, for example with the SMS reminder methods from Module 2."},{"q":"Before submitting a monthly report, a good self-check is to:","opts":["Recount one or two indicators from the register and compare with the summary","Round all numbers up to look better","Submit first and check later","Change figures until they match last month exactly"],"correct":0,"exp":"A quick register recount catches copying and tallying errors before they travel up the chain, the same spirit as DHIS2 validation rules."},{"q":"Comparing this July's malaria cases with LAST July's cases (rather than with January's) is smart because:","opts":["July is the only month that matters","January data is always wrong","It controls for seasonality, since malaria in Liberia follows the rains","Older data is more accurate"],"correct":2,"exp":"Malaria rises with the May-October rains; same-month year-on-year comparison separates real change from normal seasonal patterns."},{"q":"Which spreadsheet feature turns a monthly indicator column into a visible trend?","opts":["Changing the font color only","Printing the sheet","Deleting the column","Inserting a line chart from the data"],"correct":3,"exp":"A line chart makes rises and falls visible at a glance, the fastest way to spot a problem or show one to colleagues."},{"q":"The most effective way to present a data finding at a staff meeting is:","opts":["Reading every number in the register aloud","One clear chart plus a sentence stating the problem and a proposed action","Keeping findings secret until the annual report","Presenting only good news"],"correct":1,"exp":"Evidence, problem, proposal, one chart and one actionable sentence is how data actually changes decisions in a facility."}]}},"reviews":[{"name":"Korpo Weah","loc":"Paynesville, Liberia","date":"April 2026","bg":"#9f1239","init":"KW","rating":5,"text":"I am a records clerk at a private clinic in Paynesville. After Module 1, I built our first digital intake form in KoboToolbox and we digitized three years of patient files in two months. Our doctor now finds any patient history in seconds. My supervisor gave me a new title: Health Records Officer."},{"name":"Emmanuel Dolo","loc":"Ganta, Nimba County","date":"March 2026","bg":"#002868","init":"ED","rating":5,"text":"As a community health assistant, I used to walk hours to hand in paper reports. This course taught me how our data feeds into DHIS2 and how to do patient follow-up by SMS on the Lonestar network. My defaulter tracing for TB patients improved so much that the county health team asked me to train other CHAs."},{"name":"Princess Toe","loc":"Monrovia, Liberia","date":"May 2026","bg":"#10b981","init":"PT","rating":5,"text":"I am a nurse and I always feared technology. Dr. Musu explains everything with examples from JFK and Redemption that I recognize from my own work. I now run phone follow-up consultations for our hypertension patients over WhatsApp, and our missed-appointment rate dropped by almost half."},{"name":"Abraham Fahnbulleh","loc":"Voinjama, Lofa County","date":"June 2026","bg":"#7c3aed","init":"AF","rating":4,"text":"Our clinic pharmacy in Lofa kept running out of essential drugs. Using the inventory lesson in Module 4, I set up a simple stock tracker on a spreadsheet and we have not had a stockout of malaria medicine since February. The capstone project became a real system we use every day. Internet in Voinjama is slow, but the lessons downloaded fine."}],"faqs":[{"q":"Do I need to be a doctor or nurse to take this course?","a":"No. This course is for anyone connected to health work, nurses, physician assistants, CHAs, pharmacy staff, records clerks, health sciences students, and tech-minded people who want to serve clinics and hospitals. No medical or IT background is required."},{"q":"Will the tools taught cost my clinic money?","a":"No. The course focuses on free tools: Google Forms, KoboToolbox, WhatsApp, SMS, and free spreadsheet software. DHIS2 is already provided by MOH Liberia to health facilities. Everything you learn can be applied with a smartphone and mobile data."},{"q":"Is patient data safe with these digital tools?","a":"Yes, when used correctly, and an entire lesson is dedicated to privacy and confidentiality. You will learn consent, need-to-know sharing, safe messaging practices, and the confidentiality standards expected by MOH Liberia and health NGOs."},{"q":"Is the certificate useful for health sector jobs?","a":"Yes. Your TIH certificate carries a unique verification code that employers can confirm online. Health facilities, county health teams, and NGOs across Liberia increasingly ask for digital skills, and your capstone project gives you real evidence to show at interviews."}]};
COURSES_DB['remote-work'] = {"id":"remote-work","title":"Remote Work & Freelancing","shortDesc":"Earn US dollars online, package your skills, win clients on Upwork and Fiverr, build a portfolio, price your work, and get paid reliably from Liberia.","category":"Remote Work & Freelancing","icon":"💼","gradient":"linear-gradient(135deg,#c2410c,#e31e24)","instructor":"Emmanuel Gaye","instructorTitle":"Remote Work Coach & Top-Rated Upwork Freelancer, TIH","instructorBio":"Emmanuel Gaye is a Top-Rated Plus Upwork freelancer who built a six-figure remote career in digital marketing and writing without ever leaving Monrovia. He has coached over 800 West African freelancers to land their first international clients and get paid reliably in USD.","rating":4.9,"reviewCount":612,"students":"3,200+","duration":"29h","level":"Intermediate","price":"FREE","origPrice":"$140","isFree":true,"badge":"free","certId":"TIH-2026-RMT-0001","learn":["Understand the global remote work market and which skills earn USD from Liberia","Identify, package, and position your most marketable skill for international clients","Build an Upwork profile and Fiverr gigs that win high-paying clients","Write proposals and cover letters that get replies and interviews","Create a professional portfolio for free using tools like Canva and Google Sites","Price your services confidently and negotiate rates in US dollars","Receive international payments in Liberia using Payoneer, Wise, and mobile money","Deliver 5-star work, earn repeat clients, and grow from solo freelancer to agency owner"],"requirements":["Basic computer and internet skills (or complete our free Computer Literacy course first)","A reliable smartphone or laptop plus a plan for managing data costs and power outages","At least one skill to offer such as writing, design, virtual assistance, or data entry (we help you find yours)"],"about":["The internet has erased the distance that once locked Liberian youth out of the global job market. Today a young person in Monrovia, Buchanan, or Gbarnga can earn United States dollars from clients in New York, London, or Nairobi without ever leaving home. This course is a complete, practical roadmap for turning your skills into real global income from right here in Liberia.","You will learn exactly how to choose a marketable skill, build a winning profile on Upwork and Fiverr, write proposals that get replies, and price your work fairly. Most importantly, this course tackles the challenge that stops most Liberians before they start: how to actually get paid. We walk through Payoneer, Wise, mobile money, and real PayPal workarounds, plus how to plan around data costs and electricity outages so you never miss a deadline.","Thousands of West African freelancers are already earning $800 to $2,000 every month online. Whether you are a student, a job seeker, or a professional wanting extra income, this free course gives you a clear, step-by-step path from your first proposal to your first paycheck and beyond, all the way to building your own small agency."],"modules":[{"title":"Module 1: The Global Remote Work Opportunity","icon":"💼","meta":"4 lessons · 40 min","lessons":[{"t":"1.1 The Remote Work Landscape: What Skills Actually Sell","d":"11:20","v":"7oM-Nfl8CtQ"},{"t":"1.2 Finding & Packaging Your Marketable Skill","d":"10:15","v":"Tn6-PIqc4UM"},{"t":"1.3 Creating an Upwork Profile That Wins Clients","d":"13:40","v":"9NzTAZPra3A"},{"t":"📝 Quiz: The Remote Work Opportunity","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Winning Clients & Building Your Presence","icon":"🎯","meta":"4 lessons · 40 min","lessons":[{"t":"2.1 Fiverr Gigs That Sell: Setup & Optimization","d":"12:30","v":"8gNUUK6fwX4"},{"t":"2.2 Writing Winning Proposals & Cover Letters","d":"11:45","v":"rErBcmM1wDk"},{"t":"2.3 Building a Portfolio with Free Tools","d":"10:50","v":"DvMNG6MUlGI"},{"t":"📝 Quiz: Winning Your First Clients","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Pricing & Getting Paid in Liberia","icon":"💰","meta":"3 lessons · 50 min","lessons":[{"t":"3.1 Pricing Your Services & Negotiating Rates","d":"12:10","v":"2GzslyLAD1E"},{"t":"3.2 Getting Paid in Liberia: Payoneer, Wise, Mobile Money & PayPal","d":"13:20","v":"9uU-i5ZI-_U"},{"t":"🛠️ Capstone: Launch Your Complete Freelance Profile & Portfolio","d":"Project","isProject":true}]},{"title":"Module 4: Delivering, Growing & Certification","icon":"🏆","meta":"3 lessons · 40 min","lessons":[{"t":"4.1 Delivering Excellent Work & Earning 5-Star Reviews","d":"9:40","v":"Tn6-PIqc4UM"},{"t":"4.2 Growing from Freelancer to Agency","d":"14:00","v":"FTOpohYyn1o"},{"t":"📝 Quiz: Delivering Excellence & Growing Your Freelance Business","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Client Communication, Contracts & Freelance Finances","icon":"🤝","meta":"4 lessons · reading + quiz","lessons":[{"t":"5.1 Client Communication Mastery: From Kickoff to Final Delivery","d":"Video + notes","v":"cZ_nqaptW88"},{"t":"5.2 Contracts, Scope Creep & Handling Difficult Clients","d":"Video + notes","v":"vSsVueEptN4"},{"t":"5.3 Managing Your Freelance Money: Budgeting, Fees & Reinvesting in Liberia","d":"Video + notes","v":"gw428ygPNiY"},{"t":"📝 Quiz: Client Communication, Contracts & Money","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Capstone, Your Freelance Business Launch","icon":"🚀","meta":"4 lessons · capstone + final","lessons":[{"t":"6.1 Positioning & Personal Brand: Becoming the Obvious Choice","d":"Video + notes","v":"rk9nCnLpreU"},{"t":"6.2 Beyond the Marketplaces: Direct Clients, Referrals & LinkedIn","d":"Video + notes","v":"d7Ms-a2Z9mY"},{"t":"6.3 The 90-Day Launch Plan: Portfolio, Targets & Your First $1,000","d":"Video + notes","v":"Oos9UXRvr28"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: The Remote Work Opportunity","moduleNum":1,"unlocks":3,"questions":[{"q":"What does remote work allow a freelancer in Liberia to do?","opts":["Only work for local companies","Earn income in US dollars from international clients online","Avoid using the internet entirely","Work only inside a physical office"],"correct":1,"exp":"Remote work lets you serve clients anywhere in the world and get paid in USD without leaving Liberia."},{"q":"Which is a beginner-friendly skill that sells well online?","opts":["Brain surgery","Virtual assistance","Operating heavy machinery","Driving a local taxi"],"correct":1,"exp":"Virtual assistance needs organization and communication, making it one of the fastest ways to start earning online."},{"q":"A truly marketable skill is one that:","opts":["Only you personally enjoy","Clients are actively searching for and paying for","Always requires a university degree","Cannot be found anywhere on Upwork"],"correct":1,"exp":"A skill only earns money when there is real client demand for it on platforms like Upwork and Fiverr."},{"q":"The best Upwork profile title is:","opts":["Generic, like just Freelancer","Specific and benefit-driven, like SEO Blog Writer for Health Brands","Left completely blank","Only your full name"],"correct":1,"exp":"A specific, benefit-driven title tells clients exactly what you do and helps you stand out."},{"q":"Why should you not hide that you are based in Liberia?","opts":["It is illegal to hide your location","Many clients value hardworking African freelancers and fair rates","Upwork automatically bans hidden locations","Hiding it slows down your internet"],"correct":1,"exp":"Many clients appreciate reliable African freelancers, so your location can be a strength, not a weakness."},{"q":"Which section of an Upwork profile gives clients visual proof of what you can actually deliver?","opts":["The notification settings","The portfolio section with work samples","The password page","The payment tax form"],"correct":1,"exp":"The portfolio section shows real samples of your work, visual proof that backs up the claims in your title and overview."},{"q":"A recent graduate in Gbarnga is organized, writes clear English, and manages her church's schedule and records. The most natural first freelance skill to package is:","opts":["Aerospace engineering","Virtual assistance and administrative support","Courtroom litigation","Heavy equipment repair"],"correct":1,"exp":"Packaging means matching skills you already use, organization, communication, scheduling, to services clients already buy, like virtual assistance."},{"q":"The overview (bio) section of a winning Upwork profile should focus mainly on:","opts":["The client's problems and the results you deliver for them","Your life story starting from childhood","Complaints about the job market","A list of hobbies unrelated to work"],"correct":0,"exp":"Clients scan for what you can do for them, leading with their problems and your results converts profile views into invitations."},{"q":"Which is a realistic way to verify that a skill has real paying demand before committing to it?","opts":["Assume demand because you enjoy the skill","Search the skill on Upwork and Fiverr and study how many jobs and gigs exist and what they pay","Ask only family members if they would pay","Wait for clients to find you first"],"correct":1,"exp":"The platforms themselves are free market research, job volume, gig counts, and posted rates show whether clients actually pay for a skill."},{"q":"In-demand remote skills that West African beginners commonly start earning with include:","opts":["Writing, graphic design, data entry, and virtual assistance","Skills that require being physically present abroad","Only advanced artificial intelligence research","Skills no client has ever posted a job for"],"correct":0,"exp":"Writing, design, data entry, and VA work have high job volume, low startup cost, and are proven entry points for West African freelancers."}]},"mod2":{"title":"Quiz: Winning Your First Clients","moduleNum":2,"unlocks":3,"questions":[{"q":"On Fiverr, how do clients typically start working with you?","opts":["They must call you first","They come to you and order your gigs directly","They can only pay in cash","They cannot leave reviews"],"correct":1,"exp":"On Fiverr you set up gigs once and buyers order directly, which is great when your internet is unreliable."},{"q":"How many packages can a single Fiverr gig offer?","opts":["Only one","Only two","Three: Basic, Standard, and Premium","Exactly ten"],"correct":2,"exp":"Offering Basic, Standard, and Premium packages lets buyers choose an option that fits their budget."},{"q":"A strong Upwork proposal should be:","opts":["As long as you can possibly make it","Copy-pasted identically for every job","Personalized to the client and under 200 to 300 words","Sent without reading the job post"],"correct":2,"exp":"Short, personalized proposals that address the client problem get far more replies than long generic ones."},{"q":"If you have no experience yet, the best way to win a job is to:","opts":["Lie about your past work","Create a relevant sample and attach it to your proposal","Charge the highest price possible","Skip sending proposals altogether"],"correct":1,"exp":"A relevant free sample proves your ability and can beat competitors who only make promises."},{"q":"Which is a good free tool for building a portfolio?","opts":["Canva","A paid television subscription","A landline telephone","No free tools exist"],"correct":0,"exp":"Canva lets you design professional graphics and mockups for free, even with no design experience."},{"q":"In a Fiverr gig title and description, keywords matter because they:","opts":["Change your payment method","Help your gig appear when buyers search for that service","Make the gig deliver itself","Remove the need for good reviews"],"correct":1,"exp":"Fiverr is a search engine, gigs that use the words buyers actually type (like 'logo design' or 'blog post') get found and ordered."},{"q":"The opening line of a winning proposal should:","opts":["Begin with 'Dear Sir/Madam' and your full biography","Show you read the job post by addressing the client's specific problem","Ask immediately how much they will pay","Copy the same greeting used in your last fifty proposals"],"correct":1,"exp":"Clients delete generic openings, referencing their exact project in the first line proves you read the post and instantly stands out."},{"q":"A writer with no clients yet can build a credible portfolio by:","opts":["Waiting until a client provides work to display","Creating three strong self-initiated samples in her niche and publishing them on a free Google Sites page","Copying articles from famous websites into her profile","Listing skills without any samples"],"correct":1,"exp":"Self-initiated samples are legitimate portfolio pieces, they prove ability now, and free tools like Google Sites make them look professional."},{"q":"Attaching a short relevant sample to a proposal works because it:","opts":["Makes the proposal file larger","Lets the client see proof of quality instead of just promises","Guarantees the platform will promote you","Replaces the need to read the job post"],"correct":1,"exp":"A sample shifts the client's question from 'can this person do it?' to 'when can they start?', evidence beats claims."},{"q":"On Fiverr, fast response time to buyer messages matters because:","opts":["Slow replies increase your prices automatically","Responsiveness affects your gig ranking and buyers often order from the first good answer","Fiverr charges for every reply","Buyers cannot see your response time"],"correct":1,"exp":"Fiverr tracks response rate and time, quick, helpful replies improve visibility and win buyers who message several sellers at once."}]},"final":{"title":"Final Assessment","moduleNum":6,"unlocks":null,"isFinal":true,"questions":[{"q":"When a client says their budget is tight, the smartest response is to:","opts":["Immediately cut your price in half","Adjust the scope, such as offering fewer revisions or a smaller package","Cancel the job right away","Ignore the client completely"],"correct":1,"exp":"Adjusting scope protects your value while still giving the client an option they can afford."},{"q":"Which payment method is preferred because Upwork and Fiverr pay out to it directly?","opts":["Cash pickup at a market","Payoneer","Mailing gold","A local savings club"],"correct":1,"exp":"Payoneer connects directly to Upwork and Fiverr and gives you a USD receiving account and card."},{"q":"Most negative freelance reviews are actually caused by:","opts":["Bad work quality only","Mismatched expectations and poor communication","Delivering the work too early","Politely asking for feedback"],"correct":1,"exp":"Setting clear expectations in writing and communicating often prevents most bad reviews."},{"q":"To grow from freelancer to agency, your main job becomes:","opts":["Doing every task yourself forever","Winning clients while a trained team delivers the work","Lowering all of your prices","Stopping communication with clients"],"correct":1,"exp":"As an agency owner you focus on sales and quality control while your team handles delivery."},{"q":"To handle unreliable power and internet, a smart freelancer should:","opts":["Promise impossible deadlines","Plan ahead and deliver early using backup power and data","Never tell clients about any challenges","Only try to work during blackouts"],"correct":1,"exp":"Planning ahead with backup power, data bundles, and early delivery keeps you dependable to clients."},{"q":"Strong freelance positioning is best described as:","opts":["Serving a specific client type with a specific result you can credibly prove","Listing as many unrelated skills as possible","Copying the profile of the top freelancer in every category","Hiding what you do until clients ask"],"correct":0,"exp":"Specialists get found and chosen, positioning combines what you are good at, what clients pay for, and what your samples prove."},{"q":"Which trio of independent client channels makes a freelance business resilient?","opts":["Waiting to be discovered without any outreach","Marketplaces, referrals, and LinkedIn outreach","One single platform account only","Random social media comments only"],"correct":1,"exp":"Multiple channels mean no single algorithm or account issue can cut off your income, a core lesson of the launch plan."},{"q":"For a direct (off-platform) client you found yourself, standard professional protection is:","opts":["Full payment only after the client uses the work for a month","No agreement, to appear trusting","A written agreement plus a 30-50% upfront deposit","Starting work on a verbal promise"],"correct":2,"exp":"Off-platform, you provide the structure: written scope and a deposit before work starts are worldwide freelance standards."},{"q":"Payoneer and Wise are both valuable to a Liberian freelancer because they:","opts":["Are physical banks with branches in every county","Eliminate the need to deliver work","Only operate inside the United States","Let international clients pay in USD that you can access from Liberia"],"correct":3,"exp":"Both services receive international USD payments and connect to Liberian withdrawal options, the payment bridge this course is built around."},{"q":"Verifying your Payoneer account during your first two weeks, before winning work, is smart because:","opts":["Verification takes time and you want payouts ready the moment you earn","Unverified accounts earn higher interest","Clients can see your bank balance","Payoneer charges more for early registration"],"correct":0,"exp":"Verification delays are the classic reason first payments get stuck, completing it early means your first earnings flow without stress."},{"q":"A client's message says: 'Also, could you quickly add three more product descriptions?' beyond the agreed ten. The course-recommended reply is to:","opts":["Delete the original ten descriptions","Welcome the addition and quote a price for the extra items","Do it free and stay silent","Refuse rudely and end the contract"],"correct":1,"exp":"Acknowledge-and-price turns scope creep into either fair extra income or a polite boundary, both outcomes protect you."},{"q":"Which behavior most damages the trust an international client places in a freelancer?","opts":["Asking a clarifying question at kickoff","Delivering one day before the deadline","Going silent for days without explanation","Sending a brief progress update mid-project"],"correct":2,"exp":"Silence triggers the fear every remote client has, updates, questions, and early delivery all build trust, but disappearing destroys it."},{"q":"The freelancer's three-way payment split directs money to:","opts":["Three different mobile phones","Three separate Fiverr accounts","Lottery tickets, gifts, and travel","Living costs, business reinvestment, and an emergency buffer"],"correct":3,"exp":"Paying yourself, reinvesting in the business, and building a two-to-three-month buffer is the system that survives slow months."},{"q":"Why does a savings buffer of two to three months' expenses improve the QUALITY of a freelancer's clients?","opts":["It lets you decline bad-fit or red-flag clients instead of accepting from desperation","Banks send better clients to savers","Buffers automatically raise platform rankings","It has no effect on client quality"],"correct":0,"exp":"Financial breathing room is negotiating power, freelancers with buffers can say no to exploitative offers and wait for good ones."},{"q":"A gig titled 'I will do stuff for you' underperforms mainly because it:","opts":["Is priced too high by default","Contains no searchable keywords or clear service for buyers","Is too specific about the service","Uses too many technical terms"],"correct":1,"exp":"Fiverr is search-driven, vague titles match no buyer searches and communicate no clear value."},{"q":"The strongest evidence-based update to a profile after your first successful contracts is:","opts":["Removing your portfolio to look mysterious","Switching to a completely unrelated niche every week","Adding real results, like 'delivered 12 articles for a US wellness brand'","Claiming ten years of experience you do not have"],"correct":2,"exp":"Real, specific results are credibility gold, they upgrade your profile from promises to proof and justify higher rates."},{"q":"During days 15-45 of the launch plan, the weekly proposal target is:","opts":["One proposal per month","Fifty identical copy-pasted proposals daily","Zero proposals, wait for invitations only","Five to eight personalized proposals, each with a tailored sample"],"correct":3,"exp":"Consistent, personalized volume, not spam and not passivity, is what produces the first two to three contracts on schedule."},{"q":"Moving an existing Upwork client off-platform to avoid fees is:","opts":["A violation of platform rules that risks your account","Encouraged by Upwork","Required after five contracts","The only way to get paid in Liberia"],"correct":0,"exp":"Circumventing platform payment breaks the rules and can end your account, direct channels are for clients you find directly."},{"q":"A freelancer's capstone launch package should include:","opts":["Screenshots of other freelancers' work","Positioning statement, live profiles, portfolio with samples, income tracker, and a 90-day calendar","Only a selfie and a phone number","A list of platforms with no accounts created"],"correct":1,"exp":"The launch package is working evidence of a professional operation, usable with clients, employers, and support programs alike."},{"q":"The long-term progression this course maps for a Liberian freelancer is:","opts":["Staying at beginner prices permanently","Abandoning freelancing after the first difficult client","First contracts on marketplaces, then repeat and direct clients, then higher rates or an agency team","Starting an agency before ever completing a contract"],"correct":2,"exp":"Reviews build reputation, reputation builds repeat and direct work, and proven demand funds higher rates or a team, the full growth ladder."}]},"mod4":{"title":"Quiz: Delivering Excellence & Growing Your Freelance Business","moduleNum":4,"questions":[{"q":"The moment you win a new contract, the FIRST professional step is to:","opts":["Disappear until the deadline","Confirm scope, deliverables, and deadline in writing with the client","Ask for a five-star review immediately","Raise the price you already agreed"],"correct":1,"exp":"A written kickoff confirmation aligns expectations from day one, the single best protection against disputes and bad reviews."},{"q":"Delivering work a day or two BEFORE the deadline helps a Liberian freelancer because it:","opts":["Creates a buffer against power cuts and network outages while impressing the client","Lets you charge double automatically","Means you can skip checking your work","Forces the client to respond faster"],"correct":0,"exp":"Early delivery absorbs Liberia's power and data risks and builds a reputation for reliability that earns repeat work."},{"q":"A client requests a third revision that is clearly outside the agreed scope. The professional response is to:","opts":["Do unlimited free work to avoid conflict","Politely point to the agreed scope and offer the extra work as a paid add-on","Block the client without replying","Delete the project files"],"correct":1,"exp":"Referencing the written scope keeps the relationship professional, extras are welcome, as paid additions, not silent losses."},{"q":"The habit that most reliably produces 5-star reviews is:","opts":["Begging every client repeatedly for stars","Clear communication, meeting the agreed scope, and delivering on or before time","Offering the lowest price on the platform forever","Adding surprise extras the client never asked for instead of the actual work"],"correct":1,"exp":"Reviews follow met expectations, communicate, deliver what was agreed, deliver on time, and stars take care of themselves."},{"q":"A freelancer is fully booked every week but income has stopped growing. The classic next moves are to:","opts":["Raise rates or delegate work to trained subcontractors","Take even more orders at the same price and sleep less","Cancel all current contracts","Stop responding to new inquiries entirely"],"correct":0,"exp":"When time is sold out, growth comes from higher prices or from other people's hands, the doorway from freelancer to agency."},{"q":"When an agency owner delegates client work to a team member, the owner remains responsible for:","opts":["Nothing once the task is assigned","Quality control and the client relationship","Only collecting the payment","Writing the team member's family budget"],"correct":1,"exp":"Clients hired YOUR reputation, review every deliverable and own the communication, even when others do the production."},{"q":"The safest way to grow from solo freelancer into an agency is to:","opts":["Hire ten full-time staff before finding extra clients","Start with one trusted subcontractor on overflow work and grow as demand proves itself","Accept every job in every skill category at once","Stop doing quality checks to save time"],"correct":1,"exp":"Subcontracting overflow work first tests your systems with low risk, scale the team only as real demand grows."},{"q":"A repeat client is more valuable than a new client mainly because:","opts":["Repeat clients always pay triple","There is no proposal competition, trust already exists, and work arrives without acquisition cost","Platforms charge no fees on repeat work","New clients cannot leave reviews"],"correct":1,"exp":"Winning a new client costs proposals, connects, and time, a happy repeat client sends work directly, which is why delivery quality is a growth strategy."},{"q":"Halfway through a project, a freelancer realizes she will miss the deadline. She should:","opts":["Tell the client immediately, explain, and propose a new realistic date","Go silent and hope the client forgets","Deliver half-finished work without comment","Cancel her internet subscription"],"correct":0,"exp":"Clients forgive early honesty far more than silent lateness, proactive communication protects the relationship and the review."},{"q":"Which pricing evolution is typical as a freelancer's reviews and skills grow?","opts":["Prices must stay at beginner level forever","Starting lower to earn reviews, then raising rates as proof and demand build","Starting at the highest possible rate with zero reviews","Random price changes every day"],"correct":1,"exp":"Strategic beginners price to win early reviews, then climb, Prince in the course reviews went from low-price logos to 50 dollars per order this way."}]},"mod5":{"title":"Quiz: Client Communication, Contracts & Money","moduleNum":5,"questions":[{"q":"A proper kickoff message after winning a contract should include:","opts":["Your full employment history since school","Thanks, a restatement of deliverables, your questions, and when the client will next hear from you","Only the word 'thanks'","A request to move the conversation off the platform"],"correct":1,"exp":"Restating the work in your own words catches misunderstandings on day one, plus questions and a next-contact date set a professional tone."},{"q":"On a two-week project, a professional freelancer should:","opts":["Message the client every hour","Wait for the client to ask what is happening","Send short progress updates at agreed intervals","Contact the client only at delivery"],"correct":2,"exp":"Regular brief updates, done, next, blockers, prevent client anxiety and set you apart from freelancers who vanish."},{"q":"Liberia is on GMT. A New York (EST) client says 'deadline Friday 5 p.m. my time.' For the freelancer in Monrovia that is roughly:","opts":["Friday noon in Liberia","Saturday 5 p.m. in Liberia","Thursday morning in Liberia","Friday 9 or 10 p.m. in Liberia"],"correct":3,"exp":"New York is 4-5 hours behind GMT depending on daylight saving, so 5 p.m. EST is about 9-10 p.m. in Monrovia, always confirm the zone."},{"q":"Keeping project communication inside Upwork or Fiverr messaging matters because:","opts":["It creates a record and preserves the platform's protection in disputes","It makes messages travel faster","Clients cannot read external email","The platforms pay you per message"],"correct":0,"exp":"On-platform records are the evidence dispute teams rely on, going off-platform sacrifices that protection."},{"q":"Which agreement term BEST protects a freelancer from endless free revisions?","opts":["Agreeing on revisions verbally only","Stating the number of included revision rounds and the price of extra rounds","Promising unlimited revisions to seem friendly","Avoiding any mention of revisions"],"correct":1,"exp":"A written revision limit converts 'just one more change' from a silent loss into a normal paid add-on."},{"q":"On a large project, funded milestones protect the freelancer because:","opts":["They make the project shorter automatically","Clients prefer paying everything at the very end","Payment for each stage is secured before that work is done","They remove the need for any communication"],"correct":2,"exp":"Milestone funding means you never work weeks on trust alone, each completed stage releases secured payment."},{"q":"'Scope creep' refers to:","opts":["A client paying more than agreed","Delivering work ahead of schedule","A platform raising its service fees","Work gradually expanding beyond the agreement without added pay"],"correct":3,"exp":"Scope creep is the slow pile-up of small unpaid extras, the acknowledge-and-price reply keeps it in check politely."},{"q":"A client on a $100 Upwork contract praises your work. After the 10% platform fee and roughly $5 in withdrawal and transfer costs, your income tracker should record approximately:","opts":["$85 net received","$100 net received","$110 net received","$50 net received"],"correct":0,"exp":"$100 minus the $10 service fee and about $5 in payout costs leaves roughly $85, track the net, and price with fees in mind."},{"q":"The recommended three-way split for each freelance payment is:","opts":["Keeping it all as cash at home","Living costs, business reinvestment, and a savings buffer","Spending it all immediately to celebrate","Lending it all to friends"],"correct":1,"exp":"Salary-to-yourself, reinvestment (like backup power or training), and a two-to-three-month buffer create a business that survives slow months."},{"q":"A freelancer's income and expense spreadsheet can double as:","opts":["A public advertisement","A way to avoid all platform fees","Proof of income for banks, loans, visas, and rentals","A replacement for delivering client work"],"correct":2,"exp":"Self-employed people show trackers and payment histories where salaried workers show pay slips, disciplined records open financial doors."}]}},"reviews":[{"name":"Grace Johnson","loc":"Monrovia, Liberia","date":"February 2026","bg":"#c2410c","init":"GJ","rating":5,"text":"I always thought freelancing was for people abroad. This course changed my mind completely. Within six weeks I set up my Upwork profile, sent proposals the way Emmanuel taught, and landed my first 500 dollar contract as a virtual assistant. I got paid through Payoneer with no stress. This is real income for my family."},{"name":"Prince Karweaye","loc":"Paynesville, Liberia","date":"March 2026","bg":"#e31e24","init":"PK","rating":5,"text":"The Fiverr lessons are gold. I started a logo design gig at a low price to earn reviews, and after fifteen 5-star reviews I now charge 50 dollars per order. Buyers come to me even while my data is off. I never believed I could earn dollars from Paynesville, but here I am."},{"name":"Bendu Massaquoi","loc":"Gbarnga, Bong County","date":"May 2026","bg":"#0e7490","init":"BM","rating":4,"text":"I had no portfolio and no confidence. The lesson on free tools showed me how to build sample work in Canva and put it online for free. I used one sample in a proposal and won my first international writing client. Living in Gbarnga has never stopped me since."},{"name":"Alfred Toe","loc":"Buchanan, Grand Bassa","date":"June 2026","bg":"#7c3aed","init":"AT","rating":5,"text":"Getting paid was my biggest fear, and this course solved it. The payment module walked me through Payoneer and Wise step by step. My first 500 dollar Upwork payment reached my local bank within days. Every Liberian who wants to work online needs this course."}],"faqs":[{"q":"How do I receive payment in Liberia as a freelancer?","a":"The proven setup is Payoneer for Upwork and Fiverr payouts, plus Wise for direct client bank transfers with low fees, and then withdrawing to your Liberian bank account or mobile money such as Orange Money or MTN MoMo. We show you how to open and verify each account early so your payments are never held up."},{"q":"Do I need experience or a university degree to start freelancing?","a":"No. Many successful freelancers start with no experience and no degree. This course shows you how to identify a skill you already have, create sample work to prove it, and win your first clients through strong profiles and personalized proposals."},{"q":"How do I deal with unreliable internet and electricity in Liberia?","a":"We teach practical planning: buy data bundles ahead of deadlines, keep a power bank or generator backup, and deliver work early so an outage never causes a late delivery. Fiverr gigs are also ideal because orders arrive even when you are offline."},{"q":"Is this course really free and is the certificate recognized?","a":"Yes, it is completely free with no credit card required. On passing the final assessment you receive a TIH certificate with a unique verification code that employers and clients can confirm as genuine."}]};
COURSES_DB['ielts'] = {"id":"ielts","title":"IELTS Masterclass: Band 7+ in Listening, Reading, Writing & Speaking","shortDesc":"A complete, strategy-driven IELTS course covering all four skills, the band-score system, question-type tactics, model answers, and full practice, built to move you to Band 7 and beyond.","category":"Exam Preparation","icon":"🌍","gradient":"linear-gradient(135deg,#0b3d91,#1e3a8a,#3b82f6)","instructor":"Samuel Tolbert","instructorTitle":"Founder & CEO, Tolbert Innovation Hub","instructorBio":"Samuel Tolbert founded TIH to bring world-class exam preparation to Liberia and West Africa, coaching hundreds of students toward the scores they need to study and work abroad.","rating":4.9,"reviewCount":512,"students":"1,200+","duration":"36h","level":"Intermediate → Advanced","price":"$20","origPrice":"$150","isFree":false,"badge":"premium","certId":"TIH-2026-IELTS-0001","learn":["Understand the Academic and General Training tests and choose the right one","Decode the 0–9 band-score system and the examiner criteria for each skill","Master every Listening question type with prediction and keyword tactics","Read faster with skimming, scanning and time control, and beat True/False/Not Given","Write Task 1 (graphs and letters) and Task 2 essays that hit Band 7 structure","Speak fluently across Parts 1–3 with model answers and pronunciation tips","Avoid the common mistakes that keep candidates stuck at Band 5–6"],"requirements":["An intermediate level of English (roughly Band 5) to build from","A notebook or device to complete the writing and speaking practice tasks","Commitment to practise with a timer, IELTS is as much about timing as accuracy"],"about":["IELTS is the world’s most widely accepted English test for university admission, professional registration, and migration. A strong band score opens doors to scholarships and opportunities across the UK, Canada, Australia, and beyond.","This masterclass is not a collection of random tips. It is a structured system: you learn how each of the four skills is scored, then work through the exact strategies for every question type, with model answers and practice built in.","Written specifically for learners in Liberia and West Africa, every lesson is clear, practical, and focused on turning effort into a higher band score."],"modules":[{"title":"Module 1: IELTS Foundations & the Band System","icon":"🧭","meta":"4 lessons","lessons":[{"t":"1.1 The IELTS Test: Academic vs General Training","d":"Reading","v":"tOFm-zoI6-w"},{"t":"1.2 Understanding the Band Score System (0–9)","d":"Reading","v":"zBLsjez-D3s"},{"t":"1.3 Test-Day Logistics & Smart Preparation","d":"Reading","v":"tIpP4M1kvvE"},{"t":"📝 Quiz: IELTS Format & Scoring","d":"5 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Listening","icon":"🎧","meta":"4 lessons","lessons":[{"t":"2.1 The Four Sections & Every Question Type","d":"Reading","v":"q2odDqMhYOg"},{"t":"2.2 Strategies: Prediction, Keywords & Distractor Traps","d":"Reading","v":"gfTqr_9BMjs"},{"t":"2.3 Spelling, Numbers & Transferring Answers","d":"Reading","v":"RrViOflRWg0"},{"t":"📝 Quiz: Listening","d":"5 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Reading","icon":"📖","meta":"4 lessons","lessons":[{"t":"3.1 Skimming, Scanning & Time Management","d":"Reading","v":"7etaXjWJVJg"},{"t":"3.2 True / False / Not Given (and Yes / No / Not Given)","d":"Reading","v":"cNyLs7YWFL8"},{"t":"3.3 Matching Headings, Completion & Multiple Choice","d":"Reading","v":"SXdMpskBDmA"},{"t":"📝 Quiz: Reading","d":"5 questions","isQuiz":true,"quizId":"mod3"}]},{"title":"Module 4: Writing","icon":"✍️","meta":"5 lessons","lessons":[{"t":"4.1 Task 1 Academic: Describing Graphs, Charts & Processes","d":"Reading","v":"mTDjuQ-G31I"},{"t":"4.2 Task 1 General: Formal & Informal Letters","d":"Reading","v":"TbdP4Sz5Bn0"},{"t":"4.3 Task 2: Essay Structure & Building an Argument","d":"Reading","v":"_LwCwsFDRdE"},{"t":"4.4 Cohesion, Vocabulary & Common Mistakes","d":"Reading","v":"wSbv5bCY4No"},{"t":"🛠️ Project: Write a Full Band 7 Task 2 Essay","d":"Project","isProject":true}]},{"title":"Module 5: Speaking","icon":"🗣️","meta":"4 lessons","lessons":[{"t":"5.1 Part 1: Introduction & Interview","d":"Reading","v":"wK5mVNZGYRc"},{"t":"5.2 Part 2: The Long Turn (Cue Card)","d":"Reading","v":"BzhUwBaQK1g"},{"t":"5.3 Part 3: Discussion, Fluency & Pronunciation","d":"Reading","v":"QoeKYAqBRtE"}]},{"title":"Module 6: Vocabulary, Grammar & Your Band 7+ Plan","lessons":[{"t":"6.1 Vocabulary for Band 7+: Collocations & Precision","d":"Video + notes","v":"lhDpoCYmnNQ"},{"t":"6.2 Grammar Range: Complex Sentences Without Errors","d":"Video + notes","v":"h9fxF0LKRyY"},{"t":"6.3 The Full Mock Test: Practice Under Real Exam Conditions","d":"Video + notes","v":"NXJa7GFjY3U"},{"t":"6.4 Your 30-Day Study Plan & Test-Week Checklist","d":"Video + notes","v":"3nrujcxJSNs"},{"t":"📝 Quiz: Vocabulary, Grammar & Strategy","d":"8 questions","isQuiz":true,"quizId":"mod6"},{"t":"🏆 Final Assessment & Certificate","d":"Assessment","isQuiz":true,"quizId":"final","isFinal":true}],"icon":"🎓","meta":"6 lessons"}],"quizzes":{"mod1":{"title":"Quiz: IELTS Format & Scoring","moduleNum":1,"unlocks":4,"questions":[{"q":"Which IELTS test is required for most university admission?","opts":["General Training","Academic","Life Skills","Either one"],"correct":1,"exp":"The Academic test is used for higher education and professional registration; General Training is for migration and work."},{"q":"The IELTS band scale runs from:","opts":["1 to 10","0 to 9","0 to 100","A to F"],"correct":1,"exp":"Each skill and the overall score is reported on a band scale from 0 to 9, in half-band steps."},{"q":"Your overall band score is:","opts":["The Writing score","The average of the four skills, rounded","The lowest skill","The Speaking score"],"correct":1,"exp":"The overall band is the average of Listening, Reading, Writing and Speaking, rounded to the nearest half band."},{"q":"How many skills does IELTS test?","opts":["Two","Three","Four","Five"],"correct":2,"exp":"IELTS tests Listening, Reading, Writing and Speaking."},{"q":"A band 7 overall generally means:","opts":["Beginner","A good, operational command of English","No English","Native only"],"correct":1,"exp":"Band 7 describes a good user with operational command, occasional inaccuracies."},{"q":"How long is the IELTS Listening section (before answer transfer on paper)?","opts":["About 30 minutes","Exactly 10 minutes","2 hours","No limit"],"correct":0,"exp":"Listening runs about 30 minutes, plus 10 minutes to transfer answers on the paper test."},{"q":"On the computer-delivered test, which skill is still face-to-face with an examiner?","opts":["Reading","Writing","Speaking","Listening"],"correct":2,"exp":"Speaking is always a live interview with a real examiner, in person or by video."},{"q":"What is the minimum word count for Writing Task 2?","opts":["150","200","250","400"],"correct":2,"exp":"Task 2 needs at least 250 words; Task 1 needs at least 150."},{"q":"An overall score of 6.25 is reported as:","opts":["6.0","6.5","6.25","7.0"],"correct":0,"exp":"It rounds to the nearest half band, so 6.25 becomes 6.0 (6.75 would become 7.0)."},{"q":"Which two skills are identical on the Academic and General Training tests?","opts":["Reading and Writing","Listening and Speaking","Reading and Speaking","Writing and Listening"],"correct":1,"exp":"Listening and Speaking are the same in both versions; Reading and Writing differ."}]},"mod2":{"title":"Quiz: Listening","moduleNum":2,"unlocks":4,"questions":[{"q":"How many times is the Listening audio played?","opts":["Once","Twice","As many as you want","Three times"],"correct":0,"exp":"The IELTS Listening recording is played ONE time only, so prediction and focus are essential."},{"q":"Before the audio starts you should:","opts":["Close your eyes","Read the questions and predict answers","Write your name","Do nothing"],"correct":1,"exp":"Use the preparation seconds to read ahead and predict the type of answer needed (number, name, noun)."},{"q":"A distractor in Listening is:","opts":["A correct answer","Information that sounds right but is corrected/changed by the speaker","A spelling rule","A type of accent"],"correct":1,"exp":"Speakers often give one answer then correct it, listen to the end before deciding."},{"q":"Spelling in Listening answers:","opts":["Does not matter","Must be correct to earn the mark","Only matters for names","Is optional"],"correct":1,"exp":"Incorrectly spelled answers are marked wrong, so spelling accuracy is critical."},{"q":"If you miss an answer, you should:","opts":["Stop the test","Panic","Let it go and focus on the next question","Guess randomly for all"],"correct":2,"exp":"Dwelling on a missed answer causes you to miss more, move on immediately."},{"q":"How many sections does the Listening test have?","opts":["Two","Three","Four","Five"],"correct":2,"exp":"There are four sections that increase in difficulty."},{"q":"If the instruction says NO MORE THAN TWO WORDS, a three-word answer is:","opts":["Accepted","Marked wrong","Given half a mark","Ignored"],"correct":1,"exp":"Going over the word limit makes an otherwise correct answer wrong."},{"q":"Section 2 is usually:","opts":["A two-person chat","A monologue on a social topic, such as a tour","An academic lecture","A group discussion"],"correct":1,"exp":"Section 2 is a monologue in an everyday social context."},{"q":"Numbers like 15 and 50 are commonly confused because of:","opts":["Spelling","Word stress in speech","Grammar","Punctuation"],"correct":1,"exp":"Listen for the stressed syllable to tell 15/50 or 13/30 apart."},{"q":"On the paper test, the 10 minutes at the end are for:","opts":["Extra questions","Transferring answers to the answer sheet","A break","Checking Reading"],"correct":1,"exp":"Use the transfer time to copy answers carefully and spell them correctly."}]},"mod3":{"title":"Quiz: Reading","moduleNum":3,"unlocks":4,"questions":[{"q":"Skimming means:","opts":["Reading every word slowly","Reading quickly for the general idea","Looking for one specific word","Translating the text"],"correct":1,"exp":"Skimming is fast reading to grasp the main idea and structure of a passage."},{"q":"\"Not Given\" means:","opts":["The statement contradicts the text","The statement matches the text","There is no information to confirm or deny it","The question is wrong"],"correct":2,"exp":"Not Given means the passage neither confirms nor contradicts the statement."},{"q":"For Matching Headings you should focus on:","opts":["The first line only","The main idea of each paragraph","Individual names","Punctuation"],"correct":1,"exp":"Headings summarise the central idea of a paragraph, not a single detail."},{"q":"Academic Reading gives you:","opts":["30 minutes","60 minutes for 40 questions","90 minutes","No time limit"],"correct":1,"exp":"You have 60 minutes for 3 passages and 40 questions, budget about 20 minutes per passage."},{"q":"A good time strategy is to:","opts":["Read all passages fully first","Answer easy questions first and not get stuck","Skip Reading","Only read titles"],"correct":1,"exp":"Secure the marks you can get quickly and return to harder items with remaining time."},{"q":"Academic Reading contains how many passages?","opts":["One","Two","Three","Four"],"correct":2,"exp":"Three passages with 40 questions in 60 minutes."},{"q":"Scanning is used to:","opts":["Understand the whole text","Find a specific word or fact quickly","Translate the passage","Memorise the text"],"correct":1,"exp":"Scanning locates specific information fast once you know what to look for."},{"q":"Yes / No / Not Given questions test:","opts":["Facts in the text","The writer’s opinions or claims","Vocabulary","Spelling"],"correct":1,"exp":"Yes/No/Not Given is about the writer’s views; True/False/Not Given is about facts."},{"q":"For sentence-completion answers you should:","opts":["Use your own words","Copy words exactly from the passage within the word limit","Write full sentences","Guess"],"correct":1,"exp":"Use the exact words from the text and respect the word limit."},{"q":"If a statement is true in real life but the passage never mentions it, the answer is:","opts":["True","False","Not Given","Yes"],"correct":2,"exp":"Use only the passage, if it is not stated, it is Not Given."}]},"final":{"title":"Final Assessment","moduleNum":5,"unlocks":null,"isFinal":true,"questions":[{"q":"A strong Task 2 essay always includes:","opts":["One long paragraph","An introduction, body paragraphs and a conclusion","Only bullet points","A drawing"],"correct":1,"exp":"Band 7 essays are clearly organised with an intro, developed body paragraphs and a conclusion."},{"q":"In Speaking Part 2 you speak for:","opts":["10 seconds","1–2 minutes on a cue card","15 minutes","You do not speak"],"correct":1,"exp":"Part 2 is the long turn: 1 minute to prepare, then speak for 1–2 minutes."},{"q":"\"Coherence and Cohesion\" in Writing refers to:","opts":["Handwriting","Logical organisation and linking of ideas","Vocabulary only","Grammar only"],"correct":1,"exp":"It is one of the four Writing criteria: how well ideas are organised and connected."},{"q":"To raise your Speaking fluency score you should:","opts":["Speak very slowly","Memorise long scripts","Speak at a natural pace with linking words","Use one-word answers"],"correct":2,"exp":"Fluency rewards natural, connected speech, avoid long pauses and memorised chunks."},{"q":"Task 2 is worth:","opts":["The same as Task 1","Less than Task 1","More than Task 1 (twice the weight)","Nothing"],"correct":2,"exp":"Task 2 carries twice the marks of Task 1, so manage your 60 minutes accordingly."},{"q":"In Speaking Part 1, the best answers are:","opts":["One word","Extended, with a reason or example","Memorised paragraphs","Silent"],"correct":1,"exp":"Give 2–3 sentence answers, adding a reason or example."},{"q":"Academic Writing Task 1 asks you to:","opts":["Give your opinion","Describe visual data such as a graph or chart","Write a letter","Tell a story"],"correct":1,"exp":"Academic Task 1 describes and compares data shown in a visual."},{"q":"The overview paragraph in Task 1 should describe:","opts":["Every small figure","The main trends or biggest features","Your opinion","Only the conclusion"],"correct":1,"exp":"The overview summarises the most striking overall features and is vital to the score."},{"q":"Complete the first conditional: \"If it rains, we ______ stay home.\"","opts":["will","would","were","are"],"correct":0,"exp":"First conditional: if + present simple, then will + base verb."},{"q":"Which word is the most formal?","opts":["kids","loads of","numerous","a lot of"],"correct":2,"exp":"\"Numerous\" is formal; the others are informal."},{"q":"A distractor in Listening is:","opts":["The correct answer","Information given, then corrected or changed","A grammar rule","An accent"],"correct":1,"exp":"Speakers often say one thing then correct it, listen to the end."},{"q":"Matching Headings tests your understanding of each paragraph’s:","opts":["First word","Main idea","Punctuation","Length"],"correct":1,"exp":"A heading summarises the paragraph’s central idea."},{"q":"Speaking Part 2 gives you how long to prepare?","opts":["No time","1 minute","5 minutes","10 minutes"],"correct":1,"exp":"You get 1 minute to prepare, then speak for 1–2 minutes."},{"q":"Choose the correct form: \"She has worked here ______ 2020.\"","opts":["since","for","during","from"],"correct":0,"exp":"\"Since\" is used with a point in time; \"for\" is used with a period of time."},{"q":"To improve a Task 2 essay you should:","opts":["Add memorised phrases","Fully develop two clear ideas with examples","List many undeveloped ideas","Write under 250 words"],"correct":1,"exp":"Two well-developed ideas beat many shallow ones."},{"q":"In Reading, when two options both seem true, choose the one that:","opts":["Is longest","Best paraphrases the passage","Contains \"always\"","Comes first"],"correct":1,"exp":"The answer is usually a precise paraphrase, not an overstatement."},{"q":"A good pronunciation score depends on being:","opts":["British-sounding","Clearly understood, with good stress and intonation","Very fast","Very slow"],"correct":1,"exp":"Clarity, stress and intonation matter, not a particular accent."},{"q":"The Listening recording is played:","opts":["Once","Twice","Three times","On demand"],"correct":0,"exp":"It plays one time only, so prediction and focus are essential."},{"q":"\"Not Given\" in Reading means:","opts":["The text contradicts it","The text confirms it","There is not enough information to decide","The question is wrong"],"correct":2,"exp":"Not Given means the passage neither confirms nor denies the statement."},{"q":"General Training Writing Task 1 is:","opts":["An essay","A letter","A graph description","A speech"],"correct":1,"exp":"General Training Task 1 is a letter (formal, semi-formal or informal)."}]},"mod6":{"title":"Quiz: Vocabulary, Grammar & Strategy","moduleNum":6,"questions":[{"q":"What does the examiner reward most under \"Lexical Resource\" at Band 7?","opts":["Long, rare words used everywhere","Flexible, precise vocabulary with natural collocations","Repeating the question words","American slang"],"correct":1,"exp":"Band 7 rewards flexibility and precision, using less common items and collocations naturally, not memorized \"big words\"."},{"q":"Which of these is a natural English collocation?","opts":["Do a mistake","Heavy rain","Strong homework","Big attention"],"correct":1,"exp":"\"Heavy rain\" is a natural collocation. Collocations are word partners that native speakers use together."},{"q":"A complex sentence contains…","opts":["Two simple sentences joined by \"and\"","At least one independent clause and one dependent clause","Only very long words","A quotation"],"correct":1,"exp":"A complex sentence joins an independent clause with a dependent clause (e.g. using although, because, which)."},{"q":"Using memorized \"fancy\" phrases that do not fit the question will…","opts":["Impress the examiner","Guarantee Band 8","Lower your score, examiners recognize memorized language","Save time"],"correct":2,"exp":"Examiners are trained to spot memorized language and mark it down when it does not answer the question naturally."},{"q":"The most useful way to take a full mock test is…","opts":["Split it over one week","One sitting, strictly timed, no dictionary, then review every mistake","Only the sections you like","With a friend answering together"],"correct":1,"exp":"Simulating real conditions builds stamina and timing; the error review afterwards is where the learning happens."},{"q":"For Grammatical Range & Accuracy at Band 7, you need…","opts":["Perfect grammar in every sentence","A variety of complex structures with most sentences error-free","Only simple sentences with no errors","Passive voice in every sentence"],"correct":1,"exp":"Band 7 requires a mix of structures where the majority of sentences are error-free, variety plus control."},{"q":"A good 30-day study plan should…","opts":["Focus only on your strongest skill","Cover all four skills with regular timed practice and error review","Leave writing until the last day","Avoid mock tests to reduce stress"],"correct":1,"exp":"Balanced daily work across Listening, Reading, Writing and Speaking, with timed practice and review, moves your band fastest."},{"q":"In the final week before your test you should…","opts":["Learn 500 new words","Stay up late practising every night","Do light review, one timed practice, and protect your sleep","Change your writing templates completely"],"correct":2,"exp":"The last week is for consolidation and rest, cramming new material or losing sleep hurts performance on test day."}],"unlocks":25}}};
COURSES_DB['toefl'] = {"id":"toefl","title":"TOEFL iBT Masterclass: Reading, Listening, Speaking & Writing","shortDesc":"A complete TOEFL iBT preparation course covering the format and 1–120 scoring, all four sections, integrated tasks, templates, and model responses to reach a competitive score.","category":"Exam Preparation","icon":"🎓","gradient":"linear-gradient(135deg,#7c2d12,#b45309,#f59e0b)","instructor":"Samuel Tolbert","instructorTitle":"Founder & CEO, Tolbert Innovation Hub","instructorBio":"Samuel Tolbert founded TIH to bring world-class exam preparation to Liberia and West Africa, helping students meet the TOEFL scores required by universities worldwide.","rating":4.9,"reviewCount":388,"students":"900+","duration":"34h","level":"Intermediate → Advanced","price":"$20","origPrice":"$150","isFree":false,"badge":"premium","certId":"TIH-2026-TOEFL-0001","learn":["Understand the TOEFL iBT format and the 0–120 scoring scale","Read academic passages efficiently and master every question type","Take effective notes for the Listening section lectures and conversations","Deliver strong independent and integrated Speaking responses using templates","Write the Integrated and Academic Discussion tasks to a high standard","Manage timing and stress across the full test"],"requirements":["An intermediate level of English to build from","A headset or quiet space to practise Speaking responses out loud","Willingness to practise note-taking, which is central to TOEFL success"],"about":["The TOEFL iBT is accepted by more than 11,000 universities worldwide and is often required for admission and scholarships in the United States and beyond.","This masterclass breaks the test into its four sections and teaches a reliable method for each, including the integrated tasks that combine reading, listening and speaking or writing, which most candidates find hardest.","Every lesson is written for clarity and built around templates and model answers you can adapt on test day."],"modules":[{"title":"Module 1: TOEFL iBT Foundations","icon":"🧭","meta":"3 lessons","lessons":[{"t":"1.1 The TOEFL iBT Format & the 0–120 Score","d":"Reading","v":"i8p28izQNdQ"},{"t":"1.2 How Each Section Is Scored & What Universities Want","d":"Reading","v":"fGrxgRAISlM"},{"t":"📝 Quiz: TOEFL Format & Scoring","d":"5 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Reading","icon":"📖","meta":"3 lessons","lessons":[{"t":"2.1 Academic Passages & the 10 Question Types","d":"Reading","v":"UrsAfqDc_jI"},{"t":"2.2 Strategy: Vocabulary, Inference & Prose Summary","d":"Reading","v":"aXAEeeyaeuo"},{"t":"📝 Quiz: Reading","d":"5 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Listening","icon":"🎧","meta":"3 lessons","lessons":[{"t":"3.1 Lectures & Conversations: What to Expect","d":"Reading","v":"EXAbraAOdBQ"},{"t":"3.2 Note-Taking Systems & Attitude/Function Questions","d":"Reading","v":"il_l3WGEZho"},{"t":"📝 Quiz: Listening","d":"5 questions","isQuiz":true,"quizId":"mod3"}]},{"title":"Module 4: Speaking","icon":"🗣️","meta":"3 lessons","lessons":[{"t":"4.1 The Independent Task: Templates & Timing","d":"Reading","v":"RUfPjA7UODU"},{"t":"4.2 The Integrated Tasks: Read, Listen, Speak","d":"Reading","v":"C4J96Q-JzwM"},{"t":"🛠️ Project: Record a 45-Second Independent Response","d":"Project","isProject":true}]},{"title":"Module 5: Writing","icon":"✍️","meta":"3 lessons","lessons":[{"t":"5.1 The Integrated Writing Task","d":"Reading","v":"KvBauox4auk"},{"t":"5.2 The Academic Discussion Task","d":"Reading","v":"QL4r78VQq1M"}]},{"title":"Module 6: Vocabulary, Full Practice & Your Score Plan","lessons":[{"t":"6.1 Academic Vocabulary: The Words Every Section Uses","d":"Video + notes","v":"fE0W18Yz9hM"},{"t":"6.2 Speaking & Writing Vocabulary That Scores 30/30","d":"Video + notes","v":"nMfDRilzxGw"},{"t":"6.3 Full-Length Practice Test: Walkthrough & Review","d":"Video + notes","v":"oygHNmHfaIk"},{"t":"6.4 Your One-Month Study Plan & Test-Day Success","d":"Video + notes","v":"_URwZza44rA"},{"t":"📝 Quiz: Vocabulary & Test Strategy","d":"8 questions","isQuiz":true,"quizId":"mod6"},{"t":"🏆 Final Assessment & Certificate","d":"Assessment","isQuiz":true,"quizId":"final","isFinal":true}],"icon":"🎓","meta":"6 lessons"}],"quizzes":{"mod1":{"title":"Quiz: TOEFL Format & Scoring","moduleNum":1,"unlocks":3,"questions":[{"q":"The TOEFL iBT total score ranges from:","opts":["0 to 9","0 to 120","0 to 100","200 to 800"],"correct":1,"exp":"Each of the four sections is scored 0–30, giving a total of 0–120."},{"q":"How many sections does the TOEFL iBT have?","opts":["Two","Three","Four","Six"],"correct":2,"exp":"Reading, Listening, Speaking and Writing."},{"q":"TOEFL is primarily used for admission to universities in:","opts":["Only Liberia","The United States and worldwide","Only France","Only online schools"],"correct":1,"exp":"TOEFL is accepted by 11,000+ institutions, especially in the US."},{"q":"Each section is scored out of:","opts":["9","30","100","120"],"correct":1,"exp":"Each section is scored 0–30; the four combine to 120."},{"q":"The TOEFL is delivered mainly:","opts":["On paper only","On a computer (internet-based)","By phone","In person orally only"],"correct":1,"exp":"The \"iBT\" means internet-based test, taken on a computer."},{"q":"Which section combines reading, listening and speaking or writing?","opts":["Independent tasks","Integrated tasks","Vocabulary tasks","Grammar tasks"],"correct":1,"exp":"Integrated tasks require you to use two or more skills together."},{"q":"Many universities ask for a total TOEFL score of about:","opts":["20–30","80–100","150–200","300+"],"correct":1,"exp":"Common requirements are 80–100, with competitive programs asking for 100+."},{"q":"Note-taking during the test is:","opts":["Not allowed","Allowed and encouraged","Only for Reading","Only for Writing"],"correct":1,"exp":"You may take notes throughout, it is essential for Listening and integrated tasks."},{"q":"The Speaking section is:","opts":["Handwritten","Recorded on a microphone","Skipped","A live debate"],"correct":1,"exp":"You speak into a microphone; responses are recorded and scored by raters and AI."},{"q":"A section minimum (e.g. Speaking 22+) means you must:","opts":["Ignore that section","Reach a set score in that specific section","Retake the whole test","Score 120"],"correct":1,"exp":"Some programs require a minimum in each section, not just the total."}]},"mod2":{"title":"Quiz: Reading","moduleNum":2,"unlocks":3,"questions":[{"q":"A TOEFL vocabulary question asks you to:","opts":["Spell a word","Choose the closest meaning of a word in context","Translate a word","Pronounce a word"],"correct":1,"exp":"You pick the option closest in meaning to the highlighted word as used in the passage."},{"q":"The Prose Summary question requires you to:","opts":["Write an essay","Select the main ideas that belong in a summary","Fix grammar","Read aloud"],"correct":1,"exp":"You choose the answer choices that capture the passage’s major ideas."},{"q":"An inference question asks about:","opts":["Something stated directly","Something strongly implied but not stated","The title","Vocabulary"],"correct":1,"exp":"Inference answers are supported by the text but not written word-for-word."},{"q":"Best Reading time strategy:","opts":["Read the whole passage slowly first","Skim for structure, then answer using scanning","Answer without reading","Only read the first paragraph"],"correct":1,"exp":"Skim to map the passage, then scan back to the relevant lines for each question."},{"q":"Reading passages are:","opts":["Casual chats","Academic, university-level texts","Poems","Advertisements"],"correct":1,"exp":"TOEFL Reading uses academic passages similar to first-year university texts."},{"q":"A \"negative factual\" question asks which statement is:","opts":["True and stated","NOT true or not stated in the passage","The main idea","A vocabulary word"],"correct":1,"exp":"You identify the option that is not supported by the passage."},{"q":"To answer a Reading question you should:","opts":["Rely on memory","Scan back to the exact lines","Use outside knowledge","Guess from the title"],"correct":1,"exp":"Return to the relevant lines rather than relying on memory."},{"q":"The Prose Summary question is worth:","opts":["1 point","2 points","5 points","0 points"],"correct":1,"exp":"It is worth 2 points because it tests understanding of the whole passage."},{"q":"A vocabulary answer should keep the sentence:","opts":["Longer","Meaning the same in context","More formal","Rhyming"],"correct":1,"exp":"Choose the word closest in meaning as used in that sentence."},{"q":"You do NOT need prior knowledge of the topic because:","opts":["The topics are easy","Every answer is found in the passage","You can use Google","The topics are random"],"correct":1,"exp":"All the information you need is in the text."}]},"mod3":{"title":"Quiz: Listening","moduleNum":3,"unlocks":3,"questions":[{"q":"During Listening you should:","opts":["Not take notes","Take structured notes","Close your eyes","Only listen to the first minute"],"correct":1,"exp":"Note-taking is allowed and essential; capture main ideas and signpost words."},{"q":"A \"function\" question asks:","opts":["Why the speaker says something","How to spell a word","The exact words used","The speaker’s name"],"correct":0,"exp":"Function/purpose questions test why a statement was made, not just what was said."},{"q":"TOEFL Listening includes:","opts":["Only songs","Lectures and campus conversations","Only news","Only interviews"],"correct":1,"exp":"You hear academic lectures and everyday campus conversations."},{"q":"You hear each lecture:","opts":["Twice","Once","Three times","On demand"],"correct":1,"exp":"Audio plays once, so active note-taking matters."},{"q":"Signpost words like \"however\" or \"for example\" signal:","opts":["The end of the test","Important structure and relationships between ideas","Nothing","A break"],"correct":1,"exp":"They flag contrasts, examples and emphasis, often tested by questions."},{"q":"A good note-taking system separates:","opts":["Colours and fonts","Main ideas from details/examples","Names from dates","Nothing"],"correct":1,"exp":"Split-page notes (main ideas vs details) make questions easier to answer."},{"q":"An \"attitude\" question asks about the speaker’s:","opts":["Exact words","Feeling or certainty","Name","Grammar"],"correct":1,"exp":"Attitude questions test tone, certainty, doubt, surprise, and so on."},{"q":"Campus conversations usually involve:","opts":["Two people solving a practical problem","A single lecture","A song","A news report"],"correct":0,"exp":"Conversations are everyday campus situations, e.g. a student and an advisor."},{"q":"If a clip is replayed and you are asked what the speaker means, the answer is about:","opts":["Spelling","Purpose or implied meaning","Volume","Speed"],"correct":1,"exp":"Replayed clips test the function or intended meaning, not literal words."},{"q":"You cannot write down everything, so you should capture:","opts":["Every word","Main ideas and relationships","Only names","Only numbers"],"correct":1,"exp":"Focus on main ideas and how points connect."}]},"final":{"title":"Final Assessment","moduleNum":5,"unlocks":null,"isFinal":true,"questions":[{"q":"The Integrated Writing task asks you to:","opts":["Give only your opinion","Summarise how a lecture relates to a reading","Draw a chart","Translate"],"correct":1,"exp":"You explain how the lecture supports or challenges points in the reading passage."},{"q":"A good independent Speaking response length is about:","opts":["5 seconds","45 seconds","5 minutes","No limit"],"correct":1,"exp":"Independent speaking responses are ~45 seconds; use preparation time to plan."},{"q":"The Academic Discussion writing task asks you to:","opts":["Copy the professor","Contribute your own supported opinion to a discussion","Only agree","Write one sentence"],"correct":1,"exp":"You add your own well-supported point to an online class discussion prompt."},{"q":"Integrated Speaking tasks combine:","opts":["Only speaking","Reading, listening and speaking","Only writing","Drawing"],"correct":1,"exp":"You read, then listen, then speak about how the sources relate."},{"q":"Templates help because they:","opts":["Replace ideas","Give a reliable structure so you focus on content","Are required word-for-word","Lower your score"],"correct":1,"exp":"A template frees mental effort for content and delivery under time pressure."},{"q":"The TOEFL total score is out of:","opts":["9","30","100","120"],"correct":3,"exp":"Four sections of 0–30 combine to a total of 0–120."},{"q":"In Integrated Writing, the lecture usually:","opts":["Repeats the reading","Challenges or casts doubt on the reading","Is unrelated","Is optional"],"correct":1,"exp":"The lecture typically responds to and challenges the reading’s points."},{"q":"In Integrated Writing you should spend most words on:","opts":["Your opinion","What the professor (lecture) says","The introduction","New examples"],"correct":1,"exp":"The lecture is more important; report what the professor argues."},{"q":"The Academic Discussion response should be about:","opts":["10 words","100+ well-organised words","1000 words","A single sentence"],"correct":1,"exp":"Aim for roughly 100+ words with a clear position and support."},{"q":"A \"function\" question tests:","opts":["What was said","Why the speaker said it","How fast they spoke","The spelling"],"correct":1,"exp":"Function/purpose questions ask why a statement was made."},{"q":"Reading passages resemble:","opts":["Text messages","First-year university textbooks","Poems","Song lyrics"],"correct":1,"exp":"They are academic, textbook-style passages."},{"q":"A vocabulary question wants the option that is closest in:","opts":["Spelling","Meaning in context","Length","Sound"],"correct":1,"exp":"Pick the nearest meaning as the word is used in the passage."},{"q":"The Speaking section is scored by:","opts":["Only a computer","Human raters and AI","Only the test-taker","Other students"],"correct":1,"exp":"Responses are rated on delivery, language use and topic development."},{"q":"Independent Speaking gives you how long to prepare?","opts":["0 seconds","15 seconds","2 minutes","5 minutes"],"correct":1,"exp":"You get 15 seconds to prepare and 45 seconds to speak."},{"q":"To reach a top score you generally need balanced sections rather than:","opts":["One very strong and one very weak","All equal","High Reading only","High Speaking only"],"correct":0,"exp":"A single very weak section can pull your total below a requirement."},{"q":"The best way to prepare for Listening is to practise:","opts":["Reading aloud","Structured note-taking","Typing speed","Vocabulary lists only"],"correct":1,"exp":"Note-taking is the core Listening skill."},{"q":"Integrated Speaking asks you to speak for about:","opts":["10 seconds","60 seconds","5 minutes","No limit"],"correct":1,"exp":"Integrated speaking responses are around 60 seconds."},{"q":"\"Numerous studies indicate\" is preferred over \"a lot of studies show\" because it is:","opts":["Shorter","More academic and precise","Funnier","Informal"],"correct":1,"exp":"Academic writing favours precise, formal phrasing."},{"q":"A good transition for contrast is:","opts":["therefore","nevertheless","because","for example"],"correct":1,"exp":"\"Nevertheless\" signals contrast."},{"q":"The TOEFL iBT runs about:","opts":["30 minutes","Under 2 hours","5 hours","A full day"],"correct":1,"exp":"The current test takes under 2 hours in total."}]},"mod6":{"title":"Quiz: Vocabulary & Test Strategy","moduleNum":6,"questions":[{"q":"The Academic Word List (AWL) contains…","opts":["Slang used on campus","Words common across academic subjects","Only scientific terms","Words banned from essays"],"correct":1,"exp":"The AWL collects the words that appear across academic fields, exactly the vocabulary TOEFL passages and lectures use."},{"q":"The best way to learn new academic vocabulary is…","opts":["Memorizing isolated word lists","Learning words in context with example sentences","Reading translations only","Studying only synonyms"],"correct":1,"exp":"Words stick when you meet them in real sentences and reuse them in your own speaking and writing."},{"q":"A full practice test is most valuable when…","opts":["You take it in pieces over a week","You take it timed in one sitting, then review every mistake","You skip the speaking section","You retake the same test daily"],"correct":1,"exp":"One timed sitting builds real stamina; the structured error review afterwards converts mistakes into points."},{"q":"TOEFL iBT scores are usually available…","opts":["Immediately on screen only","Around 4–8 days after the test online","After 2 months by post","Only at the test centre"],"correct":1,"exp":"ETS typically posts scores online roughly 4–8 days after your test date."},{"q":"MyBest (superscore) on TOEFL means…","opts":["Your single best total","ETS combines your best section scores from tests in the last 2 years","Your last test only","An average of all attempts"],"correct":1,"exp":"MyBest scores combine your highest Reading, Listening, Speaking and Writing scores from all valid tests within two years."},{"q":"In Speaking and Writing, varied sentence structure mainly improves…","opts":["Your typing speed","The language-use dimension of your score","The topic development only","Nothing, structure is not scored"],"correct":1,"exp":"Raters score language use directly, controlled variety in grammar and vocabulary lifts both Speaking and Writing."},{"q":"When you finish the official practice tests, the smartest next step is…","opts":["Stop practising","Re-review your error log and re-do your weakest sections","Only watch movies","Memorize full essays"],"correct":1,"exp":"Your error log tells you exactly where the remaining points are, targeted re-practice beats random new material."},{"q":"The night before test day you should…","opts":["Learn 200 new words","Check ID and logistics, do light review, and sleep well","Take two full practice tests","Change all your templates"],"correct":1,"exp":"Logistics plus rest protect the score you have already built; cramming that night adds stress, not points."}],"unlocks":19}}};
COURSES_DB['sat'] = {"id":"sat","title":"Digital SAT Masterclass: Reading & Writing + Math","shortDesc":"A full Digital SAT preparation course covering the adaptive format and 400–1600 scoring, the Reading & Writing section, the Math section, and a proven pacing and strategy system.","category":"Exam Preparation","icon":"📐","gradient":"linear-gradient(135deg,#14532d,#15803d,#22c55e)","instructor":"Samuel Tolbert","instructorTitle":"Founder & CEO, Tolbert Innovation Hub","instructorBio":"Samuel Tolbert founded TIH to bring world-class exam preparation to Liberia and West Africa, guiding students toward the SAT scores that unlock US university admission and scholarships.","rating":4.9,"reviewCount":274,"students":"700+","duration":"38h","level":"Intermediate → Advanced","price":"$20","origPrice":"$160","isFree":false,"badge":"premium","certId":"TIH-2026-SAT-0001","learn":["Understand the Digital SAT’s adaptive format and the 400–1600 score","Master Reading & Writing: craft, structure, expression and Standard English conventions","Solve Math faster: Algebra, Advanced Math, Problem-Solving & Data, and Geometry","Use the built-in Desmos calculator and reference sheet effectively","Apply pacing strategies for the two adaptive modules per section","Attempt a full-length practice set with worked solutions"],"requirements":["Solid basic English and math (roughly high-school level) to build on","A device to practise on Bluebook-style questions when possible","Discipline to practise under timed conditions"],"about":["The SAT is a key admission and scholarship test for universities in the United States. The exam is now the Digital SAT, shorter, adaptive, and taken on a computer through the Bluebook app.","This masterclass explains the new adaptive format, then teaches the content and question strategies for both the Reading & Writing section and the Math section, with worked examples throughout.","Every lesson is written clearly for learners in Liberia and West Africa who are aiming for competitive scores and international opportunities."],"modules":[{"title":"Module 1: The Digital SAT & How It Is Scored","icon":"🧭","meta":"3 lessons","lessons":[{"t":"1.1 The Digital SAT Format: Adaptive Modules & Bluebook","d":"Reading","v":"2aiVO9FoGg4"},{"t":"1.2 Scoring 400–1600 & Setting Your Target","d":"Reading","v":"HXP17Be8TRY"},{"t":"📝 Quiz: Digital SAT Format","d":"5 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Reading & Writing, Reading Skills","icon":"📖","meta":"3 lessons","lessons":[{"t":"2.1 Craft & Structure: Main Idea, Purpose & Vocabulary","d":"Reading","v":"Pw5uTD3_FKw"},{"t":"2.2 Information & Ideas: Evidence, Inference & Data","d":"Reading","v":"POcYofMngBw"},{"t":"📝 Quiz: Reading Skills","d":"5 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Reading & Writing, Writing Skills","icon":"✍️","meta":"3 lessons","lessons":[{"t":"3.1 Standard English Conventions: Grammar & Punctuation","d":"Reading","v":"4jgnbFnXiYs"},{"t":"3.2 Expression of Ideas: Transitions & Rhetorical Synthesis","d":"Reading","v":"lo7LFbac_9o"},{"t":"📝 Quiz: Writing Skills","d":"5 questions","isQuiz":true,"quizId":"mod3"}]},{"title":"Module 4: Math","icon":"🔢","meta":"4 lessons","lessons":[{"t":"4.1 Algebra: Linear Equations, Systems & Inequalities","d":"Reading","v":"vrPbC9fao6Y"},{"t":"4.2 Advanced Math: Quadratics, Exponents & Functions","d":"Reading","v":"zvczFfWx40k"},{"t":"4.3 Problem-Solving, Data Analysis & Geometry","d":"Reading","v":"i0bBokmVtWw"},{"t":"🛠️ Project: Solve a Mixed Math Set with the Desmos Calculator","d":"Project","isProject":true}]},{"title":"Module 5: Strategy & Full Practice","icon":"🏁","meta":"3 lessons","lessons":[{"t":"5.1 Pacing, Guessing & the Adaptive Second Module","d":"Reading","v":"gMGQHSUFRCU"},{"t":"5.2 Test-Day Plan & Score-Boosting Habits","d":"Reading","v":"XKu4sgpHWN8"}]},{"title":"Module 6: Advanced Drills, Mock Tests & Beyond the SAT","lessons":[{"t":"6.1 Advanced Math: Conquering the Hardest Questions","d":"Video + notes","v":"yqcyspQ6HSg"},{"t":"6.2 Hard Reading & Writing: Beating the Toughest Items","d":"Video + notes","v":"IhWiMWq3VhE"},{"t":"6.3 Bluebook Practice Tests: Take & Review Like a Top Scorer","d":"Video + notes","v":"bUVI0iK740o"},{"t":"6.4 After the SAT: Superscoring, Score Choice & Applications","d":"Video + notes","v":"MUcULumd2hM"},{"t":"📝 Quiz: Advanced Strategy & Next Steps","d":"8 questions","isQuiz":true,"quizId":"mod6"},{"t":"🏆 Final Assessment & Certificate","d":"Assessment","isQuiz":true,"quizId":"final","isFinal":true}],"icon":"🎓","meta":"6 lessons"}],"quizzes":{"mod1":{"title":"Quiz: Digital SAT Format","moduleNum":1,"unlocks":3,"questions":[{"q":"The Digital SAT total score ranges from:","opts":["0 to 120","400 to 1600","0 to 9","200 to 800"],"correct":1,"exp":"The SAT total is 400–1600: 200–800 for Reading & Writing plus 200–800 for Math."},{"q":"The Digital SAT is \"adaptive,\" which means:","opts":["It never changes","The second module’s difficulty depends on your first-module performance","It has no time limit","It is on paper"],"correct":1,"exp":"Each section has two modules; performance on the first sets the difficulty of the second."},{"q":"The SAT is taken through:","opts":["Email","The Bluebook app on a computer","WhatsApp","A paper booklet only"],"correct":1,"exp":"The Digital SAT is administered through College Board’s Bluebook application."},{"q":"The two sections of the SAT are:","opts":["Reading & Writing, and Math","Speaking and Writing","Listening and Reading","Essay and Math"],"correct":0,"exp":"The Digital SAT has a Reading & Writing section and a Math section."},{"q":"A calculator is:","opts":["Never allowed","Allowed on the entire Math section (built-in Desmos)","Only on paper","Banned"],"correct":1,"exp":"A built-in Desmos graphing calculator is available for the whole Math section."},{"q":"The Reading & Writing section has how many modules?","opts":["One","Two","Three","Four"],"correct":1,"exp":"Each section (Reading & Writing, and Math) has two modules."},{"q":"Doing well on Module 1 leads to:","opts":["A shorter test","A harder Module 2 with a higher score ceiling","No Module 2","A lower score"],"correct":1,"exp":"Strong Module 1 performance unlocks the harder, higher-scoring Module 2."},{"q":"The whole Digital SAT takes about:","opts":["45 minutes","2 hours 14 minutes","4 hours","A full day"],"correct":1,"exp":"The digital test is about 2 hours 14 minutes."},{"q":"Reading & Writing gives you how long per module?","opts":["10 minutes","32 minutes","60 minutes","No limit"],"correct":1,"exp":"27 questions in 32 minutes per Reading & Writing module."},{"q":"Which tool is available for the whole test to revisit questions?","opts":["A dictionary","Mark-for-review","A phone","A friend"],"correct":1,"exp":"Bluebook lets you flag questions and return to them."}]},"mod2":{"title":"Quiz: Reading Skills","moduleNum":2,"unlocks":3,"questions":[{"q":"\"Words in Context\" questions test:","opts":["Spelling","The best word for meaning and tone in a sentence","Handwriting","Pronunciation"],"correct":1,"exp":"You choose the word that best fits the logic and tone of the passage."},{"q":"A \"Command of Evidence\" question asks you to:","opts":["Ignore the text","Find data or a quote that best supports a claim","Write an essay","Guess"],"correct":1,"exp":"You select the detail (text or graph) that most directly supports the point."},{"q":"Digital SAT Reading passages are:","opts":["Very long (700+ words)","Short, one passage per question","Poems only","Absent"],"correct":1,"exp":"Each question has its own short passage of roughly 25–150 words."},{"q":"An inference question requires an answer that is:","opts":["Directly stated","Logically supported by the passage","Unrelated","The longest option"],"correct":1,"exp":"Choose the option most logically supported by the given text."},{"q":"Reading & Writing questions are arranged:","opts":["Randomly","Roughly easy to hard within a type","Hardest first","By colour"],"correct":1,"exp":"Questions are grouped by type and generally increase in difficulty."},{"q":"For a quantitative-evidence question you should read first:","opts":["The answer choices","The graph’s axis labels and units","The last line","Nothing"],"correct":1,"exp":"Misreading axes/units causes wrong answers, check them first."},{"q":"A central-idea question asks for the passage’s:","opts":["Longest sentence","Main point","First word","A minor detail"],"correct":1,"exp":"Summarise the passage, then pick the closest option."},{"q":"Wrong answer choices are often:","opts":["True but off-topic, or overstated","Always shortest","Always first","Always correct"],"correct":0,"exp":"Eliminate options that are irrelevant or use extreme words like \"always\"."},{"q":"The best approach to a mini-passage is to:","opts":["Read the answers first","Read the whole passage, then answer","Skip it","Guess"],"correct":1,"exp":"Context decides the answer, so read the short passage fully."},{"q":"For \"Words in Context,\" a useful tactic is to:","opts":["Pick the hardest word","Predict a word yourself, then match it","Choose the longest","Choose the first"],"correct":1,"exp":"Predict a fitting word, then find the closest option."}]},"mod3":{"title":"Quiz: Writing Skills","moduleNum":3,"unlocks":3,"questions":[{"q":"A comma splice is fixed by:","opts":["Adding more commas","Using a period, semicolon, or conjunction between two independent clauses","Removing all punctuation","Capitalising"],"correct":1,"exp":"Two independent clauses cannot be joined by a comma alone."},{"q":"Transition questions test whether the logical relationship is:","opts":["Contrast, cause, example, etc.","Spelling","Length","Font"],"correct":0,"exp":"Pick the transition that matches the logic: however, therefore, for example, etc."},{"q":"Subject–verb agreement means:","opts":["Verbs match the subject in number","All verbs are past tense","Sentences are short","Nouns are capitalised"],"correct":0,"exp":"A singular subject takes a singular verb; a plural subject takes a plural verb."},{"q":"\"Rhetorical Synthesis\" asks you to:","opts":["Use given bullet-point notes to meet a stated goal","Write a poem","Translate","Draw"],"correct":0,"exp":"You combine given notes to accomplish a specific rhetorical goal."},{"q":"The best answer for conventions questions is usually:","opts":["The longest","The one that is grammatically correct and concise","The most complex","Any option"],"correct":1,"exp":"SAT rewards correct, clear, concise writing."},{"q":"A colon is correctly used to:","opts":["Join two independent clauses with no words","Introduce a list or explanation after a complete sentence","Replace every comma","End a question"],"correct":1,"exp":"A colon follows a complete sentence to introduce a list or explanation."},{"q":"\"The team of players ______ ready.\" Choose the verb:","opts":["are","is","were","being"],"correct":1,"exp":"The subject \"team\" is singular, so use \"is\"."},{"q":"A transition showing cause and effect is:","opts":["however","therefore","for example","meanwhile"],"correct":1,"exp":"\"Therefore\" signals a result."},{"q":"A pronoun must agree with its noun in:","opts":["Colour","Number","Length","Font"],"correct":1,"exp":"Singular noun → singular pronoun; plural → plural."},{"q":"For rhetorical synthesis you should first:","opts":["Ignore the goal","Underline the stated goal, then test each option","Pick the longest","Guess"],"correct":1,"exp":"The correct answer accomplishes the specific stated goal."}]},"final":{"title":"Final Assessment","moduleNum":5,"unlocks":null,"isFinal":true,"questions":[{"q":"On the Digital SAT you should guess when unsure because:","opts":["There is a penalty","There is no penalty for wrong answers","It lowers your score","Guessing is banned"],"correct":1,"exp":"There is no wrong-answer penalty, so never leave a question blank."},{"q":"Solve 3x + 5 = 20. x =","opts":["3","5","15","45"],"correct":1,"exp":"3x = 15, so x = 5."},{"q":"The slope of the line y = 2x + 4 is:","opts":["4","2","–4","1/2"],"correct":1,"exp":"In y = mx + b, the slope m is the coefficient of x, which is 2."},{"q":"Good pacing means:","opts":["Spending all time on question 1","Moving steadily and flagging hard items to revisit","Skipping the section","Rushing everything"],"correct":1,"exp":"Answer efficiently, mark tough questions, and return with remaining time."},{"q":"The Math reference sheet provides:","opts":["The answers","Common geometry formulas","Vocabulary","Nothing"],"correct":1,"exp":"A reference sheet with geometry formulas is available throughout the Math section."},{"q":"Solve 2(x − 4) = 10. x =","opts":["3","7","9","12"],"correct":2,"exp":"x − 4 = 5, so x = 9."},{"q":"A shirt costs $50 and is 20% off. The sale price is:","opts":["$30","$40","$45","$48"],"correct":1,"exp":"20% of 50 = 10, so 50 − 10 = 40."},{"q":"The mean of 6, 10 and x is 9. x =","opts":["9","10","11","12"],"correct":2,"exp":"(6+10+x)/3 = 9 → 16+x = 27 → x = 11."},{"q":"A right triangle has legs 6 and 8. The hypotenuse is:","opts":["10","12","14","48"],"correct":0,"exp":"√(6²+8²) = √100 = 10."},{"q":"The slope of y = −3x + 2 is:","opts":["2","3","−3","−2"],"correct":2,"exp":"The slope is the coefficient of x: −3."},{"q":"If 25% of a number is 40, the number is:","opts":["100","120","160","200"],"correct":2,"exp":"0.25n = 40 → n = 160."},{"q":"A car goes 180 km in 3 hours. Its average speed is:","opts":["40 km/h","50 km/h","60 km/h","90 km/h"],"correct":2,"exp":"180 ÷ 3 = 60 km/h."},{"q":"Two independent clauses joined by only a comma is called a:","opts":["Colon","Comma splice","Semicolon","Fragment"],"correct":1,"exp":"A comma splice, fix with a period, semicolon or conjunction."},{"q":"\"Words in Context\" tests the word that best fits the:","opts":["Rhyme","Meaning and tone","Length","Spelling"],"correct":1,"exp":"Choose the word matching the sentence’s logic and tone."},{"q":"On the Digital SAT, each Reading question has:","opts":["A shared long passage","Its own short passage","No passage","A video"],"correct":1,"exp":"Each question comes with its own short passage."},{"q":"A command-of-evidence answer must:","opts":["Be the longest","Directly support the claim","Be unrelated","Contain a number"],"correct":1,"exp":"Pick the detail that most directly supports the point."},{"q":"Solve for x: x/4 = 5.","opts":["9","20","1.25","45"],"correct":1,"exp":"Multiply both sides by 4: x = 20."},{"q":"The Math section allows a calculator on:","opts":["No questions","The entire section","Only Module 1","Only Module 2"],"correct":1,"exp":"The built-in Desmos calculator is available for the whole Math section."},{"q":"Good test-day habit: in the last minutes of a module,","opts":["Leave hard ones blank","Make sure no question is unanswered","Stop early","Change every answer"],"correct":1,"exp":"With no penalty, guess anything unanswered before time runs out."},{"q":"Subject–verb agreement: \"The results ______ clear.\"","opts":["is","was","are","being"],"correct":2,"exp":"\"Results\" is plural, so use \"are\"."}]},"mod6":{"title":"Quiz: Advanced Strategy & Next Steps","moduleNum":6,"questions":[{"q":"You receive the HARDER second module when…","opts":["You do poorly on Module 1","You perform well on Module 1","It is assigned randomly","You finish Module 1 early"],"correct":1,"exp":"The Digital SAT is adaptive: strong Module 1 performance routes you to the harder (higher-ceiling) Module 2."},{"q":"The smartest first move on a hard math question is…","opts":["Skip it forever","Identify the question type, then decide: algebra or Desmos","Always solve by hand","Always use Desmos"],"correct":1,"exp":"Top scorers classify the problem first, some are faster by hand, many are faster graphed in Desmos."},{"q":"Bluebook is…","opts":["A vocabulary book","College Board’s official app with full-length adaptive practice tests","A paid tutoring service","The test centre check-in app"],"correct":1,"exp":"Bluebook is the official College Board app, its full-length adaptive practice tests are the gold standard for preparation."},{"q":"Reviewing a practice test \"like a top scorer\" means…","opts":["Checking only your total score","Analyzing every miss: why it happened and how to prevent it","Retaking it immediately","Reviewing only math"],"correct":1,"exp":"The score tells you where you are; the miss-by-miss analysis tells you how to move up."},{"q":"There is a penalty for wrong answers on the Digital SAT.","opts":["True","False","Only in math","Only in Module 2"],"correct":1,"exp":"False, never leave a question blank. An educated guess can only help you."},{"q":"Score Choice lets you…","opts":["Delete scores permanently","Choose which test dates’ scores to send to colleges","Combine sections from different dates","Retake one module only"],"correct":1,"exp":"Score Choice controls which complete test-date scores you send. (Some colleges ask for all scores, check each policy.)"},{"q":"Superscoring means a college…","opts":["Averages all your attempts","Uses only your most recent score","Combines your best section scores across different test dates","Doubles your math score"],"correct":2,"exp":"Superscoring takes your best Reading & Writing and best Math from different dates, retaking strategically can raise it."},{"q":"If a hard question is eating your time, you should…","opts":["Stay until you solve it","Mark it, guess, move on, and return if time allows","Leave it blank","Panic"],"correct":1,"exp":"Pacing wins points: bank the questions you can answer, then return with the flag tool if time remains."}],"unlocks":20}}};
COURSES_DB['bible-ot'] = {"id":"bible-ot","title":"Old Testament Survey: God's Promise Unfolding","shortDesc":"Journey through the entire Old Testament, creation and the patriarchs, the exodus and the Law, the kings and prophets, exile and return, and see how it all points to Christ.","category":"TIH Bible School","icon":"📜","gradient":"linear-gradient(135deg,#E31E24,#0B1F3A)","instructor":"TIH Bible School","instructorTitle":"Biblical Studies Faculty","instructorBio":"The TIH Bible School equips learners across Liberia with clear, Bible-centered teaching for a growing faith and a life of service.","rating":4.9,"reviewCount":96,"students":480,"duration":"6 weeks","level":"Beginner","price":"$2","origPrice":"$10","isFree":false,"badge":"new","certId":"TIH-2026-BIB-OT01","learn":["Understand the structure and storyline of all 39 Old Testament books","Explain key events: creation, the Fall, the exodus, the kingdom, and the exile","Know the major covenants God made with His people","Understand the message of the Law, wisdom books, and prophets","See how the Old Testament points forward to Jesus Christ","Read and apply the Old Testament wisely today"],"requirements":["No prior Bible knowledge required","A Bible (print or app) is helpful","Curiosity about the Scriptures"],"about":"This survey takes you through the entire Old Testament in six modules, from the creation and the patriarchs, through the exodus and the giving of the Law, into the era of judges, kings, and prophets, and finally the exile and return. Along the way you will grasp the big storyline, meet the major figures, understand the covenants, and discover how the whole Old Testament prepares the way for Jesus. Perfect for anyone who wants to read the first two-thirds of the Bible with understanding and confidence.","modules":[{"title":"Module 1: The Law (Torah)","icon":"📜","meta":"4 lessons","lessons":[{"t":"1.1 The Old Testament: One Story in 39 Books","d":"12:00","v":"ALsluAKBZ-c"},{"t":"1.2 Genesis: Creation, Fall, and Promise","d":"12:00","v":"GQI72THyO5I"},{"t":"1.3 The Patriarchs & The Exodus","d":"12:00","v":"F4isSyennFo"},{"t":"📝 Quiz: The Law","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: Israel in the Land","icon":"🏔️","meta":"4 lessons","lessons":[{"t":"2.1 Exodus: Rescue, Passover, and the Law","d":"12:00","v":"jH_aojNJM3E"},{"t":"2.2 Wilderness and the Edge of the Promised Land","d":"12:00","v":"tp5MIrMZFqo"},{"t":"2.3 Conquest and the Judges","d":"12:00","v":"JqOqJlFF_eU"},{"t":"📝 Quiz: Israel in the Land","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Wisdom & Worship","icon":"🎵","meta":"4 lessons","lessons":[{"t":"3.1 Job and the Question of Suffering","d":"12:00","v":"xQwnH8th_fs"},{"t":"3.2 The Psalms: Prayers and Songs","d":"12:00","v":"e5LBsYy_4EM"},{"t":"3.3 Proverbs and the Wisdom Books","d":"12:00","v":"AzmYV8GNAIM"},{"t":"🛠️ Project: A Psalm of Your Own","d":"Project","isProject":true}]},{"title":"Module 4: Kings and Prophets","icon":"👑","meta":"4 lessons","lessons":[{"t":"4.1 The Kings: David, Solomon, and a Divided Nation","d":"12:00","v":"QJOju5Dw0V0"},{"t":"4.2 The Major Prophets","d":"12:00","v":"d0A6Uchb1F8"},{"t":"4.3 The Minor Prophets","d":"12:00","v":"qjbYnCadoGw"},{"t":"📝 Quiz: Kings and Prophets","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: Exile and Return","icon":"🕯️","meta":"4 lessons","lessons":[{"t":"5.1 Exile: When the Nation Fell","d":"12:00","v":"FwZejz71UrA"},{"t":"5.2 Return and Rebuilding: Ezra, Nehemiah","d":"12:00","v":"MkETkRv9tG8"},{"t":"5.3 Esther and the Hidden Hand of God","d":"12:00","v":"JydNSlufRIs"},{"t":"📝 Quiz: Exile and Return","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Themes & Christ in the OT","icon":"✡️","meta":"4 lessons","lessons":[{"t":"6.1 The Covenants: God's Unfolding Plan","d":"12:00","v":"6HjlGvl8ljM"},{"t":"6.2 Christ in the Old Testament","d":"12:00","v":"QxOeq3of3O4"},{"t":"6.3 Reading the Old Testament Today","d":"12:00","v":"ak06MSETeo4"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: The Law","moduleNum":1,"unlocks":2,"questions":[{"q":"How many books are in the Old Testament?","opts":["27","39","66","12"],"correct":1,"exp":"The Old Testament contains 39 books, from Genesis to Malachi."},{"q":"The first five books of the Bible (Genesis–Deuteronomy) are called:","opts":["The Prophets","The Gospels","The Law / Torah / Pentateuch","The Wisdom books"],"correct":2,"exp":"These five books are the Torah, Law, or Pentateuch, traditionally associated with Moses."},{"q":"In Genesis 3, the entrance of sin into the world is called:","opts":["The Flood","The Fall","The Exodus","The Exile"],"correct":1,"exp":"The Fall (Genesis 3) describes humanity's first disobedience and its consequences."},{"q":"Genesis 3:15, the \"first gospel,\" promises that:","opts":["The flood will end","A descendant of the woman will crush the serpent","Abraham will have a son","The Law will be given"],"correct":1,"exp":"Genesis 3:15 is the first hint of a coming Savior who will defeat the serpent (Satan)."},{"q":"God's covenant promise to Abraham included that:","opts":["He would become Pharaoh","In him all families of the earth would be blessed","He would never leave home","He would write the Law"],"correct":1,"exp":"Genesis 12:2-3 promises blessing to all the families of the earth through Abraham."},{"q":"\"He believed the Lord, and he counted it to him as righteousness\" (Genesis 15:6) is about:","opts":["Moses","Abraham","Joshua","David"],"correct":1,"exp":"Abraham was counted righteous because he believed God's promise, a key picture of faith."},{"q":"Joseph told his brothers, \"you meant evil against me, but God meant it for good.\" This shows:","opts":["Revenge is right","God's providence works through hardship","Dreams are always literal","Egypt was the promised land"],"correct":1,"exp":"Genesis 50:20 reveals God's providence bringing good even out of others' evil."},{"q":"The event in which God rescued Israel out of slavery in Egypt is called:","opts":["The Conquest","The Exodus","The Return","The Fall"],"correct":1,"exp":"The Exodus is Israel's deliverance from Egypt under Moses."},{"q":"The Passover lamb's blood on the doorposts (Exodus 12) points forward to:","opts":["King David","Jesus, our Passover lamb","The prophets","The temple"],"correct":1,"exp":"1 Corinthians 5:7 calls Christ \"our Passover lamb,\" whose blood saves us."},{"q":"The Ten Commandments were given to Israel at:","opts":["Mount Sinai","Jerusalem","Babylon","Jericho"],"correct":0,"exp":"God gave the Law, including the Ten Commandments, at Mount Sinai (Exodus 20)."}]},"mod2":{"title":"Quiz: Israel in the Land","moduleNum":2,"unlocks":6,"questions":[{"q":"Because of unbelief at the border of the Promised Land, that generation of Israel:","opts":["Entered immediately","Wandered 40 years in the wilderness","Returned to Egypt","Built the temple"],"correct":1,"exp":"Numbers 14 records 40 years of wandering because Israel refused to trust God."},{"q":"\"Hear, O Israel: The Lord our God, the Lord is one. You shall love the Lord your God with all your heart\" is found in:","opts":["Genesis","Deuteronomy 6","Judges","Job"],"correct":1,"exp":"Deuteronomy 6:4-5, the Shema, was called the greatest commandment by Jesus."},{"q":"Who led Israel into the Promised Land after Moses died?","opts":["Joshua","Gideon","Samson","Samuel"],"correct":0,"exp":"Joshua led Israel into Canaan (Joshua 1)."},{"q":"God's encouragement to Joshua was:","opts":["\"Be strong and courageous... the Lord is with you\"","\"Do not enter the land\"","\"Return to Egypt\"","\"Build an ark\""],"correct":0,"exp":"Joshua 1:9 commands strength and courage because God is present."},{"q":"The first city Israel conquered, whose walls fell down, was:","opts":["Jerusalem","Jericho","Babylon","Nineveh"],"correct":1,"exp":"Jericho's walls collapsed after Israel obeyed God's unusual instructions (Joshua 6)."},{"q":"The repeated cycle in the book of Judges was:","opts":["Sin, oppression, crying out, deliverance","Peace, war, peace, war","Build, destroy, build, destroy","Plant, harvest, rest, plant"],"correct":0,"exp":"Israel repeatedly sinned, was oppressed, cried out, and was delivered by a judge."},{"q":"The tragic refrain of Judges, \"Everyone did what was right in his own eyes,\" shows the need for:","opts":["More money","A true, righteous king","Bigger armies","Longer feasts"],"correct":1,"exp":"Judges 21:25 highlights the moral chaos and the longing for godly kingship."},{"q":"Leviticus teaches that approaching a holy God required:","opts":["Nothing at all","Sacrifice / the shedding of blood","Wealth","Military victory"],"correct":1,"exp":"Leviticus' sacrifices show that sin requires atonement (Hebrews 9:22)."},{"q":"Deborah, Gideon, and Samson were:","opts":["Kings of Judah","Judges God raised up to deliver Israel","Prophets of the exile","Priests in the temple"],"correct":1,"exp":"They were among the judges God used to rescue Israel from oppression."},{"q":"The repeated command \"be holy, for I am holy\" comes from:","opts":["Leviticus","Esther","Ecclesiastes","Nehemiah"],"correct":0,"exp":"Leviticus 19:2 calls God's people to holiness reflecting His character."}]},"mod4":{"title":"Quiz: Kings and Prophets","moduleNum":4,"unlocks":5,"questions":[{"q":"The shepherd boy who trusted God to defeat Goliath and later became king was:","opts":["Saul","David","Solomon","Samuel"],"correct":1,"exp":"David defeated Goliath (1 Samuel 17) and became Israel's great king."},{"q":"God's covenant with David promised that:","opts":["He would never sin","One of his descendants would reign forever","He would build the temple himself","Israel would never divide"],"correct":1,"exp":"2 Samuel 7 promises an everlasting throne, fulfilled in Jesus, the son of David."},{"q":"After Solomon, the kingdom of Israel:","opts":["Grew stronger and united","Split into Israel (north) and Judah (south)","Was destroyed completely","Moved to Egypt"],"correct":1,"exp":"1 Kings 12 records the division into northern Israel and southern Judah."},{"q":"Isaiah 53 describes the Messiah as:","opts":["A wealthy king","A suffering servant \"pierced for our transgressions\"","A military general","An angel"],"correct":1,"exp":"Isaiah 53 foretells the suffering servant whose wounds bring healing."},{"q":"Jeremiah promised a coming:","opts":["New covenant written on the heart","Second flood","Return to Egypt","End of all prophecy"],"correct":0,"exp":"Jeremiah 31:31-33 promises a new covenant, fulfilled by Jesus."},{"q":"The prophet who remained faithful in Babylon and was thrown into the lions' den was:","opts":["Ezekiel","Daniel","Hosea","Amos"],"correct":1,"exp":"Daniel stayed faithful under Babylon and was delivered from the lions (Daniel 6)."},{"q":"Micah 5:2 foretold that the Messiah would be born in:","opts":["Jerusalem","Bethlehem","Nazareth","Babylon"],"correct":1,"exp":"Micah 5:2 names Bethlehem as the Messiah's birthplace."},{"q":"Micah 6:8 summarizes what God requires as:","opts":["Wealth and power","\"Do justice, love kindness, walk humbly with your God\"","Many sacrifices only","Silence"],"correct":1,"exp":"Micah 6:8 gives a memorable summary of true devotion to God."},{"q":"The prophets were primarily God's:","opts":["Kings","Messengers who called people back to God","Priests only","Soldiers"],"correct":1,"exp":"Prophets delivered God's messages of warning, repentance, and hope."},{"q":"Malachi, the last Old Testament book, promised:","opts":["A messenger to prepare the way for the Lord","The end of Israel","A new king in Babylon","No more prophets ever"],"correct":0,"exp":"Malachi 3:1 promises a messenger (fulfilled by John the Baptist) preparing Christ's way."}]},"mod5":{"title":"Quiz: Exile and Return","moduleNum":5,"unlocks":6,"questions":[{"q":"The southern kingdom of Judah was conquered, and Jerusalem's temple destroyed in 586 BC, by:","opts":["Assyria","Babylon","Persia","Egypt"],"correct":1,"exp":"Babylon destroyed Jerusalem and the temple in 586 BC and took Judah into exile."},{"q":"Lamentations grieves the fall of Jerusalem yet declares:","opts":["God has abandoned His people forever","\"His mercies are new every morning\"","The exile will never end","Idols are powerful"],"correct":1,"exp":"Lamentations 3:22-23 shines hope: God's mercies are new every morning."},{"q":"Jeremiah 29:11 promises the exiles:","opts":["Immediate wealth","Plans for welfare, a future and a hope","A new temple in Babylon","The end of the world"],"correct":1,"exp":"God promised a future and a hope even during the exile."},{"q":"The empire that conquered Babylon and allowed the Jews to return home was:","opts":["Egypt","Persia","Rome","Greece"],"correct":1,"exp":"Persia (King Cyrus) permitted the Jews to return (Ezra 1)."},{"q":"Who rebuilt the walls of Jerusalem in just 52 days despite opposition?","opts":["Ezra","Nehemiah","Esther","Daniel"],"correct":1,"exp":"Nehemiah led the rebuilding of Jerusalem's walls (Nehemiah 6:15)."},{"q":"Ezra led a spiritual renewal primarily by:","opts":["Winning a war","Reading and explaining God's Law to the people","Building a palace","Crowning a king"],"correct":1,"exp":"Ezra taught the Law, and the people responded with weeping and joy (Nehemiah 8)."},{"q":"A striking feature of the book of Esther is that:","opts":["It has many miracles","God is never mentioned by name, yet His providence is clear","It is written in Greek","It takes place in Egypt"],"correct":1,"exp":"God's name never appears in Esther, yet His hidden hand saves His people."},{"q":"Mordecai told Esther she may have come to her position \"for such a time as this,\" found in:","opts":["Esther 4:14","Genesis 1","Psalm 23","Daniel 6"],"correct":0,"exp":"Esther 4:14 is Mordecai's challenge to Esther to act courageously."},{"q":"The exile taught Israel that:","opts":["Idols are worthless and sin has consequences, yet God stays faithful","God does not care about sin","Other nations' gods are real","The covenant was cancelled"],"correct":0,"exp":"Exile showed sin's seriousness and God's enduring faithfulness to His covenant."},{"q":"The prophets Haggai and Zechariah encouraged the returned exiles to:","opts":["Return to Babylon","Rebuild the temple","Abandon worship","Fight Persia"],"correct":1,"exp":"Haggai and Zechariah encouraged the rebuilding of the temple (Ezra 5-6)."}]},"final":{"title":"Final Assessment & Certificate","moduleNum":6,"unlocks":0,"isFinal":true,"questions":[{"q":"The Old Testament tells:","opts":["Unrelated ancient myths","One unfolding story leading to a Savior","Only Israel's laws","A book of poems only"],"correct":1,"exp":"The 39 books tell one story of God preparing the way for Christ."},{"q":"Genesis records both the good creation and:","opts":["The building of the temple","The Fall of humanity into sin","The exile to Babylon","The reign of David"],"correct":1,"exp":"Genesis 1-3 covers creation and the Fall."},{"q":"God's covenant with Abraham promised blessing to:","opts":["Only his family","All the families of the earth","Egypt alone","No one"],"correct":1,"exp":"Genesis 12:3, through Abraham all nations would be blessed."},{"q":"The Passover pointed forward to:","opts":["The Law","Jesus, the Lamb of God","King Solomon","The exile"],"correct":1,"exp":"The Passover lamb foreshadowed Christ, our Passover (1 Corinthians 5:7)."},{"q":"The Ten Commandments were given at:","opts":["Bethlehem","Mount Sinai","Babylon","Jericho"],"correct":1,"exp":"God gave the Law at Sinai (Exodus 20)."},{"q":"Joshua is known for leading Israel to:","opts":["Egypt","Conquer the Promised Land","Babylon","Rebuild the walls"],"correct":1,"exp":"Joshua led the conquest of Canaan."},{"q":"The book of Judges repeatedly shows:","opts":["Faithful obedience","A cycle of sin, oppression, and deliverance","A united strong kingdom","Peaceful worship"],"correct":1,"exp":"Judges records Israel's cycle of sin and rescue."},{"q":"\"The Lord is my shepherd\" comes from:","opts":["Psalm 23","Proverbs 1","Job 1","Genesis 1"],"correct":0,"exp":"Psalm 23 is the beloved psalm of trust in God as shepherd."},{"q":"\"The fear of the Lord is the beginning of knowledge\" is the theme of:","opts":["Exodus","Proverbs","Esther","Numbers"],"correct":1,"exp":"Proverbs 1:7 grounds wisdom in reverence for God."},{"q":"Job wrestles honestly with the question of:","opts":["How to build the temple","Why the righteous suffer","How to win battles","When the exile ends"],"correct":1,"exp":"Job explores suffering and God's trustworthiness in it."},{"q":"God promised David that his descendant would:","opts":["Rule Egypt","Reign forever","Never be born","Destroy Jerusalem"],"correct":1,"exp":"2 Samuel 7 promises an everlasting throne, fulfilled in Jesus."},{"q":"After Solomon, the kingdom:","opts":["Grew stronger","Split into Israel and Judah","Moved to Persia","Ended immediately"],"correct":1,"exp":"The kingdom divided into north (Israel) and south (Judah)."},{"q":"Isaiah 53 famously describes:","opts":["A conquering army","The suffering servant","The building of walls","A great feast"],"correct":1,"exp":"Isaiah 53 foretells the Messiah as the suffering servant."},{"q":"Jeremiah promised a \"new covenant\" that would be:","opts":["Written on stone again","Written on the heart","Given only to kings","Cancelled soon"],"correct":1,"exp":"Jeremiah 31:31-33 promises the law written on the heart."},{"q":"Judah was taken into exile by Babylon because of:","opts":["A natural disaster","Persistent idolatry and injustice","A famine only","Losing a sports contest"],"correct":1,"exp":"Exile came as judgment for ongoing unfaithfulness, as the prophets warned."},{"q":"Nehemiah is remembered for rebuilding:","opts":["The temple","Jerusalem's walls","The palace","The tabernacle"],"correct":1,"exp":"Nehemiah led the rebuilding of Jerusalem's walls."},{"q":"The book of Esther highlights God's:","opts":["Loud miracles","Hidden providence","Silence and absence","Anger only"],"correct":1,"exp":"God works unseen to save His people in Esther."},{"q":"The covenants of the Bible find their \"Yes\" in:","opts":["The Law","Christ (2 Corinthians 1:20)","The kings","The temple"],"correct":1,"exp":"All God's promises are fulfilled in Jesus."},{"q":"Jesus taught that the Old Testament Scriptures:","opts":["Are unimportant now","Bear witness about Him","Contradict the New Testament","Were written by Him alone"],"correct":1,"exp":"Jesus said the Scriptures testify about Him (John 5:39; Luke 24:27)."},{"q":"A good way to read the Old Testament today is to:","opts":["Ignore its message","Read it as one story leading to Jesus","Follow every ceremonial law exactly","Treat it as fiction"],"correct":1,"exp":"Read the OT as God's unified story of redemption fulfilled in Christ."}]}},"reviews":[{"name":"Joseph W.","rating":5,"text":"The Old Testament finally makes sense as one story. I loved seeing how it all points to Jesus."},{"name":"Ruth D.","rating":5,"text":"Clear, well-organized, and easy to understand. The maps of the storyline helped so much."},{"name":"Prince G.","rating":4,"text":"Excellent survey. The quizzes made me actually remember the books and their order."}],"faqs":[{"q":"Is this course hard if I have never read the Old Testament?","a":"No. It is designed for beginners and explains everything clearly, pointing you to the verses so you can read along."},{"q":"Do I need to read all 39 books first?","a":"No. This survey guides you through the big picture; you can read the books alongside or after the course."},{"q":"Will I get a certificate?","a":"Yes. Complete all modules and pass the final assessment (70%) to earn your TIH Bible School certificate."}]};
COURSES_DB['bible-nt'] = {"id":"bible-nt","title":"New Testament Survey: The Good News of Jesus","shortDesc":"Journey through the entire New Testament, the four Gospels, the birth of the Church in Acts, the letters of Paul and others, and the hope of Revelation, and meet Jesus, the Savior of the world.","category":"TIH Bible School","icon":"✝️","gradient":"linear-gradient(135deg,#1565D8,#0B1F3A)","instructor":"TIH Bible School","instructorTitle":"Biblical Studies Faculty","instructorBio":"The TIH Bible School equips learners across Liberia with clear, Bible-centered teaching for a growing faith and a life of service.","rating":4.9,"reviewCount":112,"students":560,"duration":"6 weeks","level":"Beginner","price":"$2","origPrice":"$10","isFree":false,"badge":"new","certId":"TIH-2026-BIB-NT01","learn":["Understand the structure and storyline of all 27 New Testament books","Know the life, teaching, death, and resurrection of Jesus from the four Gospels","Explain the gospel and how a person is saved","Trace the birth and growth of the early Church in Acts","Understand the main themes of Paul's and the general letters","Grasp the hope of Revelation and how the whole Bible fits together"],"requirements":["No prior Bible knowledge required","A Bible (print or app) is helpful","An open and curious heart"],"about":"This survey walks you through the entire New Testament in six modules, beginning with the life of Jesus in the four Gospels, moving to the gospel message and the birth of the Church in Acts, then through the letters of Paul and other apostles, and finishing with the hope of Revelation and the big picture of the whole Bible. You will come to know Jesus, who He is and what He has done, and understand how to live as His follower. Ideal for new believers, seekers, and anyone wanting to read the New Testament with clarity and confidence.","modules":[{"title":"Module 1: The Life of Jesus (Part 1)","icon":"⭐","meta":"4 lessons","lessons":[{"t":"1.1 The New Testament: The Story of Jesus and His Church","d":"12:00","v":"Q0BrP8bqj0c"},{"t":"1.2 The Four Gospels: Four Portraits of Jesus","d":"12:00","v":"3Dv4-n6OYGI"},{"t":"1.3 The Birth and Early Life of Jesus","d":"12:00","v":"XIb_dCIxzr0"},{"t":"📝 Quiz: The Life of Jesus (Part 1)","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: The Life of Jesus (Part 2)","icon":"✝️","meta":"4 lessons","lessons":[{"t":"2.1 Jesus' Teaching: The Kingdom & Sermon on the Mount","d":"12:00","v":"B0O525zOstQ"},{"t":"2.2 Parables and Miracles","d":"12:00","v":"XIb_dCIxzr0"},{"t":"2.3 The Death and Resurrection of Jesus","d":"12:00","v":"G_OlRWGLdnw"},{"t":"📝 Quiz: The Life of Jesus (Part 2)","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Who Is Jesus & the Gospel","icon":"🕊️","meta":"4 lessons","lessons":[{"t":"3.1 Who Is Jesus? The Heart of the New Testament","d":"12:00","v":"CGbNw855ksw"},{"t":"3.2 The Gospel Message and How to Respond","d":"12:00","v":"Kq3-bwr25j4"},{"t":"3.3 The Reliability of the New Testament","d":"12:00","v":"ej_6dVdJSIU"},{"t":"🛠️ Project: Share the Story of Jesus","d":"Project","isProject":true}]},{"title":"Module 4: The Early Church and Paul","icon":"🔥","meta":"4 lessons","lessons":[{"t":"4.1 The Birth of the Church: Acts and Pentecost","d":"12:00","v":"lXF2nBEkgUE"},{"t":"4.2 The Gospel Spreads: Persecution and Mission","d":"12:00","v":"CGbNw855ksw"},{"t":"4.3 Paul's Letters to the Churches","d":"12:00","v":"5nvVVcYD-0w"},{"t":"📝 Quiz: The Early Church and Paul","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: The Letters and Revelation","icon":"📨","meta":"4 lessons","lessons":[{"t":"5.1 Living the Christian Life: The General Letters","d":"12:00","v":"7_CGP-12AE0"},{"t":"5.2 The Church as God's Family and Body","d":"12:00","v":"ak06MSETeo4"},{"t":"5.3 Hope and Victory: The Book of Revelation","d":"12:00","v":"ak06MSETeo4"},{"t":"📝 Quiz: The Letters and Revelation","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: The Whole Story & Next Steps","icon":"🌍","meta":"4 lessons","lessons":[{"t":"6.1 The Whole Story: How the Bible Fits Together","d":"12:00","v":"QxOeq3of3O4"},{"t":"6.2 Applying the New Testament to Your Life","d":"12:00","v":"B0O525zOstQ"},{"t":"6.3 Continuing to Grow: Your Next Steps","d":"12:00","v":"Q0BrP8bqj0c"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: The Life of Jesus (Part 1)","moduleNum":1,"unlocks":2,"questions":[{"q":"How many books are in the New Testament?","opts":["39","27","66","12"],"correct":1,"exp":"The New Testament contains 27 books, from Matthew to Revelation."},{"q":"The first four books of the New Testament are called:","opts":["The Letters","The Gospels","The Prophets","The Acts"],"correct":1,"exp":"Matthew, Mark, Luke, and John are the four Gospels, accounts of Jesus' life."},{"q":"The word \"gospel\" means:","opts":["Old law","Good news","A prophecy","A miracle"],"correct":1,"exp":"\"Gospel\" means \"good news\", the announcement of salvation in Jesus."},{"q":"Which Gospel presents Jesus most clearly as God the Son, beginning \"In the beginning was the Word\"?","opts":["Matthew","Mark","Luke","John"],"correct":3,"exp":"John 1:1 opens with the Word who \"was God\" and \"became flesh.\""},{"q":"Matthew especially presents Jesus as:","opts":["The suffering servant only","The promised Messiah and King","A Greek philosopher","An angel"],"correct":1,"exp":"Matthew, written for Jewish readers, presents Jesus as the promised Messiah and King."},{"q":"Jesus was born in the town of:","opts":["Nazareth","Bethlehem","Jerusalem","Capernaum"],"correct":1,"exp":"Jesus was born in Bethlehem, fulfilling Micah 5:2."},{"q":"The \"incarnation\" means:","opts":["Jesus became an angel","God the Son became a human being","A prophet wrote Scripture","Jesus never truly existed"],"correct":1,"exp":"The incarnation is God the Son taking on human flesh (John 1:14)."},{"q":"Who prepared the way for Jesus, calling people to repent and baptizing Him?","opts":["Peter","John the Baptist","Paul","Stephen"],"correct":1,"exp":"John the Baptist prepared the way and baptized Jesus (Matthew 3)."},{"q":"When tempted by Satan in the wilderness, Jesus responded by:","opts":["Performing a miracle","Quoting Scripture","Calling angels","Staying silent"],"correct":1,"exp":"Jesus answered each temptation with Scripture and did not sin (Matthew 4:1-11)."},{"q":"John 20:31 says the Gospels were written so that you may:","opts":["Learn history only","Believe that Jesus is the Christ and have life","Memorize genealogies","Follow Jewish law"],"correct":1,"exp":"The Gospels aim to lead readers to saving faith in Jesus."}]},"mod2":{"title":"Quiz: The Life of Jesus (Part 2)","moduleNum":2,"unlocks":6,"questions":[{"q":"The central theme of Jesus' preaching was:","opts":["The kingdom of God","Roman politics","Farming techniques","His own comfort"],"correct":0,"exp":"Jesus preached \"the kingdom of God is at hand; repent and believe\" (Mark 1:15)."},{"q":"The Sermon on the Mount begins with the:","opts":["Ten Commandments","Beatitudes","Lord's Supper","Great Commission"],"correct":1,"exp":"Matthew 5 opens with the Beatitudes (\"Blessed are...\")."},{"q":"The \"Golden Rule\" (Matthew 7:12) teaches us to:","opts":["Store up gold","Do to others what you wish they would do to you","Avoid all people","Give only to the rich"],"correct":1,"exp":"Treat others as you would want to be treated."},{"q":"A parable is:","opts":["A miracle","A short story that reveals truth about God's kingdom","A prophecy of doom","A type of prayer"],"correct":1,"exp":"Jesus used parables, everyday stories, to teach kingdom truths."},{"q":"The parable of the Prodigal Son mainly shows:","opts":["God's grace toward returning sinners","How to farm","The end of the world","Rules for sacrifice"],"correct":0,"exp":"Luke 15 pictures a father joyfully welcoming home a rebellious child, God's grace."},{"q":"Which was a miracle of Jesus?","opts":["Feeding five thousand with five loaves and two fish","Building the temple","Writing the Law","Parting the Red Sea"],"correct":0,"exp":"Jesus fed the five thousand (John 6), among many miracles."},{"q":"Jesus' final words on the cross, \"It is finished,\" declared that:","opts":["His life was wasted","The work of salvation was complete","The Law was cancelled","He would not rise"],"correct":1,"exp":"John 19:30, the work of salvation was accomplished on the cross."},{"q":"On the cross, Jesus died as:","opts":["A martyr with no purpose","Our substitute, bearing the punishment for sin","A political rebel only","An accident"],"correct":1,"exp":"Jesus bore our sins as our substitute (Isaiah 53:5)."},{"q":"The resurrection of Jesus proves:","opts":["Nothing important","His victory over sin and death","That He was only human","That the tomb was never used"],"correct":1,"exp":"The bodily resurrection confirms Jesus' victory and identity as God's Son (Romans 1:4)."},{"q":"How many witnesses does 1 Corinthians 15 say saw the risen Jesus?","opts":["Only one","Just the twelve","More than five hundred","No one"],"correct":2,"exp":"Paul cites more than 500 eyewitnesses of the risen Christ (1 Corinthians 15:6)."}]},"mod4":{"title":"Quiz: The Early Church and Paul","moduleNum":4,"unlocks":5,"questions":[{"q":"The book that tells the story of the early Church is:","opts":["Revelation","Acts","Genesis","Hebrews"],"correct":1,"exp":"Acts, written by Luke, records the birth and growth of the Church."},{"q":"The Holy Spirit was poured out on the believers at:","opts":["Passover","Pentecost","Christmas","The Exodus"],"correct":1,"exp":"Acts 2 records the Spirit coming at Pentecost, birthing the Church."},{"q":"On the day of Pentecost, about how many people believed and were baptized?","opts":["Twelve","One hundred","Three thousand","Five hundred"],"correct":2,"exp":"About 3,000 were added to the Church that day (Acts 2:41)."},{"q":"Jesus said in Acts 1:8 that His followers would be His witnesses:","opts":["Only in Jerusalem","To the end of the earth","For one year only","In secret"],"correct":1,"exp":"The gospel was to spread from Jerusalem to the ends of the earth."},{"q":"The fierce persecutor who became the great missionary Paul was first named:","opts":["Simon","Saul","Stephen","Silas"],"correct":1,"exp":"Saul of Tarsus was converted on the Damascus road and became Paul (Acts 9)."},{"q":"The first Christian martyr, stoned for his witness, was:","opts":["Peter","Stephen","James","John"],"correct":1,"exp":"Stephen was the first martyr (Acts 7), and the persecution scattered the believers."},{"q":"God showed Peter (Acts 10) that the gospel is for:","opts":["Only the Jews","Everyone, including Gentiles","Only the rich","Only the apostles"],"correct":1,"exp":"The good news is for all peoples, not the Jews alone."},{"q":"Paul's letter that most fully explains the gospel, teaching we are \"justified by faith,\" is:","opts":["Romans","Philemon","Jude","Revelation"],"correct":0,"exp":"Romans is Paul's great explanation of the gospel and justification by faith."},{"q":"\"For by grace you have been saved through faith\" is found in:","opts":["Ephesians 2:8","Genesis 1:1","Psalm 23","Acts 1:8"],"correct":0,"exp":"Ephesians 2:8-9 teaches salvation by grace through faith, not works."},{"q":"Paul's letters typically move from:","opts":["Rules to rewards","The truth of what God did to how we should live","Stories to songs","Law to more law"],"correct":1,"exp":"Paul first states gospel truth, then the response, live transformed because you are saved."}]},"mod5":{"title":"Quiz: The Letters and Revelation","moduleNum":5,"unlocks":6,"questions":[{"q":"The letter that shows Jesus is greater than everything in the Old Testament is:","opts":["Hebrews","James","Jude","Revelation"],"correct":0,"exp":"Hebrews presents Jesus as the better priest and sacrifice, urging perseverance."},{"q":"James teaches that genuine faith:","opts":["Needs no action","Produces good works","Is only a feeling","Is impossible"],"correct":1,"exp":"\"Faith by itself, if it does not have works, is dead\" (James 2:17)."},{"q":"1 John stresses that those who know God will:","opts":["Seek wealth","Love one another","Live alone","Avoid the church"],"correct":1,"exp":"\"God is love\"; those who know Him love one another (1 John 4:8)."},{"q":"\"You are the body of Christ and individually members of it\" is a picture of:","opts":["The Roman empire","The Church","The temple building","The nation of Israel"],"correct":1,"exp":"1 Corinthians 12:27 pictures the Church as Christ's body with many members."},{"q":"The many \"one another\" commands (love, encourage, forgive) show that the Church is:","opts":["A solo activity","A family meant to live in love together","A business","A political party"],"correct":1,"exp":"Believers belong to one another and are called to love and serve one another."},{"q":"Jesus said people would know we are His disciples by our:","opts":["Wealth","Love for one another","Buildings","Knowledge"],"correct":1,"exp":"\"By this all people will know that you are my disciples, if you have love\" (John 13:35)."},{"q":"The book of Revelation was written to:","opts":["Frighten people needlessly","Encourage persecuted Christians that Jesus wins","Predict every news event","Replace the Gospels"],"correct":1,"exp":"Revelation encourages suffering believers with the certainty of Christ's victory."},{"q":"Revelation promises that in the end God will:","opts":["Abandon the earth","Make all things new and wipe away every tear","Leave evil in power","Start over with a flood"],"correct":1,"exp":"Revelation 21:3-4 promises a new heaven and earth with no more death or pain."},{"q":"The Bible closes with the prayer:","opts":["\"Come, Lord Jesus!\"","\"Let there be light\"","\"It is finished\"","\"Here am I\""],"correct":0,"exp":"Revelation 22:20, \"Amen. Come, Lord Jesus!\""},{"q":"The main message of Revelation, despite its symbols, is that:","opts":["Evil will win","Jesus reigns and will triumph","No one can be saved","The Church will fail"],"correct":1,"exp":"Revelation assures believers that Christ reigns and evil will finally be defeated."}]},"final":{"title":"Final Assessment & Certificate","moduleNum":6,"unlocks":0,"isFinal":true,"questions":[{"q":"The New Testament contains how many books?","opts":["39","27","66","12"],"correct":1,"exp":"The New Testament has 27 books."},{"q":"The four accounts of Jesus' life are called the:","opts":["Letters","Gospels","Prophets","Psalms"],"correct":1,"exp":"Matthew, Mark, Luke, and John are the Gospels."},{"q":"Jesus was born in Bethlehem to:","opts":["A queen","The virgin Mary","A priest","An angel"],"correct":1,"exp":"Jesus was born to the virgin Mary in Bethlehem."},{"q":"The central theme of Jesus' preaching was:","opts":["Wealth","The kingdom of God","Roman law","Farming"],"correct":1,"exp":"Jesus preached the kingdom of God (Mark 1:15)."},{"q":"The Sermon on the Mount begins with the:","opts":["Beatitudes","Ten Commandments","Lord's Supper","Great Commission"],"correct":0,"exp":"Matthew 5 opens with the Beatitudes."},{"q":"Jesus taught mainly through short stories called:","opts":["Laws","Parables","Songs","Letters"],"correct":1,"exp":"Parables reveal truths about God's kingdom."},{"q":"On the cross Jesus died as:","opts":["A helpless victim only","Our substitute for sin","A myth","A soldier"],"correct":1,"exp":"Jesus bore our sins as our substitute (Isaiah 53:5)."},{"q":"\"It is finished\" declared that:","opts":["Jesus failed","Salvation's work was complete","The Law was expanded","He would not rise"],"correct":1,"exp":"John 19:30, the work of salvation was accomplished."},{"q":"The resurrection of Jesus:","opts":["Was only symbolic","Was bodily and defeated death","Never happened","Was seen by no one"],"correct":1,"exp":"Jesus rose bodily, proving His victory over death."},{"q":"The Holy Spirit came upon the believers at:","opts":["Passover","Pentecost","Christmas","Sinai"],"correct":1,"exp":"The Spirit was poured out at Pentecost (Acts 2)."},{"q":"The persecutor who became the great missionary Paul was named:","opts":["Peter","Saul","Stephen","James"],"correct":1,"exp":"Saul of Tarsus became Paul after meeting the risen Jesus."},{"q":"Acts 1:8 says the gospel would spread:","opts":["Only in Jerusalem","To the end of the earth","For one year","In secret"],"correct":1,"exp":"The gospel was to reach the ends of the earth."},{"q":"Romans teaches that we are:","opts":["Saved by works","Justified by faith in Christ","Saved by the Law","Never able to be saved"],"correct":1,"exp":"Romans explains justification by faith (Romans 5:1)."},{"q":"\"For by grace you have been saved through faith\" is in:","opts":["Ephesians 2:8","Genesis 1:1","Psalm 23","Mark 1:1"],"correct":0,"exp":"Ephesians 2:8-9, salvation by grace through faith."},{"q":"James teaches that genuine faith:","opts":["Needs no action","Produces good works","Is only feeling","Is impossible"],"correct":1,"exp":"Real faith produces works (James 2:17)."},{"q":"The Church is pictured in the New Testament as:","opts":["A building only","The body and family of Christ","A government","A business"],"correct":1,"exp":"The Church is Christ's body and God's family."},{"q":"The final book of the Bible is:","opts":["Acts","Revelation","Jude","Hebrews"],"correct":1,"exp":"Revelation is the last book of the Bible."},{"q":"Revelation's main message is that:","opts":["Evil wins","Jesus reigns and triumphs","No one is saved","The Church fails"],"correct":1,"exp":"Revelation assures believers that Christ wins."},{"q":"The whole Bible tells one story often summarized as:","opts":["Creation, Fall, Redemption, Restoration","Law, War, Peace, End","Birth, Life, Death only","Rich, Poor, Rich again"],"correct":0,"exp":"The Bible's storyline: Creation, Fall, Redemption, Restoration."},{"q":"According to John 14:6, the way to the Father is:","opts":["Through good works","Through Jesus alone","Through many paths","Through no one"],"correct":1,"exp":"Jesus said, \"No one comes to the Father except through me.\""}]}},"reviews":[{"name":"Mercy K.","rating":5,"text":"I have read the Gospels before, but now I finally understand how the whole New Testament fits together. Beautiful course."},{"name":"Daniel S.","rating":5,"text":"Clear, Christ-centered, and easy to follow. The section on Paul's letters was so helpful."},{"name":"Blessing T.","rating":5,"text":"This course helped me understand the gospel and share it with my family. Thank you TIH Bible School!"}],"faqs":[{"q":"Do I need to have read the New Testament before taking this?","a":"No. This survey is written for beginners and explains everything clearly, pointing you to the verses so you can read along."},{"q":"Is this course only for Christians?","a":"Not at all. Seekers with honest questions are very welcome. The course explains who Jesus is and invites you to consider the good news."},{"q":"Will I get a certificate?","a":"Yes. Complete all modules and pass the final assessment (70%) to earn your TIH Bible School certificate."}]};
COURSES_DB['bible-foundations'] = {"id":"bible-foundations","title":"Christian Foundations & Discipleship: Building a Life on the Word","shortDesc":"A complete beginner's guide to the Christian faith, who God is, the gospel of Jesus, salvation, prayer, the Holy Spirit, the Church, and how to grow as a disciple.","category":"TIH Bible School","icon":"🕊️","gradient":"linear-gradient(135deg,#1565D8,#0B1F3A)","instructor":"TIH Bible School","instructorTitle":"Discipleship Faculty","instructorBio":"The TIH Bible School equips learners across Liberia with clear, Bible-centered teaching for a growing faith and a life of service.","rating":4.9,"reviewCount":128,"students":640,"duration":"6 weeks","level":"Beginner","price":"$2","origPrice":"$10","isFree":false,"badge":"new","certId":"TIH-2026-BIB-CF01","learn":["Understand who God is and the doctrine of the Trinity","Explain the gospel: sin, the cross, the resurrection, and salvation by grace","Know what it means to be born again and have assurance of salvation","Build daily habits of prayer and Bible reading","Understand the Holy Spirit and grow the fruit of the Spirit","Live and share your faith as a committed disciple of Jesus"],"requirements":["No prior Bible knowledge required","A Bible (print or app) is helpful","An open heart and willingness to learn"],"about":"This course lays a solid, Bible-based foundation for anyone exploring or beginning the Christian faith. Over six modules you will move from knowing who God is, through the gospel of Jesus Christ and the meaning of salvation, into the practical habits of prayer, Scripture, church life, and mission. Whether you are a brand-new believer, a seeker with questions, or someone wanting to refresh the basics, this course will ground you in the essentials and set you on a path of lifelong growth as a disciple of Jesus.","modules":[{"title":"Module 1: Knowing God","icon":"📖","meta":"4 lessons","lessons":[{"t":"1.1 Who Is God? Knowing the One We Worship","d":"12:00","v":"eAvYmE2YYIU"},{"t":"1.2 The Trinity: One God, Three Persons","d":"12:00","v":"eAvYmE2YYIU"},{"t":"1.3 The Bible: God's Word to Us","d":"12:00","v":"ak06MSETeo4"},{"t":"📝 Quiz: Knowing God","d":"10 questions","isQuiz":true,"quizId":"mod1"}]},{"title":"Module 2: The Human Problem and God's Rescue","icon":"✝️","meta":"4 lessons","lessons":[{"t":"2.1 Created in God's Image, and the Problem of Sin","d":"12:00","v":"GQI72THyO5I"},{"t":"2.2 Jesus Christ: Fully God, Fully Man","d":"12:00","v":"QxOeq3of3O4"},{"t":"2.3 The Cross and the Resurrection","d":"12:00","v":"G_OlRWGLdnw"},{"t":"📝 Quiz: The Human Problem and God's Rescue","d":"10 questions","isQuiz":true,"quizId":"mod2"}]},{"title":"Module 3: Salvation and New Life","icon":"🕊️","meta":"4 lessons","lessons":[{"t":"3.1 Grace, Faith, and Salvation","d":"12:00","v":"B0O525zOstQ"},{"t":"3.2 The New Birth: Becoming a Child of God","d":"12:00","v":"Kq3-bwr25j4"},{"t":"3.3 Assurance: How Can I Know I Am Saved?","d":"12:00","v":"7_CGP-12AE0"},{"t":"🛠️ Project: Write Your Testimony","d":"Project","isProject":true}]},{"title":"Module 4: Walking with God","icon":"🙏","meta":"4 lessons","lessons":[{"t":"4.1 Prayer: Talking with Your Father","d":"12:00","v":"3Dv4-n6OYGI"},{"t":"4.2 The Holy Spirit and the Fruit He Grows","d":"12:00","v":"Kq3-bwr25j4"},{"t":"4.3 Reading and Obeying God's Word","d":"12:00","v":"ak06MSETeo4"},{"t":"📝 Quiz: Walking with God","d":"10 questions","isQuiz":true,"quizId":"mod4"}]},{"title":"Module 5: The Church and the Christian Life","icon":"⛪","meta":"4 lessons","lessons":[{"t":"5.1 The Church: God's Family and Community","d":"12:00","v":"7_CGP-12AE0"},{"t":"5.2 Living as a Disciple: Holiness and Everyday Faith","d":"12:00","v":"B0O525zOstQ"},{"t":"5.3 The Church's Ordinances in Practice","d":"12:00","v":"G_OlRWGLdnw"},{"t":"📝 Quiz: The Church and the Christian Life","d":"10 questions","isQuiz":true,"quizId":"mod5"}]},{"title":"Module 6: Mission, Hope, and Next Steps","icon":"🌍","meta":"4 lessons","lessons":[{"t":"6.1 Sharing Your Faith and the Great Commission","d":"12:00","v":"B0O525zOstQ"},{"t":"6.2 Hope for the Future: Christ's Return and Eternity","d":"12:00","v":"Zy2AQlK6C5k"},{"t":"6.3 Next Steps: Growing for a Lifetime","d":"12:00","v":"ak06MSETeo4"},{"t":"🏆 Final Assessment & Certificate","d":"20 questions","isQuiz":true,"quizId":"final","isFinal":true}]}],"quizzes":{"mod1":{"title":"Quiz: Knowing God","moduleNum":1,"unlocks":2,"questions":[{"q":"According to Genesis 1:1, what did God do \"in the beginning\"?","opts":["Created the heavens and the earth","Rested from His work","Called Abraham","Gave the Ten Commandments"],"correct":0,"exp":"Genesis 1:1 opens the Bible: \"In the beginning God created the heavens and the earth.\""},{"q":"When Moses asked God His name, God replied:","opts":["\"I am the God of thunder\"","\"I AM WHO I AM\"","\"My name is hidden\"","\"Call me the Almighty only\""],"correct":1,"exp":"In Exodus 3:14 God reveals Himself as \"I AM WHO I AM,\" the self-existent, eternal One."},{"q":"The doctrine of the Trinity teaches that God is:","opts":["Three separate gods","One God who wears three masks at different times","One God eternally existing as three Persons","A force with no personality"],"correct":2,"exp":"God is one Being in three distinct Persons, Father, Son, and Holy Spirit, not three gods and not one Person in three roles."},{"q":"Which verse affirms that there is only one God?","opts":["Deuteronomy 6:4, \"The Lord our God, the Lord is one\"","John 11:35, \"Jesus wept\"","Psalm 23:1, \"The Lord is my shepherd\"","Genesis 6:9, \"Noah was a righteous man\""],"correct":0,"exp":"Deuteronomy 6:4, the Shema, declares the oneness of God."},{"q":"Which of these is a true statement about God's character?","opts":["God changes His mind about right and wrong","God is holy, loving, and faithful","God can be surprised by events","God needs creation to survive"],"correct":1,"exp":"Scripture describes God as holy (Isaiah 6:3), love (1 John 4:8), and faithful (Deuteronomy 32:4)."},{"q":"How many books are in the Bible?","opts":["27","39","66","100"],"correct":2,"exp":"The Bible contains 66 books, 39 in the Old Testament and 27 in the New Testament."},{"q":"\"All Scripture is God-breathed\" is found in:","opts":["2 Timothy 3:16","Genesis 1:1","Matthew 1:1","Revelation 22:21"],"correct":0,"exp":"2 Timothy 3:16 teaches that Scripture is inspired (\"God-breathed\") and useful for teaching and training."},{"q":"At Jesus' baptism (Matthew 3:16-17), how did all three Persons of the Trinity appear?","opts":["Only the Father spoke; no others were present","The Son in the water, the Spirit as a dove, the Father's voice from heaven","Three identical men stood together","An angel represented all three"],"correct":1,"exp":"At the baptism the Son is in the water, the Spirit descends like a dove, and the Father speaks, a clear picture of the Trinity."},{"q":"Which statement about the Bible is correct?","opts":["It was written by one author in one year","It is our final authority for faith and life","It contains only human opinions","It should be trusted only where it agrees with tradition"],"correct":1,"exp":"Though written by about 40 human authors, the Bible is God-breathed and is the Christian's final authority."},{"q":"A good first Gospel for a new believer to read, to meet Jesus, is:","opts":["Leviticus","John","Numbers","Chronicles"],"correct":1,"exp":"The Gospel of John is often recommended first because it clearly presents who Jesus is and why to believe in Him."}]},"mod2":{"title":"Quiz: The Human Problem and God's Rescue","moduleNum":2,"unlocks":6,"questions":[{"q":"According to Genesis 1:27, human beings are made:","opts":["From nothing important","In the image of God","Only to serve animals","Without any purpose"],"correct":1,"exp":"Genesis 1:27 says God created humanity \"in his own image,\" giving every person dignity and worth."},{"q":"At its root, sin is best described as:","opts":["Only major crimes like murder","Turning away from God to go our own way","Making honest mistakes","Being poor or uneducated"],"correct":1,"exp":"Isaiah 53:6 pictures sin as each turning \"to his own way\", a rebellion of the heart, not merely outward crimes."},{"q":"Romans 3:23 states that:","opts":["Only some people sin","All have sinned and fall short of the glory of God","Sin is not a real problem","Good people have no sin"],"correct":1,"exp":"Romans 3:23 declares that everyone has sinned and falls short of God's glory."},{"q":"The \"incarnation\" refers to:","opts":["Jesus becoming an angel","The Word (God the Son) becoming flesh/human","A prophet writing Scripture","The Spirit filling the temple"],"correct":1,"exp":"John 1:14, \"the Word became flesh\", describes the incarnation, God the Son taking on humanity."},{"q":"Why is it essential that Jesus is both fully God and fully man?","opts":["So He could avoid suffering","So He could stand in our place as a man and, as God, carry sin's full weight","So He would not need to die","So He could rule only in heaven"],"correct":1,"exp":"Only one who is truly human could represent us, and only one who is truly God could bear the infinite weight of sin."},{"q":"According to 1 Peter 2:24, on the cross Jesus:","opts":["Merely gave a good example","Bore our sins in His body","Escaped death entirely","Taught a new philosophy"],"correct":1,"exp":"1 Peter 2:24 says Jesus \"himself bore our sins in his body on the tree\", a substitution for us."},{"q":"Romans 5:8 shows God's love in that:","opts":["Christ died for us while we were still sinners","We first made ourselves worthy","God waited until people were good","Only the righteous were saved"],"correct":0,"exp":"Romans 5:8, Christ died for us \"while we were still sinners,\" showing love we did not earn."},{"q":"The resurrection of Jesus is important because it:","opts":["Was only symbolic","Proves His sacrifice was accepted and death is defeated","Made no difference to faith","Happened only in a vision"],"correct":1,"exp":"The bodily resurrection proves the sacrifice was accepted and that Jesus conquered death (Romans 1:4; 1 Corinthians 15)."},{"q":"Paul says in 1 Corinthians 15:17 that if Christ has not been raised, then:","opts":["Faith is stronger than ever","Your faith is futile","Sin is no longer a problem","The Old Testament is false"],"correct":1,"exp":"Paul stakes everything on the resurrection: without it, \"your faith is futile.\""},{"q":"The \"wages of sin,\" according to Romans 6:23, is:","opts":["Wealth","Death (separation from God)","Wisdom","Nothing at all"],"correct":1,"exp":"Romans 6:23, \"the wages of sin is death, but the free gift of God is eternal life in Christ Jesus.\""}]},"mod4":{"title":"Quiz: Walking with God","moduleNum":4,"unlocks":5,"questions":[{"q":"Prayer is best defined as:","opts":["Reciting magic words","Communication with God, speaking and listening","A ritual only priests may do","Asking only for money"],"correct":1,"exp":"Prayer is talking with God as our Father, both bringing requests and listening to Him."},{"q":"The memory aid \"ACTS\" for prayer stands for:","opts":["Ask, Come, Take, Stop","Adoration, Confession, Thanksgiving, Supplication","Action, Care, Trust, Serve","Adore, Cry, Talk, Sing"],"correct":1,"exp":"ACTS = Adoration, Confession, Thanksgiving, and Supplication, a balanced pattern for prayer."},{"q":"The Holy Spirit is:","opts":["An impersonal force","The third Person of the Trinity who lives in believers","An angel sent by Jesus","Only an Old Testament figure"],"correct":1,"exp":"The Holy Spirit is a divine Person, God Himself, who indwells every believer (John 14:16-17)."},{"q":"Which list gives the fruit of the Spirit from Galatians 5:22-23?","opts":["Wealth, power, fame, comfort","Love, joy, peace, patience, kindness, goodness, faithfulness, gentleness, self-control","Knowledge, speed, strength, beauty","Rules, rituals, feasts, offerings"],"correct":1,"exp":"Galatians 5:22-23 lists the ninefold fruit the Spirit grows in a believer's character."},{"q":"The fruit of the Spirit is called \"fruit\" rather than \"works\" because it:","opts":["Is optional for Christians","Grows naturally as we stay connected to Christ","Is earned by hard effort alone","Only applies to pastors"],"correct":1,"exp":"Like fruit on a branch, godly character grows as we abide in Christ (John 15:5), not by mere willpower."},{"q":"A helpful method for reading Scripture is:","opts":["Read, Reflect, Respond","Skim and forget","Read only the maps","Wait for a dream"],"correct":0,"exp":"Read the text, reflect on what it teaches, and respond in prayer and obedience."},{"q":"James 1:22 warns us to be:","opts":["Hearers only","Doers of the word, not hearers only","Silent always","Teachers before learners"],"correct":1,"exp":"James 1:22 calls us to be \"doers of the word, and not hearers only,\" or we deceive ourselves."},{"q":"Psalm 119:11 gives a reason to memorize Scripture:","opts":["To impress others","\"That I might not sin against you\"","To win debates","To finish reading faster"],"correct":1,"exp":"Storing God's Word in the heart guards us against sin (Psalm 119:11)."},{"q":"According to John 16:13, the Holy Spirit guides believers into:","opts":["Wealth","All truth","Political power","Secret knowledge for a few"],"correct":1,"exp":"Jesus promised the Spirit would guide His people \"into all truth.\""},{"q":"Jesus' warning in Matthew 7:24-27 is that hearing His words without doing them is like:","opts":["Building a house on rock","Building a house on sand","Planting a strong tree","Storing treasure in heaven"],"correct":1,"exp":"The one who hears but does not obey is like a foolish man who built on sand, his house falls."}]},"mod5":{"title":"Quiz: The Church and the Christian Life","moduleNum":5,"unlocks":6,"questions":[{"q":"In the Bible, the \"Church\" is primarily:","opts":["A building made of stone","The community of all who belong to Jesus","A government office","A single denomination only"],"correct":1,"exp":"The Church is the people of God, all who belong to Christ, gathered locally to worship and serve."},{"q":"Hebrews 10:24-25 encourages believers to:","opts":["Avoid other Christians","Not neglect meeting together","Worship only alone","Stop encouraging one another"],"correct":1,"exp":"We are told not to neglect meeting together but to stir one another to love and good works."},{"q":"Baptism is best described as:","opts":["A way to earn salvation","The public sign of a believer's union with Christ in His death and resurrection","A ritual only for babies","An optional cultural custom"],"correct":1,"exp":"Baptism pictures the believer's union with Christ (Romans 6:4), an outward sign of an inward change."},{"q":"The Lord's Supper (Communion) is given to help us:","opts":["Forget the past","Remember Christ's body and blood given for us","Earn extra blessings","Replace prayer"],"correct":1,"exp":"1 Corinthians 11:24-26, the Supper is taken in remembrance of Christ until He returns."},{"q":"God's call in 1 Peter 1:16 is:","opts":["\"You shall be wealthy\"","\"You shall be holy, for I am holy\"","\"You shall be famous\"","\"You shall be comfortable\""],"correct":1,"exp":"God calls His people to holiness that reflects His own character."},{"q":"Taking up your cross daily (Luke 9:23) means:","opts":["Wearing a cross necklace","Denying self and following Jesus","Avoiding all hardship","Living for personal comfort"],"correct":1,"exp":"Jesus calls disciples to deny themselves, take up their cross daily, and follow Him."},{"q":"When a believer sins, the right response according to 1 John 1:9 is to:","opts":["Hide from God in shame","Confess, trusting God to forgive","Give up on faith","Pretend it did not happen"],"correct":1,"exp":"\"If we confess our sins, he is faithful and just to forgive us\", we run to God, not from Him."},{"q":"The right motive for obedience, according to 1 John 4:19, is:","opts":["To earn God's love","Because \"we love because he first loved us\"","Fear of other people","To look good in public"],"correct":1,"exp":"We obey out of gratitude for love already received, not to earn what is freely given."},{"q":"Ephesians 4:13 says the Church helps believers grow toward:","opts":["Financial success","The fullness of Christ / maturity","Political influence","Isolation from others"],"correct":1,"exp":"The Church exists in part to bring believers to maturity, \"the measure of the stature of the fullness of Christ.\""},{"q":"According to 1 Corinthians 12:7, spiritual gifts are given:","opts":["For personal pride","For the common good / to build up others","Only to leaders","To keep secret"],"correct":1,"exp":"Every believer receives gifts \"for the common good\", to serve and strengthen the body."}]},"final":{"title":"Final Assessment & Certificate","moduleNum":6,"unlocks":0,"isFinal":true,"questions":[{"q":"The Bible reveals God as:","opts":["A distant force","Eternal, Creator, and personal","One of many equal gods","A human invention"],"correct":1,"exp":"God is eternal, the Creator of all, and a personal God who can be known."},{"q":"The Trinity means God is one Being in:","opts":["Three separate gods","Three Persons, Father, Son, and Holy Spirit","One Person with three names","Two Persons only"],"correct":1,"exp":"One God eternally exists as three distinct Persons."},{"q":"The Old Testament and New Testament together contain how many books?","opts":["39","27","66","73"],"correct":2,"exp":"39 (OT) + 27 (NT) = 66 books."},{"q":"Human beings are made \"in the image of God,\" which gives every person:","opts":["The right to sin freely","Dignity, worth, and capacity to know God","Automatic salvation","Power over God"],"correct":1,"exp":"Genesis 1:27 grounds human dignity and our capacity to know God in being made in His image."},{"q":"Sin, at its heart, is:","opts":["Only breaking human laws","Turning away from God to go our own way","A minor weakness","Impossible to overcome by grace"],"correct":1,"exp":"Sin is rebellion of the heart against God (Isaiah 53:6), affecting everyone (Romans 3:23)."},{"q":"Jesus Christ is:","opts":["Only a good teacher","Fully God and fully man","An angel","A myth"],"correct":1,"exp":"Jesus is the eternal Son of God who became truly human (John 1:14)."},{"q":"On the cross, Jesus:","opts":["Set only a moral example","Bore our sins as our substitute","Failed in His mission","Merely appeared to suffer"],"correct":1,"exp":"Jesus bore our sins in His body (1 Peter 2:24), taking the punishment we deserved."},{"q":"The resurrection of Jesus:","opts":["Was symbolic only","Was a bodily rising that defeated death","Never really mattered","Happened to someone else"],"correct":1,"exp":"Jesus rose bodily, proving His victory over death and His identity as God's Son."},{"q":"We are saved, according to Ephesians 2:8-9:","opts":["By our good works","By grace through faith, as a gift of God","By keeping religious rules","By our family background"],"correct":1,"exp":"Salvation is by grace through faith, \"not a result of works, so that no one may boast.\""},{"q":"To be \"born again\" (John 3) means:","opts":["To be physically reborn","To receive new spiritual life from God","To join a certain tribe","To become sinless immediately"],"correct":1,"exp":"The new birth is God giving new life so we become His children (John 1:12-13)."},{"q":"A believer can have assurance of salvation based on:","opts":["Feelings alone","God's promises, Christ's finished work, and the Spirit's witness","Never sinning again","Being religious enough"],"correct":1,"exp":"1 John 5:13, assurance rests on God's Word, Christ's work, and the Spirit, not on perfect performance."},{"q":"The pattern \"ACTS\" helps us:","opts":["Read history","Pray in a balanced way","Memorize maps","Plan finances"],"correct":1,"exp":"Adoration, Confession, Thanksgiving, Supplication, a balanced approach to prayer."},{"q":"The fruit of the Spirit (Galatians 5:22-23) begins with:","opts":["Wealth","Love, joy, peace","Fear, guilt, shame","Power, fame, comfort"],"correct":1,"exp":"The list begins \"love, joy, peace, patience...\", the character the Spirit grows in us."},{"q":"James 1:22 tells us to be:","opts":["Hearers only","Doers of the word","Silent listeners","Teachers first"],"correct":1,"exp":"We must put God's Word into practice, not merely hear it."},{"q":"The local church matters because it provides:","opts":["A place to be alone","Worship, fellowship, growth, and service","Only entertainment","A way to avoid God"],"correct":1,"exp":"The church is God's family where believers worship, grow, serve, and encourage one another."},{"q":"Baptism and the Lord's Supper are:","opts":["Ways to earn salvation","Two ordinances Jesus gave the Church","Old Testament laws","Optional cultural customs"],"correct":1,"exp":"Jesus gave baptism and the Lord's Supper as signs for His Church to observe."},{"q":"The Great Commission (Matthew 28:19-20) commands believers to:","opts":["Stay silent about Jesus","Make disciples of all nations","Focus only on themselves","Wait for angels to do it"],"correct":1,"exp":"Jesus commands His followers to go, make disciples, baptize, and teach."},{"q":"When sharing the gospel, 1 Peter 3:15 says to do it with:","opts":["Force and pressure","Gentleness and respect","Cleverness and tricks","Money and gifts"],"correct":1,"exp":"We witness with \"gentleness and respect,\" trusting the Spirit to convince hearts."},{"q":"The Christian's future hope includes:","opts":["Nothing after death","Christ's return and a new heaven and new earth","Reincarnation","Becoming a god"],"correct":1,"exp":"Believers await Jesus' return and the renewal of all things (Revelation 21:1-4)."},{"q":"A key habit for lifelong spiritual growth is:","opts":["Avoiding church and Scripture","Daily time with God in the Word and prayer","Trusting only feelings","Keeping faith completely private"],"correct":1,"exp":"Growing disciples feed daily on Scripture and prayer, gather with the church, and obey what they learn."}]}},"reviews":[{"name":"Grace M.","rating":5,"text":"Clear and easy to follow. I finally understand the gospel and how to pray. Thank you TIH!"},{"name":"Emmanuel T.","rating":5,"text":"As a new believer this gave me exactly the foundation I needed. The quizzes helped me remember."},{"name":"Fatu K.","rating":5,"text":"Every lesson points to Scripture. I feel more confident sharing my faith now."}],"faqs":[{"q":"Do I need to be a Christian to take this course?","a":"No. This course is perfect for seekers with questions as well as new believers. Come as you are and explore the faith honestly."},{"q":"Do I need to know the Bible already?","a":"Not at all. Every lesson explains the Scriptures clearly and points you to the verses so you can read them yourself."},{"q":"Will I get a certificate?","a":"Yes. Complete all modules and pass the final assessment (70%) to earn your TIH Bible School certificate."}]};
